window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-013.json"] = [{"name":"黄额鬼鸮","english_name":"Buff-fronted Owl","scientific_name":"Aegolius harrisii","overview":"黄额鬼鸮（英文名：Buff-fronted Owl，学名：Aegolius harrisii），是鸮形目鸱鸮科鬼鸮属的鸟类。小型的、色彩鲜明的鸮。分布广泛但断断续续，遍布南美洲各国，除法属圭亚那和苏里南。以其独特的巧克力棕色外观和奶油色至红褐色的腹部著称。","appearance":"黄额鬼鸮长约19至21厘米，体重介于104至155克之间。它拥有短小的尾巴和大而方正的头部，无耳羽簇。面部盘呈黄褐色，边缘黑色，与深色头部形成强烈对比；眼上有一条显著的黑色斑纹；眼先至喙基部棕色；前冠和颈背黄色至黄褐色；上体巧克力棕色，最深色部分位于头部；翼覆羽有白色斑点；尾部黑褐色，具两道断裂的白色横带和白色尖端；下体黄色至黄褐色；虹膜绿色至黄绿色；喙淡黄色至灰色；跗跖羽黄色；脚裸露部分黄色。幼鸟缺乏上体的黄褐色斑点。dabbenei亚种上体较暗，下体带肉桂色；iheringi亚种上体暗，肩羽边缘黄褐色，脸部和下体更深的橙色。","call":"雄性黄额鬼鸮的叫声为快速、波动的颤音，持续约6至10秒，每秒约15至16个音符，被描述为“frurururururururu”。依赖期的幼鸟会发出嘶哑的‘cheet’声乞食。","habits":"黄额鬼鸮栖息于多种环境，包括开阔湿润森林到树线，干燥地带和峡谷，以及森林边缘；例如松果杉和桤木森林、Polylepis林地、干燥的查科落叶林、塞拉多林地、茂密的卡廷加，半湿润、较为开放的森林，苔藓覆盖的矮树森林近树线处；也出现在富含果树和棕榈的人工景观，以及散布着南洋杉的半开放亚热带雨林。在安第斯山脉，海拔高度为1500至3800米；其他地方较低，大约600至1000米。已知其猎食昆虫、小型哺乳动物、鸟类和小型有袋类。","breeding":"关于黄额鬼鸮的繁殖生态知之甚少。在巴西，3月初在一个死掉的棕榈树洞中发现了一个巢，可能是一个废弃的鹦鹉巢穴，巢深60厘米，直径15厘米，开口10厘米宽，内部铺有牛粪、羽毛和毛发。阿根廷的巢穴位于空心树中。卵的大小在33.0至33.4毫米×27.0至27.6毫米之间。孵化期和育雏期的长度未知。","identification":"黄额鬼鸮与其他同类物种的区别在于其巧克力棕色的上体、奶油色至红褐色的腹部、面部的黑边黄褐色盘和眼上的黑色斑纹。dabbenei和iheringi亚种在颜色上有细微差别。","protection":"IUCN：LC（无危）","distribution":"在南美洲的分布不连续，包括安第斯山脉从委内瑞拉到秘鲁南部的地区，玻利维亚、巴拉圭、巴西东部和南部、阿根廷东北部和巴拉圭东北部，以及阿根廷西北部。在委内瑞拉和圭亚那的特普伊山局部发现。"},{"name":"棕鹰鸮","english_name":"Rufous Owl","scientific_name":"Ninox rufa","overview":"棕鹰鸮（英文名：Rufous Owl，学名：Ninox rufa），是鸮形目鸱鸮科鹰鸮属的鸟类。身披红褐色羽毛，常见于澳大利亚北部、新几内亚及周边岛屿。体型稍小于澳洲最大的猫头鹰——猛鹰鸮，体重介于700至1700克之间，拥有广泛分布但数量稀少的特点。","appearance":"成年棕鹰鸮体长可达40至52厘米，翼展约115厘米，雄鸟体重1150至1300克，雌鸟较轻，为700至1050克。头部相对较小，尾部长。面部轮廓不明显，背部为暗红褐色，饰有淡棕色条纹；腹部白色至浅黄色，密布红褐色条纹；眼睛金黄色，喙为淡蓝灰色。两性外观相似，但雌鸟体型较小。不同亚种在颜色和大小上有所差异。","call":"棕鹰鸮发出低沉、缓慢的双音节叫声，比南方斑猫头鹰或吠鹰鸮的声音更低沉、更慢。","habits":"栖息于热带雨林、湿润草原、季风林和河流沿岸森林边缘，也会出现在城市地区的大型孤立树木中。夜间活动，以中等大小的哺乳动物、小型鸟类和大型昆虫为食。狩猎技巧娴熟，能在地面或空中捕捉猎物。","breeding":"繁殖季节一般在6月至10月，筑巢于大树洞中，巢位高达40米，一窝产卵2枚，孵化期约为36至38天。幼鸟需长时间的父母照顾，直至下一个繁殖季节开始。","identification":"与其他鹰鸮相比，棕鹰鸮的红褐色羽毛更为显著，叫声独特，且栖息地主要限于热带地区。","protection":"IUCN：LC（无危）；CITES II（华盛顿公约附录二）","distribution":"分布于新几内亚和澳大利亚北部，包括阿纳姆地、北金伯利、东约克角半岛和昆士兰东部的麦凯地区。","other":"受森林砍伐、干旱季节热火增多及传统狩猎压力影响，种群数量可能正在下降。"},{"name":"托岛鹰鸮","english_name":"Togian Boobook","scientific_name":"Ninox burhani","overview":"托岛鹰鸮（英文名：Togian Boobook，学名：Ninox burhani），是鸮形目鸱鸮科鹰鸮属的中型棕色猫头鹰，具有醒目的黄色眼睛，仅限于印尼托吉安群岛。于2004年被科学界描述为新种，以当地环保人士Burhan的名字命名。分布于托吉安群岛的三个岛屿，是该地区的特有种。","appearance":"托岛鹰鸮长约25厘米，体重介于98至100克之间，是一种中等体型的暗褐色猫头鹰，尾巴相对较长。其面部有淡色眉毛，在喙基部相连；冠部和上体为深褐色，带浅色斑点和细条纹；肩羽和飞羽为棕色，有条纹和白色斑点，初级飞羽内侧主要是暗褐色；尾巴呈深褐色，带有狭窄的淡褐色横纹；喉咙到胸部为棕红色，边缘为浅色，看起来有斑点或条纹，下胸至腹部为白色，带有棕色条纹；虹膜为橙黄色至黄色；喙尖端为浅奶油色，基部大部分为橄榄灰色；腿和脚趾覆盖有羽毛，底色为暗黄色至暗褐色。雌雄相似，幼鸟特征尚未描述。","call":"托岛鹰鸮的叫声独特，类似于蛙鸣，发出低沉而粗糙的‘kuk kuk-kukkukkuk’声，警报声则为沙哑的‘rrrrrrr-wa-waak’。","habits":"栖息于低地和山地森林，包括受干扰和退化的森林，混交园和西谷沼泽，海拔从海平面至400米。经常出现在灌木丛生的森林中，这些地方通常位于常绿雨林残片的镶嵌地带。白天在树冠中部的隐蔽微环境中休息，有时在密集的小树和藤蔓丛中，或在茂密的竹林中。","identification":"与北鹰鸮相比，托岛鹰鸮的下体有更精细的斑纹，腹部较浅，翅膀上有广泛分布的白色斑点，眉线更加低调。叫声与其他区域内的猫头鹰种类截然不同。","protection":"IUCN：NT（近危）","distribution":"仅分布于托吉安群岛（Malenge、Togian和Batudaka），位于印尼苏拉威西岛东北部的托米尼湾。","other":"托岛鹰鸮的全球数量估计在2500至10000只（约1500至7000只成熟个体），根据BirdLife International的数据。由于其地理范围极小，且种群被分割成几个岛屿亚群，其中一个亚群位于保护区，数量可能超过1000只。"},{"name":"猛鹰鸮","english_name":"Powerful Owl","scientific_name":"Ninox strenua","overview":"猛鹰鸮（英文名：Powerful Owl，学名：Ninox strenua），是鸮形目鸱鸮科鹰鸮属的鸟类。广泛分布在澳大利亚东部和东南部，包括昆士兰东南部至南澳大利亚东南部。此物种以其庞大的体型、令人印象深刻的黄色巨爪和深褐色与白色的鲜明对比羽毛而闻名。","appearance":"猛鹰鸮是一种非常大的猫头鹰，身长可达48至65厘米，翼展110至140厘米。它拥有一个比例较小、较为圆润的头部和一条长尾巴。上体呈暗灰褐色，带有白色条纹，下体白色，布满大胆的暗色V字型条纹。它的脸盘不明显，眼睛呈亮黄色，脚趾和腿被灰色羽毛覆盖，足部呈橙黄色或黄色。雄鸟略大于雌鸟，但雌鸟更小。","call":"雄鸟的叫声是低沉而哀伤的双重呼噜声，'whoo-hooo'，持续几秒，中间有短暂停顿，第二声通常比第一声高。雌鸟的叫声相似，但音调更高。","habits":"猛鹰鸮栖息于沿海和内陆山脉的高大森林，偏好潮湿的森林环境，如硬叶树森林。它们是顶级夜间掠食者，主要以树栖哺乳动物为食，如树袋熊、负鼠和滑翔类动物。它们的领土广阔，维持着大型的家园范围。","breeding":"繁殖季节主要在澳大利亚的冬季，通常在5月至6月间进行。巢通常建在大树的空洞中，高度至少10至15米。每窝产卵数通常是两个，偶尔只有一个或三个。孵化期为36至38天，由雌鸟负责孵化，雄鸟负责狩猎。","identification":"与棕鹰鸮相比，猛鹰鸮体型稍大，形状更修长，缺乏赤褐色调，条纹更粗。幼鸟与成鸟相似，但有更宽更干净的白色条纹。","protection":"IUCN：LC（无危）","distribution":"猛鹰鸮分布于澳大利亚东部和东南部，从昆士兰南部延伸到南澳大利亚东南部，包括塔斯马尼亚岛及其附近岛屿。","other":"尽管数量估计仅为数千只，但总体上其全球保护状态评估为无危。"},{"name":"吠鹰鸮","english_name":"Barking Owl","scientific_name":"Ninox connivens","overview":"吠鹰鸮（英文名：Barking Owl，学名：Ninox connivens），是鸮形目鸱鸮科鹰鸮属的鸟类。夜行性鸟类，原生于澳大利亚大陆、新几内亚部分地区和摩鹿加群岛。中等体型，以独特的‘woof-woof’犬吠声著称，毛色灰褐，腹部白底带深棕色条纹。","appearance":"成年个体长度约38至44厘米，体重介于425至510克之间，雄鸟略重，可达约700克，雌鸟约600克。翼展宽85至125厘米。具有不明显的面部盘和白色眉毛，头部及上部暗褐色至深灰色，肩羽和翼覆羽有醒目的白色斑点；腹部乳黄色至白色，饰有深棕色粗条纹；眼睛黄色，喙黑色。与南鹰鸮相比，体型更大，头部比例更小，上部斑纹更重；与相似大小的栗鹰鸮相比，腹部条纹而非横纹；与较小的鹰鸮相比，头部颜色较淡，上部有花纹。不同亚种在体型和下部条纹颜色上有细微差异。","call":"叫声独特，包括重复的、低沉的、类似狗吠的‘wuk-wuk’声，由雄鸟发出，而雌鸟的叫声更高亢，为‘wok-wok’。偶尔会发出拉长的尖叫，被描述为‘恐怖的’。伴侣常合唱。","habits":"栖息于低地河流森林、林地和稀树草原，偏好靠近湖泊、溪流和其他湿地的边缘森林。日间在树冠层或中层的叶丛中或树洞中休息，通常成对或家庭群居。在澳大利亚，常见于干燥的硬叶林和林地。分布海拔最高可达1500米。主要以大型昆虫和小型哺乳动物为食，如负鼠、滑翔类、兔子、啮齿类和中小型栖息鸟类。偶尔也会捕食家猫。活动时间主要是黄昏到夜间，善于猎捕陆地、树上或空中的猎物。","breeding":"繁殖季节主要在7月至9月，稍晚于北方。社会上一夫一妻制，领地性强。巢筑于大树干的大空洞中，少有在树枝、树叉或地面。平均产卵2至3枚，孵化期约36天，幼鸟孵化时覆盖着奶油白色的绒毛，第二次换羽为白色。离巢期约为5周，幼鸟在夏季末离开出生地，据报道至少部分依赖父母养育长达5个月。","identification":"与其他鹰鸮属物种如南鹰鸮、栗鹰鸮和鹰鸮在体型、斑纹和下部条纹类型上有所区别。","protection":"IUCN：LC（无危）。但在维多利亚州被认为是极度罕见的，仅在1998-1999年的调查中出现在257个地点中的11个。","distribution":"广泛分布于澳大利亚东部和北部沿海、西南部珀斯周边地区，以及新几内亚和摩鹿加群岛（包括哈马黑拉、莫罗泰、巴坎和奥比）。在澳大利亚南部，分布密度较低。","other":"曾被短暂称为‘barking boobook’，但这一称呼并未在澳大利亚或其分布区内的英语国家中普遍使用，现已纠正为‘吠鹰鸮。"},{"name":"松巴鹰鸮","english_name":"Sumba Boobook","scientific_name":"Ninox rudolfi","overview":"松巴鹰鸮（英文名：Great Sumba Boobook，学名：Ninox rudolfi），是鸮形目鸱鸮科鹰鸮属的独特鸟类。其名称来源于分布地——印度尼西亚小巽他群岛中的松巴岛。松巴鹰鸮拥有棕色的羽毛，头顶圆形，眼睛深色，上体和头部有大量白色斑点，喉部显白，腹部带有厚实的棕色条纹。仅限于松巴岛的森林、林缘和红树林地带。","appearance":"松巴鹰鸮体长30至36厘米，体重约222克，雄鸟可能略大于雌鸟。其特征包括白色的眉线和下巴，棕色的眼睛，头部和上体呈棕色并有大量白色斑点，翅膀和尾巴有细条纹，下体白色且有强烈的红棕色条纹。与它共栖的同类，如小松巴鹰鸮，体型更小，虹膜黄色，眉毛更突出，上体无白色斑点。","call":"雄鸟的领地歌是一系列连续的“cluck-cluck-cluck”或“tok-tok-tok”声，音节每秒重复约2.3次，从不以双音形式发出，不同于南鹰鸮。雌鸟会发出类似嘶吼的求食叫声，两性均能发出咕噜声和猴子般的尖叫声。","habits":"松巴鹰鸮主要栖息于常绿和落叶原始森林、季雨林和残留森林碎片，高度通常在海拔500米以下，但也有记录到930米左右。它们不仅限于夜间森林，也会在开放区域飞行并在单树上栖息。饮食习惯与南鹰鸮相似，主要以昆虫为食，但已知会捕食鼠类和壁虎。","breeding":"关于繁殖行为的信息尚无报道，但观察到一只鸟频繁返回可能的树洞巢穴。","identification":"松巴鹰鸮与小松巴鹰鸮的区别在于体型更大，虹膜颜色更深，头冠白色斑点更多，下体有条纹。此外，其叫声也不同于南鹰鸮。","protection":"IUCN：NT（近危）","distribution":"松巴鹰鸮仅分布于印度尼西亚的小巽他群岛中的松巴岛。","other":"曾更常见，现在变得稀少或罕见，仅在五个地点被发现。受到农业和放牧导致的森林砍伐和焚烧威胁，目前森林覆盖率不到岛屿的10%，只有一个保护区存在。全球粗略估计的种群数量约为1万至2万只。"},{"name":"南鹰鸮","english_name":"Australian Boobook","scientific_name":"Ninox boobook","overview":"南鹰鸮（英文名：Australian Boobook，学名：Ninox boobook），是鸮形目鸱鸮科鹰鸮属的鸟类。尾长，翅短而尖，脸部无明显扩大的脸盘和耳羽束。分布广泛，见于澳大利亚大陆、小巽他群岛、新几内亚中南部，体型小巧，颜色多样，以独特的‘boo-book’叫声著称。","appearance":"体长27至36厘米，雄鸟体重146至360克，雌鸟170至298克，翼展56至82厘米。头、背呈暗褐色，有白色斑点，下体颜色变化大，常带红褐色条纹，眼睛颜色多样，从黄绿色到榛色不等。雌鸟头部和背部条纹较雄鸟更明显。幼鸟比成鸟更苍白，头、颈和胸部分布有更多条纹。","call":"发出熟悉的‘boo-book’叫声，第二声通常比第一声低沉，声音粗糙，不同于同类物种新西兰鹰鸮。","habits":"栖息于各种生境，包括森林、灌木丛、农田、果园乃至城市郊区花园。夜间活动，偶尔晨昏活跃，日间藏身于树冠密叶中。以昆虫为主食，也捕食小型脊椎动物。","breeding":"繁殖期自8月至11月，一窝通常产3枚卵，偶尔4至5枚，孵化期约30天。幼鸟在5周左右离巢，家族群维持3个月，夏季末至秋季幼鸟分散。","identification":"与新西兰鹰鸮相比，体型更大、颜色更淡，斑点较少。叫声也有所不同，更粗犷。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚大陆、小巽他群岛、新几内亚中南部。在中国大陆，主要见于西南部地区。","other":"三个亚种因其独特叫声和遗传特征，在2019年被分类为独立物种。"},{"name":"新西兰鹰鸮","english_name":"Morepork","scientific_name":"Ninox novaeseelandiae","overview":"新西兰鹰鸮（英文名：Morepork，学名：Ninox novaeseelandiae），是鸮形目鸱鸮科鹰鸮属的鸟类。又称为新西兰鹰鸮，体型较小的鹰鸮，广泛分布于新西兰的森林地带，包括本土和外来林区。其独特的双音‘新西兰鹰鸮叫声使其在夜间易于识别。在新西兰的北、南岛及斯图尔特岛常见，也曾存在于诺福克岛和豪勋爵岛。","appearance":"新西兰鹰鸮体长26至29厘米，体重在140至216克之间，雌鸟略大于雄鸟。上体呈深棕色，带有白色斑点，下体颜色较淡，具棕色条纹。头部、颈部斑点明显，眼睛金黄色，喙蓝灰色，脚橙色或黄色。年轻个体的羽毛尖端呈现白色，整体颜色偏灰暗。","call":"新西兰鹰鸮最著名的叫声是重复的双音‘boo-book’，还有单调的‘more’声和上升的‘quee’叫声，后者常在狩猎时发出。","habits":"新西兰鹰鸮主要栖息于新西兰的森林中，包括以Podocarpus、Nothofagus为主的森林，白天藏匿于密林中，夜间活跃，以昆虫、小型脊椎动物为食。在恶劣天气或夜间黑暗时，也可能在日间捕食。","breeding":"繁殖季节为9月至11月，幼鸟在12月初至1月底离巢。一般每窝产卵2枚，偶尔3枚，孵化期约25至30天，雏鸟在35至40天后离巢，之后可能在出生地停留70天以上。","identification":"与引进的纵纹腹小鸮区别在于更深的颜色、较大的头部和较长的尾巴。叫声中的上升‘quee’声容易被误认为是鹬鸵的叫声。","protection":"IUCN：LC（无危）。诺福克岛亚种N. n. undulata曾濒临灭绝，通过引入新西兰鹰鸮进行杂交恢复种群，现在岛上存在的为杂交个体。","distribution":"在新西兰的北岛南部至塔拉纳基、南岛西部及斯图尔特岛普遍分布，诺福克岛亚种曾分布于诺福克岛。","other":"曾被认为是南鹰鸮的一个亚种，后基于遗传和形态学差异被确认为独立物种。"},{"name":"鹰鸮","english_name":"Brown Boobook","scientific_name":"Ninox scutulata","appearance":"鹰鸮体长27-33厘米，重约172-227克，体色暗棕色，背部斑点状，胸部有棕色斑点，腹部白色，有明显的红棕色条纹。头部无明显面盘，眼睛明亮黄色，喙蓝黑色，尾巴较长。雄雌羽毛相似。","call":"发出一系列上升的柔和呼叫声：“whoo-wup, whoo-wup, whoo-wup”，在黄昏和黎明时分最为常见。","habits":"鹰鸮适应性强，栖息于各种森林环境，包括原始雨林至果园和花园，通常在夜间和黄昏活动，善于从显眼的栖木猎食，主要食物包括大型昆虫、青蛙、蜥蜴、小型哺乳动物、小鸟和螃蟹。","breeding":"繁殖季节为3月至6月，筑巢于树洞中，高5-20米，一窝产卵2枚，卵大小约36mm×31mm，孵化期至少25天，雏鸟期24-28天。","identification":"与北鹰鸮相比，鹰鸮具有较小的白色眉斑，上体和下体有斑纹，尾羽有条纹，而非纯色。","protection":"IUCN：LC（无危）。被列入CITES附录II。在低地雨林被砍伐的地方，其数量可能正在下降。","distribution":"繁殖区域包括远东、欧亚地区的印度北部至中国南部和婆罗洲；非繁殖区域包括印尼的苏拉威西岛和小巽他群岛。","other":"在城市和郊区，如斯里兰卡的科伦坡，鹰鸮较为常见。"},{"name":"北鹰鸮","english_name":"Northern Boobook","scientific_name":"Ninox japonica","overview":"北鹰鸮（英文名：Northern Boobook，学名：Ninox japonica），是鸮形目鸱鸮科鹰鸮属的鸟类。修长的褐色鹰鸮，拥有引人注目的金色眼睛。广泛分布于东亚及东南亚国家，包括俄罗斯远东地区至朝鲜半岛、日本和台湾。日本最常见的繁殖鸮类。","appearance":"体长29-33厘米，翼展66-70厘米，体重约168克。上体呈巧克力棕色，下体白色，胸部有红棕色条纹，尾巴棕色带淡色横斑。头部和颈部灰棕色，喙黑色，脚爪黄色，眼虹膜金黄色。飞行时外形似鹰。","call":"发出一系列深沉的双音节呼呼声：‘ho-ho, ho-ho’。","habits":"偏好低海拔落叶林，但也在木公园、花园和居住区发现。海拔分布从海平面到1700米。夜间狩猎昆虫，偶尔捕食小型脊椎动物。在台湾，八成的巢位于次生林中，两成位于城市郊区。","breeding":"在台湾，雄鸟1-2月开始鸣叫占地盘，3-4月配对，3月中旬至4月产卵，4月中旬至5月中旬幼鸟孵化。巢穴通常设在大树洞中，每窝产卵3-4枚，孵化期25-31天，幼鸟留巢25-28天。在日本，繁殖季节为5月至7月。","identification":"亚种totogo翅膀较短，尾巴较长，适应迁徙。","protection":"IUCN：LC（无危）","distribution":"繁殖于俄罗斯远东至朝鲜半岛、日本及台湾。在台湾，两个亚种共同存在。冬季在东南亚雨林越冬。","other":"N. j. totogo和N. j. japonica在遗传上有区别，前者为留鸟，后者为候鸟。"},{"name":"茶色鹰鸮","english_name":"Chocolate Boobook","scientific_name":"Ninox randi","overview":"茶色鹰鸮（英文名：Chocolate Boobook，学名：Ninox randi），是鸮形目鸱鸮科鹰鸮属的鸟类。是菲律宾特有种，分布于除帕拉旺群岛以外的所有主要岛屿。体型中等，上体深巧克力棕色，下体白色布满红棕色条纹，眼睛黄色，脸部灰白。与其它几种鹰鸮共存，但体型更大，翅膀单一棕色，胸部条纹更为分明。","appearance":"茶色鹰鸮体长27至33厘米，体重200至220克。上体呈深巧克力棕色，肩羽上有淡色斑点；下体白色，胸腹部布满大胆的栗色条纹；尾巴有四条明显的暗色横带；眼睛鲜黄色，喙和脚强健，脚橙黄色。与鹰鸮相似，但两者地理分布不重叠。","call":"叫声独特，一系列低沉的‘whoop’音符，每对音符间有0.3至0.6秒的间隔，音调稍降。","habits":"栖息于低地雨林、次生林和红树林，通常避开人类居住区和耕作区。活动范围一般低于海拔1000米。可能以昆虫和其他小型脊椎动物为食。","breeding":"关于繁殖的已知信息有限，幼鸟记录显示在6月存在。推测在树洞中筑巢，如同其他鹰鸮。","identification":"与菲律宾鹰鸮、棉岛鹰鸮、宿务鹰鸮和民都洛鹰鸮的区别在于体型更大，翅膀无斑点，下体条纹更明显。","protection":"IUCN：NT（近危）。CITES II。由于森林砍伐导致其栖息地丧失，茶色鹰鸮面临适度快速的人口下降。","distribution":"分布于菲律宾（除帕拉旺群岛）和塔劳群岛（印尼苏拉威西岛东北部）。","other":"直到最近，被认为是鹰鸮的一个亚种，但现在因其独特的叫声和部分度量差异而被确认为独立物种。"},{"name":"休氏鹰鸮","english_name":"Hume's Boobook","scientific_name":"Ninox obscura","overview":"休氏鹰鸮（英文名：Hume's Boobook，学名：Ninox obscura），是鸮形目鸱鸮科鹰鸮属的鸟类。中等体型的鹰鸮，全身呈深棕色，拥有独特的黄色眼睛。主要分布在安达曼群岛的低地森林、森林边缘、橡胶种植园边界以及人类居住区附近，常见于水边。","appearance":"体长26-30厘米，羽毛颜色为深巧克力棕色，腹部偏红棕色，下腹有明显的白色条纹。眼睛之间有一个小白点，尾巴末端有薄薄的白色尖端。虹膜和脚趾为鲜亮的黄色，蜡膜呈淡绿色。","call":"发出重复的双音节‘wooo-oop’叫声，第二音节比第一音节高，与鹰鸮类似，但音调稍高，两音节间的音差更大。","habits":"仅在夜间活动，栖息于低地森林、森林边缘、橡胶园边界及人类居住区附近。已知捕食甲虫、蚱蜢、Glossy Swiftlets和Edible-nest Swiftlets。","breeding":"关于繁殖的信息极少，据推测，幼鸟可能在五月下旬达到约一个月大。","identification":"与安达曼鹰鸮相比，体型明显较大，羽色和图案差异显著。","protection":"IUCN：LC（无危）。CITES II级保护。虽然种群被认为稳定，但缺乏具体数量和趋势数据。","distribution":"主要分布于安达曼群岛，曾经认为在尼科巴群岛也有分布，但后来证实这一信息有误。"},{"name":"安达曼鹰鸮","english_name":"Andaman Boobook","scientific_name":"Ninox affinis","overview":"安达曼鹰鸮（英文名：Andaman Boobook，学名：Ninox affinis），是鸮形目鸱鸮科鹰鸮属的小型猛禽，以棕色脸庞和上身，以及鲜明的锈色条纹著称，腹部通常是白色，尾巴带有横纹。活跃于安达曼群岛的森林地带，叫声独特低沉。","appearance":"该鹰鸮体长21-28厘米，头面呈灰色，面部盘模糊，黄色角质喙被白色刚毛包围。背部深褐色，略带红褐色调，尾部有窄暗带和突出的棕色末端带。下体白色，密布鲜亮的红褐色条纹，眼睛和脚黄色，头部绿色。雌雄羽毛相似，雌鸟略大；幼鸟下体条纹较淡。","call":"发出一系列低沉、下滑的‘crauwu’音符，间隔约1至数秒。","habits":"栖息于低地原生和次生森林，以昆虫为主食，已观察到捕捉空中飞蛾和甲虫。比同域的更为羞涩。","breeding":"关于繁殖生态的资料尚未发表。","identification":"与休氏鹰鸮相比，体型较小，下体有条纹，喙色不同。","protection":"IUCN：LC（无危）。列入CITES附录II。虽然在安达曼群岛的原生森林较为完好，但面临人类活动增加、森林退化和砍伐的压力。","distribution":"分布于安达曼群岛（北安达曼岛至小安达曼岛），属于东洋界范围。"},{"name":"白眉鹰鸮","english_name":"White-browed Hawk-Owl","scientific_name":"Ninox superciliaris","appearance":"白眉鹰鸮是一种矮胖的猫头鹰，头部大而圆，没有耳羽簇。成鸟上部棕色，冠、肩和翼覆羽上有白色斑点，面部盘灰棕色，有明显的白色眉毛和淡黄色的下巴。下部羽毛淡黄色，宽幅的暗棕色条纹贯穿。下翼、腹部和腿单一淡黄色，尾巴纯棕色。喙和蜡膜角黄色，眼睛深棕色，腿和脚淡黄色。体长约25厘米(9.8英寸)，翼展约70厘米(28英寸)。","call":"其叫声为间隔性的咆哮声\"woohoo\"，开始时相当嘶哑。另一种叫声为响亮的\"kuang\"，起始时音量更大，音调更高，可能是一种攻击性的叫声。","habits":"白眉鹰鸮特有于马达加斯加，在东北部、南部和西南部都有分布。最常见于南部和西部较干燥的森林和画廊森林，东北部湿润雨林中较少见。也在耕作区和次生林中出现。主要栖息于低地，海拔上限为800米(2,600英尺)。","breeding":"繁殖期为10月至12月，巢是一个浅坑，位于地面，产3-5枚白色蛋。繁殖行为知之甚少。这是一种严格的夜行性物种，主要以昆虫和小型脊椎动物为食，从栖木上捕猎。也可能在飞行中捕食昆虫和蝙蝠。","identification":"白眉鹰鸮通过其独特的白色眉毛、淡黄色下巴和宽幅的暗棕色下部条纹与其它猫头鹰区分开来。","distribution":"白眉鹰鸮分布于马达加斯加的东北部、南部和西南部，常见于南部和西部干燥森林和画廊森林，以及东北部的湿润雨林，也在耕作区和次生林中出现。"},{"name":"菲律宾鹰鸮","english_name":"Luzon Boobook","scientific_name":"Ninox philippensis","overview":"菲律宾鹰鸮（英文名：Luzon Boobook，学名：Ninox philippensis）是鸮形目鸱鸮科鹰鸮属的鸟类，属菲律宾特有种。它以棕色和白色斑驳的羽毛著称，雌雄外观相似。作为该国的标志性物种之一，菲律宾鹰鸮广泛分布在低地和丘陵森林地带。","appearance":"体型较小，体长15至20厘米，体重约125克。头部和上体呈深红褐色，无明显标记；肩羽、翼覆羽和飞羽具白色斑点；下体为淡黄色，带有红褐色条纹；眼睛橙黄色，喙为奶油灰黄色。具有不明显的棕色面部盘，灰色的口角刚毛和白色的眉毛。","call":"叫声包括一系列响亮的吠声，开始为单音节，常以‘大约四个犹豫的音符’结束，第一个音最轻，无哨音，通常无咆哮声。","habits":"栖息于原始雨林和次生林，包括残存林地、河岸林和林缘，活动范围多在海拔1000米以下，偶尔可达1800米。日间在森林较暗处休息。","breeding":"繁殖资料稀少，筑巢于树洞中，成鸟在2月发现有发达的生殖腺，幼鸟在3月和5月被报道。","identification":"与巧克力鹰鸮相比，菲律宾鹰鸮体型更小，胸部无白色斑点。不同亚种在羽毛颜色和斑纹上有细微差异。","protection":"IUCN：LC（无危）。被列入CITES附录II。尽管面临严重森林破坏，但由于能适应一定程度的栖息地改变，该物种在局部地区仍常见。","distribution":"分布于菲律宾的低地和丘陵森林，包括吕宋岛、内格罗斯岛和保和岛等地。","other":"该物种能够容忍次生林和开阔地带，被认为数量稳定，无特定威胁。"},{"name":"棉兰鹰鸮","english_name":"Mindanao Boobook","scientific_name":"Ninox spilocephala","appearance":"体型小，约18厘米，无体重数据。头部、颈背及上背布满斑点；中下背至臀部均匀暗褐无斑；翅膀覆羽具大白色斑点及窄色带；尾部有窄暗带；眼淡黄；喙橄榄黄色；脚亮黄色。幼鸟冠及颈背斑点较弱。独特的耳羽，有长丝状延伸。","call":"鸣声为一系列低沉、柔和、缓慢的鸽子般音符，以双音节形式发出，首音强调。","habits":"偏好原生低地雨林，但也见于次生林。食性主要为昆虫，具体饮食信息有限。","breeding":"已知在三月发现绒羽雏鸟，繁殖生态未详，推测如同其他鹰鸮，可能在树洞筑巢。","identification":"与其他‘菲律宾鹰鸮’复合群成员（均为异域分布）的区别在于头部和下体的羽毛图案，以及较长的耳羽延伸。","protection":"IUCN：NT（近危）","distribution":"分布于菲律宾南部的巴西兰省、棉兰老岛、锡亚高岛和迪纳加特群岛。","other":"由于森林砍伐用于木材、农业、采矿和放牧导致的疑似中等速度的人口减少，其全球保护状况并不乐观。"},{"name":"民岛鹰鸮","english_name":"Mindoro Boobook","scientific_name":"Ninox mindorensis","appearance":"民都洛鹰鸮体长约20厘米，体重介于100至118克之间，雌雄外观相似。其头顶和颈背有精细的斑纹，具有一对明显的小白色眉纹，喉部有一片淡色斑块。上体颜色均匀，带有细密的条纹，肩部有白色斑点，尾巴上的条纹相对密集。下体颜色变化较大，从浅黄色到橙赤色不等，通常有细小的条纹，有时可见白色条状纹。虹膜黄色，喙和蜡膜呈淡黄色，略带绿色，脚爪橄榄黄色。","call":"民都洛鹰鸮的叫声为一系列高音哨声，常以‘tittering high toots’开始，逐渐变为尖锐的啸声。","habits":"栖息于低地森林和次生林，海拔高度从海平面至1250米，常见于民都洛岛的开放林地。其活动范围广泛，包括森林边缘、空地和种植园。","breeding":"关于繁殖的信息有限，但推测其筑巢习性与其他鹰鸮相似，可能在树洞中筑巢。","identification":"与民都洛角鸮相比，民都洛鹰鸮体型更小，胸部无明显的栗色条纹，下体颜色较深，且眼间无白色斑块。","protection":"IUCN：VU（易危）","distribution":"民都洛鹰鸮仅分布于菲律宾的民都洛岛，包括该岛的Sablayan Penal Colony、Mts Iglit-Baco National Park和Naujan Lake National Park等地区。","other":"尽管民都洛鹰鸮在一些保护区中得以生存，但由于森林砍伐、采矿和农业发展导致的栖息地丧失，其全球数量估计在3500至15000只之间，且处于下降趋势。"},{"name":"朗布隆鹰鸮","english_name":"Romblon Boobook","scientific_name":"Ninox spilonotus","overview":"朗布隆鹰鸮（英文名：Romblon Boobook，学名：Ninox spilonotus），是鸮形目鸱鸮科鹰鸮属的鸟类。仅分布于菲律宾的塔布拉斯岛、朗布隆岛和锡布延岛。曾被认为是菲律宾鹰鸮的一个亚种，但在2012年被确认为独立物种。该鸟主要栖息于热带湿润低地森林，面临严重的栖息地丧失威胁。","appearance":"该鹰鸮体长约26厘米，上身、胸部和头部呈暗褐色，条纹模糊不清；下体为红褐色，面部周围有长须状羽毛，眼睛明亮黄色。额头、头顶和颈背为深褐色，带有细小的浅色斑点；肩羽和三级飞羽有深褐色和浅色条纹；尾巴较深，有窄带状浅色条纹；虹膜亮黄色，喙和蜡膜淡橄榄黄色。雌雄外观相似。","call":"其鸣叫声是一系列短促的哨音，音调下降，通常以单个音符开始，随后转变为三音节或四音节版本，具体取决于岛屿位置，锡布延岛上的叫声略显嘶哑且节奏更慢。","habits":"栖息于残存的原始森林和高大的次生林中，海拔高度从海平面至约1000米。面临森林因木材采伐、农业、采矿和放牧而大量消失的威胁。","breeding":"繁殖季节大约在二月，会在空心树中筑巢。","identification":"朗布隆鹰鸮在范围内可能是唯一的鹰鸮，除曼坦阿尼角鸮外，但朗布隆鹰鸮的颜色为红褐色而非灰色，且面部无黑色线条。与菲律宾鹰鸮其他亚种相比，其叫声有所不同。","protection":"IUCN：EN（濒危）；CITES II；种群估计在250至999只成熟个体之间。主要威胁来自栖息地丧失，包括合法和非法伐木、采矿和土地转换为农田。部分栖息地如Mount Guiting-Guiting受到保护，但保护力度不足。","distribution":"分布于菲律宾的锡布延岛和塔布拉斯岛，可能也在朗布隆岛存在，但尚未得到确认。","other":"直到最近，被认为与菲律宾鹰鸮、棉岛鹰鸮、苏禄鹰鸮和民都洛鹰鸮同种，但基于声音、羽毛和形态测量的详细审查确定它们均为独立物种。"},{"name":"宿务鹰鸮","english_name":"Cebu Boobook","scientific_name":"Ninox rumseyi","overview":"宿务鹰鸮（英文名：Cebu Boobook，学名：Ninox rumseyi），是鸮形目鸱鸮科鹰鸮属的鸟类。为菲律宾宿务岛特有种。其头及上部呈深棕色，带有不明显的条纹，下部橙棕色，翅膀点缀白色，肩后有一淡色条纹，眼黄亮，眉白形成V形拱。喉部有显著的白色斑块，是识别特征之一。叫声独特，中间音先降后升，末音下降，亦发单音节声和嘶声。","appearance":"宿务鹰鸮身长约25厘米，头部圆润，耳羽不发达。上体深棕色，条纹密集，下体橙棕色，有弱条纹或暗斑。腹部和尾下覆羽白色至淡黄色，有少许暗褐色斑点。眼黄色，喙橄榄色，爪黑色，脚黄色。与其他鹰鸮相比，上体和头部图案更鲜明。","call":"宿务鹰鸮的鸣叫特征明显，发出独特的“wip！Doo-wip！Doh”声调，中间音先降后升，最后音下降。也会发出单独的“wip”音和嘶声。","habits":"栖息于宿务岛的各类森林中，无特定偏好，从森林内部到边缘，沟壑或山脊，小片林地或高树冠皆可。偶尔在纯种植园区域出现。白天休息，夜间活动，以鼠类、小鸟、蛇、蜥蜴、蛙类、昆虫等为食。","breeding":"繁殖期在5月初，一对宿务鹰鸮占据约10公顷的森林区域。已知巢穴位于高大树木主干上的自然洞穴中，距离地面2-2.5米，巢中发现2枚卵。具体繁殖细节未知。","identification":"宿务鹰鸮与N. (philippensis) mindorensis最相似，但体型更大，下体条纹更稀疏或更平滑。叫声节奏快，音调较低，与N. (philippensis) spilonota不同。","protection":"IUCN：VU（易危）","distribution":"仅分布于菲律宾的宿务岛，具体在Alcoy、Argao、Dalaguete、Tabunan和Boljoon等地的保护森林中。","other":"宿务鹰鸮是在2012年依据声音、羽毛和形态学数据重新分类的物种，之前被认为是菲律宾鹰鸮的一个亚种。"},{"name":"卡米金鹰鸮","english_name":"Camiguin Boobook","scientific_name":"Ninox leventisi","overview":"卡米金鹰鸮（英文名：Camiguin Boobook，学名：Ninox leventisi），是鸮形目鸱鸮科鹰鸮属的鸟类。独特的中等体型鹰鸮，仅见于菲律宾南部的Camiguin Sur岛上残留的热带湿润低地森林。拥有绿色至淡黄绿色的眼睛，这在同类中极为罕见。其体长约25厘米，是菲律宾鹰鸮物种群中体型较大的种类。","appearance":"卡米金鹰鸮头部及上体呈均匀的棕色条纹，肩后有一浅色横纹，下体颜色较暖，面部周围有长而细的羽毛，眼睛淡黄色。最显著的特征是喉咙处有一大片白色斑块，当鸟儿鸣叫时尤为显眼。头顶圆形，耳羽盖仅有短丝状延伸，大部分羽毛看起来均匀地以深棕色和米色至棕褐色条纹装饰。上翼覆羽暗褐色，具狭窄的淡色条纹，次级飞羽暗褐色，弱条纹明显，三级飞羽更带米色条纹。下体棕色至棕红色或红褐色，密布深棕色条纹。","call":"发出极低沉的音调，通常由一系列快速而不规则的‘barking’音符组成，有时会以二重唱的形式出现。单个鸟儿也会发出短暂、低强度的约6个‘boo’音符序列，持续约2秒，第四个音符最高且强调。","habits":"栖息于海拔700米以下的热带湿润低地原始和次生森林，偶尔出现在林缘、空地和种植园。以夜间活动为主，主要以小型哺乳动物、昆虫和其他小型脊椎动物为食。","breeding":"繁殖信息有限，但推测与其他鹰鸮相似，包括在树洞或岩石裂缝中筑巢，每次产卵数枚，由雌鸟主要孵化。","identification":"通过其独特的绿色至淡黄绿色的眼睛、喉咙上的白色斑块、肩部的白色斑点、缺乏眉毛上的白色以及下体密集的条纹来区分于其他近亲种类。与罗姆布隆鹰鸮和宿务鹰鸮相比，体型较大。","protection":"IUCN：VU（易危）","distribution":"分布于菲律宾南部Camiguin Sur（棉兰老岛北侧的小岛）。","other":"由于森林栖息地的丧失，包括合法和非法砍伐、采矿、转变为农田以及城市化，尤其是旅游业的激增，导致了森林的大规模清理，这对该物种构成了主要威胁。"},{"name":"苏禄鹰鸮","english_name":"Sulu Boobook","scientific_name":"Ninox reyi","overview":"苏禄鹰鸮（英文名：Sulu Boobook，学名：Ninox reyi），是鸮形目鸱鸮科鹰鸮属的鸟类。以森林为栖息地。其上体呈棕色，下体橙棕色，翅膀上有白色斑点，肩后有一段淡色条纹，腹部颜色较浅，脸部周围有长长的羽毛，黄色的眼睛，喉部有一块明显的白色斑块。与同域内的南菲律宾角鸮相比，苏禄鹰鸮毛色偏赤褐色，面部无黑色线条。","appearance":"苏禄鹰鸮体长19至20厘米，翼展约172至195毫米，尾长约88.5至107.5毫米。头部和胸部有均匀的条纹，窄白眉纹和白色的喉部斑块。上体包括头顶，有细窄的深棕色条纹，背景色为白色或淡黄色；翅膀覆羽有明显的条带，上尾有中等宽度的暗色条纹。下体变化较大，通常带有宽幅的白色条纹或不规则的暗色斑点。眼睛明亮的黄色，嘴为暗绿黄色，脚和趾为芥末黄色。","call":"叫声独特，由一系列快速的咯咯声组成，开始时声音较低沉，随后逐渐升高，最后三声较慢：'kukukukukuku klok-klok-klok'。还有另一种叫声，由空洞音节组成的三重奏，'tluk tluk tluk, tluk tluk tluk, tluk tluk tluk'。","habits":"苏禄鹰鸮原生于原始雨林，现今适应于次生林、森林边缘、成熟的红树林和村庄附近的大型树木。其活动范围广泛，包括热带湿润低地的初级和次级森林，高度可达700米。","breeding":"繁殖信息未详述。","identification":"与南菲律宾角鸮相比，苏禄鹰鸮的毛色更偏向赤褐色，且面部缺乏黑色线条。与同属物种的区别在于头部和胸部有均匀的条纹，以及窄白眉纹和白色喉部斑块。","protection":"IUCN：VU（易危）；CITES II（濒危野生动植物种国际贸易公约二级附录）。苏禄鹰鸮仅分布于苏禄群岛的六个岛屿，其中五个岛屿的原生森林已几乎消失。目前全球估计成熟个体数量为1000至2499只，主要集中在Tawitawi岛。森林砍伐、油棕种植园、果园和牧场扩张导致其栖息地迅速减少。","distribution":"分布于菲律宾南部的苏禄群岛。","other":"苏禄鹰鸮之前被认为是菲律宾鹰鸮的一个亚种，但在2012年因声音和其他证据显示其为独立物种而被重新分类。"},{"name":"赭腹鹰鸮","english_name":"Ochre-bellied Boobook","scientific_name":"Ninox ochracea","overview":"赭腹鹰鸮（英文名：Ochre-bellied Boobook，学名：Ninox ochracea），是鸮形目鸱鸮科鹰鸮属的鸟类。仅见于印度尼西亚的苏拉威西岛和Butung岛。其最显著的特征是红褐色的腹部、清晰的白色眉纹和醒目的黄色眼睛。上体呈巧克力棕色，翼上有明显的白色斑点。","appearance":"赭腹鹰鸮体长25至29厘米。拥有圆头和中等体型，上体为栗色，下体为肉桂色，喉咙为白色，突出的白色眉纹和翅膀覆羽上的白色斑点。虹膜黄色，喙和蜡膜为黄角质色，脚趾为灰黄色。雌雄相似，雌鸟略大。","call":"发出嘶哑、有点儿粗犷的单音‘kau’，逐渐发展为两音节的叫声‘wuu kau’，第二个音比第一个更长。","habits":"栖息于低地和山麓森林的林下层，白天单独或成对在密集的植被中休息，如藤本植物中。活动范围包括原始和高大的次生低地森林及河岸森林，高度可达约1000米。以昆虫为主要食物，从树冠中部的栖木上狩猎。","breeding":"关于繁殖行为的信息尚无报道。","identification":"与斑鹰鸮和棕红鹰鸮在体型和颜色上有所不同，前者翼长较短，后者翼长较长。与迁徙中的北鹰鸮相比，本种体型更大，上体无斑点，有明显的白色眉纹，头部和下体的颜色截然不同。","protection":"IUCN：NT（近危）。CITES II。数量估计在15,000至30,000只之间，需进一步核实。在洛雷林杜国家公园等地局部较为常见，但总体数量因大面积的砍伐和农业侵占而减少。","distribution":"分布于苏拉威西岛和Butung岛，包括Buton南部。在Dumoga-Bone国家公园和Tangkoko自然保护区也有记录。","other":"本物种具有异常低的羽毛密度，这是其独特之处。"},{"name":"棕红鹰鸮","english_name":"Cinnabar Boobook","scientific_name":"Ninox ios","overview":"棕红鹰鸮（英文名：Cinnabar Boobook，学名：Ninox ios），是鸮形目鸱鸮科鹰鸮属的鸟类。身长约为22厘米，以其独特的红褐色羽毛而著称，主要分布在印尼苏拉威西岛的山区。由美国鸟类学家Pamela C. Rasmussen于1999年首次科学描述，基于在苏拉威西北部Bogani Nani Wartabone国家公园采集的标本。之后，在苏拉威西中部的Lore Lindu国家公园也有观察记录，扩大了其已知的分布范围。","appearance":"棕红鹰鸮拥有相对长的尾巴和窄尖的翅膀，全身几乎均匀地呈现红褐色，除了肩部有白色的斑点和下体部分有白色的羽轴，可能不明显地带有波状纹。下体后部较淡，呈红褐色，除了羽尖。上翼和尾羽为较暗的红褐色，有狭窄的深色条纹。黄色虹膜外有一圈明显的暗色环，眼眶周围有狭窄的淡粉色裸露环，喙色从象牙白到浅角质色不等，腿相对较短且细，几乎覆盖至脚趾基部，裸露部分为黄白色至暗黄色。","call":"发出独特的两声硬耦合音‘wruck-wruck’，音符间隔约0.5秒。偶尔会发出单一的鼻音嘶嘶声，持续约0.5至0.7秒，每6至10秒一次，有时频率更快。","habits":"生活在海拔约1100至1700米的中高森林地带，常以成对的形式出现在树冠层。以飞行昆虫为主要食物来源，通过短暂的突袭捕食暴露在枝头的猎物。","breeding":"关于繁殖行为的信息极为有限，尚无具体数据。","identification":"与该地区的其他鹰鸮相比，棕红鹰鸮体型较小，尾巴较长，羽毛颜色非常统一，缺乏面部的特殊图案。与相似的赭腹鹰鸮不同，它没有白色的面部标记，且生活在更高的海拔，叫声也显著不同。","protection":"IUCN：LC（无危）。该物种仅在苏拉威西岛上发现，估计总数量在3500至15000只之间，由于森林栖息地的持续丧失和退化，其种群数量很可能正在减少。在Bogani Nani Wartabone国家公园、Gunung Ambang严格自然保护区和Lore Lindu国家公园内有记录。","distribution":"分布于苏拉威西岛北部山区和中部地区，包括Bogani Nani Wartabone国家公园和Lore Lindu国家公园。","other":"系统发育历史关系尚不清楚，目前认为是单型种，但苏拉威西中部发现的具有白色眉纹和斑点下体的鹰鸮可能属于该物种的亚种或紧密相关的物种。"},{"name":"栗鹰鸮","english_name":"Seram Boobook","scientific_name":"Ninox squamipila","overview":"栗鹰鸮（英文名：Seram Boobook，学名：Ninox squamipila），是鸮形目鸱鸮科鹰鸮属的鸟类。一种中型猫头鹰，分布于印尼摩鹿加群岛的塞拉姆岛、凯朗岛和安汶岛。其特征包括暗褐色上体、白色斑纹的肩羽和翅膀上的白色点状斑，以及红棕色至黄色的眼睛。在低地和山脚森林中生活，常在夜晚发出深沉回响的‘huhuhuhuhu’叫声。","appearance":"栗鹰鸮体型中等，长度约25至36厘米，重量约为210克。上体呈红褐色，肩羽有白色条纹，翅膀覆羽有白色斑点。上胸部分为红棕色，其余下体部分为白色，带有红棕色条纹。眼睛颜色从棕红色到黄色不等，可能与年龄有关，年轻个体的眼睛颜色更深。喙部呈淡灰色，眼周裸露部分为黄色。","call":"栗鹰鸮的叫声独特，发出一系列约50至80声的柔和、沉闷的鸣叫，每秒约6声，声音逐渐由低到高，再由高到低，中间音调可达300至500Hz。两鸟对鸣时，音调差异大约100Hz。","habits":"栗鹰鸮主要栖息在原始森林、高大的次生林、选择性砍伐的森林和森林边缘，白天在茂密植被中休息。它们主要以昆虫为食，偶尔也会捕食小型哺乳动物和蛇类。通常从树冠中层的暴露枝干或树桩上狩猎。","identification":"与哈岛鹰鸮的区别在于胸部和下体的颜色和条纹密度，以及眼睛颜色的可能差异。与布鲁鹰鸮相比，栗鹰鸮的上体和翅膀颜色更深，下体白色带细窄的棕色条纹。与塔宁巴鹰鸮的区别在于胸部的斑纹和上体的颜色，以及眼睛颜色的可能差异。","protection":"IUCN：LC（无危）。CITES II。在1990年代中期，于Manusela国家公园内被视为常见物种。","distribution":"主要分布在印尼的塞拉姆岛、凯朗岛和安汶岛。在海拔从海平面至1400米的范围内都有发现，有一对鸟在Mt Binaya海拔2100米处的记录。","other":"曾被认为与布鲁鹰鸮是同一物种的一部分，直到近期基于分子证据才被确认为独立物种。"},{"name":"哈岛鹰鸮","english_name":"Halmahera Boobook","scientific_name":"Ninox hypogramma","overview":"哈岛鹰鸮（英文名：Halmahera Boobook，学名：Ninox hypogramma），是鸮形目鸱鸮科鹰鸮属的鸟类。以棕色为主色调，具有圆形头部、黄色眼睛和红褐色条纹状下部羽毛，常见于印尼的哈马黑拉岛、Ternate和Bacan等岛屿的低地森林中，通常成对出现，被认为是当地特有种。","appearance":"哈岛鹰鸮体长约39厘米，体重超过200克，是摩鹿加群岛中体型最大的Ninox属鹰鸮。其头部呈灰褐色，喉部有一块白色斑点，背部为红褐色，下部羽毛红褐色带密集的黑白条纹，肩羽有白色横纹，翼覆羽上有白色斑点，尾巴较长且有六条以上的灰色条纹。虹膜明亮黄色，蜡膜暗黄色，脚橙黄色，喙黑色。","call":"其叫声独特，为粗哑、突然的两音节蛙鸣般的\"woo-wooo\"，第二个音节略长。","habits":"哈岛鹰鸮栖息于低海拔热带雨林和高大的次生林中，海拔高度从海平面至约1200米。它们全年居住在这些区域，以昆虫为食。","identification":"与其他Ninox属物种如北鹰鸮和吠鹰鸮相比，哈岛鹰鸮可通过其红褐色条纹状下部羽毛和不同的声音来区分。它与布鲁鹰鸮的区别在于其下部羽毛的颜色和条纹，与塔宁巴鹰鸮的区别在于其上部羽毛颜色和翅膀前缘的差异。","protection":"IUCN：LC（无危）。CITES II。在1990年代末期，哈岛鹰鸮在哈马黑拉岛和Bacan被认为‘局部适度常见’，但由于持续的栖息地丧失，其种群可能正在下降。","distribution":"哈岛鹰鸮分布于印尼北摩鹿加群岛的哈马黑拉岛、Ternate和Bacan。"},{"name":"塔宁巴鹰鸮","english_name":"Tanimbar Boobook","scientific_name":"Ninox forbesi","overview":"塔宁巴鹰鸮（英文名：Tanimbar Boobook，学名：Ninox forbesi），是鸮形目鸱鸮科鹰鸮属的鸟类。独特的栗色猫头鹰，仅分布在印尼摩鹿加群岛南部的塔宁巴尔群岛。其最显著的特征是鲜亮的红褐色羽毛，翅膀上散布着白色斑点，腹部有条纹，以及锐利的黄色眼睛。幼鸟腹部无条纹。成对生活在低地和山丘森林的上层。","appearance":"中等体型的鹰鸮，体长约30厘米，具有赭红色头部、背部和胸部，腹部为白色并带有规律间隔的赭红色条纹，翅膀和尾巴有明显的条纹，脚胫部覆盖着红色羽毛。黄色的眼睛周围有黑色眼环，蜡膜和脚呈黄绿色，喙为淡灰色。","call":"叫声为一对‘oo-ook’或更粗哑的‘broo-broo’短语，也会发出类似蛙鸣的‘brrrr’叫声。","habits":"栖息于低地和山丘的原始森林和高大的次生林，可能过着定居的生活。食性信息未发表，推测以昆虫为主。","breeding":"繁殖信息未知。","identification":"与同属其他物种的区别在于胸部无条纹，且颜色较浅，头部和披肩的颜色也有所不同。","protection":"IUCN：LC（无危）。CITES II。仅分布于塔宁巴尔群岛，属于限制性分布物种。自1990年代后期被认为在当地中等常见，但由于缺乏最新数据，其数量可能因栖息地丧失和碎片化而减少。","distribution":"分布于澳新界：塔宁巴尔群岛（印尼摩鹿加群岛南部）。"},{"name":"圣诞岛鹰鸮","english_name":"Christmas Boobook","scientific_name":"Ninox natalis","overview":"圣诞岛鹰鸮（英文名：Christmas Boobook，学名：Ninox natalis），是鸮形目鸱鸮科鹰鸮属的鸟类。体型较小，具有显著的栗棕色横斑。圣诞岛上唯一的常驻猫头鹰，分布于印度洋中的圣诞岛，面临人类活动和外来物种的威胁。","appearance":"体长26至29厘米，体重130至190克。拥有棕色的面部罩，白色眉纹，丰富的赤褐色上体，颈部和翼覆羽上有细小的白色斑点，肩羽上有精细的白色条纹，以及密布赤褐色横斑的淡黄色下体。眼睛黄色，眼睑浅蓝灰色，脚呈稻草黄色。两性羽毛相似，雌鸟略大于雄鸟。","call":"典型的求偶鸣声为重复的双音节咕咕声，带有轻微的咯咯声，听起来像是'klu-gook'。幼鸟乞食时发出尖锐的颤鸣声。","habits":"栖息于密集的雨林，包括高大的常绿和落叶森林，偶尔在次生林中出现。夜行性和黄昏活动，以大型昆虫为主食，偶尔捕食蜘蛛和小型脊椎动物，如壁虎、小鸟和黑鼠。在清理过的区域，如道路和人类居住区附近狩猎，会在灯光周围捕捉昆虫。","breeding":"繁殖季节较长，雏鸟在4月、5月和8月至12月被报道。社会上一夫一妻制，领土性强烈，筑巢于树洞中，离地面18至26米。每窝产卵数可能为2枚，幼鸟依赖成鸟至少2.5个月。","identification":"与迁徙的北鹰鸮相比，体型明显较小，颜色更浅，头部非全棕色，下体有白色条纹。","protection":"IUCN：VU（易危）","distribution":"分布于印度洋的圣诞岛，位于爪哇岛南侧，西太平洋。","other":"受到黄疯蚁（Anoplolepis gracilipes）的影响，导致其在部分栖息地消失。"},{"name":"褐鹰鸮","english_name":"Papuan Boobook","scientific_name":"Ninox theomacha","overview":"褐鹰鸮（英文名：Papuan Boobook，学名：Ninox theomacha），是鸮形目鸱鸮科鹰鸮属的鸟类。中等体型、深色系的猫头鹰。其面部圆盘呈暗灰褐色，配以较浅色的眉毛，下体颜色从烟灰色到巧克力色不等，翅膀主要为深灰色。褐鹰鸮主要栖息于新几内亚的低地森林、山地森林及亚山地森林的边缘地带。","appearance":"褐鹰鸮体型小至中等，长度介于20至28厘米之间，体重约185克。上体颜色统一，呈现深巧克力至栗棕色，下体颜色因亚种而异。面部圆盘黑色，眉毛较淡，上体无斑点或仅有少许肩部斑点。虹膜黄色，喙灰色。雌雄相似，雌鸟略大，幼鸟颜色较暗淡。亚种间存在大小和颜色差异，如指名亚种胸部多为栗棕色，背部巧克力色；hoedtii亚种上体较暗，喉部和前颈有明显的条纹；goldii亚种更大，下体白色带有巧克力色条纹。","call":"褐鹰鸮的鸣叫声为一系列沙哑的双音节音符，‘hyu-hyu’，两音相同，音调略有下降，每3至4秒重复一次，通常持续整晚。","habits":"褐鹰鸮主要生活在低地森林、森林边缘、花园和开阔地带的树丛中，海拔高度从海平面到2500米的云雾林。日间栖息于茂密的树冠下，有时藏身于密集的藤蔓中。以大型昆虫为主食，采用从栖息处出击的方式狩猎，也会在空中捕食昆虫，常见于人类聚居区附近被灯光吸引的昆虫。","breeding":"繁殖生态知之甚少，似乎在8月至12月期间筑巢孵化，10月可见幼鸟。推测为一夫一妻制，领域性强，繁殖前会加强鸣叫。巢建于树洞中，预计每窝产2枚蛋。","identification":"与同域内的其他Ninox属猫头鹰相比，褐鹰鸮体型较小，上体和下体颜色更加均匀，缺乏强烈的条纹或横纹。与异域的N. jacquinoti不同，后者具有白色喉咙和条纹下体。","protection":"IUCN：LC（无危）。CITES II级。全球种群数量未知，但分布广泛，被认为是相当常见的物种，适应多种生境，包括接近人类居住区的区域。","distribution":"主要分布在新几内亚，除了中南部地区。","other":"褐鹰鸮在某些地区，腹部有宽阔的白色条纹，背部有白色斑点。"},{"name":"马努斯鹰鸮","english_name":"Manus Boobook","scientific_name":"Ninox meeki","overview":"马努斯鹰鸮（英文名：Manus Boobook，学名：Ninox meeki），是鸮形目鸱鸮科鹰鸮属的鸟类。具有独特的棕色面部盘，锈色的冠和背部，白色条纹的飞行羽和尾巴，以及带有锈色条纹的白色下体。叫声似蛙鸣，为连续的低沉咆哮声。仅分布于新几内亚东北的阿德默尔蒂群岛中的Manus岛，偏好森林环境，但也可见于接近人类居住区的树木和河岸生境。","appearance":"中等大小，体长25-31厘米，翼展适中，头部圆润，眼睛黄色。面部盘呈均匀棕色，无明显标记，上体深棕色，散布着不规则的淡色斑点。胸部和腹部白色，带有显著的暗色条纹。幼鸟上体有更粗大的白条纹，下体条纹较细。雌雄相似，但雌鸟头顶可能有横纹。","call":"发出一系列约10个粗糙的、逐渐加速的音符，声音类似青蛙的叫声。","habits":"栖息于森林地带，包括高度退化的林地、河流旁的耕作区以及村庄周围的树木。活动范围限于Manus岛。食物可能包括昆虫。","breeding":"繁殖信息未知。","identification":"是Manus岛上仅有的两种猫头鹰之一，另一种是截然不同的马努斯草鸮，属于仓鸮。通过其独特的外观和叫声易于区分。","protection":"IUCN：LC（无危）。CITES II。在阿德默尔蒂群岛EBA中发现的限制分布物种。尽管分布范围小，但由于大部分Manus岛被森林覆盖，物种目前不处于风险之中。","distribution":"分布于Manus岛和Los Negros岛（Manus岛东北部，新几内亚东北的阿德默尔蒂群岛，俾斯麦群岛西北部）。","other":"在有限的分布范围内相对常见。"},{"name":"斑鹰鸮","english_name":"Speckled Boobook","scientific_name":"Ninox punctulata","overview":"斑鹰鸮（英文名：Speckled Boobook，学名：Ninox punctulata），是鸮形目鸱鸮科鹰鸮属的鸟类。小型鹰鸮，体长17-20厘米，具有红褐色外观，头部、背部和翅膀上布满白色斑点，拥有白色的喉部斑块、黑色面部盘以及醒目的白色眉毛。广泛分布于印尼苏拉威西岛、Kabaena、Muna和Butung等岛屿，偏好森林环境，常见于河流附近的森林、开阔林地和散布着树木的耕作区，通常在海拔1100米以下活动，偶尔可达2300米。","appearance":"斑鹰鸮是一种中等体型的鸮类，体长20-26厘米，体重约151克。其特征为圆头，突出的白色眉毛，深色眼睛，白色的腹部，以及灰色上部和头顶布满斑点。上体和冠部呈深棕色，密布白色斑点；下体红色至棕色，胸部有淡黄色斑点，其余部分为淡黄色带微弱条纹；虹膜颜色从棕褐色到橙黄色不等；蜡膜和喙为绿黄色。雄雌相似，雌鸟略大。","call":"斑鹰鸮的叫声与众不同，发出一系列上升加速的“toi toi toi...”音节，最终以较低音的“toi”结束。","habits":"斑鹰鸮主要栖息于低地和丘陵的原始森林，最高可达1300米，偶尔至2300米，也可见于高大的次生林、林地、森林边缘、选择性采伐的森林和耕作区。饮食信息有限，已知在北苏拉威西以引入的鼠类（Rattus exulans和R. rattus）和昆虫（包括鞘翅目）为主食，曾有记录显示其捕杀过果蝠（Thoopterus nigrescens）。它们单独或成对沿溪流觅食。","breeding":"斑鹰鸮的繁殖细节尚未被详细描述，但在九月有雏鸟的报道。","identification":"斑鹰鸮与同域的赭腹鹰鸮的区别在于颜色较暗，肩部无明显的白色斑点；与鹰鸮的区别在于下体无条纹。","protection":"IUCN：LC（无危）。CITES II。全球种群规模和趋势无具体估计，但假定在缺乏相反证据的情况下种群稳定。广泛分布但总体稀少，局部地区如Dumoga-Bone国家公园和Lore Lindu国家公园较为常见。","distribution":"斑鹰鸮分布于印尼的苏拉威西岛，包括Kabaena、Muna和Butung等岛屿。"},{"name":"俾斯麦鹰鸮","english_name":"New Ireland Boobook","scientific_name":"Ninox variegata","overview":"俾斯麦鹰鸮（英文名：New Ireland Boobook，学名：Ninox variegata），是鸮形目鸱鸮科鹰鸮属的鸟类。体型较小的猫头鹰，拥有灰褐色头部，棕色背部点缀着白色斑点，以及带有赤褐色条纹的白色下体。广泛分布于新爱尔兰山脉和俾斯麦群岛东北部的森林地带，海拔高度至少可达1000米。","appearance":"俾斯麦鹰鸮体长23至30厘米，翼展适中，翼长介于192至224毫米之间。头部呈灰褐色，上半身巧克力色至赤褐色，背部、肩羽和翅膀覆羽上有白色斑点或条纹。初级飞羽和尾羽深棕色，带有较浅的棕色条纹。下体白色，伴有深棕色或橙褐色的条纹。眼睛黄色，喙呈淡角黄色，尖端更浅。脚黄色至橙色。雌雄外观相似，雌鸟略大于雄鸟。亚种superior比指名亚种稍大，颜色更浅的棕色。","call":"其叫声粗哑，类似青蛙的叫声，重复的双音节'kra-kra kra-kra'或'prrrt-prrrt prrrt-prrrt'。有时会形成二重唱。鸣叫时，雄鸟采取水平姿势，每次鸣叫时向下摆动翅膀。","habits":"该物种生活在低地森林、山地和较低的山脉，海拔从海平面到至少1000米。关于其生态和生物学特性的数据有限，急需进一步研究。","breeding":"关于繁殖行为的具体信息不足。","identification":"与相似的新不列颠鹰鸮相比，俾斯麦鹰鸮的下体有条纹而非斑点，胸部无明显暗色对比，且无细长的白色眉毛。它们的分布范围很少重叠。","protection":"IUCN：LC（无危）。该物种被列入《濒危野生动植物种国际贸易公约》（CITES）附录II。它是新不列颠和新爱尔兰的特有种，需要紧急研究以了解其种群规模、趋势、生态和生物学。","distribution":"分布于新爱尔兰山脉和俾斯麦群岛东北部（澳新界：Lavongai New Ireland山区和（俾斯麦群岛东北部））。"},{"name":"新不列颠鹰鸮","english_name":"New Britain Boobook","scientific_name":"Ninox odiosa","overview":"新不列颠鹰鸮（英文名：New Britain Boobook，学名：Ninox odiosa），是鸮形目鸱鸮科鹰鸮属的小型鸟类，主要分布于新不列颠岛和沃特姆岛。该鸟以深棕色头部、显著的白色眉纹和喉部斑块，以及橙黄色眼睛为特征。新不列颠鹰鸮是新不列颠岛上唯一的棕色小型鸮类。","appearance":"体长20至23厘米，体重雌鸟约209克，雄鸟约240克。翼展170至187毫米，体型小巧。上体巧克力棕色，散布着细小的奶油白色斑点，尤其是在头顶和颈背。下体呈白色和浅棕色斑驳。虹膜颜色从黄色到橙黄色不等。喙色淡绿色，尖端绿黄色。雌雄外观相似，雌鸟稍大。幼鸟特征未详述。","call":"其叫声独特，是一系列快速的单音节“whoo”音符，通常从低音开始，随后音调上升，速度加快且音量增大。","habits":"栖息于森林地带，从海平面到至少1100米的高度，亦可见于耕作区、种植园和城镇。白天单独或成对在树冠中栖息。食性方面，已知以长腿昆虫为食，也可能捕食小型脊椎动物，包括蝙蝠。","identification":"与附近的纽爱尔兰岛上出现的俾斯麦鹰鸮相比，新不列颠鹰鸮更小，面部有白色标记，头顶和颈背有斑点，上体图案较少。","protection":"IUCN：VU（易危）；CITES II。因低地森林的砍伐，该物种自2008年起被列为易危。据估计，目前种群数量在15,000至30,000只之间。在适宜生境中似乎相对常见，但研究甚少。","distribution":"分布于澳新界的新不列颠岛和沃特姆岛（位于新不列颠岛东北部，俾斯麦群岛东南部）。"},{"name":"小松巴鹰鸮","english_name":"Least Boobook","scientific_name":"Ninox sumbaensis","overview":"小松巴鹰鸮（英文名：Little Sumba Boobook，学名：Ninox sumbaensis），是鸮形目鸱鸮科鹰鸮属的鸟类。是分布于印尼松巴岛的一种特有种。自然栖息地为热带湿润低地森林，面临严重的栖息地丧失威胁。","appearance":"小松巴鹰鸮体长约23厘米，体重约90克，头部呈灰色并带有细密的暗色条纹，拥有醒目的白色眉毛，但面部盘不明显。喙大而黄色，眼睛同样为黄色，无耳羽簇。上体淡棕色，有间隔较宽的深色波浪状斑纹；下体白色，饰有精细的暗色人字形斑纹。尾部呈浅红棕色，有深色横纹。腿和爪子均为黄色。相较于同岛的松巴鹰鸮，本物种体型较小，翅膀相对更长。","call":"主叫声为单一低沉、类似笛声的“呼”音，每三秒重复一次。幼鸟发出的是一种蝉鸣般的昆虫似叫声。可能有对鸣现象。","habits":"主要栖息于残存的原始森林、受扰动的原始森林和次生林，海拔高度在600至950米之间。不同于松巴鹰鸮，它不会在邻近森林的开阔地带停留或捕猎。推测为留鸟。","breeding":"最近观察到的一只刚离巢的幼鸟在12月24日向两只成年鸟乞食。关于繁殖的其他信息尚缺乏。","identification":"与松巴鹰鸮相比，小松巴鹰鸮体型更小，翅膀相对较长，眼色为黄色，下体具有人字形斑纹而非条纹，叫声也显著不同。","protection":"IUCN：EN（濒危）；CITES II级附录物种。分布范围仅限于Sumba EBA，已知地点稀少，总范围约为6100平方公里。数量估计稀少，因森林砍伐、焚烧、放牧和森林土地的农业开垦，其种群数量很可能正在减少。部分栖息地受到Manupeu Tanadaru国家公园的保护。","distribution":"分布于印尼的小巽他群岛中西部的松巴岛。","other":"在1980年代，通过目击和鸣叫声的记录，科学家们就已知松巴岛上存在一种未知的鹰鸮。通过对样本羽毛的基因分析，确定了这是一种Ninox属下的新物种。"},{"name":"笑鸮","english_name":"Laughing Owl","scientific_name":"Ninox albifacies","overview":"笑鸮（英文名：Laughing Owl，学名：Ninox albifacies），是鸮形目鸱鸮科鹰鸮属的鸟类。已灭绝的新西兰特有猫头鹰。当欧洲人在19世纪中期抵达新西兰时，笑鸮仍广泛分布，但在1914年后几乎完全消失。这种猫头鹰以其独特的‘笑声’叫声而闻名，体长约35.5至40厘米，翼展约26.4厘米，重约600克。羽毛呈黄褐色，带深褐色条纹，眼睛非常暗红棕色。","appearance":"笑鸮是一种中等体型的陆地猫头鹰，体长38至47厘米，体重约600克。头部宽阔，翅膀短，尾巴和腿长。额头、头部两侧和喉咙呈灰白色，带有黑色羽轴；面部面具从白色到浅赤褐色，边缘明显但不规则；上体呈赤褐色，有深棕色条纹，羽毛边缘为白色至赭黄色；肩部和翼覆羽深棕色，条纹和点状黄色；尾巴深棕色，有黄色横纹；下体深赭色，广泛有深棕色条纹；喙灰角色；眼睛非常深的红棕色或榛色；腿被淡赭色羽毛覆盖；脚趾呈淡棕色，覆盖着深色毛发。幼鸟特征未描述。","call":"笑鸮的叫声被描述为一系列悲凉的尖叫声，频繁重复，类似人的笑声，因此得名。叫声还被描述为像小狗吠叫，或是远处两人互相呼喊的声音，甚至是一声忧郁的呜咽，或高音的叽叽喳喳声，通常在阴暗潮湿的夜晚或雨前听到。","habits":"笑鸮主要栖息于岩石山谷和悬崖的开阔地带及温带林地，也出现在灌木丛和森林边缘。它们被认为是留鸟，以蚯蚓、昆虫和小型脊椎动物如鸟类、蝙蝠、啮齿类、青蛙和蜥蜴为食。据推测，笑鸮主要在地面狩猎，也会从低矮的灌木或树木下部捕食，活动时间主要是夜间和黄昏。","breeding":"繁殖习性知之甚少。产卵期为8月末至10月。巢建在干燥的岩石缝隙或巨石下，有时巢穴用干草、莎草、根等物质铺垫。一般产2枚蛋，由雌鸟孵化；孵化出的小鸟身披粗糙的黄白色绒毛。","identification":"笑鸮与其他猫头鹰的主要区别在于其特有的叫声和颜色模式。由于已灭绝，现代辨识主要依赖于历史标本和描述。","protection":"IUCN：EX（灭绝）","distribution":"笑鸮曾经广泛分布在新西兰北岛南部半部的低降雨区，南岛东部的南方山脉，以及斯图尔特岛。在北岛，它们出现在塔拉纳基山和怀拉拉帕的森林区域。在南岛，它们居住在尼尔森、坎特伯雷和奥塔哥的低降雨区，包括山区和可能的峡湾地区。","other":"笑鸮的灭绝主要归咎于欧洲定居者的到来，导致栖息地变化和引入的捕食者（如鼬科动物和家猫）的影响，以及人类的迫害。最后一次确认的标本发现于1914年，之后的疑似目击报告和声音记录直到1950年，但均未得到证实。"},{"name":"罗地岛鹰鸮","english_name":"Rote Boobook","scientific_name":"Ninox rotiensis","appearance":"这种小型的棕色猫头鹰具有鲜明的黄色眼睛，头部为褐色，带有斑点。下体呈红褐色与白色斑驳，翅膀为褐色，布满白色斑点。上背散有白色斑点，与下背、臀部和尾羽覆羽的红褐色与白、黄褐色条纹形成对比。肩羽、中覆羽和大覆羽为深褐色，散布着广泛的白色斑点。初级飞羽均匀地以深褐色和淡褐色条纹交替，次级飞羽类似，但外侧的浅色条纹带有白色边缘。尾羽明显以褐色和暗褐色条纹交错。喉部和胸部主要为暗白色，带有红褐色（和肉桂色）条纹。腹部和两侧大部分为白色，带有肉桂色条纹。下翼覆羽杂有肉桂色和白色条纹。下尾羽模糊地以灰色和灰白色条纹交错。","call":"发出干燥、刺耳的‘grukgruk’声，通常以延长系列和二重奏形式出现。","habits":"罗地岛鹰鸮主要栖息于石灰岩喀斯特高大的常绿森林中，临近海岸地带，也出现在农业区域和村庄周边的大树上。它们可能全年居住于此，夜间从隐蔽的栖息处狩猎。","breeding":"关于繁殖生态的信息未知。","identification":"与南鹰鸮相似，但后者体型更大，羽毛颜色更淡，上体白色斑点不明显，尾羽条纹更密集。与帝汶鹰鸮相比，其红灰色胸纹更为密集，尾羽条纹更清晰，头部颜色更偏红。与阿洛鹰鸮的区别在于体型较小，胸纹不明显，颜色更深，尾羽条纹间距较大，初级飞羽、臀部和尾羽覆羽条纹更重。","protection":"IUCN：NT（近危）","distribution":"该物种仅限于印度尼西亚小巽他群岛中的罗地岛（Rote）。","other":"虽然在种植园和开阔地区观察到，但密度最高的是在原生森林中，可能需要一些成熟的树木才能繁殖。"},{"name":"帝汶鹰鸮","english_name":"Timor Boobook","scientific_name":"Ninox fusca","overview":"帝汶鹰鸮（英文名：Timor Boobook，学名：Ninox fusca），是鸮形目鸱鸮科鹰鸮属的鸟类。在帝汶岛特有分布。其羽毛呈灰褐色，无红褐色调，腹部有灰色条纹，翅膀和背部有白色斑点。帝汶鹰鸮的叫声独特，较之澳大利亚鹰鸮更为短促且频繁。在2019年被重新分类为独立物种。","appearance":"帝汶鹰鸮体型约30厘米长，拥有明亮的黄色眼睛，头颈部灰褐色，上体羽毛密集分布着显眼的白色斑点，尤其是在肩羽、次级飞羽、内翼覆羽和颈背。腹部棕色，饰以宽阔而不规则的白色条纹，呈现出较为斑驳的外观。初级和次级飞羽以及尾羽呈深灰褐色，带有更暗的条纹。脚趾为棕灰色，爪子角质色，尖端稍暗。幼鸟的眼睛颜色比成鸟更深，呈现暗褐色。","call":"帝汶鹰鸮发出一种略带模糊、弹跳感的“woop-woop!”叫声，以及更加平滑、低沉的“dwoop-a-woop!”声。叫声的音高变化大，最长频率约在600至700赫兹之间，有时会发出类似“wup..wup”的短促音。叫声可能由两个相同的音符组成，或者第二个音符更长且明显分为两拍（woop..huwoop），甚至可能分裂为两到三个元素（woop..hu.hwoop）。经常能听到两只鸟以不同音调或不同叫声变体进行二重唱。","habits":"帝汶鹰鸮主要栖息于帝汶岛的低地和山麓森林地带，对于退化生境的容忍度高于同类中的其他印尼物种，包括原始森林、次生林、种植园乃至村庄周边的小树林。已知它们在海拔高达2,300米的地方出现。帝汶鹰鸮是夜行性的，以静止狩猎的方式在夜间从树上的栖木捕捉猎物，食物主要包括鸟类、小型哺乳动物和大型昆虫。","identification":"与南鹰鸮相比，帝汶鹰鸮的叫声更低沉，音符音高大致相等，具有多种叫声变体，且重复率更快。在视觉上，帝汶鹰鸮几乎所有的红褐色调都被灰色取代，仅在下翼覆羽保留了红褐色，上体的白色斑点更为鲜明和大。此外，帝汶鹰鸮的面部圆盘不明显，尾部和外翼的条纹模糊不清。","protection":"IUCN：LC（无危）","distribution":"帝汶鹰鸮仅分布于帝汶岛（包括印度尼西亚西帝汶和东帝汶），遍布全岛各个海拔高度。","other":"帝汶鹰鸮曾经被认为是南鹰鸮的一个亚种，但在遗传和叫声分析显示其显著差异后，于2019年被重新分类为独立物种。"},{"name":"阿洛鹰鸮","english_name":"Alor Boobook","scientific_name":"Ninox plesseni","overview":"阿洛鹰鸮（英文名：Alor Boobook，学名：Ninox plesseni），是鸮形目鸱鸮科鹰鸮属的鸟类。原生于印度尼西亚小巽他群岛东端的Alor和Pantar岛的鸮形目鸟类。其独特的黄眼和密集斑纹的下体使其易于识别。由于其独特的鸣声和地理位置，被认为是南鹰鸮的一个独立物种。","appearance":"阿洛鹰鸮是一种小型的棕色鸮类，拥有醒目的黄色眼睛和密集斑纹的下体。头部呈棕色，上体为棕褐色，带有不规则的白色斑点，尤其是在肩胛骨、次级飞羽、内翼覆羽和颈部。下体为棕色，胸部有不规则的白色条纹，腹部则有交叉条纹。羽毛腿为淡黄色，脚部灰色。雌鸟成年个体的体重约为180克，总长度约30厘米。","call":"阿洛鹰鸮的鸣声是一系列深沉的吼叫音符，通常由5至20个相同的粗哑低音组成，以每秒约4个音符的速度重复。这种声音完全不同于其近亲的鸣声。","habits":"阿洛鹰鸮居住在各种林木环境中，包括原始雨林到轻度树林种植园。它们在黄昏开始鸣叫，直至黎明，主要在树冠下的重枝上发出叫声。它们可能全年都在夜间活动。","breeding":"关于阿洛鹰鸮的繁殖信息未知。","identification":"阿洛鹰鸮与南鹰鸮和其他近缘物种的区别在于其更深色的羽毛、独特的鸣声和体型大小。与帝汶鹰鸮相比，它具有更明显的胸纹和较少的腹部交叉条纹。","protection":"IUCN：LC（无危）","distribution":"阿洛鹰鸮仅分布于印度尼西亚小巽他群岛中的Alor和Pantar两个岛屿，包括热带山地森林、红树林和桉树林等生境。","other":"阿洛鹰鸮因其独特的声音和地理隔离，被重新分类为独立物种，此前曾被认为是南鹰鸮的亚种。"},{"name":"布鲁鹰鸮","english_name":"Buru Boobook","scientific_name":"Ninox hantu","overview":"布鲁鹰鸮（英文名：Buru Boobook，学名：Ninox hantu），是鸮形目鸱鸮科鹰鸮属的小型鹰鸮，具有独特的亮肉桂棕色羽毛，几乎无斑纹。该物种仅分布于印尼摩鹿加群岛中的布鲁岛，栖息于低地和山脚森林。其叫声奇特，似蛙或昆虫发出的一系列粗糙而持续的呱呱声，通常以中等长度的序列发出。","appearance":"布鲁鹰鸮体型中等偏小，体长25至36厘米，体重约140克。上体呈深肉桂棕色，下体红棕色，条纹较模糊，翼羽覆羽可能无条纹或仅有稀疏条纹。头部具黄色鼻蜡，喙为淡灰色，虹膜亦为黄色。","call":"主要叫声为一系列5至9个粗糙音符，类似恶魔般的笑声，音符持续约0.1秒，频率范围宽泛，音调和音量在序列结尾略有上升，每秒约5至6个音符。经常能听到两只鸟以相似的叫声对鸣。","habits":"布鲁鹰鸮常栖息于原始和高大的次生森林及灌木丛，海拔从海平面至1750米。主要以昆虫为食，但饮食研究尚未正式进行。该物种为留鸟，全年可能都有叫声，尤其是在繁殖季节叫声更频繁。","breeding":"关于繁殖的信息尚不明确。","identification":"与栗鹰鸮外观相似，但可通过红棕色的下体和较弱的条纹区分，后者下体多为白色且条纹明显。","protection":"IUCN：LC（无危）。被列入CITES II附录。由于本土森林的丧失和破碎化，种群数量可能正在下降。","distribution":"分布于印尼摩鹿加群岛中的布鲁岛。","other":"布鲁鹰鸮曾被认为是摩鹿加鹰鸮的亚种，现已确认为独立物种。"},{"name":"塔岛鹰鸮","english_name":"Tasmanian Boobook","scientific_name":"Ninox leucopsis","overview":"塔岛鹰鸮（英文名：Tasmanian Boobook，学名：Ninox leucopsis），是鸮形目鸱鸮科鹰鸮属的鸟类。广泛分布于塔斯马尼亚及周边岛屿，如金岛和巴斯海峡诸岛。在非繁殖季节，部分个体会迁至澳大利亚大陆，主要在维多利亚南部地区。体型较小，通常雄鸟比雌鸟小，以昆虫、蜘蛛、小型鸟类、哺乳动物为食。","appearance":"塔岛鹰鸮是一种中小型猫头鹰，具有一双深褐色的眼睛，周围环绕着独特的暗色眼镜状斑纹。羽毛颜色为棕色，带有斑点，腹部为暗褐色到红褐色，混杂白色和黄褐色条纹，下腹部有较大的白色斑点。头部和颈部较暗，呈灰色调，上体为深红色，有白色或黄色斑点边缘。翼长118-250毫米，尾长120-160毫米，喙长15-25毫米，跗跖长25-35毫米。体重在118-275克之间，雄鸟平均189.8克，雌鸟平均214.3克。","call":"其叫声特征明显，为熟悉的“boo-book”声，第二音节音调低于第一音节，声音比南方斑猫头鹰更高更平滑。","habits":"塔岛鹰鸮栖息于多种生境，包括温带雨林、较为开阔的森林区域、果园，偶尔出现在树线以上的巨石间。在塔斯马尼亚普遍可见，冬季期间，一些个体会迁徙至澳大利亚大陆的维多利亚南部。它们主要以昆虫和蜘蛛为食，也会捕食小型鸟类、哺乳动物，包括啮齿类和兔子。","breeding":"繁殖信息有限，但据观察，繁殖期可能在9月至12月，筑巢于树洞中。幼鸟孵化后，最初的绒羽为板岩灰色，一周后变为白色。幼鸟在离巢前会逐渐失去出生时的绒毛。","identification":"与南鹰鸮相比，塔岛鹰鸮体型较小，颜色更深，头部和背部的白色斑点更多，叫声也有差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚塔斯马尼亚州及其周边岛屿，如金岛和巴斯海峡的其他岛屿。在非繁殖季节，部分个体会迁徙至澳大利亚大陆的维多利亚南部。","other":"历史上曾被认为是新西兰鹰鸮的亚种，但多项系统发育研究证实了它作为一个独立物种的地位。"},{"name":"丛鹰鸮","english_name":"Papuan Hawk-Owl","scientific_name":"Uroglaux dimorpha","overview":"丛鹰鸮（英文名：Papuan Hawk-Owl，学名：Uroglaux dimorpha），是鸮形目鸱鸮科丛鹰鸮属的中型鸟类。其特征为头部较小，尾巴较长，翅膀圆短。拥有白色且边缘不明显的面部盘，上有黑色细纹及白色眼眉，上身呈现淡黄色，下身则有黑褐相间的条纹。眼睛鲜黄色，喙灰至黑色。雄鸟体型较雌鸟大，这一特性在猫头鹰中较为罕见。","appearance":"丛鹰鸮头部比例较小，尾巴长，翅膀圆而短。面部盘白色，细小而不明显，有黑色细纹，眼眉白色。上身颜色为淡黄色，下身黑色和褐色条纹显著，眼睛亮黄，喙色从灰色至黑色。幼鸟比成鸟颜色更淡。","call":"发出独特的低沉、哀伤的双音节‘呼呼’声，两音之间有明显停顿。有时声音会连续快速发出，更显强调。","habits":"栖息于低地雨林、森林边缘及草原中的带状林，海拔可达1500米。以昆虫、小型啮齿动物及中大型鸟类为食，如Wompoo果鸠，猎物体重可达自身重量的80%。","breeding":"仅知幼鸟在8月初被观察到，其余繁殖信息未知。","identification":"与吠鹰鸮相似，但丛鹰鸮略小，腹部条纹更稀疏，背部无白色斑点，叫声亦可区分。","protection":"IUCN：LC（无危）。CITES II。虽然分布广泛但稀少，可能因低地森林砍伐受威胁。","distribution":"主要分布在新几内亚及部分周边岛屿，包括Yapen岛，可能遍及新几内亚低地，但确切分布细节尚不清楚。","other":"尽管分布范围较广，但丛鹰鸮罕见且难以见到，其保育状况需持续关注。"},{"name":"牙买加鸮","english_name":"Jamaican Owl","scientific_name":"Asio grammicus","overview":"牙买加鸮（英文名：Jamaican Owl，学名：Asio grammicus），是鸮形目鸱鸮科长耳鸮属的鸟类。仅见于牙买加岛。以显著的耳羽和红褐色面部盘为特征，边缘带有黑白斑点，体长约27至33厘米，体重可达335克。在牙买加的沿海和低地地区广泛分布。","appearance":"牙买加鸮是一种中等体型的猫头鹰，体长在27至33厘米之间，体重约335克。具有明显的耳羽，面部盘为红褐色，边缘镶有白色和黑色。上体红褐色，细密地布有黑色波状纹。胸部和腹部为红褐色，有狭窄的深棕色条纹。翅膀和尾巴较短，不规则地带有深棕色条纹。虹膜为榛子棕色，脚趾裸露，呈灰色。","call":"牙买加鸮发出高亢颤抖的呼叫声和低沉的喉音。","habits":"牙买加鸮主要栖息于开放林地、森林边缘、偶尔出现在开阔的公园、种植园和花园中。通常在树洞或茂密的枝叶中休息。主要在夜间活动，以昆虫为主食，尤其是甲虫，同时也捕食蜘蛛、鼠类、蜥蜴和树蛙。","breeding":"牙买加鸮的繁殖信息知之甚少。筑巢记录显示时间从3月至10月，产卵期从12月至6月。巢通常位于大树的洞穴或被植被遮蔽的树杈中，每窝产卵2枚。","identification":"与仓鸮相比，牙买加鸮体型相似但颜色更深，有明显的耳羽。幼鸟的上部颜色更浅，背部呈浅灰褐色，其余羽毛为淡肉桂色。","protection":"IUCN：LC（无危）","distribution":"牙买加鸮分布在牙买加全岛，主要在沿海和低地地区，偶尔出现在海拔高达600米的山区。","other":"牙买加鸮曾被认为是Pseudoscops属的唯一成员，但现在已被重新分类到Asio属中。"},{"name":"纹鸮","english_name":"Striped Owl","scientific_name":"Asio clamator","overview":"纹鸮（英文名：Striped Owl，学名：Asio clamator），是鸮形目鸱鸮科长耳鸮属的鸟类。以其独特的外观和分布于南美洲及部分中美洲地区而著称。其具有显著的耳羽簇，面部盘呈黄褐色并以黑色边框环绕，喙部黑色，眼睛为肉桂色。在自然草原、牧场、农田以及轻度林地甚至城市公园等开放环境中，纹鸮较为常见，尽管它主要是夜行性的。","appearance":"纹鸮是一种相对较大的猫头鹰，身长可达30-38厘米，体重介于320至546克之间。最显著的特征是其头部两侧突出的耳羽簇，背部、翅膀和尾巴为棕色并带有黑色条纹和小斑点，腹部则为淡赭色，胸部有深色条纹。面部盘纯白，边缘有一圈细黑线。雄雌外观相似，无颜色变异形态。","habits":"纹鸮偏好开阔地带，如草原、稀树草原、农田和城市绿地。它主要在夜间活动，栖息在密集的树叶中或地面，但在公路旁的电线杆等地方也能看到它们狩猎的身影。纹鸮的地理分布虽广，但由于其夜行性和局部罕见的特性，使得其具体分布范围尚不完全清楚。","identification":"纹鸮与短耳鸮相比，后者耳羽簇较短，虹膜为黄色，面部盘为棕色，羽毛总体更深的棕色。乌耳鸮虽然耳羽簇较长，但全身颜色较暗，面部盘和虹膜均为深色。","protection":"IUCN：LC（无危）","distribution":"纹鸮分布于南美洲大部分地区和中美洲的部分国家，包括阿根廷、巴西、哥伦比亚、厄瓜多尔、秘鲁、委内瑞拉、墨西哥、危地马拉、洪都拉斯、尼加拉瓜、巴拿马等国。它可以在海拔从海平面至1600米的高度找到，适应多种生境，如河岸林地、沼泽、草原、热带雨林。"},{"name":"所罗门鸮","english_name":"Fearful Owl","scientific_name":"Asio solomonensis","overview":"所罗门鸮（英文名：Fearful Owl，学名：Asio solomonensis），是鸮形目鸱鸮科长耳鸮属的鸟类，为所罗门群岛特有种。其特征包括大型、有力的喙和爪，浅赤褐色的面部圆盘，眼周黑色，显著的白色眉毛，深棕色的冠部和背部，斑驳的赤褐色，下体深赭色带黑褐色条纹，亮黄色的眼睛，黑色的喙，腿羽覆盖，趾灰蓝色。体型中等偏大，雄雌相似，雌鸟略大。","appearance":"体长约38厘米，体重可达1155克（仅雌鸟样本数据）。拥有强大的喙和爪，面部盘为浅赤褐色，眼周黑色，白眉延伸至喙边形成独特的‘胡须’。头顶及上身暗棕色，饰以赤褐色斑点；飞羽和尾羽赤褐色与棕色条纹明显；下体深赭色，带有深棕色条纹；虹膜明亮黄色，鼻蜡深灰色，喙黑色，腿部被羽，趾为灰蓝色。雄雌外观相似，雌鸟体型略大，幼鸟特征未详述。","call":"叫声鲜为人知，据报道发出一种拉长的、鬼魅而哀伤的单音，音调在结尾处上升。","habits":"偏好原始森林或发达的次生林，海拔高度可达800米。可能定居，主要以树袋鼠，尤其是Phalanger orientalis，和负鼠为食，也会捕食中型鸟类。","breeding":"关于繁殖信息有限。在圣伊莎贝尔岛，叫声活跃期为6月至9月，暗示繁殖期可能在此期间。巢筑于高树上的天然洞穴、裂缝中，或寄生植物丛中。","identification":"与Solomon hawk owl（未提供学名）相比，体型稍大且更健壮；外观上与已灭绝的笑鸮相似。","protection":"IUCN：NT（近危）。全球数量估计在2500至10000只之间，面临森林破坏威胁。","distribution":"分布于布干维尔岛、舒瓦瑟尔岛和圣伊莎贝尔岛（所罗门群岛北部、中部）。生活在原始低地和山地森林，有时也在附近的次生林和林缘地带，海拔至少达到2000米。"},{"name":"乌耳鸮","english_name":"Stygian Owl","scientific_name":"Asio stygius","overview":"乌耳鸮（英文名：Stygian Owl，学名：Asio stygius），是鸮形目鸱鸮科长耳鸮属的鸟类。大型、深色、具耳羽的鸮类，拥有金色的眼睛。在松林和松栎混交林中偏好较高海拔的栖息地，通常在中上层树枝上栖息。这种鸮类广泛分布于中美洲至南美洲，包括墨西哥、部分中美洲地区、古巴、海地岛以及南美洲的10个国家。其英文名'Stygian'意味着深暗，与它黑暗的羽毛相呼应。","appearance":"乌耳鸮体长38-46厘米，体重约400-675克。全身羽毛非常暗沉，面部黑色带淡色边缘，前额白色，头部两侧有突出的长暗色羽毛形成\"耳\"状。背部暗色，有浅色条纹和斑点；腹部和胸部有黑色或深棕色的条纹和斑驳。尾巴细密条纹。眼睛黄色，喙蓝黑色至黑色，脚部暗灰色或棕粉色。","call":"发出深沉的单声呼噜声，重复间隔出现，有时被描述为低沉而响亮的'hu'或'boo'。","habits":"乌耳鸮主要栖息在从海平面到3000米高海拔的多种景观中，包括山地松林、松栎林、云雾林、荆棘灌木丛、塞拉多、松树种植园甚至城市公园。它完全夜行，以鸟类为主要食物来源，从小型鸟类到如小拟䳍大小的猎物均有捕食，还包括蝙蝠、其他哺乳动物、青蛙和昆虫。","breeding":"乌耳鸮的繁殖生态学了解不多，但其繁殖季节在其分布范围内差异很大。雄鸟会在飞行中展示翼拍动作。它们在地面或树上筑巢，有时会利用其他物种的旧巢，产卵数量为两到三枚。","identification":"乌耳鸮与长耳鸮相似，但体型更大，羽毛更暗，面部盘灰而非肉桂色，前额有白色斑块。与美洲雕鸮的区别在于体型较小，前额无白色斑块，下体条纹更强。","protection":"IUCN：LC（无危）","distribution":"乌耳鸮分布于中美洲至南美洲，包括墨西哥、部分中美洲地区、古巴、海地岛以及南美洲的多个国家，从墨西哥向南直至阿根廷北部。","other":"尽管分布广泛，乌耳鸮的总体数量被认为正在减少，具体威胁尚不明确。"},{"name":"长耳鸮","english_name":"Long-eared Owl","scientific_name":"Asio otus","appearance":"长耳鸮为中型猛禽，体长31至40厘米，翼展86至102厘米，体重在160至435克之间，雄鸟一般比雌鸟稍轻和更淡色。耳羽簇明显，头部圆大，面部盘圆，眼圈黄色至橙红色，嘴铅褐色，先端黑色。上体棕黄色，布满黑褐色粗羽干纹和虫蠹状细斑，下体淡色，带有暗色条纹。腿和脚趾被密羽覆盖，爪黑色。","call":"长耳鸮的典型叫声是重复的低沉‘呼’声，每隔几秒钟发出一次。此外，它还会发出各种类似猫的尖叫声和狗吠声。","habits":"长耳鸮偏爱半开放的生境，如森林边缘和开阔草地。它们白天隐蔽于密集的树冠中，黄昏和夜晚开始活动，捕食小型哺乳动物，尤其是田鼠。迁徙习性部分存在，一些个体会长距离迁徙，尤其是在食物短缺时。","breeding":"繁殖期为4月至6月，长耳鸮通常利用其他鸟类如乌鸦、喜鹊的旧巢，或选择树洞筑巢。每窝产卵3至8枚，孵化期约27至28天，由雌鸟独自承担孵化任务。雏鸟晚成性，约45至50天后离巢。","identification":"与短耳鸮相比，长耳鸮的耳羽簇更长，脸上的白色‘X’图纹更明显，下胸及腹部细纹较少，飞行时翼端更细且褐色更浓，翼下白色较少。与雕鸮区别在于雕鸮的面盘边界不明显，耳羽向水平方向伸展。","protection":"IUCN：LC（无危）","distribution":"长耳鸮广泛分布于北半球的温带区域，包括欧洲大部分地区、亚洲北部、北美大陆。在北美的繁殖区域从加拿大南部延伸至美国的北部地区，冬季南迁至美国南部及墨西哥。在欧洲，从英国、法国向东至俄罗斯，南至地中海区域。","other":"长耳鸮在一些地区的数量因栖息地破坏和农业活动导致的鼠类减少而有所下降。"},{"name":"埃塞长耳鸮","english_name":"Abyssinian Owl","scientific_name":"Asio abyssinicus","overview":"埃塞长耳鸮（英文名：Abyssinian Owl，学名：Asio abyssinicus），是鸮形目鸱鸮科长耳鸮属的鸟类。中等体型的真鸮，具有明显的长耳羽簇。主要分布在非洲东部，包括埃塞俄比亚和肯尼亚北部的山地森林、草原和高山沼泽地带，海拔高度可达3900米。物种在分布区内较为罕见。","appearance":"成年埃塞长耳鸮体长42至44厘米，体重245至400克，雌鸟略大于雄鸟。头部呈浅褐色，具深褐色条纹和长而边缘白色的褐色耳羽簇。面部圆盘颜色从淡到暗的红褐色，有明显的灰色眉毛。上体为褐色，饰有深褐色、浅色和白色的波状花纹。翅膀和尾巴带有褐色和浅色的横纹。胸部颜色从淡黄褐色到更红褐色，饰有粗厚的褐色断续条纹。腹部淡黄褐色或象牙色，布满紧密的褐色条纹和交叉横纹，形成棋盘状效果。眼睛橙黄色，喙黑色。","call":"雄鸟的叫声为深沉的‘who-woohm’声，音调逐渐上升，每隔几秒重复一次。雌鸟发出类似但音调更高且柔和的声音。在受惊时，会发出吠叫声和尖锐的尖叫。","habits":"埃塞长耳鸮栖息于开阔的高地、山地森林、沼泽地和带橡树或雪松林的草地。夜间活动，依靠敏锐的听觉猎食。主要以小型哺乳动物为食，偶尔捕食小鸟和昆虫。在食物充足的地方，有时会形成多达30只的群居巢穴。","breeding":"繁殖季节可能从1月持续到6月，通常在其他鸟类废弃的巢中筑巢，类似于长耳鸮的繁殖习性。","identification":"与斑点雕鸮相比，埃塞长耳鸮体型稍小、更苗条，毛色更深，耳羽簇更长。与灰鹰鸮的区别在于其橙黄色的眼睛。幼鸟的描述尚未详尽，但可能与长耳鸮幼鸟相似。","protection":"IUCN：LC（无危）","distribution":"主要分布在埃塞俄比亚和肯尼亚北部，包括阿尔伯丁裂谷的山地森林。在埃塞俄比亚，常见于巴勒山脉国家公园；在肯尼亚，格雷厄里亚种群在肯尼亚山极为罕见。","other":"埃塞长耳鸮的爪子比长耳鸮更强壮，使它能够捕食更大的猎物。"},{"name":"马岛长耳鸮","english_name":"Madagascar Owl","scientific_name":"Asio madagascariensis","overview":"马岛长耳鸮（英文名：Madagascar Owl，学名：Asio madagascariensis），是鸮形目鸱鸮科长耳鸮属的鸟类。是分布于马达加斯加岛的中等体型的鸮。被认为是马达加斯加最大的鸮类，具有独特的橙色眼睛和显著的耳簇。雌鸟比雄鸟体型更大。","appearance":"马岛长耳鸮长约40至50厘米，体重约770克。头部呈深棕色，点缀着浅褐色斑点，拥有长长的同色耳簇。脸部呈淡土黄色，逐渐变为深棕色。上体带有棕色、浅褐色和黑色的网纹和斑点，翅膀和尾巴有棕色和土黄色的条纹。胸部和腹部为淡土黄色，带有深棕色的轴状条纹，越接近腹部条纹越宽且箭头状。虹膜为橙色，喙为黑褐色，趾为黄褐色。雌雄相似，但雌鸟体型较大。雏鸟覆盖白色绒毛，面部有鲜明的黑色面具和可见的耳簇，第一次换羽后，体羽比成鸟更浅，下体颜色更浅。","call":"发出一系列类似鵟的吠叫声，如'wan gwan, wan gwan'，音调和音量逐渐升高，最后降低并逐渐消失。还会发出悠扬的'ulooh'声，间歇重复。幼鸟乞食时发出上扬的尖叫。","habits":"居住在各种森林类型中，包括湿润常绿林、干燥落叶林和画廊林，以及密集的次生林木，包括城市区、公园和种植园。从海平面到至少1625米，可能高达1800米。白天在茂密植被中栖息。主要以小型哺乳动物为食，包括鼠类和鼠狐猴，也捕食蝙蝠、两栖动物、爬行动物、鸟类和昆虫。夜间狩猎，能在森林及其附近的开阔地带捕食。拥有强大的爪子，能捕获大型猎物。","breeding":"繁殖信息有限。巢置于离地面约9米的附生植物丛中。8月至11月间繁殖，巢由其他鸟类旧巢改建。一次产卵2至3枚，孵化期35至36天，雏鸟期约36天。幼鸟离开巢穴后仍靠近巢址一段时间，直到64天大时永久离开。","identification":"与长耳鸮相似，但体型更大，耳簇更明显，胸部有细条纹。远大于马达加斯加和托罗托罗卡角鸮。","protection":"IUCN：LC（无危）；CITES II（华盛顿公约附录二）","distribution":"马岛长耳鸮分布于马达加斯加全岛，广泛见于西部和中部，从海平面到1600米，偶尔高达1800米。在东部的安达帕、马罗安特塞特拉、锡哈纳卡森林、安达西贝、拉诺马法纳和北部的山比拉诺、蒙塔涅达安布尔、高原地区较为常见。在西部的莫龙达瓦和南部的贝伦蒂也有观察记录。","other":"村民因迷信其为不祥之兆而迫害，1982年曾见到被钉在村庄边缘的死亡成鸟。"},{"name":"短耳鸮","english_name":"Short-eared Owl","scientific_name":"Asio flammeus","overview":"短耳鸮（英文名：Short-eared Owl，学名：Asio flammeus），是鸮形目鸱鸮科长耳鸮属的鸟类。这种中等体型的鸮类在日间更为活跃，常见于开阔的田野或沼泽地带，以小型哺乳动物为食。分布广泛，遍及北美、欧亚大陆、南美草原以及冰岛、夏威夷和加拉帕戈斯群岛等地。","appearance":"短耳鸮体长34-43厘米，体重206-475克，雌鸟略大于雄鸟。羽毛呈淡褐色，腹部颜色最浅，翅膀及胸部有条纹和斑点。翼尖附近有明显的淡色斑块。头部圆大，耳羽极短，不明显。面部盘灰白色，眼眶黑色，眼睛黄色。雄鸟面部盘白色偏灰，雌鸟整体颜色更深。幼鸟外观与成鸟相似，但上部羽毛更暗，具浅色尖端。","call":"在繁殖地会发出一系列低沉的“呼呼”声和各种刺耳的吠声。在繁殖地以外的地区，它们很少发声。","habits":"栖息于低山、丘陵、平原、沼泽、湖岸和草地。多在黄昏和晚上活动，但白天亦可见其活动。飞行时贴近地面，常交替进行鼓翼飞翔和滑翔。以鼠类为主要食物，也会捕食小鸟、蜥蜴、昆虫等。","breeding":"繁殖期为4-6月，巢筑于沼泽附近地面草丛或次生阔叶林内的朽木洞中。每窝产卵3-8枚，卵为白色，由雌鸟孵化，孵化期24-28天。雏鸟晚成性，约24-27天后可飞翔。","identification":"与长耳鸮的区别在于：短耳鸮有黑色眼影，眼为光艳的黄色，耳羽不明显；而长耳鸮眼红黄色，耳羽明显。短耳鸮偏好开阔草地，白天活动；长耳鸮则主要夜间活动。","protection":"IUCN：LC（无危）","distribution":"全球分布广泛，除澳大利亚外。在中国，常见于北部地区。","other":"短耳鸮在全球的分布与数量受小哺乳动物密度影响，数量波动较大，部分地区的种群呈现下降趋势。"},{"name":"沼泽耳鸮","english_name":"Marsh Owl","scientific_name":"Asio capensis","overview":"沼泽耳鸮（英文名：Marsh Owl，学名：Asio capensis），是鸮形目鸱鸮科长耳鸮属的鸟类。中到大型的暗褐色猫头鹰，具有小型耳羽，主要栖息于湿地、耕作区和草甸，尤其是湿润的草甸。分布广泛，遍及非洲各地。","appearance":"沼泽耳鸮体型介于31至38厘米，翼展可达82至99厘米，雄鸟体重约221至351克，雌鸟略重，通常在283至393克之间。头部呈圆状，眼睛周围有深色区域，额头中央有不显眼的耳羽。背部均匀呈棕色，尾部具淡黄色横纹，次级飞羽深色带淡黄色边缘，腹部有条纹。虹膜深褐色，喙黑色，脚覆有淡黄色羽毛。雌鸟比雄鸟更大更暗，幼鸟面部盘更暗，边缘黑色。亚种tingitanus颜色更深，带有赤褐色标记，尤其是腹部，与白色斑点形成对比；hova亚种体型最大，腹部有更多条纹和斑点。","call":"沼泽耳鸮发出响亮的‘creeouw’叫声，尤其是在受到惊扰、高空盘旋、求偶和地面活动时。雌鸟的叫声比雄鸟更高音且柔和。","habits":"沼泽耳鸮偏爱开阔的生境，如湿润的沿海草地、沼泽地、高达3000米的山地草地、稻田和轻度林木覆盖的草原。它们避免密集森林，但有时也会在开敞的橡树林中筑巢。它们的活动范围从海平面至马达加斯加的1500米高度。它们可能部分迁徙，季节性地离开繁殖区，尤其在雨季期间。当栖息地因火灾或干旱而改变时，它们会成为游荡者，有时形成大量群体，共用栖息地。","breeding":"繁殖期在北非为2月至10月，高峰在3月；西南非洲为9月至11月；马达加斯加为4月至7月。巢建于草丛中心的浅坑中，通常无衬垫，位于草丛下方。领地面积大约80公顷，但有时巢间距仅75米，或占地多达2平方公里。雄鸟在黄昏时展示飞行，深沉拍打翅膀。每次产卵2至3枚（最多6枚），孵化期约为28天，幼鸟在14至18天后离巢，35天左右学会飞翔。","identification":"与仓鸮相比，沼泽耳鸮颜色更深，特别是在背部和胸部。飞行时通常沉默无声，而仓鸮则经常发出尖锐的叫声。亚种之间存在颜色差异，tingitanus亚种颜色更深，有赤褐色标记；hova亚种体型最大，腹部条纹和斑点更多。","protection":"IUCN：LC（无危）。被列入CITES II附录。沼泽耳鸮全球数量未知，但广泛分布于多个保护区。tingitanus亚种在其有限范围内罕见，估计有50至140对，由于栖息地变化数量减少。hova亚种在马达加斯加分布不规则，适应性强，能捕食非本地鼠类。","distribution":"沼泽耳鸮广泛分布于非洲，包括南非北部至东开普省，津巴布韦的马绍纳兰高原，博茨瓦纳的马卡迪卡迪盐湖洼地，纳米比亚海岸的泛滥平原，以及摩洛哥和马达加斯加的孤立种群。","other":"沼泽耳鸮面临的主要威胁包括栖息地破坏、火灾、过度放牧、芦苇砍伐、道路事故和捕食者的侵扰。"},{"name":"云斑蛙口夜鹰","english_name":"Marbled Frogmouth","scientific_name":"Podargus ocellatus","overview":"云斑蛙口夜鹰（英文名：Marbled Frogmouth，学名：Podargus ocellatus），是蛙口夜鹰目蛙口夜鹰科蛙口夜鹰属的鸟类。属于蛙口夜鹰科蛙口夜鹰属，体型较大的夜间活动鸟类，以宽大的‘蛙状’喙和雨林栖息环境著称。与城市和郊区常见的棕蛙口夜鹰相比，其尾巴更长，上喙上方的条纹羽簇更长，腹部花纹更呈斑驳或云纹状。发出独特的下降式、类似火鸡咕噜声的叫声，随后是喙的响亮啪嗒声。","appearance":"体长37至48厘米，体重132至180克（ocellatus亚种）。羽毛颜色变化大，雄鸟背部颜色从暗灰褐色到深赤褐色不等，腹部常带有不规则的白色条纹和深棕色及黑色纵向条纹。雌鸟通常比雄鸟颜色更深，但并不总是能区分。幼鸟描述不详，但据报道为赤褐色，头部和腹部有模糊的白色条纹和暗色尖端，背部和肩部有模糊的暗色条纹。各亚种在大小和色彩细节上有所不同，inexpectatus亚种最为独特，背部有细密的暗色标记和明显的白色翼羽斑点。","call":"叫声非常独特，频繁从树上的栖息处发出声音。两性都能发出全套叫声，但频率、持续时间和元素数量存在性别差异。'kerloo'叫声，由4至7个'coo-loo'单元快速重复组成，用于配偶间的沟通，经常由双方以对唱二重奏形式发出。威胁叫声在领土争端中使用，是一系列快速的咕噜声，通常以响亮的机械式喙击结束，这是全年唯一可听到的叫声类型。还有一种安静的'蛤蟆'叫声，用于近距离个体间的沟通。","habits":"栖息于湿润森林，包括雨林边缘、高大的次生森林和藤本森林。主要生活在低地，但在澳大利亚记录到海拔高达800米，在新几内亚可达2200米。成年鸟似乎全年在领地内定居。主要以大型昆虫如甲虫和蚱蜢为食，有报道称会吃青蛙。通过从显眼的栖木上浅飞俯冲猎食，通常在离地面几米的森林次生层，捕食地面、树叶、树枝或树干上的猎物，使用喙捕获猎物。较大的或硬质猎物可能被带回栖木上，剧烈敲打后再食用。","breeding":"繁殖期为8月至12月（至次年2月）在澳大利亚；新几内亚的数据较少，表明繁殖期可能为3月、5月、8月至11月；在布干维尔岛，8月观察到大型雏鸟。筑巢高度3至15米（极少数25米），位于平直的树叉或寄生植物冠部的小而平坦或浅的巢穴。每窝产卵一枚，偶尔两枚。incubation期约为四周。两性共同孵卵和照顾幼鸟，雄鸟白天孵卵和照料幼鸟。巢中雏鸟首次覆盖白色绒毛。通常仅有一只幼鸟从巢中离巢，即使巢中有两枚卵。","identification":"与茶色蛙口夜鹰的区别主要在于更长的尾巴和不同的叫声；与巴布亚蛙口夜鹰相比，体型明显更大，鸣唱不同。雌鸟通常比雄鸟颜色更深，但并不总是能区分。inexpectatus亚种背部有细密的暗色标记和明显的白色翼羽斑点，与其它亚种有显著区别。","protection":"IUCN：LC（无危）。尽管地理分布广泛，但在澳大利亚的两个亚种因依赖于雨林碎片而引起关注。尤其是plumiferus亚种，由于森林被大规模破坏用于农业、放牧和木材生产，其数量大幅减少，现在成为稀有鸟类，未来需要谨慎监测。","distribution":"分布于新几内亚、周边岛屿以及澳大利亚东部和东北部。在昆士兰州阳光海岸的Conondale山脉被认为是plumiferus亚种的栖息地。物种在亚热带雨林和藤本森林中罕见，海拔从50至800米。当前种群受到土地清理、不当的火灾管理和木材采伐的威胁，气候变化对未来的影响构成额外风险。","other":"Rigidipenna inexpectatus，特有于所罗门群岛的四个岛屿，以前被认为是本种的一个亚种，2007年被划分为独立的Rigidipenna属。"},{"name":"巴布亚蛙口夜鹰","english_name":"Papuan Frogmouth","scientific_name":"Podargus papuensis","overview":"巴布亚蛙口夜鹰（英文名：Papuan Frogmouth，学名：Podargus papuensis），是蛙口夜鹰目蛙口夜鹰科蛙口夜鹰属的鸟类。体型巨大的夜间活动鸟类，拥有独特的‘蛙状’喙和长尾，主要分布在新几内亚、约克角半岛西部卫星岛、昆士兰东北部（澳大利亚东北部）以及阿鲁群岛。","appearance":"雄鸟上体灰棕色，下体浅棕灰色，具白色斑点和不规则条纹，有时黑色条纹明显，虹膜常为亮红色，但在某些个体中可能呈橙色、黄色或棕色。雌鸟外观与雄鸟相似，但颜色更偏向棕色或红棕色，尤其是上体，且光暗对比不那么强烈；罕见的雌鸟个体可呈现‘红棕色形态’，几乎全身为肉桂色。幼鸟的色彩变化极大，从类似成鸟到更淡，下体主要为白色。","call":"叫声为重复低沉的‘ooom ooom ooom...’，通常仅在繁殖季节时鸣叫。","habits":"栖息于树木边缘的草原、雨林边缘、次生林地、河岸林地、树丛和城市花园，海拔从海平面至1000米，偶尔可达2250米。以大型甲虫和蚱蜢为主食，也会捕食蜘蛛、千足虫、蜗牛、蜥蜴、啮齿类甚至小鸟。狩猎时从突出的栖木如低矮裸枝、树桩或围栏飞扑而下，无声滑翔捕捉猎物。","breeding":"繁殖季节在澳大利亚为7月至次年2月，主要集中在8月至12月，高峰在10月至11月。筑巢于树干水平叉上，高度6至20米，巢为交错的细枝平台，产卵1枚，偶尔2枚，可能双亲轮流孵卵。雏鸟的首次绒毛为白色，二次绒羽为乳白色至浅褐色。幼鸟离巢后约一个月开始自立，但仍可能与父母一起直到下一个繁殖季节开始。","identification":"与同属其他物种相比，巴布亚蛙口夜鹰体型更大，具有长尾和暗色翅膀，虹膜颜色在红色时是识别的重要特征。","protection":"IUCN：LC（无危）。在澳大利亚的部分区域仍然常见，在新几内亚一般不稀少，局部地区相当常见。能容忍一定程度的栖息地破坏和农业发展，因此在历史分布范围内仍广泛存在。","distribution":"分布于新几内亚、约克角半岛西部卫星岛、昆士兰东北部（澳大利亚东北部）和阿鲁群岛。在澳大利亚主要出现在低地地区，雨林边缘、雨林灌木丛、藤本森林、沿溪流的画眉树（Melaleuca）森林、一些桉树林地、沼泽林地和红树林。","other":"分为三个亚种：P. p. papuensis、P. p. baileyi 和 P. p. rogersi。"},{"name":"茶色蛙口夜鹰","english_name":"Tawny Frogmouth","scientific_name":"Podargus strigoides","overview":"茶色蛙口夜鹰（英文名：Tawny Frogmouth，学名：Podargus strigoides），是蛙口夜鹰目蛙口夜鹰科蛙口夜鹰属的鸟类。又名: 褐蟆口鸱、茶色蛙口鹰、茶色夜鹰，是分布于澳大利亚和塔斯曼尼亚的特有鸟类。以大头、宽喙和独特的黄色眼睛著称，能够巧妙地融入树皮背景，展现出高超的伪装技巧。这种鸟广泛分布于各种生境，包括城市郊区。","appearance":"体长介于34至53厘米，体重可达680克，头部宽大，喙部橄榄灰至黑色，尖端带钩，顶部有细小的刚毛。眼色明亮黄色，上体灰色，有明显的黑色条纹和精细的横斑。下体颜色较浅，带有黑色条纹和褐色或红褐色的斑点，白色横斑变化多样。雌鸟比雄鸟更暗，常带有更多的红褐色斑点。幼鸟与成鸟相似，但暗色标记对比不那么强烈，羽毛质地更柔软。","call":"发出低沉连续的“oom-oom-oom...”声，尤其在繁殖季节频繁鸣叫，声音柔和，不易引起注意。此外，还有多种其他叫声，遇威胁时会机械地拍打喙部。","habits":"栖息于有树木或灌木丛的环境，包括桉树林、灌木丛、城市公园和大花园。主要以大型昆虫和其他无脊椎动物为食，偶尔捕食蛙类、小型哺乳动物。白天隐蔽休息，黄昏至黎明活动，从暴露的栖木捕食地面或树枝上的猎物。","breeding":"繁殖期一般在8月至12月，筑巢于树叉，使用交错的细枝搭建，巢直径可达30厘米。每次产卵1至3枚，通常2枚，孵化期28至32天。幼鸟由父母双方共同喂养，离巢时间约25至35天。","identification":"与其他蟆口鸱相比，其体型较大，颜色变化多样，尤其是雌鸟个体可能呈现更多红褐色。通过观察其独特的喙形和羽色模式来辨认。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚大陆，包括塔斯曼尼亚北部和东部地区，但远西部昆士兰州、中央北领地和大部分的纳拉伯平原较少见。","other":"适应人类居住区，常见于城市公园和树园，受到农业发展和交通意外的威胁。"},{"name":"所罗门蛙口夜鹰","english_name":"Solomons Frogmouth","scientific_name":"Rigidipenna inexpectata","overview":"所罗门蛙口夜鹰（英文名：Solomons Frogmouth，学名：Rigidipenna inexpectata）是蛙口夜鹰目蛙口夜鹰科所罗门蛙口夜鹰属的唯一成员。此物种于1901年首次被描述，直到2007年才被确认为独立物种。仅分布于所罗门群岛的伊莎贝尔岛、布干维尔岛和瓜达尔卡纳尔岛，属于巴布亚新几内亚和所罗门群岛国家。其显著特征包括大而突出的眼睛、棕色或赤褐色的羽毛，尾羽和翅膀上有条纹，翅膀上点缀着白色斑点。","appearance":"所罗门蛙口夜鹰体长37厘米，尾羽仅有八根，与同类相比极为独特。头部顶部呈棕色，通常带有淡黄色斑点。颈背、背部和臀部为棕色，有时略带赤褐色，有微弱的黑色条纹或斑点。眼上方的眉纹通常为淡黄色，靠近眼睛处更明显。下巴和喉咙部分为棕色，带有黑色斑点，常有大胆的白色斑点。胸部和两侧颜色比背部稍浅，有黑色斑点和大胆的白色或极淡的黄色斑点。尾巴为棕色，有宽阔的淡黄色条纹，条纹边缘带有黑色斑点。雄鸟和雌鸟外观相似，但雄鸟的臀部和头部可能颜色更深，整体较少赤褐色。虹膜颜色为黄色、橙色或棕色，喙为棕色至红棕色，脚为角质色、淡黄色或乳白色。","call":"所罗门蛙口夜鹰有两种鸣叫声：一系列短暂的哨声，音调逐渐升高，以不规则间隔重复；另一系列则是快速连续的下降哨声。","habits":"栖息于原始森林、次生林和花园地带，海拔从海平面至至少700米。夜间活动，昼间隐匿。","breeding":"繁殖习性知之甚少。已知在8月于高约25米的次生森林树冠水平枝叉上的平台状巢穴中发现接近离巢的小鸟。","identification":"与有强烈的外表相似性，但在结构细节上存在差异，缺乏白色的颈背项圈。","protection":"IUCN：NT（近危）","distribution":"分布于北所罗门群岛的布干维尔岛、舒瓦瑟尔岛、圣伊莎贝尔岛和San Jorge岛；报道还出现在布干维尔岛北侧的Buka岛。","other":"其分类地位的确定基于尾羽形态、骨学特征和遗传分离，与有明显的区别。"},{"name":"大蛙口夜鹰","english_name":"Large Frogmouth","scientific_name":"Batrachostomus auritus","overview":"大蛙口夜鹰（英文名：Large Frogmouth，学名：Batrachostomus auritus），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。属于蛙口夜鹰科亚洲蟆口鸱属，拥有深邃黑眼和淡色须状羽，外观酷似教授。温暖的浅棕色羽毛，翼上点缀着明亮的白色斑点。分布于东南亚低地雨林，包括泰国南部、马来西亚半岛、苏门答腊、婆罗洲等地。","appearance":"体长约39至43厘米，重约206克，是亚洲蟆口鸱中体型最大的种类。成鸟背部呈栗色至浅棕色，肩羽带有浅色横纹，翼羽覆羽边缘黑色，中心白色或淡黄色。下体为红棕色，常伴有淡黄色至白色斑点。雌雄差异不明显，但雌鸟通常色彩较为暗淡。幼鸟上体主要为灰棕色，细密的淡黄色虫蚀状斑纹，下体为淡灰棕色，带红棕色色调，腹部颜色较浅。","call":"其歌声被描述为深沉的滚动颤音，可能重复4至8次，每次持续约1秒；还发出连续的‘coerrr’声或低沉的‘oow-OP’声，以及非常尖锐的叫声。","habits":"偏好未受干扰的原始森林，但也偶尔出现在次生林中，甚至在沼泽森林和冲积土上的森林。似乎具有留鸟习性。夜间猎食，以蚱蜢和蝉为食，通过飞扑捕获地面或树枝上的昆虫。","breeding":"繁殖期记录显示，马来西亚国家公园Taman Negara的巢穴中发现有卵，时间为2月。巢位于水平枝条分叉处的小型平台上，每窝仅产一枚卵，孵化期至少32天，双亲共同孵卵，雏鸟孵化后全身覆盖着细小的白色绒毛。","identification":"与栗颊蛙口夜鹰相比体型稍大，但区别不大。主要通过体型和分布区域进行区分。","protection":"IUCN：VU（易危）。在泰国极罕见，马来西亚稀少，但在吉隆坡周边的破碎森林中仍有记录。在苏门答腊和婆罗洲，记录较少，可能受到威胁。","distribution":"分布于泰国南部、马来西亚半岛、苏门答腊、婆罗洲（包括Labuan岛）及附近的北Natuna岛。","other":"由于低地森林栖息地的破坏，其种群数量很可能正在下降。"},{"name":"栗颊蛙口夜鹰","english_name":"Dulit Frogmouth","scientific_name":"Batrachostomus harterti","overview":"栗颊蛙口夜鹰（英文名：Dulit Frogmouth，学名：Batrachostomus harterti），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。分布于婆罗洲中北部山区的大蛙口夜鹰，仅在该地区有零星记录。其体型较大，颜色深沉，以胸褐色为主，翼上有醒目的白色斑点，生活在海拔600至1230米的山地森林中。","appearance":"体长34至37厘米，拥有宽阔的身躯，脸部有胡须状的羽毛，翼上带有明亮的白色斑点。与大蛙口夜鹰相比，其翼上的白斑更宽大，喉部有明显的淡色横纹，整体色调更深。雌雄相似，但雌鸟的上部可能更呈栗棕色，翼覆羽上的白点更大，尾部条纹更宽。","call":"发出低沉、共鸣的‘hooooo’m’声，以及成对的吠叫声‘woo’WUP!’，通常连续出现。","habits":"栖息于山地森林，偏好亚高山环境，海拔600至1230米。在夜间活动，以昆虫为食。","breeding":"繁殖季节在3月至4月间，雌鸟在11月中旬准备产卵。巢筑于离地面约4米高的树叉中，形状为杯状，内部铺有白色的羽毛。孵化期约为17天以上，雏鸟离巢时间大约35天。","identification":"与大蛙口夜鹰的区别在于，栗颊蛙口夜鹰的翼斑更宽大，喉部有更强的淡色条纹，整体颜色更深。此外，栗颊蛙口夜鹰的叫声与大蛙口夜鹰明显不同。","protection":"IUCN：LC（无危）","distribution":"分布于婆罗洲中北部的山地，具体包括马来西亚沙捞越的杜利特山（Mt Dulit）、乌孙阿保高原（Usun Apau Plateau）、凯拉比特高地（Kelabit Uplands），以及印尼西加里曼丹的梁库邦山（Mt Liang Kubung）。","other":"目前全球仅知七个标本，其中六个来自沙捞越，一个来自西加里曼丹。"},{"name":"菲律宾蛙口夜鹰","english_name":"Philippine Frogmouth","scientific_name":"Batrachostomus septimus","overview":"菲律宾蛙口夜鹰（英文名：Philippine Frogmouth，学名：Batrachostomus septimus），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。中等体型的夜行鸟，广泛分布于菲律宾群岛的低地和山地森林，常见于低地森林和成熟中的次生林。其具有独特的伪装能力，外观如同折断的树枝。","appearance":"体长约24至26厘米，重量约75.2至96.5克。存在两种色型：一种为赤褐色，底色深赤褐色；另一种为较浅的棕色，具丰富的淡色和黑色条纹。两色型间有过渡个体。特征包括颈后、喉部下方及胸下部的三条明显的淡色带。眼睛呈黄橙色，脚和喙为棕色。雌雄相似，但雌鸟颜色更深，斑纹更单调。","call":"雄鸟的叫声为一系列低沉的'woah, wash, Guam, or g-aw'声，或短暂均匀的颤音。雌鸟的叫声更为响亮，是一声短促的哀鸣，音调下降。两性都会发出尖锐的嘶哑叫声，可能为警报声。","habits":"栖息于从低地到约2500米海拔的森林及边缘地带，可能为留鸟。夜间活动，日间伪装极佳，如同断枝。以大型昆虫如蚱蜢、蝉、蟋蟀和甲虫为食，通过蹲伏在低枝上等待猎物移动时捕食。","breeding":"繁殖季节在4月至6月或7月。巢穴为小型杯状，由亲鸟的绒羽、蜘蛛丝、苔藓和地衣制成，放置于距地面2至5米的水平树枝上。每季仅产一枚卵，雄鸟白天孵卵，雌鸟夜晚接手。","identification":"与菲律宾夜鹰形状相似但羽毛图案明显不同。雌雄两性间差异在于雌鸟颜色更深，白色项圈较窄，翅膀上的白色较少，肩部无白色或淡色。不同亚种主要在体型上有所差异。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾群岛（除帕拉旺群岛和民都洛岛）。","other":"尽管被列为无危物种，但由于栖息地破坏，其种群数量被认为正在缓慢减少。"},{"name":"鳞腹蛙口夜鹰","english_name":"Gould's Frogmouth","scientific_name":"Batrachostomus stellatus","overview":"鳞腹蛙口夜鹰（英文名：Gould's Frogmouth，学名：Batrachostomus stellatus），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。夜行性的鸟类。以英国鸟类学家John Gould命名，具有独特的斑点羽毛和相似的两性外观，主要分布在东南亚低地森林，包括马来西亚、新加坡、泰国南部及印尼的苏门答腊、邦加岛和婆罗洲。","appearance":"该鸟体型中等，体重约47至48.5克，身长21至25厘米。有两种色型：亮色型呈明亮的栗色，翅膀散布着白色斑点，下体斑驳白色；暗色型为棕色，但图案相似。雌雄羽毛几乎相同，雌鸟颜色略深，具红褐色底色，虹膜为棕色，腿黄色；雄鸟虹膜黄色，腿粉红色。幼鸟也有两种色型，上体较暗，斑纹不明显。","call":"其叫声独特，包括‘wooah-weo’的幽灵般歌声，第一音节拉长，第二音节下降，持续约1秒。还有快速的‘wek’音符串，类似鸫鸟的警报声。","habits":"栖息于热带雨林，偏好未受人类干扰的本土树种森林，主要生活在低地森林，海拔可达500米。生活习性似为定居，以昆虫为食，如正翅目昆虫、蛾类和甲虫。","breeding":"繁殖季节因地区而异，马来西亚为6月至9月，婆罗洲为2月至7月。筑巢于细枝上，巢为浅杯状，高约1.3米，每窝产1枚卵，由双亲共同孵化，孵化期约30天。","identification":"与苏门答腊和婆罗洲的其他蛙口夜鹰相比，鳞腹蛙口夜鹰的两性相似，但可通过颜色深浅和叫声加以区分。","protection":"IUCN：NT（近危）。在泰国因低地森林破坏面临局部灭绝风险。","distribution":"分布于马来半岛南部、苏门答腊、Riau和Lingga群岛、邦加岛、北Natuna岛和婆罗洲。","other":"尽管分布广泛，但因生境破坏，其种群数量持续下降。"},{"name":"领蛙口夜鹰","english_name":"Sri Lanka Frogmouth","scientific_name":"Batrachostomus moniliger","overview":"领蛙口夜鹰（英文名：Sri Lanka Frogmouth，学名：Batrachostomus moniliger），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。外观介于猫头鹰和夜鹰之间，拥有宽阔的嘴巴和相对较小的眼睛，体色以灰色和棕色为主，雄鸟偏灰褐色，雌鸟则呈红褐色调。该鸟广泛分布于印度西南部的高雨量区域以及斯里兰卡的湿润森林地带。","appearance":"领蛙口夜鹰体型小至中等，长度约22-23厘米，性别二型性明显。雄鸟通常为灰褐色，带有黑色和白色的细纹，肩部有白色斑点，翼覆羽和腹部也有白色点缀，上背有一圈淡色颈环。雌鸟色彩较为均匀，红褐色，颈环不明显，腹部和尾下覆羽有较多白色。幼鸟羽毛质地柔软，颜色似成年雌鸟。","call":"领蛙口夜鹰的叫声包括一种可怕的刮擦声尖叫，以及一系列咕咕声，有时会连续发出10-15个快速的'呼呼'音，用于领地防御。此外，还有一种响亮的、液体般的'啊呜'声，重复每2-3秒，持续时间可达30分钟。","habits":"生活在密林中，偏好竹林、芦苇丛或次生林的底层植被，如茄属和穗花丹属植物。白天隐蔽于茂密的枝叶间。活动范围从海平面至海拔1200米，可能在斯里兰卡高达1850米。以昆虫为食，如蚱蜢、蛾子和甲虫，捕食方式为地面或树枝上的猎捕。","breeding":"繁殖季节长，主要在1月到4月，偶尔至9月。筑巢由双亲共同完成，巢为圆形垫状，直径约57-60毫米，深约37毫米，主要由鸟自身绒羽、蜘蛛网结合苔藓、地衣和树皮碎片制成，位于离地2-6米的水平树枝或小树叉上。每窝仅一枚白色无斑点的蛋，孵化期约7天，雏鸟第7天开始长毛，15天时接近成鸟体型。","identification":"领蛙口夜鹰是其分布区域内唯一的蛙口夜鹰种类，通过其特有的灰褐色和红褐色体色以及宽嘴和小眼的组合可以与其他夜鹰科鸟类区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于印度西南部的高雨量地区，从果阿至特里凡得琅区，以及斯里兰卡，除北部和东南部干旱区域外。在印度的分布可达海拔1200米，斯里兰卡则可能高达1850米。"},{"name":"黑顶蟆口鸱","english_name":"Hodgson's Frogmouth","scientific_name":"Batrachostomus hodgsoni","overview":"黑顶蟆口鸱（英文名：Hodgson's Frogmouth，学名：Batrachostomus hodgsoni），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。在中国是唯一的蟆口鸱代表，为罕见的留鸟，广泛分布于喜马拉雅山脉、缅甸北部及东南亚山地的常绿林和灌木丛中，海拔可达1900米。","appearance":"黑顶蟆口鸱是一种小型蛙口夜鹰，体长介于22-27厘米之间，体重约50克。其特征性的软质、斑驳的羽毛如同树皮，具有极好的隐蔽效果。雄鸟上身呈锈褐色，布满黑色斑纹，肩部和背部形成白色项圈；雌鸟更均匀的锈色，带有较少的淡色斑点。幼鸟拥有柔软的羽毛，颜色较浅，带有黑色和棕色条纹。成年鸟以其较大的头部、厚实的喙和相对较小的腿脚著称，适应了树栖生活。","call":"黑顶蟆口鸱的鸣声独特，雌鸟的叫声为单一声长哨音，通常先上升再下降至初始音调；雄鸟则发出一系列最多十个短暂而柔和的上升哨音，例如'whaaeee'，间隔1-7秒。","habits":"黑顶蟆口鸱栖息于常绿林和混合山地森林，海拔范围在300至1900米。它们通常在夜间活动，以蛾子、甲虫和其他大型昆虫为食，采取从枝头短距离飞行的方式捕捉猎物。它们具有良好的伪装能力，白天通过与树干相似的羽毛颜色进行自我保护。","breeding":"繁殖季节一般在4月至7月，筑巢于离地面1.5至5米的裸露或半裸露水平树枝上，巢由鸟羽构成，每次产卵1至2枚。雄鸟在白天孵化，雌鸟在黄昏和黎明前1-2小时接手。幼鸟的绒毛为亮锈色或暗淡的米黄色，带有深色条纹。","identification":"黑顶蟆口鸱与其他小型蛙口夜鹰的区别在于其分布区域、栖息环境、海拔高度和相对较小的体型。雄鸟和雌鸟在颜色上有明显的二态性，雌鸟更为锈色，雄鸟则偏灰褐色。","protection":"IUCN：LC（无危）。然而，在中国国家重点保护野生动物名录中被列为二级保护动物（2021.02.05）。","distribution":"分布于印度东北部至东南亚的热带地区，包括喜马拉雅山脉东部、缅甸北部、泰国、老挝、越南等地。","other":"黑顶蟆口鸱属于夜行性鸟类，与夜鹰目中的其他鸟类共享类似的喙边刚毛，用于感知猎物。"},{"name":"苍头蛙口夜鹰","english_name":"Sumatran Frogmouth","scientific_name":"Batrachostomus poliolophus","overview":"苍头蛙口夜鹰（英文名：Sumatran Frogmouth，学名：Batrachostomus poliolophus），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。苏门答腊岛的特有种，主要分布在巴里山山脉的山地森林中，高度范围在600至1200米之间。","appearance":"苍头蛙口夜鹰是一种中等体型的夜行鸟，长度约20至22厘米，具有明显的性二型性。雄鸟呈暗褐色，带有淡色斑点，上背有白色项圈，翅膀覆羽上有明显的白色斑点，腹部白色，边缘带棕色。雌鸟颜色更深，为赤褐色至栗色，白色斑点较少，项圈可能较窄。幼鸟的羽毛未知。","call":"发出一系列变化多端的叫声，包括一种诡异下降的哨音颤音，以及其他各种尖叫、嘶吼和较短的哨声。","habits":"主要栖息于苏门答腊岛的山地森林和混合松林中，通常在较高的海拔活动。其生活方式和同类物种相似，可能是留鸟，以小昆虫如甲虫和小型正翅目昆虫为食。","breeding":"繁殖资料有限，已知在六月发现过一个巢，位于地面约5米高的树叉处，由鸟的下部羽毛构成，含有一枚正在孵化的蛋。雄鸟白天孵卵，雏鸟在七月初被成年雄鸟陪伴。","identification":"与其他小型Batrachostomus属物种相比，苍头蛙口夜鹰有相对较短的尾巴，下体有清晰（而非杂乱）且广泛的白色斑纹，叫声也不同。","protection":"IUCN：LC（无危）","distribution":"主要分布于苏门答腊岛的巴里山山脉，位于山地森林和混合松林中。","other":"曾被认为是的亚种，但现在被认定为独立物种。"},{"name":"婆罗洲蛙口夜鹰","english_name":"Bornean Frogmouth","scientific_name":"Batrachostomus mixtus","overview":"婆罗洲蛙口夜鹰（英文名：Bornean Frogmouth，学名：Batrachostomus mixtus），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的小型鸟类。由Charles Hose在婆罗洲的Mount Dulit发现，并由Richard Bowdler Sharpe于1892年首次描述。婆罗洲蛙口夜鹰主要分布在婆罗洲的中央和南部山地森林中，以其独特的外观和习性著称。","appearance":"婆罗洲蛙口夜鹰体型短小而健壮，面部覆盖着缕缕细长的胡须状羽毛。雄鸟个体通体呈深棕色，而雌鸟则呈现明亮的赤褐色。成年雄鸟具有窄而淡黄白色的颈环，肩羽和翼覆羽上有鲜明的黑缘白色斑点，尾巴相对较短。成年雌鸟颜色更为红褐，颈环较窄，上体的白色斑点减少。幼鸟的描述目前尚不明确。","call":"婆罗洲蛙口夜鹰的鸣叫特征多样，但研究尚不充分。常见的是发出哀伤的下降哨音，以及流畅、波动的下滑颤音。","habits":"婆罗洲蛙口夜鹰栖息于海拔610至1675米的低山和亚高山森林中，偶尔可达2540米的高度，可能利用次生林环境。其饮食以甲虫为主，具体觅食行为资料有限。","breeding":"繁殖信息极少。已知的活跃巢穴（带有雏鸟）在4月的基纳巴卢国家公园被发现。","identification":"与苍头蛙口夜鹰相似，但尾巴较短，雌鸟尤其更为赤褐色。星喉蟆口鸱与其在部分海拔范围内共享，但后者尾巴更长，两性的下体斑点更为明显。","protection":"IUCN：LC（无危）。婆罗洲的广泛森林砍伐威胁了其生存，但在婆罗洲的亚高山区域影响较小。物种数量未知，但认为较为罕见，出现在多个保护区，包括Sarawak的Gunung Mulu国家公园和Kalimantan Timur的Kayan Mentarang自然保护区。","distribution":"分布于婆罗洲的山脉，包括北部和南部的山地。","other":"曾被认为是短尾蛙口夜鹰的一个亚种，但现在被广泛认为是一个独立的物种。"},{"name":"爪哇蛙口夜鹰","english_name":"Javan Frogmouth","scientific_name":"Batrachostomus javensis","overview":"爪哇蛙口夜鹰（英文名：Javan Frogmouth，学名：Batrachostomus javensis），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。小型鸟类，以独特的棕色羽毛，白色斑点和浅色条纹为显著特征，主要分布在爪哇岛的热带雨林中。","appearance":"爪哇蛙口夜鹰长约20至23厘米，上身由棕色、灰色、米色和白色组成，带有黑色斑点。肩羽上有几个大的椭圆形白点，眼上方有一条白色条纹和半环状白色领圈。下体呈棕色，点缀着米色、肉桂色和白色的斑点，腹部和两侧通常更淡，带有棕色的横纹。雌鸟比雄鸟更偏棕黄色，更亮丽，而幼鸟则与成鸟相似，但颜色更淡、更暗淡。喙为棕色，虹膜为淡黄色，腿为棕色。","call":"这种鸟类发出一系列激动人心、尖锐的笑声，速度约为10个音符在1.3秒内，这被认为是雌鸟的领地歌曲。还包括嘶哑的‘KWAHa’声，随后是一到四个高音的‘twoowa’声，四音符的尖叫声，以及一个略微下降的哨声，持续2.6秒。","habits":"生活在从低地到山地森林的各种茂密的树林环境中，偏好密集的雨林，常在树冠层下生活。常见于海拔1700米以上的西部和中部爪哇，以及东部爪哇高达2150米的地方。它似乎是一年四季都留在其领域内的留鸟。饮食主要包括昆虫，如甲虫、蚱蜢、蠼螋、毛虫、蛾子、蟑螂、白蚁、蚂蚁、蝉、蟋蟀、黄蝴蝶和蜗牛。","breeding":"繁殖季节一般从二月持续到六月中旬。巢是一个小的、低矮的、椭圆形（长65毫米宽55毫米）、浅杯状的结构，主要由鸟自身腹部和两侧羽毛间的精细灰绒构成，外侧有小片叶子。巢位于甘蔗丛中的斜枝上。每次产卵1-2枚，未标记的白色蛋。","identification":"与其他小型蛙口夜鹰很难仅凭外观区分，但通过声音可分辨。雌鸟比雄鸟更明亮、更偏棕黄色。","protection":"IUCN：LC（无危）","distribution":"爪哇蛙口夜鹰的分布局限于印度尼西亚的爪哇岛。","other":"尽管目前被归类为普遍且没有特殊威胁的物种，但其实际数量可能因记录不足而在许多地方被低估。"},{"name":"星喉蟆口鸱","english_name":"Blyth's Frogmouth","scientific_name":"Batrachostomus affinis","overview":"星喉蟆口鸱（英文名：Blyth's Frogmouth，学名：Batrachostomus affinis），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。其分布范围从东南亚的缅甸南部至马来西亚半岛，印度尼西亚的苏门答腊北部和婆罗洲等地。该物种以棕色为主色调，雌雄羽色差异明显，雄鸟具白色斑点和条纹，而雌鸟则更呈红褐色，腹部有‘项链’状白色斑点。","appearance":"星喉蟆口鸱体型较小，全长约20至23厘米，上体呈棕灰色，带有细小的淡色斑点和黑色斑点。雄鸟具有明显的黑斑和白色半颈环，翅膀有广泛的条纹，下腹白色，胸部长有不规则的白色斑点。雌鸟颜色更温暖，近似红褐色，翅膀条纹较少，胸部有宽大的白色‘项链’状斑点。下体色彩较暗，有不规则的黑色边缘白点。","call":"雄鸟发出一系列清晰的颤音哨声，而雌雄双方都会发出刺耳的鼻音呱呱声。","habits":"星喉蟆口鸱栖息于低地和山脚的热带雨林，偏好密集的雨林环境，通常在树干上静止不动，利用其棕色羽毛进行伪装。夜间活动，以昆虫为食，包括蚱蜢、蝉、毛虫、小甲虫和蝎子。","breeding":"繁殖季节在1月至4月间，会在树枝上建造小型垫状巢穴，巢穴由鸟自身绒毛构成，外饰以树叶、苔藓等，以匹配树皮颜色。每窝产1至2枚无斑点的白色蛋。","identification":"与其它小型蟆口鸱相比，星喉蟆口鸱的雄鸟具有更重的黑色标记，雌鸟腹部颜色更浅，白色标记更显著。在泰国南部和马来半岛，与鳞腹蛙口夜鹰的区别在于体型较小，雄鸟上下的黑色标记更重，雌鸟腹部颜色更淡，白色标记更突出。","protection":"IUCN：LC（无危）","distribution":"分布于泰国北部、缅甸南部、越南中部至马来半岛、苏门答腊北部、印尼的Riau群岛（苏门答腊中部以东）和婆罗洲。","other":"尽管分布广泛，但该物种仍然知之甚少，可能在其分布范围内被低估。"},{"name":"巴拉望蟆口鸱","english_name":"Palawan Frogmouth","scientific_name":"Batrachostomus chaseni","overview":"巴拉望蟆口鸱（英文名：Palawan Frogmouth，学名：Batrachostomus chaseni），是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的鸟类。中等体型的夜行鸟类，仅分布于菲律宾的巴拉望岛及其附近岛屿。雄鸟灰褐色，带轻微斑点，雌鸟更偏赤褐色，两者均有肩上白线和腹部白色鳞片状羽毛。其独特的面部胡须是辨识特征之一。","appearance":"巴拉望蟆口鸱体长约21至22厘米，翼展约116至123毫米，尾长109至108毫米。雄鸟呈灰褐色，带有淡色斑点，雌鸟则颜色更深，呈赤褐色。两性均具有肩部上方的断续白线，腹部布满白色鳞片状羽毛，胸部有较大泪滴状斑点。喙部颜色多变，从角质色到粉棕色不等。","call":"其鸣声有两种类型：一是柔和、哀怨的哨音，持续约2秒，每10秒重复一次；二是粗糙、悲凉的咆哮声，持续约1秒，间隔6至15秒重复。","habits":"栖息于低地常绿森林和次生林中，包括茂密的灌木丛和竹林。食性不明，可能以蛾类为主食。生活方式似乎定居，没有迁徙记录。","breeding":"繁殖季节可能在6月至8月间，巢由植被和绒羽构成，通常产1至2枚未标记的白色蛋。目前关于繁殖行为的详细信息有限。","identification":"与其他蟆口鸱属物种如星喉蟆口鸱和爪哇蛙口夜鹰相比，主要通过声音和一些形态差异辨识。具体细节尚待进一步研究。","protection":"IUCN：LC（无危）。尽管如此，其种群受到森林砍伐的威胁，尤其是在其分布范围内。","distribution":"主要分布在菲律宾的巴拉望岛及其附近的Busuanga和Culion岛。在远东地区，还出现在Banggi（婆罗洲东北部北部）。","other":"物种界限曾与星喉蟆口鸱和爪哇蛙口夜鹰混淆，但现在被视为独立物种。"},{"name":"巽他蛙口夜鹰","english_name":"Sunda Frogmouth","scientific_name":"Batrachostomus cornutus","overview":"巽他蛙口夜鹰（英文名：Sunda Frogmouth，学名：Batrachostomus cornutus）是蛙口夜鹰目蛙口夜鹰科亚洲蟆口鸱属的小型鸟类，以其刺眼的黄色眼睛著称。广泛分布于印尼的苏门答腊岛和婆罗洲，偏好低地和低山脚下的森林、种植园及森林边缘地带。雄鸟和雌鸟的羽毛颜色变化大，雄鸟通常具有更为复杂的图案，而雌鸟更常呈现红褐色调。","appearance":"体长23至28厘米，羽毛色彩极为多变，成年雄鸟有宽大的淡色眉纹、上背部的淡色颈环以及肩部明显的白色椭圆形斑点；下体斑驳，腹部和两胁较淡，带有深色斑点和条纹。存在两种色型：黑白相间型，上体黑色，细碎地散布着白色到淡黄褐色的斑点；棕黄相间型，上体棕色，原本的黑色区域变为棕色，白色部分替换为淡黄褐色。雌鸟变异范围广，从较为单一的深红褐色到高度斑驳，与雄鸟的棕黄相间型相似。幼鸟的唯一已知样本为雌鸟，羽毛柔软，色泽接近成年雌鸟的红褐色变种，但上体和下体颜色较浅。","call":"发出尖锐、沙哑的叫声，类似大型乌鸦的“caw”声，同时也会发出清晰的哨音和一系列短暂的滚动式尖锐音符。","habits":"生活在低地和低山脚下的森林、种植园及森林边缘，以昆虫为食，包括甲虫、大型蝉鸣、美洲蟑螂、蟋蟀、蚱蜢和螳螂。白天隐蔽，夜间活动。","breeding":"繁殖记录稀少，但在苏门答腊和婆罗洲有观察到筑巢和育雏的行为。巢是一个小而圆的结构，由绒毛、苔藓和小块树皮构成，直径约7厘米，深度仅1厘米，建在离地面1.5米至6米高的水平树枝上。每窝产一枚白色的蛋，大小约为25-31.9毫米×18.8-21.2毫米。雄鸟在白天孵卵，雌鸟在夜间，可能在黎明和黄昏时交换。","identification":"与星喉蟆口鸱相比，其羽毛中的白色部分较少；而与婆罗洲和苏门答腊的蛙口夜鹰相比，尾巴较短。Bornean和Sumatran蛙口夜鹰更偏好高海拔地区。","protection":"IUCN：LC（无危）。在婆罗洲，它可能是较小的Batrachostomus中最常见的物种，特别是在Tanjung Puting国家公园。最近的记录来自苏门答腊的Way Kambas国家公园。","distribution":"主要分布在东洋界，具体为印尼的苏门答腊岛和婆罗洲，包括繁殖区域。","other":"对于该物种在Mentawai群岛的Siberut岛上的发现，仍需进一步研究确认。"},{"name":"油夜鹰","english_name":"Oilbird","scientific_name":"Steatornis caripensis","overview":"油夜鹰（英文名：Oilbird，学名：Steatornis caripensis）是油夜鹰目油夜鹰科油夜鹰属的唯一物种。分布于南美洲北部，包括特立尼达岛。以油棕榈果为主的果实为食，夜间活动，具有独特的回声定位能力。","appearance":"体型大，约40-49厘米长，翼展95-107厘米，重350-475克。全身暗红褐色，有白色小斑点，头部鹰状，具深棕色钩喙，周围有长达5厘米的触须状刚毛。脚小而弱，主要用于在垂直表面攀爬。翅膀长而宽，适合在洞穴狭窄空间飞行。","call":"发出一系列尖锐的点击声用于回声定位，同时在洞穴内还会发出各种刺耳的尖叫。","habits":"栖息于常绿低地和山地森林，白天在洞穴或峡谷峭壁上的群落中休息，夜晚外出觅食。飞行特点独特，能在低光条件下导航，使用回声定位技巧。主要食物为Lauraceae、Burseraceae和Palmae家族的果实。","breeding":"在洞穴中集体筑巢，巢由排泄物堆成，位于水面上方的岩石架上。每窝产2-4枚白色蛋，孵化后雏鸟在离巢前体重可达600克，远超成鸟体重。","identification":"体型较大，颜色为暗红褐色，具白色斑点，与夜鹰科鸟类相似，但可通过其更大体型、更圆润的体形和更为懒散的飞行方式来区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲北部，从圭亚那、特立尼达岛到委内瑞拉、哥伦比亚、厄瓜多尔、秘鲁、玻利维亚和巴西，海拔从海平面至3,400米。","other":"历史上，油夜鹰幼鸟曾被捕捉以提取油脂。"},{"name":"大钩嘴夜鹰","english_name":"Great Potoo","scientific_name":"Nyctibius grandis","overview":"大钩嘴夜鹰（英文名：Great Potoo，学名：Nyctibius grandis），是钩嘴夜鹰目钩嘴夜鹰科钩嘴夜鹰属的鸟类。体型庞大的钩嘴夜鹰，广泛分布在中美洲和南美洲的热带森林中。其最显著的特征是大型头部和独特的夜间叫声，这种叫声在新热带区中异常突出。","appearance":"大钩嘴夜鹰拥有相对较大的头部和厚实的颈部，羽毛呈现斑驳的灰白色至棕色，与树干上的苔藓色泽相仿。成鸟上体羽毛混杂着灰色、棕色和白色，下体颜色较浅，喉部和前颈为淡黄色至肉桂色，腹部更白。幼鸟全身更偏白色，暗色条纹和斑点较少。大钩嘴夜鹰是该属中体型最大、颜色最淡的物种。","call":"大钩嘴夜鹰以其独特的夜间叫声而闻名，这是一种拉长的呻吟式咆哮声，令人印象深刻且略感不安。","habits":"大钩嘴夜鹰主要栖息在湿润和半湿润的森林环境，白天它们几乎不动，模仿断枝藏身于大树中，夜晚则活跃起来，以大型飞虫为食，偶尔也会捕食蝙蝠和小型脊椎动物。","breeding":"繁殖期通常在2月至8月间，但依据地理分布的不同，繁殖活动可能全年发生。筑巢于至少10米高的粗壮树枝上的轻微凹陷处，每次产一枚白色略带斑点的蛋。幼鸟出生一个月后独自留在巢中，大约5周后，雏鸟体型达到成鸟的三分之二，但羽色更淡，尾巴更短，喙较小，离开巢穴后不再返回。","identification":"与同属的其他物种相比，大钩嘴夜鹰体型更大，颜色更淡，缺乏深色的髭纹。在分布区域内，它比钩嘴夜鹰更大，颜色更浅；与北钩嘴夜鹰相比，体型也更大，颜色更深。","protection":"IUCN：LC（无危）","distribution":"大钩嘴夜鹰分布于中美洲南部至南美洲，从墨西哥南部到巴拿马，穿过南美洲到达玻利维亚中部和巴西中南部、东南部。","other":"尽管在分布区内常见，但在边缘地带较为罕见。人类对大钩嘴夜鹰的影响主要体现在森林砍伐上，这是其唯一的已知保护威胁。"},{"name":"长尾钩嘴夜鹰","english_name":"Long-tailed Potoo","scientific_name":"Nyctibius aethereus","overview":"长尾钩嘴夜鹰（英文名：Long-tailed Potoo，学名：Nyctibius aethereus），是钩嘴夜鹰目钩嘴夜鹰科钩嘴夜鹰属的鸟类。大型钩嘴夜鹰科鸟类，以拥有比例较长的尾巴而著称。分布于南美洲亚马逊雨林、南美东南部以及哥伦比亚西部的局部地区，其分布区被分为三个由不同亚种占据的离散区块。在亚马逊森林、巴西大西洋森林等地可达海拔1200米。","appearance":"长尾钩嘴夜鹰体长42至58厘米，体重介于280至447克之间。上体呈锈褐色，头部和颈背有斑点和黑色条纹，背部有棕色和淡色斑点，尾羽渐长且棕色，带有淡色横纹。面部大部分为锈色，具有一道明显的白色髭纹。翅膀总体呈棕色，翼下覆羽为棕色带淡色横纹。下体灰白色，胸部和两胁为棕色，有淡色斑点和深色条纹。","call":"长尾钩嘴夜鹰的鸣声为柔和起伏的“waa-OO-uh”或“ra-OOH”g，通常在月夜歌唱。","habits":"长尾钩嘴夜鹰栖息于低地热带雨林内部，从林下层到次冠层，偏好湿度较高的环境。它主要在夜间活动，以飞行昆虫为食，会从栖木上突然出击捕食。白天时，它们通常在距离地面20米高的枯枝上休息，受到干扰时会垂直拉伸身体并保持不动。","breeding":"长尾钩嘴夜鹰的繁殖季节未完全确定，已知在帕拉圭的繁殖活动从8月底持续到11月，在法属圭亚那的繁殖期为7月至9月。它们不会筑造传统意义上的巢，而是将单个蛋产在树桩顶部或弯曲处的树枝上。","identification":"长尾钩嘴夜鹰与大钩嘴夜鹰相似，但体型更纤细，尾巴更长，整体颜色更深，肩部有明显的淡色斑块。与钩嘴夜鹰相比，体型较小，尾巴较短。","protection":"IUCN：LC（无危）","distribution":"长尾钩嘴夜鹰广泛分布于南美洲亚马逊雨林区域，包括厄瓜多尔、秘鲁、哥伦比亚南部、委内瑞拉、圭亚那、巴西北部和东南部，以及阿根廷东北部、巴拉圭东部和巴西东南部的巴西大西洋森林。","other":"尽管长尾钩嘴夜鹰的分布范围广泛，但其特定亚种的分布区域有限，特别是巴西大西洋森林中的亚种面临栖息地碎片化的威胁。"},{"name":"北钩嘴夜鹰","english_name":"Northern Potoo","scientific_name":"Nyctibius jamaicensis","overview":"北钩嘴夜鹰（英文名：Northern Potoo，学名：Nyctibius jamaicensis），是钩嘴夜鹰目钩嘴夜鹰科钩嘴夜鹰属的鸟类。属于钩嘴夜鹰科的独特夜行性鸟类。以大头、大眼和伪装般的羽毛条纹著称，主要分布在中美洲的热带低地森林，包括红树林区域，以及加勒比海的大安的列斯群岛如牙买加和海地。白天很难发现，因为它们像断枝般站立，夜间则因明亮的黄眼在手电筒下反射如琥珀而容易被辨认。","appearance":"北钩嘴夜鹰体型中等，长约38至46厘米，具长尾和尖翅，头部大，腿短小，喙短但口裂宽大。羽毛呈灰褐色，饰有复杂的黑色、灰色和奶油色斑点。脸颊较淡，有一条明显的黑喉侧纹。眼睛大，虹膜黄色，在夜间光线下可反射红色。叫声粗哑且沙哑。","call":"发出粗糙、嘶哑的'kwaaah, kwa-kwa-kwa'叫声，也有突然、强调的'rrah!'声，以及类似犬吠的警报声。","habits":"栖息于林地和灌木丛中的开阔地带，包括农田附近的散树，有时可见于高尔夫球场或城市区域。夜晚活动，白天则静止不动地站在树枝或柱子上，伪装得如同折断的树枝。以停歇的方式捕食大型昆虫，如飞蛾和甲虫。","breeding":"单产一枚蛋，直接产在折断的树枝上，无需筑巢材料。双亲共同参与孵化和喂养幼鸟。","identification":"与常见的钩嘴夜鹰外观相似，但声音截然不同，后者发出一系列哀伤的、哀号似的哨声。与大钩嘴夜鹰相比，体型较小，颜色更深，具黑喉侧纹。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥南部到哥斯达黎加，以及大安的列斯群岛的牙买加和海地。在中美洲，其分布涵盖从墨西哥到哥斯达黎加的低地森林，以及加勒比海的牙买加和海地。","other":"在莫潘文化中，如果北钩嘴夜鹰（莫潘语：ajsooch’）在夜晚反复飞过某人的房屋，这预示着这家人中会有人去世。为了防止这种不幸，人们会用点燃的棍子驱赶鸟，据说燃烧的余烬能吓退这种鸟。"},{"name":"钩嘴夜鹰","english_name":"Common Potoo","scientific_name":"Nyctibius griseus","overview":"钩嘴夜鹰（英文名：Common Potoo，学名：Nyctibius griseus）是钩嘴夜鹰目钩嘴夜鹰科钩嘴夜鹰属的鸟类，因其独特的外观而引人注目。拥有大头和醒目的黄色眼睛，整体呈灰褐色，斑驳的羽毛图案使其能够融入森林环境。分布于中美洲南部至南美洲北部和中部的低地森林边缘，以其令人难忘的哀伤鸣声和高超的伪装技巧而闻名。","appearance":"钩嘴夜鹰体型中等，约34至38厘米长，具有灰褐色到暗棕色的羽毛，上面点缀着黑色和浅色斑点，使其与树干融为一体。头部较大，双眼黄色，喙小而带钩，口裂宽大。胸腹部常可见黑色斑点组成的项链状图案，翅膀和尾巴较长，利于夜间飞行时的灵活性。雄雌两性在外观上相似。","call":"钩嘴夜鹰的叫声哀婉，由一系列下降音调的哨声组成，如同“POO, POO, Poo, poo, poo。”，在夜晚回荡，成为其最显著的识别特征之一。","habits":"钩嘴夜鹰主要栖息于开阔的森林地带，如森林边缘、河岸或路边，甚至在零星的林地。它们白天静止不动，巧妙地隐藏在树桩或暴露的树枝上，夜间则从显眼的栖木出发捕食飞行中的昆虫。钩嘴夜鹰的活动范围广泛，能在多种环境中生存。","breeding":"繁殖期，钩嘴夜鹰会在树桩或断枝上产下一枚蛋，不筑巢，而是直接将蛋放置在平坦处。雌雄双方轮流孵卵，共同承担育雏责任，幼鸟孵化后约33天离开巢穴，开始独立生活。","identification":"钩嘴夜鹰与大钩嘴夜鹰相比，体型较小，颜色更深，且具有明显的黑色喉纹。而长尾钩嘴夜鹰和北钩嘴夜鹰则通过体型、颜色和鸣声的不同来区分。","protection":"IUCN：LC（无危）","distribution":"钩嘴夜鹰的分布区域从中美洲的尼加拉瓜向南延伸至南美洲的乌拉圭，遍及整个南美洲除智利外的国家，从安第斯山脉到大西洋沿岸都有其踪迹。"},{"name":"安第斯钩嘴夜鹰","english_name":"Andean Potoo","scientific_name":"Nyctibius maculosus","overview":"安第斯钩嘴夜鹰（英文名：Andean Potoo，学名：Nyctibius maculosus），是钩嘴夜鹰目钩嘴夜鹰科钩嘴夜鹰属的鸟类。属于钩嘴夜鹰科的大型暗褐色鸟类，翼部和尾部有白色斑纹，最显著的是翅膀覆羽上的大面积白色板块，雌鸟的白色部分带浅黄色调。Nyctibius属中唯一的高山代表，分布于委内瑞拉西部至哥伦比亚、厄瓜多尔、秘鲁，直至玻利维亚西部的安第斯山脉云雾森林中，海拔高度在1800至至少2800米之间。","appearance":"体长34至40.5厘米，雄鸟体重可达195克，雌鸟体重在145至185克之间。头部和眼睛较大，喙短而口宽。上身主要为棕色，具白色、浅黄色、赤褐色和黑色条纹、斑点；下体则带有黑色或暗色斑点。最突出的特征是翅膀上明显的白色带状覆羽，雌鸟的覆羽颜色偏浅黄色。腹面为浅黄色，带有棕色条纹和黑色斑点。","call":"其鸣声为几乎哀怨的长啸声'kwaaaanh'，间隔3至5秒发出一次，也会发出缓慢的空洞声'wok wok wok'以及较轻的'bu bu bu'叫声。","habits":"夜行性，以昆虫为食，具体饮食细节未知。白天在大树枝上休息，包括那些高于树冠的树枝。活动范围在安第斯山脉的湿润山林中，从1800至2800米的海拔高度。","breeding":"繁殖生态学未知，推测在树冠中的树枝上产一卵，繁殖行为类似其他钩嘴夜鹰。","identification":"与白翅钩嘴夜鹰相似，但体型更小，尾巴较短，羽毛颜色更灰，下体斑点较少；与钩嘴夜鹰相比，后者体型更大，羽毛密集程度和颜色更深，缺乏白色翅膀覆羽。","protection":"IUCN：LC（无危）","distribution":"南美洲，分布于委内瑞拉至玻利维亚的安第斯山脉区域，具体包括委内瑞拉西部、哥伦比亚、厄瓜多尔、秘鲁和玻利维亚西部。","other":"由于其隐蔽的生活习性和相对稀少，关于安第斯钩嘴夜鹰的生态和行为了解甚少。"},{"name":"白翅钩嘴夜鹰","english_name":"White-winged Potoo","scientific_name":"Nyctibius leucopterus","overview":"白翅钩嘴夜鹰（英文名：White-winged Potoo，学名：Nyctibius leucopterus），是钩嘴夜鹰目钩嘴夜鹰科钩嘴夜鹰属的鸟类。较为罕见的钩嘴夜鹰科鸟类。此物种在日间几乎不被察觉，仅在夜间活跃。其显著特征为翼上部的大片白色斑纹，分布于南美洲亚马孙雨林的高地和沙质地带，未见于沿海或草原地带。","appearance":"体长24至29厘米，重量在亚马逊地区为77至85克，东部形态未知。尾较短，上体暗褐色，下体颜色较浅，翅膀二级飞羽覆盖处有显眼的大型白色斑块。两性外观相似，但白色翼斑的范围和棕色中的红褐色调可能与年龄或性别有关。亚马逊形态比东部形态小得多，两者在颜色上几乎相同。","call":"发出独特而略带哀伤的长哨声，在亚马逊地区，叫声为逐渐下降的纯音'feeeoooooo'，持续约4秒，有时起始稍有上升。还发出柔和的单个或重复的'bweep'声。","habits":"栖息于亚马逊低地的原始森林树冠层，偏好沙质土壤的轻森林。在巴西东部的栖息地尚不清楚，推测类似地在大西洋雨林的树冠层。可能是定居物种。以小型至中型的飞行昆虫为食，包括甲虫、蛾、蝉、螳螂、直翅目昆虫、有翅白蚁和真蝽。夜间从暴露的栖木上出击捕食。","breeding":"繁殖生态未知，推测与同类相似，可能在树冠高处的树枝上产一枚蛋。","identification":"与其他Potoo的区别在于明显的白色翼斑，尤其是在日光下可见，但与钩嘴夜鹰相比，白翅钩嘴夜鹰的白色翼斑更大更亮。与安第斯钩嘴夜鹰在体型、羽毛、声音和海拔分布上有显著差异。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲亚马逊雨林的低地，包括委内瑞拉东部、巴西北部、圭亚那、法属圭亚那、苏里南以及秘鲁东部。在巴西巴伊亚州和埃斯皮里图桑托州的巴西东部地区也有记录。","other":"曾有一段时间，安第斯钩嘴夜鹰被认为是白翅钩嘴夜鹰的一个亚种，但后来因体型、羽毛、声音和分布海拔的不同而被重新分类。白翅钩嘴夜鹰目前被认为是一个单型种，但亚马逊形态可能代表了一个独立的物种。"},{"name":"棕钩嘴夜鹰","english_name":"Rufous Potoo","scientific_name":"Phyllaemulor bracteatus","overview":"棕钩嘴夜鹰（英文名：Rufous Potoo，学名：Phyllaemulor bracteatus），是钩嘴夜鹰目钩嘴夜鹰科 Phyllaemulor 属的鸟类。属于夜行性鸟类，分布于南美的亚马逊雨林区域，从委内瑞拉南部至秘鲁东部，再向东延伸至巴西、法属圭亚那和圭亚那。其深橙红色的羽毛带有大白色斑点，喉咙颜色较淡，外形独特。","appearance":"体型小巧，长度约21至25厘米，体重介于46至58克之间，是钩嘴夜鹰家族中最小的成员。全身呈深橙红色，具大白色斑点，尤以上腹部的斑点边缘呈黑色。尾巴有深色横纹，眼睛黄色，有时看似白色，下部有暗色楔形斑。喙周围有长毛状羽毛。雌雄外观相似，幼鸟羽毛色泽较暗且棕色，缺少白色斑点或斑点极小，更接近成年其他钩嘴夜鹰种类。","call":"发出柔和、快速下降的约10至15个音符的系列叫声，类似‘bu-bu-bu-bu-bu-bu...’或‘whooo, tooo, tooo, tooo, tooo, tooo, tooo, tooo, tooo, tooo, tooo, toot’，模仿某些小型猫头鹰的叫声，但节奏稍慢且声音不那么柔和。","habits":"栖息于低地亚马逊雨林的次生林和成熟森林的下层和中层，偏好营养贫瘠土壤上的森林，如含沙量高的土壤或黑水区域。主要活动于夜间，以飞行中的昆虫为食，通过短暂的向上或向外飞扑来捕食，之后返回原位。通常在树梢附近或地面以上1米处栖息，但多数时间栖息得更高。","breeding":"繁殖季节可能从9月持续至翌年2月，已知的巢穴极少。巢穴非常特殊，单枚带有斑点的蛋直接放置于断裂树干的顶部。孵化和离巢期不详，但据其他Nyctibius属的资料，推测大约分别为一个月和两个月。","identification":"与其他钩嘴夜鹰相比，棕钩嘴夜鹰体型更小，羽毛颜色独特，具有显著的白色斑点。与油夜鹰相似，但体型明显较小且站立姿势垂直。幼鸟与成鸟在颜色上有明显差异，缺乏明显的白色标记。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马逊雨林，包括委内瑞拉、厄瓜多尔、秘鲁北部、巴西、法属圭亚那、苏里南和圭亚那。最近记录显示，其分布可能扩展至玻利维亚北部和巴西的帕拉州。在一些保护区如巴西的Jaú国家公园有所发现。","other":"虽然全球范围内并不受到严重威胁，但由于亚马逊森林的持续破坏，其生存状况仍需进一步研究。"},{"name":"斑毛腿夜鹰","english_name":"Spotted Nightjar","scientific_name":"Eurostopodus argus","overview":"斑毛腿夜鹰（英文名：Spotted Nightjar，学名：Eurostopodus argus），是夜鹰目夜鹰科毛腿夜鹰属的鸟类。广泛分布于澳大利亚内陆干燥地区的夜行性鸟类。此物种在澳大利亚内陆较为常见，其显著特征为灰褐色羽毛上点缀着红棕色领圈和大量斑点与横纹。斑毛腿夜鹰活跃于开放林地至沙漠地带，偏好沙石地面和落叶丰富的环境。","appearance":"斑毛腿夜鹰体型小至中等，长度约为27-35厘米，体重在75-132克之间，两性相似。上体呈灰褐底色，饰以灰白斑点；头顶中央有黑色条纹边缘泛棕；颈部有一圈明显的淡色环带；翅膀覆羽具灰白斑点，翼缘有显眼的淡色斑点；下颚处有淡色条纹，喉部有大片白色斑块；下体灰褐色，腹部和侧腹则为棕色与淡色条纹相间。成年个体在四根最外侧初级飞羽上有大型白色斑点，但尾部缺乏白色标记。虹膜深棕色，喙及腿脚呈棕色。","call":"斑毛腿夜鹰的叫声独特，雄鸟的歌声是一系列快速上升的“whaw”音符，随后是气泡般的咕噜声，通常从地面发出。警戒时会发出深沉的吠叫或连续的churr声；还有咕哝、咕噜和爆裂声；在威胁和防御时会发出低沉的嘶嘶声；成鸟会对幼鸟发出低沉的哼声，而雏鸟则发出柔和的啾啾声和颤音。","habits":"斑毛腿夜鹰栖息于多种生境，包括开放林地、灌木丛、草原、沙丘草甸、热带雨林边缘以及红树林。它们偏爱温暖干燥的气候，避免高湿度和凉爽的森林环境。夜间活动，主要以昆虫为食，常在地面休息，很少在树上栖息。在水源附近，它们能边飞边饮水。","breeding":"繁殖期大致在8月至翌年2月，可能主要集中在9月至11月，若前一年冬季过于干旱则可能不繁殖。一般每窝仅产一枚卵，有时双窝育雏。领地意识强，可能在同一领地持续数年。巢位多选在树下或石头旁，通常靠近山顶或山脊，靠近前一年的巢址。巢穴简单，卵直接产在落叶或裸土上。卵为椭圆形，表面光滑，颜色为淡黄绿色、黄色橄榄或橄榄绿，带有紫色或棕色斑点。两性共同孵化，孵化期约29-33天。成鸟在巢位受威胁时会做出防御或吸引注意力的行为。雏鸟半早熟，出生时覆盖着红棕色或栗色绒毛，由双亲共同照顾，约30天后即可独立。","identification":"斑毛腿夜鹰与其他夜鹰的区别在于其较大的体型和更为鲜艳的羽毛花纹，尤其是成年个体在外侧初级飞羽上的大型白色斑点，而没有大型尾夜鹰那样的白色尾部标记。幼鸟相比成鸟颜色更浅，白色斑点较小。","protection":"IUCN：LC（无危）","distribution":"斑毛腿夜鹰广泛分布于澳大利亚大部分地区，但在昆士兰中部到南澳大利亚东南部的沿海地区以及塔斯马尼亚州较少见。繁殖季节结束后，部分个体向北迁徙至印尼的摩鹿加群岛南部。","other":"斑毛腿夜鹰在澳大利亚内陆地区曾经被认为数量适中，但由于栖息地丧失、土地清理、原生植被过度放牧以及外来猫和狐狸的捕食，其数量可能正在减少，特别是在其分布区的南部。"},{"name":"白喉毛腿夜鹰","english_name":"White-throated Nightjar","scientific_name":"Eurostopodus mystacalis","overview":"白喉毛腿夜鹰（英文名：White-throated Nightjar，学名：Eurostopodus mystacalis）是夜鹰目夜鹰科毛腿夜鹰属的大型夜行鸟类。体长约30-37厘米，分布于澳大利亚东部，从约克角半岛至维多利亚州东部，是当地特有种。冬季迁往新几内亚北部，偏好干燥森林环境，尤其是桉树林和干硬叶林。","appearance":"该物种上体及翅膀为灰褐底色，饰以深褐色条纹，颈部呈淡黄色，两侧喉部有显著白色斑块，形成类似领结的外观。翼覆羽灰白间杂，翼尖四根初级飞羽末端有白色斑点。尾羽暗褐色，无白色标记。喙色灰黑，腿足深棕色，体型匀称，性别相似，幼鸟较成鸟淡，带紫红色调。飞行时可见单个白色翼斑。","call":"雄鸟的叫声独特，为快速上升的泡泡音，被形容为人类笑声的爆发，通常在黄昏和黎明时分从栖木发出，或在展示飞行时发出。","habits":"栖息于低海拔干燥森林，如桉树林和干硬叶林，有时也会出现在灌木丛、草地和花园中。夜间活动，主要以飞蛾、甲虫、飞蚁等昆虫为食，常在树冠层捕食。迁徙时，会组成松散群落，数量可达20-30只。","breeding":"繁殖季节为9月至次年2月，筑巢于地面，通常在裸土或落叶上，一窝产一枚蛋，由双亲轮流孵化，孵化期约22-28天。雏鸟早熟，出生后即可移动，约30天后离巢。","identification":"与斑毛腿夜鹰和相比，白喉毛腿夜鹰体型更大，翼上有单个白色斑点，叫声明显不同。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于澳大利亚东部，从约克角半岛至维多利亚州中南部。冬季迁徙至新几内亚北部。","other":"曾被视为新喀毛腿夜鹰和所罗门毛腿夜鹰的亚种，后基于形态和声音差异分离为独立物种。"},{"name":"所罗门毛腿夜鹰","english_name":"Solomons Nightjar","scientific_name":"Eurostopodus nigripennis","overview":"所罗门毛腿夜鹰（英文名：Solomons Nightjar，学名：Eurostopodus nigripennis），是夜鹰目夜鹰科毛腿夜鹰属的鸟类。主要分布在所罗门群岛的北部与中部，包括布干维尔岛至圣伊莎贝尔岛和新乔治亚岛。这种夜行性鸟类具有大眼睛和极佳的伪装能力，羽毛呈棕色、红褐色和灰色相间的斑驳图案。","appearance":"该鸟体长25-30厘米，羽毛色彩混合了棕色、红褐色和灰色，形成斑点和条纹，喉部有一小块白色斑点，颈部有淡淡的红褐色圈带，初级飞羽外侧有细小白边而非斑点。雌鸟翼部标记偏淡黄色。体型较白喉毛腿夜鹰小，翼展雌鸟平均218-223毫米，明显小于后者平均253.5毫米的翼展长度。","call":"叫声独特，类似斧头击打木头的声音，呈现一系列急促的‘tok-tok-tok’声。","habits":"栖息于沿海地带，从海平面到海拔300米，常见于森林和海滩边的林地。常在沙滩和红树林根部筑巢休息。主要以飞行中的昆虫为食。","breeding":"繁殖季节可能在10月至12月，巢建在离海20-30米的平地，由树叶、沙子和石灰岩珊瑚混杂构成，每窝仅产一枚蛋，蛋色为白色或粉红色，布满斑点。","identification":"与白喉毛腿夜鹰相比，所罗门毛腿夜鹰体型较小，颜色略浅，颈圈更偏棕黄色，初级飞羽有细小白边。与新喀毛腿夜鹰的区别在于翼展更长，背部颜色更深，冠部暗色标记不明显，且有红褐色颈环。","protection":"IUCN：VU（易危）；全球估计数量不足2500只，自1930年代以来在布干维尔岛的记录日益稀少，近年来仅在Tetepare岛有报道。","distribution":"主要分布于北所罗门群岛和中所罗门群岛，包括Bougainville至Isabel和New Georgia群岛。","other":"其叫声类似斧头敲击木头，巢穴受到野猫和火蚁的威胁。"},{"name":"新喀毛腿夜鹰","english_name":"New Caledonian Nightjar","scientific_name":"Eurostopodus exul","overview":"新喀毛腿夜鹰（英文名：New Caledonian Nightjar，学名：Eurostopodus exul），是夜鹰目夜鹰科毛腿夜鹰属的特有种鸟类。仅知于新喀里多尼亚的Grande Terre岛，以单个标本为证，可能已灭绝。","appearance":"体长约26厘米，重约77克。翅膀长度雌鸟可达184毫米。体羽呈淡银灰色，背部有零星的黑褐色斑点和条纹。头部黑色，翼覆羽灰褐，缀以棕色斑点和宽大的黄白色斑。肩羽内侧灰褐，外侧灰白，中央有明显的黑褐色条纹。与所罗门毛腿夜鹰相似的翼部标记，但缺乏颈背的环状带。胸部棕色，带有霜状灰白色和灰褐色的霜饰，喉部有一小块白色斑点。","habits":"栖息于新喀里多尼亚沿海草原植被中，具体生态习性因资料稀缺而未知。","identification":"与白喉毛腿夜鹰和所罗门毛腿夜鹰区别在于较短的翅膀，上体更石白色，冠中部黑色更明显且连续，颈背红色部分极小（虽然某些所罗门毛腿夜鹰个体显示相对较少的红色）。","protection":"IUCN：CR (PE)（极危（可能已灭绝）），可能已灭绝)。仅在新喀里多尼亚EBA有记录，1939年在Mt Panie附近平原采集的唯一标本。1998年的密集调查未能找到该物种。","distribution":"分布于澳新界Grande Terre（新喀里多尼亚），唯一记录来自1939年的标本。"},{"name":"环颈毛腿夜鹰","english_name":"Satanic Nightjar","scientific_name":"Eurostopodus diabolicus","overview":"环颈毛腿夜鹰（英文名：Satanic Nightjar，学名：Eurostopodus diabolicus），是夜鹰目夜鹰科毛腿夜鹰属的鸟类。中型、斑点状、暗褐色的夜鹰，为印度尼西亚苏拉威西岛特有种。该物种由德国自然历史学家Gerd Heinrich于1931年首次发现，以其独特的深色外表和神秘的叫声著称。","appearance":"环颈毛腿夜鹰长约27厘米，具有独特的黑色头部、灰褐色背部、棕色腹部条纹，以及喉咙处的白色至淡黄色领圈。翅膀上有明显的第3和第4外侧初级飞羽上的白色斑点，其下体颜色从棕色到淡黄色，带有条纹，尾巴尖端略微泛黄。雌雄个体在外观上相似，但雄鸟的喉咙环更白，雌鸟的则呈丰富淡黄色。","call":"其叫声包括一系列间隔开的响亮、上升的'fWIP!'音符，有时以紧密的双音符'fWIP-WIK!'形式发出，第二个音符较短且更突然。在休息时，它会发出连续的快速颤音，音调类似双音符。","habits":"栖息于苏拉威西岛的低地和山地雨林，海拔高度在250至2300米之间。偏好边缘生境，如森林边缘、道路和小径旁的开阔空间，以及拥有低矮树冠和棕榈、藤蔓丛的区域。以昆虫为食，主要在黄昏和黎明时沿森林边缘狩猎。","breeding":"繁殖季节至少从3月持续到10月，可能包含两个不同的繁殖季。在地面筑巢，通常选择有少许遮蔽的小型开阔地带，如蕨类和苔藓覆盖的地方。每次产一枚奶油色带淡棕色条纹或斑点的蛋，雏鸟初期呈鹿皮色，逐渐接近成鸟颜色，但标记较少。巢穴期至少31天。","identification":"与毛腿耳夜鹰和苏拉威西夜鹰相比，环颈毛腿夜鹰体型较小，从不高于树冠飞翔，且尾巴上无白色标记。中央苏拉威西的个体尾部和肩部有灰色，胸羽尖端白色且呈椭圆形；而北部岛屿的个体缺乏灰色标记，胸羽不明显。","protection":"IUCN：LC（无危）","distribution":"环颈毛腿夜鹰仅分布于印度尼西亚苏拉威西岛的北部和中部山区。","other":"该物种面临的主要威胁是栖息地丧失，尤其是城市开发、农业、非法伐木和采矿。尽管其适应力强于预期，能在受干扰的环境中生存，但总体数量正在下降。"},{"name":"巴布亚毛腿夜鹰","english_name":"Papuan Nightjar","scientific_name":"Eurostopodus papuensis","overview":"巴布亚毛腿夜鹰（英文名：Papuan Nightjar，学名：Eurostopodus papuensis），是夜鹰目夜鹰科毛腿夜鹰属的鸟类。广泛分布在新几内亚低地森林中的夜行性鸟类。其最显著的特征是喉部有一道独特的白色人字形斑纹。分布于新几内亚及萨拉瓦蒂岛。","appearance":"体长约25.5至27.5厘米，体重约80至81克（雌鸟）。两性相似，上体棕色，饰以灰色、肉桂色和红褐色条纹，头部有宽广的黑褐色条纹，颈背无领状环纹。翼羽棕色，斑点和尖端呈淡褐色和肉桂色。肩羽肉桂色，饰以灰褐色斑点，黑色斑点明显。喉部有大块白色斑块，下体肉桂红褐色，饰以棕色条纹，腹部和胁部变为淡褐色条纹。两性翅膀和尾巴均无白色标记。虹膜深棕色，喙棕色至黑色，腿和脚棕色或黑色。幼鸟与成鸟相似，但通常颜色较浅，头部斑点更重，翼羽无斑点，下体无条纹。","call":"雄鸟的叫声被假定为快速连续的“咕咕咕咕”，持续约7秒。其他叫声包括低沉、粗哑的叽喳声。","habits":"巴布亚毛腿夜鹰在森林上空、林隙和河流上空捕食昆虫。它们栖息在新几内亚的低地森林及其边缘，活动范围包括森林底层的开阔地带。","breeding":"繁殖信息知之甚少，可能在6月至8月间繁殖。筑巢于小片开阔地的灌木丛中，没有真正的巢，卵直接产在裸露的地面上或落叶层上。一窝仅产一枚椭圆形卵，颜色为粉红棕色，表面有大量深浅棕色斑点，底部有灰色斑块，尺寸约为32毫米×23.8至25毫米。孵化似乎主要由雌鸟在白天进行。","identification":"与长尾夜鹰不同，巴布亚毛腿夜鹰翅膀和尾巴上无白色标记。与迁徙的白喉毛腿夜鹰相比，体型较小。阿氏毛腿夜鹰仅在山区森林中发现，而白喉毛腿夜鹰在冬季可能与巴布亚毛腿夜鹰共存，但后者的一级飞羽上有白色。可能出现在相同区域，但其翅膀和尾巴均有白色，整体颜色较浅，叫声也截然不同。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的低地地区，包括萨拉瓦蒂岛（位于四王群岛西北部的新几内亚）。在印度尼西亚的伊里安查亚的基洛斯山脉附近和巴布亚新几内亚的拉凯马库盆地都有规律的记录。"},{"name":"阿氏毛腿夜鹰","english_name":"Archbold's Nightjar","scientific_name":"Eurostopodus archboldi","overview":"阿氏毛腿夜鹰（英文名：Archbold's Nightjar，学名：Eurostopodus archboldi），是夜鹰目夜鹰科毛腿夜鹰属的鸟类。这种夜鹰仅见于新几内亚的高山地带，栖息于亚热带或热带湿润的山地森林，以美国探险家Richard Archbold命名。","appearance":"该夜鹰喉部有一白色人字形标记，翼和尾部无白色斑点。体色和尺寸的详细描述待补充。","call":"其叫声独特，先是一短促单音，随后是两声颤音，第二声下滑，类似“whip！wirrr-weerrr”的声音。","habits":"在森林空地和山地灌木丛上空捕食飞行昆虫，或从栖息处突然出击捕食。偏好于高海拔环境。","breeding":"繁殖习性细节待补充。","identification":"与低地巴布亚夜鹰相似，但不会在同一生境中共存，可通过叫声和生境区分。","protection":"IUCN状态未提供。","distribution":"分布于新几内亚的山区，具体包括新几内亚的高地。"},{"name":"马来毛腿夜鹰","english_name":"Malaysian Eared Nightjar","scientific_name":"Lyncornis temminckii","overview":"马来毛腿夜鹰（英文名：Malaysian Eared Nightjar，学名：Lyncornis temminckii），是夜鹰目夜鹰科大毛腿夜鹰属的鸟类。其别称来源于头部两侧难以察觉的‘耳朵’状突起。具有中等体型，长颈短头，脸部颜色较深，喉部有明显的白色斑纹，尤其在飞行时更为显著。分布于东南亚，包括泰国南部、马来西亚半岛、苏门答腊、尼亚斯、邦加和勿里洞岛，以及婆罗洲。","appearance":"马来毛腿夜鹰长约25至28厘米，雌雄外观相似。头部有独特的‘耳朵’，背部呈棕色并饰以淡黄色、肉桂色斑点，黑色斑块点缀于冠顶。颈部有一圈细薄的淡黄色项圈，翅膀覆羽色彩斑斓，包括棕色、淡黄色、乳白色、黄褐色和肉桂色。肩羽带有棕色斑点和黑色斑块。喉咙两侧有白色斑块，下腹部呈淡黄色，隐约可见棕色条纹。成年个体翅膀和尾巴上无白色标记。虹膜深棕色，喙角质色带暗尖，腿脚深棕色。幼鸟与成鸟相仿，但上体更偏肉桂色或黄褐色，斑点较少，下体的淡黄色部分较少。","call":"马来毛腿夜鹰在飞行时会发出类似‘嘟，威欧’的口哨声。","habits":"马来毛腿夜鹰广泛栖息于从低地雨林到开阔灌木林和农田的各种生境。它在多种环境中飞行，展现其适应力。","breeding":"关于马来毛腿夜鹰的繁殖信息尚不详尽。","identification":"马来毛腿夜鹰与毛腿耳夜鹰非常相似，但在良好光照下，观察其较为柔和的冠顶对比和整体更深的颜色可作区分。","protection":"IUCN：LC（无危）","distribution":"马来毛腿夜鹰分布于极南泰国，贯穿马来西亚半岛，至苏门答腊（含尼亚斯、邦加和勿里洞岛）及婆罗洲。"},{"name":"毛腿耳夜鹰","english_name":"Great Eared Nightjar","scientific_name":"Lyncornis macrotis","overview":"毛腿耳夜鹰（英文名：Great Eared Nightjar，学名：Lyncornis macrotis），是夜鹰目夜鹰科大毛腿夜鹰属的鸟类。这种独特的猫头鹰外观的夜鹰拥有明显的耳朵，站立时姿态突出，与多数夜鹰区别明显。其羽毛由复杂的棕色调构成，能够完美融入背景，飞行时展现出长尾。分布于西南印度和东南亚部分地区，栖息于森林、森林边缘、田野和平原有树覆盖的地带。","appearance":"体型长度31至40厘米，体重125至151克。雄雌相似，具有显著的‘耳朵’；背部为褐色，点缀着斑点和条纹，有奶油色或淡黄色颈环；翅膀覆羽呈棕色，点缀着淡黄色和肉桂色；肩羽棕色，饰有深褐色斑点；喉部下方有大的白色斑块，偶尔带有淡黄色；下体淡黄色，模糊的棕色条纹；两性翅膀和尾巴上均无白色标记。虹膜深棕色，喙棕色，腿和脚肉棕色。亚种在大小和颜色上有差异，但所有亚种的颜色变化极大。","call":"叫声为口哨式的“put, wee-oo”或“put, weeow-oo”，通常在飞行中或从栖木上发出。","habits":"主要栖息于原始森林（常沿河流）、次生林、边缘和空地、次生植被、灌木地和林木草原。也出现在更开阔的地区。一般在海拔0至1000米间被记录，但在苏拉威西岛可达1750米。大多数种群似乎定居，但cerviniceps亚种在印度东北部局部迁徙，8月到达，常见至9月，雨季之后消失。食物主要包括飞蛾、甲虫、蝽和白蚁。在飞行中捕食，猎食于森林空地、邻近草地和居民区附近。","breeding":"繁殖季节在南印度为1月至5月（主要是2月至3月），马来半岛为1月至5月；在北苏拉威西岛，10月发现带卵的巢，物种在3月至5月特别鸣叫频繁；在佩伦岛（班盖群岛）10月初见到幼鸟。巢址通常位于轻度林木覆盖国家的茂密灌木或竹丛下；无巢，蛋直接产在枯叶或裸露地面。每窝产1枚卵，椭圆形，乳白色或深鲑鱼粉红色，浅灰色和红色大理石纹和斑点，尤其在钝端。","identification":"与其他夜鹰相比，毛腿耳夜鹰最显著的特点是其明显的耳朵和站立时的挺立姿态，以及飞行时展现的长尾。此外，它具有独特的白色喉部斑块，但翅膀和尾巴上无白色标记。","protection":"IUCN：LC（无危）","distribution":"分布于南亚和东南亚，包括印度西部山脉、斯里兰卡、孟加拉国、印度尼西亚、老挝、马来西亚、缅甸、菲律宾、泰国和越南。在中国大陆，云南西部有记录。在苏拉威西岛也有分布。","other":"毛腿耳夜鹰在广泛的范围内出现在多个保护区，例如印度南部的Periyar国家公园、泰国的Khao Yai和Kaeng Krachan国家公园以及越南南部的Nam Bai Cat Tien国家公园。"},{"name":"领夜鹰","english_name":"Collared Nightjar","scientific_name":"Gactornis enarratus","overview":"领夜鹰（英文名：Collared Nightjar，学名：Gactornis enarratus），是夜鹰目夜鹰科领夜鹰属的鸟类。其最显著的外部特征是颈部的红色环状羽毛。该物种特有于马达加斯加，主要栖息于岛上的雨林中。","appearance":"领夜鹰长约24厘米，体重约54克（雌鸟数据）。雄雌相似，上体灰褐色，布满深褐色斑点，边缘呈栗色；颈后有宽阔的红色环状羽毛，上方有一条细而清晰的淡色带；翅膀覆羽灰褐，布满深褐色斑点，边缘为栗色或淡色；肩羽灰褐，布满深褐色斑点，边缘栗色；下喉部有淡色带环绕；下体一般呈棕色，布满深褐色斑点，边缘栗色，腹部和侧腹部分斑点减少，更显条纹。两性翅膀均无白色标记，尾羽最外侧一或两根有狭窄的白色尖端。虹膜深褐色，喙黑色或粉灰色，尖端黑色，腿和脚暗褐色或粉灰色。相较于马岛夜鹰，领夜鹰颜色更深，图案更简单，通常没有或仅有不明显的淡色颈环；后者雄鸟在外侧四枚初级飞羽上有白色斑点，尾羽最外侧两根有宽大的白色尖端。幼鸟比成鸟更淡，更偏米黄色，颈后有深色环，翅膀覆羽上有大块深色斑点。","call":"据观察，领夜鹰似乎完全无声，这一点对于夜鹰家族的成员来说颇为奇特。","habits":"领夜鹰主要栖息于马达加斯加东北部和东部的雨林中，偶尔出现在干燥森林的局部地区。白天通常在森林地面休息，常位于天堂树下。夜晚活动，但其具体生活习性尚待更多研究。","breeding":"关于领夜鹰的繁殖信息有限，需进一步研究以了解其繁殖周期、求偶、筑巢、交配、产卵、孵化和育雏的详细过程。","identification":"领夜鹰与马岛夜鹰的区别在于前者具有红色颈环；飞行时，前者翼部无白色标记。幼鸟的颜色比成鸟更浅，更偏米黄色。","protection":"IUCN：LC（无危）","distribution":"领夜鹰的分布局限于非洲的马达加斯加岛，包括西北部和东部的区域。","other":"领夜鹰的发现和观察往往依赖于当地向导的帮助，特别是在白天它们睡觉的时候。"},{"name":"纳昆达夜鹰","english_name":"Nacunda Nighthawk","scientific_name":"Chordeiles nacunda","overview":"纳昆达夜鹰（英文名：Nacunda Nighthawk，学名：Chordeiles nacunda），是夜鹰目夜鹰科美洲夜鹰属的鸟类。是夜鹰科中体型最大的物种之一，不仅在新热带区，即使在全球范围内也是体型较大的夜鹰种类。以部分日行性的习性著称，不同于一般夜鹰，常在地面活动，拥有较长的跗跖。分布于南美的广阔区域，包括阿根廷、玻利维亚、巴西等国，偏好草原、灌木丛、沼泽和森林边缘生境。","appearance":"体型大，尾部短，翅膀长而圆。体羽沙棕色，点缀黑色斑点，与白色喉部和腹部形成鲜明对比。飞行时，可见白色翼下，黑色外翼和明显的白色翼斑。雄鸟尾端具白色尖端。雌雄异形，雌鸟翼斑较小，尾部通常无白色尖端。成年雄鸟头部、颈背呈棕色，点缀淡色斑点，背部、臀部及上覆羽呈棕色，有黑色斑点。翅膀覆盖羽和肩羽棕色，密布暗色斑点，初级飞羽棕色，有白色斑点。雌鸟与雄鸟相似，但翼斑更小，尾部白色尖端缺失或较窄。","habits":"栖息于草甸、灌木丛、沼泽和森林边缘地带，有时集结成大群。具有日行性习性，善于空中捕食，但也会花费相当时间在地面活动。其长的跗跖使得它更可能站立于地面而非仅仅停留在表面。","identification":"体型远大于其他新热带区夜鹰，下方羽毛大量白色，易于识别。与沙色夜鹰相比，体型较小，翼尖更尖，无白色翼带，上翼面有明显白色斑纹。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美中部和东部，包括阿根廷、玻利维亚、巴西、智利、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、巴拉圭、秘鲁、苏里南、特立尼达和多巴哥、乌拉圭、委内瑞拉等地，但在亚马逊西部地区较为少见。"},{"name":"小白喉夜鹰","english_name":"Least Nighthawk","scientific_name":"Chordeiles pusillus","overview":"小白喉夜鹰（英文名：Least Nighthawk，学名：Chordeiles pusillus），是夜鹰目夜鹰科美洲夜鹰属的鸟类。分布于南美洲北部和东部的草原和干燥森林地带，以昆虫为食。其显著特征为翼缘的淡色边缘，体型小巧，常在黄昏时成群出现，活跃于地面或低矮灌木丛中。","appearance":"全长约15至19厘米，是Caprimulgidae家族中较小的成员。上体呈棕色，点缀着灰色、赤褐色和浅黄色斑点；喉部有一窄白斑或两侧各有一小白斑；下体白色或浅黄色，带有棕色条纹。飞行时，最外侧四根初级飞羽上的白色带纹尤为明显。雄鸟翼尖有宽阔的白色末端，而雌鸟的翼缘较窄且偏黄褐色。","call":"发出低沉的churr声和弱鼻音的beep声或week声；地面或灌木上唱歌时，会发出快速的cur-cur-cur-curry或chu-chu-chu-chu-chuEE声。","habits":"栖息于开阔的草原和亚热带草地，包括cerrado和caatinga。活动高度从海平面到大约1000米。它是一种空中捕食昆虫的猎手，黎明和黄昏时分靠近地面狩猎，飞行灵活且方向多变。单独、成对或小群活动。","breeding":"关于繁殖生态学知之甚少。产卵季节在不同地区有所变化，通常在地上直接产一卵。","identification":"与小灰眉夜鹰相似，但体型更小，翼缘白色，外侧主翼羽的白色带纹更接近翼尖。巴伊亚夜鹰和斑尾夜鹰也有类似的形状和颜色模式，但前者胸部深栗色，后者为深棕色，带有红褐色和浅黄色斑点。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美北部和东部，包括委内瑞拉南部、圭亚那和巴西东北部的草原，以及巴西东南部的cerrados。在哥伦比亚东部低地和其他巴西东部地区也有少量分布。","other":"存在五个亚种，主要基于整体羽毛色彩差异。"},{"name":"沙色夜鹰","english_name":"Sand-colored Nighthawk","scientific_name":"Chordeiles rupestris","overview":"沙色夜鹰（英文名：Sand-colored Nighthawk，学名：Chordeiles rupestris），是夜鹰目夜鹰科美洲夜鹰属的鸟类。主要分布在南美的亚马逊雨林区域，以河流边缘的沙滩和裸露树枝为栖息地。这种夜鹰体型中等，长约20.5至22厘米，羽毛呈淡灰褐色，具有暗棕色条纹和斑点，腹部白色，翅膀下方亦为白色。常以群体形式活动，最多可达200只，白天在河滩上休息，黄昏时分活跃觅食。","appearance":"沙色夜鹰拥有长而尖的翅膀和相对长的尾巴，上体颜色为淡灰褐色，带有深棕色的条纹、斑点。下体主要是白色到灰白色，带有少许棕色斑点，尤其是在胸部。翼下和腹部白色，翼上有明显的白色横纹。尾部两侧有大面积白色，中央尾羽淡灰褐色，带有窄的棕色条纹。雄雌相似，但雌鸟的胸部有更多斑点，尾端为棕色而非黑色。成年个体的虹膜为深棕色，喙为黑色至灰棕色，脚为棕色至灰棕色。","call":"沙色夜鹰通常很少鸣唱，但在地面时会发出咕噜声，其间夹杂着清喉音和响亮的grawh音。当追逐其他鸟类或保卫巢穴时，还会发出一系列其他声音。","habits":"沙色夜鹰是黄昏和夜间活动的鸟类，白天在河岛和沙洲上群居。在高水位期间，它们会在水边的树上栖息。黄昏时分开始活跃觅食，飞行方式不太像其他夜鹰那样飘忽不定，反而有一种机械感，类似燕鸥。食物以昆虫为主，飞行中捕食。","breeding":"繁殖季节从5月至8月在东南秘鲁，从6月至9月在巴西中部，但其余范围未明确。它们在松散的群体中筑巢，通常靠近南美白额燕鸥、大嘴燕鸥和黑燕鸥的巢穴附近。在沙洲上的浅坑中产两枚卵。","identification":"与纳昆达夜鹰相比，沙色夜鹰体型较小，翼尖较窄，翼上有白色横带，与黑色翼尖形成鲜明对比，而不是大片的白色楔形。此外，它是唯一经常在开阔沙洲上群集栖息的夜鹰种类。","protection":"IUCN：LC（无危）","distribution":"沙色夜鹰广泛分布于亚马逊盆地内部，包括哥伦比亚、委内瑞拉、秘鲁、巴西、厄瓜多尔和玻利维亚的河流走廊区域。在南美亚马逊雨林中，它主要沿水道、牛轭湖和草地空地如机场跑道等生境活动。","other":"沙色夜鹰属于较为独特的夜鹰种类，它部分时间在日间活动，且倾向于群体生活，这在多数夜鹰物种中并不常见。"},{"name":"小灰眉夜鹰","english_name":"Lesser Nighthawk","scientific_name":"Chordeiles acutipennis","overview":"小灰眉夜鹰（英文名：Lesser Nighthawk，学名：Chordeiles acutipennis），是夜鹰目夜鹰科美洲夜鹰属的鸟类。分布于北美西南部至南美北部的夜行性鸟类，偏好沙漠和干燥的草原环境。其羽毛色彩以棕色和灰色为主，带有白色新月状的翼斑和喉部标记，使它在日间休息时能很好地融入沙漠地面。这种鸟体型略小于普通夜鹰，尾部稍圆，色彩偏金色，且飞行时白色的翼斑位置更接近翼尖。","appearance":"小灰眉夜鹰体长约20-23厘米，翼展约55厘米，体重约45克。全身羽毛呈斑驳的棕、灰、黑色调，上体以灰褐色为主，缀以淡黄色、棕色和黑色斑点；下体色浅，有深色条纹。成年雄鸟喉部有显著的白色V形斑，雌鸟相似但体型较小，白色翼斑更淡，无尾端白色横带。幼鸟整体颜色较浅，翼斑和尾带更小。","call":"小灰眉夜鹰以其独特的蟾蜍般的颤音闻名，通常在黄昏和黎明时分发出低沉的咕噜声，持续时间可达数分钟。","habits":"这种夜行性的鸟儿主要在黄昏和清晨活动，低空飞行捕捉昆虫。它们在白天通常静静地栖息于地面，依靠伪装与周围环境融为一体。小灰眉夜鹰会单独或成对觅食，偶尔也会形成较大的群落，尤其在特定季节。","breeding":"繁殖期，雄鸟会在空中进行复杂的求偶表演，同时发出颤音。雌鸟在地上产卵，不筑巢，每次产2枚蛋，由雌鸟独自孵化，雄鸟则负责喂养幼鸟，提供反刍的昆虫。","identification":"与美洲夜鹰相比，小灰眉夜鹰的翼斑位置更靠近翼尖，色彩更偏金色，体型更小，且飞行时的翼拍更为浅缓。通过声音辨识是最简单的方法，因为两者的叫声截然不同。","protection":"IUCN：LC（无危）","distribution":"小灰眉夜鹰分布于北美西南部至南美北部，包括美国西南部至阿根廷北部。夏季繁殖于干旱和半干旱地带，冬季迁徙至中美洲南部和南美洲北部。","other":"小灰眉夜鹰具有独特的生理适应性，能耐受极端温度，特别是在炎热环境中表现出有效的体温调节能力。"},{"name":"美洲夜鹰","english_name":"Common Nighthawk","scientific_name":"Chordeiles minor","overview":"美洲夜鹰（英文名：Common Nighthawk，学名：Chordeiles minor），是夜鹰目夜鹰科美洲夜鹰属的鸟类。又名bullbat，这种中等体型的夜行性鸟类以它独特的叫声揭示其存在。羽毛呈灰、棕、黑色，有着复杂的图案，日间很难用肉眼察觉。以灵动而不可预测的飞行最为显著，拥有小喙却配以巨大的口。雄鸟常群聚栖息，但总体上是独居的，领地大小有变异性。","appearance":"美洲夜鹰体长22至25厘米，翼展51至61厘米，体重介于55至98克之间。头部扁平宽大，眼睛大，喙小，无颊须，翅膀长而尖细，休息时略超出叉状尾巴。腹部和侧面有明显的条纹，翅膀上有白色斑块，雄鸟的尾巴有白色环带。羽毛颜色随地理位置变化，东部个体较棕色，北方大平原的则更偏银灰色。","call":"最显著的声音是一种鼻音的“peent”声，尤其在黄昏后30至45分钟达到高峰。雄鸟在求偶时会发出类似呱呱声的叫声，同时表演快速俯冲，产生轰鸣。","habits":"美洲夜鹰主要在森林、沙漠、草原、海滩、城市和草地栖息，海拔高度从海平面到3000米。它们倾向于在边缘和早期演替生境中筑巢，这使它们成为少数能在烧毁或清理过的森林地带生活的鸟类之一。它们被昆虫吸引进入城市地区。食物的可获得性是决定栖息地选择的关键因素。","breeding":"繁殖季节为3月中旬至10月初，通常每年只育一窝，有时会有第二次繁殖。在岩石露头、林地空地、烧毁区域或沙砾地面上筑巢。雌鸟选择巢址并主要负责孵卵，雄鸟偶尔参与。孵化期约为18天。雏鸟在孵化前的几小时就能听到叫声，孵化后立即活跃，眼睛半开或全开，覆盖着柔软的绒毛。幼鸟在第18天初次飞行，30天左右能熟练飞行。","identification":"与小灰眉夜鹰和安岛夜鹰相似，但可通过翼上的白色斑块位置、尾巴的白色横带和叫声进行区分。小灰眉夜鹰的翼斑更靠近初级飞羽尖端，而安岛夜鹰只能通过声音或手握检查来确定。","protection":"IUCN：LC（无危）","distribution":"繁殖区广泛分布于北美洲和中美洲，非繁殖期则迁徙至南美洲，主要在阿根廷过冬。","other":"曾经在城市中的平石屋顶筑巢，但由于屋顶建设的变化，这一习惯正在减少。"},{"name":"安岛夜鹰","english_name":"Antillean Nighthawk","scientific_name":"Chordeiles gundlachii","overview":"安岛夜鹰（英文名：Antillean Nighthawk，学名：Chordeiles gundlachii），是夜鹰目夜鹰科美洲夜鹰属的鸟类。以独特的棕色和灰色交织图案的长翼为显著特征。这种夜行性鸟类主要分布在加勒比海地区，包括巴哈马群岛、佛罗里达南部、古巴、多米尼加共和国和海地、牙买加、波多黎各以及美属维尔京群岛。","appearance":"安岛夜鹰是一种中等体型的夜鹰，长度约21.5厘米，体重约50克。其翅膀尖长，尾巴中等长度且呈凹形，上体由棕色、黑色、灰色和米色斑纹构成，形成隐蔽的羽毛模式。雄鸟特征包括初级飞羽上的白色带、喉咙上的白色斑块，以及除中央羽毛外的尾部白色次端带。雌鸟相似，但喉咙斑块呈浅黄色，整体羽毛色彩更温暖，翼斑较小，尾部白色带缺失。幼鸟类似于雌鸟，但喉咙斑块不明显。成年鸟有灰和赤褐色两种形态。","call":"安岛夜鹰的叫声为一系列快速而机械的音节，通常被描述为“drik-rik-rik-rik”。这与美洲夜鹰单一音节的叫声形成鲜明对比。","habits":"安岛夜鹰偏好开阔地带，如草地、裸露地面和灌木丛的混合环境。它们在黄昏和黎明时分活跃，也会在阴天全天出现。它们利用巨大的嘴在空中捕捉飞行中的昆虫，有时会形成大型觅食群。","breeding":"繁殖季节，安岛夜鹰通常在开阔地带筑巢于裸露的地面上，有时在树桩或砾石屋顶上。雌鸟承担大部分孵化工作，持续约20天。幼鸟在大约20天大时离巢。","identification":"安岛夜鹰与美洲夜鹰非常相似，但可以通过叫声和坐立时翅膀末端更圆钝、较短的特点来区分。此外，雌性安岛夜鹰的喉咙斑块为浅黄色，而美洲夜鹰的喉咙斑块为白色。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美的南部佛罗里达、巴哈马群岛、古巴、多米尼加共和国、海地、牙买加、波多黎各以及美属维尔京群岛。","other":"安岛夜鹰直到1982年才被确认为独立物种，此前被认为是美洲夜鹰的一个亚种。"},{"name":"半领夜鹰","english_name":"Short-tailed Nighthawk","scientific_name":"Lurocalis semitorquatus","overview":"半领夜鹰（英文名：Short-tailed Nighthawk，学名：Lurocalis semitorquatus），是夜鹰目夜鹰科半领夜鹰属的鸟类。广泛分布于中美洲和南美洲，从墨西哥至特立尼达和多巴哥，以及除智利和乌拉圭外的南美大陆各国。其独特的短尾是显著的外部特征。","appearance":"半领夜鹰体型较大，长度约19至21厘米，尾部异常短小。上体呈深棕色至黑色，点缀着赤褐色和淡黄色斑点。翅膀深棕色，无醒目的白色标记，与大多数夜鹰不同。尾羽棕色，带有土黄色或灰褐色横纹，末端有一窄带淡色。喉部白色，胸腹部以暗棕色为主，下胸至腹部呈淡黄色，带有棕色条纹。雌雄相似，亚种间在大小和斑纹的强度上略有差异。","call":"其最常听到的叫声随亚种而异，描述为连续但间隔的\"ewIT ... ewIT ... ewIT...\"或尖锐、略带液体感的\"g'wik\"或\"gweek\"声，无论是在栖息还是飞行中都能发出。","habits":"主要栖息于低地常绿森林，也可见于开阔地带，如林间空地、河流边缘、旧可可种植园和中龄次生林。飞行快速且不规则，类似蝙蝠。以昆虫为食，包括甲虫和真蝽。通常单独或成对出现，偶尔结成小群。","breeding":"半领夜鹰在树上筑巢，是夜鹰科中唯一已知在树上繁殖的种类，它将单个蛋产于大水平枝上，不使用额外材料。繁殖行为和季节分布尚需进一步研究。","identification":"与棕腹夜鹰大小和形状相近，但棕腹夜鹰栖息海拔更高，腹部缺乏黑条纹，且叫声不同。","protection":"IUCN：LC（无危）","distribution":"广泛分布于中美洲和南美洲北部，包括墨西哥、中美洲国家（除萨尔瓦多）、特立尼达和多巴哥，以及除智利和乌拉圭外的南美大陆各国。"},{"name":"棕腹夜鹰","english_name":"Rufous-bellied Nighthawk","scientific_name":"Lurocalis rufiventris","overview":"棕腹夜鹰（英文名：Rufous-bellied Nighthawk，学名：Lurocalis rufiventris），是夜鹰目夜鹰科半领夜鹰属的鸟类。分布于南美洲的委内瑞拉至玻利维亚一带的安第斯山脉云雾林中，以单个或成对出现，通常在黄昏时活跃，昼间栖息于树干上。其特征为暗褐色上部与翅膀，缀以红褐色和淡黄色斑点，白色喉部，以及红褐色腹部。","appearance":"棕腹夜鹰体长23至25厘米，上身和翅膀呈深褐色，点缀着红褐色和淡黄色的斑点与细纹。尾巴为棕色，带有红褐色或灰褐色条纹和浅色尖端。头部颜色较深，喉部为白色，胸部呈暗褐色，而腹部和两胁为红褐色。性成熟个体与幼鸟外观相似，但幼鸟的上部和翅膀覆羽散布着棕色和白色的羽毛，带有黑色和红褐色的斑点。","call":"发出一连串快速递降音调的鸣叫，如“kwa-kwa-kwa-kwa-ko”，在飞行或栖息时皆能听到，另有低沉的‘pow’声、上升的咕哝声和低吼。","habits":"棕腹夜鹰偏好生活在湿润的高山云雾森林，海拔高度介于1500至3450米之间。它们主要在黄昏时活动，白天则沿着树枝休息。飞行捕食昆虫，具体饮食尚未详细研究。","breeding":"关于繁殖生态学的研究有限，推测与近缘种半领夜鹰相似，会在水平树枝上直接产下一枚卵。具体的繁殖周期、筑巢、交配、孵化和育雏细节尚待观察。","identification":"与半领夜鹰最为相似，但体型更大，叫声不同，且红褐色腹部无横纹，这是区分两者的显著特征。分布上，半领夜鹰局限于低地，而棕腹夜鹰则位于较高海拔的安第斯山脉。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉的西部委内瑞拉、哥伦比亚东部和中部、厄瓜多尔西部大部分地区、以及通过厄瓜多尔和秘鲁到玻利维亚的东侧安第斯山脉。","other":"曾被视为半领夜鹰的亚种，自1990年代后期开始，再次被确认为独立物种。"},{"name":"斑尾夜鹰","english_name":"Band-tailed Nighthawk","scientific_name":"Nyctiprogne leucopyga","overview":"斑尾夜鹰（英文名：Band-tailed Nighthawk，学名：Nyctiprogne leucopyga）是夜鹰目夜鹰科斑尾夜鹰属的小型、暗色鸟类。主要栖息于森林与草原地带，通常靠近水源。其分布于南美洲亚马逊雨林区域，从委内瑞拉南部至玻利维亚和巴西中部。具有独特的蛙鸣般的叫声，繁殖季节通常从7月持续到10月。斑尾夜鹰的繁殖策略独特，直接在地面隐蔽处产卵，而非筑巢。","appearance":"斑尾夜鹰体型小而暗，上身呈棕色，带有淡棕色、肉桂色斑点。头部、背部、臀部及尾羽覆片颜色相近，尾羽棕色，中央两对尾羽（R2-R1）有隐约的灰褐色条纹，边缘带有赭色。最外侧三对尾羽（R5-R3）有一白色带状斑，宽度约10毫米，位于尾羽中段。翅膀长而尖，无白色翼斑。成年雄雌相似，均无喙须，尾部略呈凹陷状，中央尾羽比最外侧尾羽短约5毫米。嘴黑色，脚趾黑灰色或粉棕色，虹膜深棕色。","call":"斑尾夜鹰的叫声类似青蛙的叫声，尤其在繁殖季节的夜晚最为常见。","habits":"斑尾夜鹰主要栖息于森林和草原地带，靠近水源，以空中飞行的节肢动物为食，有时直接从植被上捕获猎物。它们的飞行特征为连续的飞行模式，常在黄昏或黎明时分低飞于水面之上，偶尔会形成较大的群体。","breeding":"斑尾夜鹰的繁殖期从7月至10月，它们采取了一种特殊的繁殖策略，即直接在地面隐蔽处产卵，而非建造传统意义上的巢穴。","identification":"与其他夜鹰相比，斑尾夜鹰最显著的特点是尾部的白色横带，以及缺乏翅膀上的白色标记。它比Lurocalis属的夜鹰更小，尾巴更长，与巴伊亚夜鹰没有地理重叠。","protection":"IUCN：LC（无危）","distribution":"斑尾夜鹰分布于南美洲亚马逊河流域，包括巴西、玻利维亚、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、巴拉圭、秘鲁和委内瑞拉。"},{"name":"巴伊亚夜鹰","english_name":"Plain-tailed Nighthawk","scientific_name":"Nyctiprogne vielliardi","overview":"巴伊亚夜鹰（英文名：Plain-tailed Nighthawk，学名：Nyctiprogne vielliardi），是夜鹰目夜鹰科斑尾夜鹰属的独特鸟类，以尾部无明显横带而得名。亦被称为巴伊亚夜鹰或卡廷加夜鹰，尽管其分布不仅限于特定区域。分布于巴西东部，偏好干燥的灌木草原生境。","appearance":"成年巴伊亚夜鹰长约17.5厘米，上体呈深栗色，头部宽条纹为黑褐色；翼羽覆羽为深栗色，有黑褐色横斑；肩羽边缘为栗棕色；喉部无白色斑点；下体为暗栗棕色，饰有淡黄色斑点和条纹，腹部和两胁变为白色，带有深栗色条纹；翅膀和尾巴无白色标记；虹膜为黄褐色，喙可能为黑色，腿和脚为黄褐色。幼鸟比成年雄鸟更浅黄，头上有黑栗色斑点，背部和臀部有深色纵纹，下体颜色更白；虹膜为栗棕色，跗跖为栗棕色。","call":"鸣唱为一系列柔和、悦耳的双音节\"whuip-purr\"声，重复不断。飞行时发出的叫声为单调的\"whip\"声。","habits":"栖息于河流沿岸的卡廷加灌木林，特别是在有沙丘和岩石露头的地方。可能为留鸟，但季节性迁徙的可能性存在。以昆虫为食，捕食行为类似于斑尾夜鹰，成群的150至200只个体在河面上方约1至10米处飞翔和滑翔。","breeding":"已知唯一的巢穴发现于1998年11月在Mocambinho，位于人类足迹凹陷的人造砂坑中，坑长约15米，宽2米，深2.5米；巢靠近坑边，距离一株小植物约1米。产卵数为2枚粉红色的蛋。关于繁殖的更多信息尚不可得。","identification":"巴伊亚夜鹰与带尾夜鹰的主要区别在于尾部无白色横带，且下体具有独特的条纹和斑点。","protection":"IUCN：LC（无危）。然而，由于其分布范围有限、稀少且零散的栖息地，可能更适合作为Vulnerable（易危）评估。在巴西，目前不被视为国家保护关注物种。","distribution":"分布于巴西东部，具体而言是在圣弗朗西斯科河及其邻近支流的巴伊亚和米纳斯吉拉斯州，位于巴西中部。","other":"巴伊亚夜鹰的科学描述相对较新，对其生态和行为的研究仍处于初步阶段。"},{"name":"暗色夜鹰","english_name":"Blackish Nightjar","scientific_name":"Nyctipolus nigrescens","overview":"暗色夜鹰（英文名：Blackish Nightjar，学名：Nyctipolus nigrescens），是夜鹰目夜鹰科暗色夜鹰属的鸟类。体型较小、羽色偏黑的夜鹰科鸟类，其羽色以黑色为主，提供了极佳的伪装效果。偏好栖息于森林边缘的花岗岩裸露处，使得它比许多新热带区的夜鹰更易被观察到。分布范围包括哥伦比亚东部至亚马逊巴西，南至委内瑞拉南部、圭亚那及玻利维亚，海拔高度从海平面至约1200米。由于数量丰富，其繁殖生态比许多新热带区夜鹰了解得更为详尽。","appearance":"暗色夜鹰体型小巧，尾部较短，全身羽毛呈深黑色，密集地布满微小的白色、灰色和淡褐色斑点。喉咙下部两侧有狭窄的白色条纹。雄鸟个体在外侧三根初级飞羽上有小白点，形成展翅时的小白带，尾羽末端有窄白边；而雌鸟则无翅膀和尾巴上的白色标记。雏鸟孵化时覆盖着灰色绒毛。","call":"黎明和黄昏时发出沙哑的‘peer！’歌声和‘pip’叫声，这是最常听到的声音。","habits":"暗色夜鹰栖息于低地热带雨林，偏好岩石斜坡和森林边缘。活动时间主要在黄昏至黎明，飞行捕食昆虫，白天则在岩石或倒木上休息。","breeding":"繁殖季节通常在干燥季节的8月至11月间。雄鸟通过竖起尾巴展示白色标记吸引雌鸟。每次产一枚蛋，通常在裸露岩石的凹陷处，偶尔也在光秃的沙地或土壤上筑巢，有时会形成小型松散的群落。","identification":"与其他夜鹰相比，暗色夜鹰体型较小，羽色更暗。与委内瑞拉夜鹰相似，但后者体型略大，羽色更黑，雄鸟翼盖上有显著的白色斑点，且分布于较高海拔。与斑翅夜鹰（ roraimae）的区别在于体型较小，两性均无红色或黄褐色颈背环，雄鸟的白色翼带更大，尾羽末端的白色部分也更大。","protection":"IUCN：LC（无危）","distribution":"分布于亚马逊雨林地区，具体而言，从哥伦比亚东部横跨大部分亚马逊巴西，北至委内瑞拉南部和圭亚那，南至玻利维亚，东至巴西东北部和北中部。"},{"name":"侏夜鹰","english_name":"Pygmy Nightjar","scientific_name":"Nyctipolus hirundinaceus","overview":"侏夜鹰（英文名：Pygmy Nightjar，学名：Nyctipolus hirundinaceus），是夜鹰目夜鹰科暗色夜鹰属的小型鸟类。体型小巧，具有明显的白色喉部斑块。分布于巴西东北部，自北至南，覆盖了从北部Ceará到Espírito Santo和Minas Gerais的广阔区域。根据三个不同的亚种，其色泽由北部最淡到南部最深渐变。目前，侏夜鹰被列为IUCN的无危级别。","appearance":"侏夜鹰体型非常小，长度约16至20厘米，雄鸟上体呈灰褐色，密布灰色和肉桂色斑点，具白色喉部条纹，胸部宽阔的肉桂色带，下体为棕色，腹部和两胁为肉桂色，带有棕色条纹。雌鸟外观相似，但颜色较浅，尾部无白色斑点。雄鸟尾羽末端有白色斑块，翅膀上有白色条纹。","call":"其鸣声为短促的单音哨声，常以快速连续的3至4个'wha'音开始，随后发出'wheeo'声。","habits":"栖息于干燥的灌木丛和落叶森林环境，偏好含砾石或岩石的地面。昼间通常单独休息，黄昏至黎明期间活跃，通过从地面起飞捕捉昆虫后返回原处的方式觅食。","breeding":"繁殖季节在雨季，即11月至次年5月，每窝产一枚蛋，直接放置在裸露的地面上。雌鸟白天照料巢穴，雄鸟夜间接手。面对威胁时，两性均会展示分散注意力的行为。","identification":"与小夜鹰的区别在于后者具有肉桂色颈环、更宽的苍白眉线和翅膀及肩部更为对比的图案。与小白喉夜鹰相比，后者通常颜色更深，喉部白色斑块较小，下体颜色更浅，翼尖更尖锐，尾巴略微分叉。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东北部，涵盖Piauí、Bahia、Alagoas、Ceará、Minas Gerais和Espírito Santo等地。"},{"name":"帕拉夜鹰","english_name":"Pauraque","scientific_name":"Nyctidromus albicollis","overview":"帕拉夜鹰（英文名：Pauraque，学名：Nyctidromus albicollis），是夜鹰目夜鹰科帕拉夜鹰属的鸟类。中等体型的夜鹰，广泛分布于中美洲和南美洲的热带和亚热带地区，部分群体在北美的南部得克萨斯州有分布。以独特的‘谁-r-you’鸣叫而知名，这一名称可能源自其哀嚎般的叫声。","appearance":"成年帕拉夜鹰体长约22至28厘米，有灰褐色和红褐色两种色型，体羽呈斑驳状，具有长尾和宽圆的翅膀。雄性帕拉夜鹰的翼尖有白色条带，外侧尾羽主要为白色；雌鸟的翼带较窄，外侧尾部的白色部分较为有限。它们的面部有对比明显的淡色眼环和面部条纹，与红色的脸颊形成鲜明对比。","call":"雄性帕拉夜鹰的鸣声变化多端，包括类似‘who-r-you’的哨音、柔和的‘puk puk’声和在求偶飞行中发出的‘whip’声。雌鸟的叫声则是一连串快速的‘whip’声。","habits":"帕拉夜鹰栖息于开放的林地/草地环境，也可见于灌木丛和农田。它们更倾向于陆生，若受到惊扰，有时会选择奔跑而非飞行，常在道路上休息。它们偏好混合型栖息地，白天藏匿于茂密植被中，夜间在开阔地带狩猎昆虫。","breeding":"繁殖季节，帕拉夜鹰通常会在裸露地面或落叶层上产下两枚粉红色的椭圆形蛋，有时仅产一枚。它们不筑巢，雌雄共同承担孵卵职责。","identification":"与其他夜鹰相比，帕拉夜鹰具有相对较长的尾巴。雄鸟与雌鸟在翼带和尾部白色区域上有明显差异。不同亚种之间存在大小和颜色深浅的差异。","protection":"IUCN：LC（无危）","distribution":"帕拉夜鹰广泛分布于中美洲和南美洲，从墨西哥南部至阿根廷北部，包括巴西、玻利维亚、巴拉圭、乌拉圭等地。北美的得克萨斯州南部也有其分布。","other":"尽管帕拉夜鹰的分布广泛，但关于其生物学和生态学的知识仍有待深入研究。"},{"name":"灌丛夜鹰","english_name":"Anthony's Nightjar","scientific_name":"Nyctidromus anthonyi","overview":"灌丛夜鹰（英文名：Anthony's Nightjar，学名：Nyctidromus anthonyi），是夜鹰目夜鹰科帕拉夜鹰属的鸟类。夜鹰科鸟类，亦被称为小夜鹰。其体型较小，具有明显的白喉和白色翼条标记，分布于南美洲的厄瓜多尔西部和秘鲁西北部干燥灌丛和沙漠地带。曾一度被误认为是小夜鹰的亚种，但在形态和声音上有显著差异。","appearance":"灌丛夜鹰是一种小型斑驳的夜鹰，体色以棕色和淡褐色为主，具有良好的隐蔽性。雄鸟拥有白色喉部，以及宽阔的白色翼带。尾羽外侧两对具有明显的白色条纹，闭合时几乎不可见，展开时可见纵向白色条纹。雌鸟相似，但白色翼带较窄，仅在外侧一对尾羽上有白色。幼鸟的描述尚不详。","call":"灌丛夜鹰发出清晰、反复的哨声“tWEE-oh”，比常见夜鹰更强调且不那么模糊。","habits":"灌丛夜鹰栖息于干旱的开阔林地、草地和灌木丛，海拔高度从海平面至800米。它们从黄昏到黎明活跃，白天在地面休息，通常独居。它们的觅食活动集中在黄昏和傍晚，通过飞行捕捉昆虫或从树枝上出击捕食。","breeding":"灌丛夜鹰的繁殖季节尚未明确界定，但似乎集中在12月至3月之间，可能与雨季相关。它在地面上的落叶层中筑巢，每窝产卵一至两枚。","identification":"与帕拉夜鹰相比，灌丛夜鹰体型较小，尾部较短，叫声不同。与小斑翅夜鹰在秘鲁西北部重叠分布区，灌丛夜鹰颜色更深，歌曲也不同。","protection":"IUCN：LC（无危）","distribution":"灌丛夜鹰主要分布在南美洲的厄瓜多尔西部和秘鲁西北部，栖息于沿海干旱的开放林地、草地和灌木丛。","other":"灌丛夜鹰的种群数量未知，但据信正在增加，可能与森林和密集灌丛的清除有关。"},{"name":"托氏夜鹰","english_name":"Todd's Nightjar","scientific_name":"Setopagis heterura","overview":"托氏夜鹰（英文名：Todd's Nightjar，学名：Setopagis heterura），是夜鹰目夜鹰科小夜鹰属的鸟类。亦被称为圣玛塔夜鹰，广泛分布在南美洲东北部，如哥伦比亚东北部、委内瑞拉北部和中部。以独特的叫声和较短的尾巴而著称。","appearance":"托氏夜鹰体型介于17至21厘米之间，雄鸟背部呈灰色，点缀有黑色和淡色条纹及斑点，颈部后方有一圈狭窄的肉桂色领环，喉部白色，胸部深棕色，饰有细密的条纹和斑点。飞行时可见翅膀上下表面的白色斑块，除最内侧尾羽外，其余尾羽均具显著的白色尖端。雌鸟头部颜色较暗，喉部为淡黄色，尾部无白色，其尾部长度比其他共栖夜鹰更短。","call":"托氏夜鹰的鸣唱是一系列均匀音调的‘pik-you, gobble-gobble-gobble’，节奏紧凑，比小夜鹰的鸣声更为凝练。它仅在繁殖季节短时间歌唱，通常从地面或低矮的栖木上发出。","habits":"托氏夜鹰栖息于落叶林、半落叶林边缘、画廊森林、开阔的林地以及郊区公园。偏好丘陵地形，海拔范围从海平面至1000米，在委内瑞拉甚至高达1870米。它通过从地面或低枝上飞扑的方式捕食昆虫。","breeding":"繁殖季节未明确界定，但观察到在哥伦比亚北部的晚十月，委内瑞拉北部的四月末至五月初期有繁殖迹象。它们在地上直接产下两枚白色的卵，通常位于浓密灌木下。","identification":"与小夜鹰相比，托氏夜鹰的鸣唱节奏更快，尾羽白色尖端更明显，下体颜色略深，尾羽尖端的白色斑点更大，且体色整体色调在两个物种中似乎都具有变异性。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲东北部，具体包括哥伦比亚东北部、委内瑞拉北部和中部，最近记录显示也出现在圭亚那和巴西北部（罗赖马州）。","other":"托氏夜鹰在哥伦比亚较为罕见，而在委内瑞拉则为不常见至局部地区相当常见。"},{"name":"小夜鹰","english_name":"Little Nightjar","scientific_name":"Setopagis parvula","overview":"小夜鹰（英文名：Little Nightjar，学名：Setopagis parvula），是夜鹰目夜鹰科小夜鹰属的鸟类。其主要特征为灰色、棕色和赤褐色条纹相间，具有白色喉部和淡色颈环。雄鸟翼端有白色斑块，尾羽中央较淡，雌鸟则无此特征。分布于南美洲的广阔开放生境，包括牧场、灌木区和森林边缘。","appearance":"小夜鹰体长19至21厘米，体重25至46.5克。雄鸟一般呈灰褐色，带有淡色、棕色和黑褐色斑点及条纹，腹部淡色带棕色横纹。颈后有一宽而模糊的淡色环，下颚淡色，喉部白色。翼上有宽阔的白色带，外侧尾羽尖端白色。雌鸟相似，但喉部淡色，翅膀和尾巴无白色部分。幼鸟特征与雌鸟类似。","call":"发出一种奇特、令人难忘的下降音调‘drui-dro-dro-dro-dro-dro’，像咔哒声，平缓而不似鸟鸣。","habits":"栖息于低地开阔林地，包括南美洲中央和东部，从秘鲁东部到巴西北部，南至阿根廷北部。夜行性，以昆虫为食，具体饮食细节未详，至少包含五个昆虫目。活动范围广泛，可能在南半球冬季向北和东迁移。","breeding":"繁殖季节在不同地区有所变化，已知的繁殖活动发生在8月至1月之间。每次产卵两枚，直接放置于地面，由双亲共同孵卵。","identification":"与白斑尾夜鹰相似，但后者整体更偏淡色，缺乏白色喉部和翼斑。雌雄白斑尾夜鹰与小夜鹰雌鸟更为相似，但白斑尾夜鹰雌鸟头部颜色更深，眉纹更为明显，胸部斑点更为显著。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲东部秘鲁至巴西东部，南至阿根廷中部和乌拉圭。在海拔上，从海平面至玻利维亚约1,500米高度都有分布。","other":"尽管分布范围广泛，目前未识别出小夜鹰的亚种。"},{"name":"委内瑞拉夜鹰","english_name":"Roraiman Nightjar","scientific_name":"Setopagis whitelyi","overview":"委内瑞拉夜鹰（英文名：Roraiman Nightjar，学名：Setopagis whitelyi），是夜鹰目夜鹰科小夜鹰属的鸟类。体型中等偏小，生活在南美洲特普伊山脉的高海拔地带，分布于委内瑞拉东部、圭亚那西部及巴西北北部。其羽毛颜色深沉，带有暗棕色和灰色，点缀着淡色条纹和斑点，雄鸟翼上有白色带状标记，雌鸟则无。由于声音独特，是辨识它的重要依据。","appearance":"委内瑞拉夜鹰体长约21至22.4厘米，雄鸟体重介于30至40克，雌鸟稍重，约45至48克。上体呈黑褐色，夹杂着肉桂色和灰白色斑点。尾巴深棕色，最外侧三对尾羽有淡淡的浅色条纹，两对外侧尾羽尖端有大块白色斑点。翅膀主要为深棕色，靠近末端有一细白条纹，靠近躯干部分有白色斑点。下巴和上喉部为深棕色，下喉部白色，胸部深棕色，带有浅色条纹，腹部和胁部淡黄色，有棕色条纹。雌鸟比雄鸟更偏棕色，翅膀上的斑点较小且呈肉桂色，尾羽上的白色斑点也较小。","call":"其叫声独特，是一连串模糊的'hreeer'声，音调先升后降，间隔1到2秒重复。","habits":"委内瑞拉夜鹰主要栖息于特普伊山脉的开阔地带，如草原、林间空地及森林边缘，海拔高度在850米至1800米之间。夜间活动，白天隐蔽。其觅食行为尚未完全了解，但可能通过从地面或低矮枝头飞扑的方式捕食昆虫。","breeding":"关于繁殖习性的信息有限，推测其会在地面上直接产卵，如同其他夜鹰种类一样，通常产一至两个蛋。","identification":"与相似的暗色夜鹰相比，委内瑞拉夜鹰略小，且两者叫声差异显著。与斑翅夜鹰相比，委内瑞拉夜鹰体型略小，缺乏棕颈圈，翼部和尾部的白色标记更为有限。","protection":"IUCN：LC（无危）","distribution":"委内瑞拉夜鹰主要分布在南美洲特普伊山脉的交汇处，覆盖委内瑞拉东部、圭亚那西部和巴西北北部。具体而言，其分布区域包括委内瑞拉东南部、圭亚那西南部以及巴西最北端。","other":"尽管其分布区域特定，但由于特普伊山脉植被受到破坏后不会自然恢复，而是被较不适合夜鹰生存的植被所取代，这构成了对委内瑞拉夜鹰的主要威胁。"},{"name":"卡宴夜鹰","english_name":"Cayenne Nightjar","scientific_name":"Setopagis maculosa","overview":"卡宴夜鹰（英文名：Cayenne Nightjar，学名：Setopagis maculosa），是夜鹰目夜鹰科小夜鹰属的鸟类。自20世纪初在法属圭亚那北部采集到唯一一只雄鸟标本后，这种神秘物种几乎完全未知。尽管有两次可能的目击报告，但至今未能确定其确切位置，对其生态和自然历史一无所知。","appearance":"卡宴夜鹰是一种小型、暗色的夜鹰，雄鸟上部灰褐色，头顶有宽大的黑褐色条纹，颈背有模糊的浅褐色环。翅膀覆羽灰褐色，布满淡色斑点；腹部淡色，带有深褐色条纹。初级飞羽最外侧有一小白斑，最外侧尾羽内网有宽白尖。雌鸟羽毛特征未知。","habits":"卡宴夜鹰的习性和生态信息尚无记录。假设其生活方式类似于其他夜鹰，夜间活动，以昆虫为食。","identification":"与更常见的暗色夜鹰和帕拉夜鹰相比，卡宴夜鹰更小，羽毛颜色较淡，斑点较大。暗色夜鹰比卡宴夜鹰略小，羽毛更暗，斑点更多，且头部无条纹。","protection":"IUCN：DD（数据缺乏）","distribution":"仅确知分布于南美的法属圭亚那，所有记录均来自湿润低地森林。"},{"name":"镰翅夜鹰","english_name":"Sickle-winged Nightjar","scientific_name":"Eleothreptus anomalus","overview":"镰翅夜鹰（英文名：Sickle-winged Nightjar，学名：Eleothreptus anomalus），是夜鹰目夜鹰科镰翅夜鹰属的鸟类。体型较小，以灰褐色为主，具有独特的黑色肩胛斑点和淡色颈环，最显著的特点是其独特的镰状翼型。分布于南美洲东南部，包括阿根廷、巴西和巴拉圭，可能还存在于乌拉圭。IUCN将其列为近危物种。","appearance":"雄性镰翅夜鹰在飞行时展现非凡的翼形，其主羽向内弯曲形成镰刀状，最内侧的初级飞羽（P1）最短，而相邻的几枚（P2-P4）最长，且带有狭窄的白色尖端。雌鸟的翅膀无此类特殊改变，羽毛呈棕色和浅红褐色条纹。成年雄鸟上体呈灰褐色，点缀着深棕色斑点，下体颜色较淡，布满棕色条纹和斑点。雌鸟羽毛颜色更偏棕色，没有雄鸟的镰状翼型。雏鸟与雌鸟相似，但上体带有一些肉桂色，尤其是翼覆羽部分，且有白色斑点。","call":"镰翅夜鹰的叫声被描述为一系列轻柔的'chip'音符，类似蟋蟀的叫声，也有报道称之为柔和的单个'tick'声。","habits":"镰翅夜鹰偏好在水边活动，常见于画廊森林附近，有时也在草原和沼泽边缘出没。它们黄昏和夜间活动，通过短暂的飞行出击从地面捕食昆虫，也可能在低空连续飞行中觅食。休息时会坐在道路、小径上或低枝和电线上。","breeding":"繁殖季节大约从8月持续到11月或更晚，基于观察到的处于繁殖状态的成鸟、卵和幼鸟的时间。如同其他夜鹰，它们可能直接在地面产卵，不筑巢。","identification":"雄性镰翅夜鹰的翼型明显区别于其他夜鹰，而雌鸟则通过其更偏向棕色的羽毛和缺乏特殊翼型与同类相区分。白翅夜鹰是镰翅夜鹰的近亲，雄鸟可通过其翅膀上的大量白色区和几乎全白的尾羽轻松识别，而雌鸟两物种较为相似，但白翅夜鹰雌鸟颜色更浅，更多肉桂色，下体斑点和条纹较少。","protection":"IUCN：VU（易危）","distribution":"镰翅夜鹰主要分布在南美洲东南部，包括巴西东南部、巴拉圭东南部至阿根廷中部，可能存在分布于乌拉圭。在繁殖季节，其活动范围可能覆盖这些区域。","other":"关于镰翅夜鹰的栖息地偏好存在争议，但普遍认为它倾向于栖息在草原和沼泽边缘。"},{"name":"白翅夜鹰","english_name":"White-winged Nightjar","scientific_name":"Eleothreptus candicans","overview":"白翅夜鹰（英文名：White-winged Nightjar，学名：Eleothreptus candicans），是夜鹰目夜鹰科镰翅夜鹰属的鸟类。珍稀的夜行性鸟类，广泛分布在南美洲的玻利维亚北部、巴西中南部以及巴拉圭东部。这种鸟体型较小，全身呈现淡灰色，带有暗褐色斑点，最显著的特征是白色的眉纹和髭纹。雄鸟在飞行中会展现出白色的翅膀和尾部，而雌鸟的羽毛则缺乏白色部分，下体呈淡黄色。","appearance":"白翅夜鹰体长约19至23厘米，体重在46至55克之间，雌雄两性有明显的性别二型性。上体颜色为浅灰棕色，饰有黑色斑点和条纹，头部顶部的黑色斑点尤为明显，没有颈圈。翼下覆羽白色，边缘呈褐色，饰以黑色斑点。肩羽为灰棕色，带有醒目的黑色标记，内侧羽毛通常呈淡黄色。面部有一条宽阔的淡黄色亚髭纹，下喉周围有一排淡黄色斑点。胸部颜色为灰棕色，带有一些栗色和赭色，饰有棕色的条纹和斑点；其余下体部位均为白色。雌鸟的下体为淡黄色，羽毛中没有白色部分。幼鸟与成鸟相似，但颜色更偏向褐色，缺少翅膀和尾巴上的白色。","call":"雄鸟的领地叫声为柔和的波动哨声‘tshere-she-shew’，在空中追逐时发出。报警叫声包括类似的哨声和突然的‘eek’叫声。","habits":"白翅夜鹰主要栖息于开阔的草地，散落着树木（如Tabebuia caraiba和Anadenanthera spp.）和灌木丛，如干燥的开阔草原，开放的cerrado或草地，散布着灌木、棕榈树、白蚁丘和蚂蚁丘。它们也会出现在火灾后再生的草地。它们通常避免高草区，有时会出现在查科林地，但这种情况似乎极不可能。它们在海拔从海平面到210米的高度活动。白翅夜鹰可能在部分范围内迁徙，但这一行为尚不清楚。","breeding":"白翅夜鹰的繁殖行为直到最近才被发现，第一个巢穴是在1997年找到的。在东巴拉圭的研究中，雄鸟的展示行为从8月底持续到次年1月初，产卵则从9月中旬持续到11月中旬。卵直接产在地面上，通常位于草丛之间；一窝产2枚卵，颜色为浅奶油色，带有可变的深褐色和紫灰色斑点和斑块，平均尺寸为27.7毫米×21.0毫米，新产下的卵重量约为6.7克；雏鸟在孵化当天的平均体重约为5.2克；孵化成功率高达86%；孵化期为19天；雏鸟期大约为19至20天。","identification":"白翅夜鹰雌雄差异明显，雄鸟在飞行中展示出的白色翅膀和尾部是其独特之处，而雌鸟的羽毛中缺乏白色部分，下体呈淡黄色。与小夜鹰雌鸟相比，后者图案更为复杂，喉部较浅，翼覆羽上有独特的淡色斑点。","protection":"IUCN：VU（易危）","distribution":"白翅夜鹰分布于南美洲的玻利维亚北部（贝尼州的贝尼生物站）、巴西中南部（戈亚斯州的埃马斯国家公园）以及巴拉圭东部（坎迪内尤的Mbaracayú森林自然保护区，圣佩德罗的Laguna Blanca）。在巴西的历史记录还来自马托格罗索和圣保罗州。","other":"白翅夜鹰受到农业和牧场开发以及故意引发的野火对其繁殖地的严重威胁。"},{"name":"斑翅夜鹰","english_name":"Band-winged Nightjar","scientific_name":"Systellura longirostris","overview":"斑翅夜鹰（英文名：Band-winged Nightjar，学名：Systellura longirostris），是夜鹰目夜鹰科斑翅夜鹰属的鸟类。中等体型的夜鹰，广泛分布于南美洲，从委内瑞拉至阿根廷南部，以及巴西东部。其特征包括颈后部的土黄色或红褐色环状标记，翼上的白色或淡褐色带纹，以及相对较长的方形尾巴。白天常隐匿于地面，夜晚通过其独特的鸣声被轻易识别。","appearance":"斑翅夜鹰体长20-27厘米，具有灰色至红褐色的上体，翼部带有明显的白色或淡褐色带纹，尾羽末端的中央一对有灰褐色斑点，而外侧几对则有宽阔的白色尖端。雄鸟的翼部带纹为白色，雌鸟则为淡褐色。颈部后方有红褐色或土黄色的环状标记，尾部呈方形延长，超出翼展。","call":"斑翅夜鹰的鸣声为高音、细长的‘tseeeeeu’，通常在黄昏或黎明时分发出，是其夜间活动时最容易被察觉的特征。","habits":"该物种栖息于多种开放生境，从海平面至安第斯山脉边缘的云雾森林（海拔4,400米）。它们主要在夜间活动，日间则在地面隐蔽处休息。迁徙习性取决于地理位置，南部种群为迁徙种，而大部分分布区内的种群为留鸟。食物以昆虫为主，包括蛾类、甲虫和白蚁。","breeding":"繁殖季节随地区而异，例如在委内瑞拉西部为2月至9月，阿根廷和巴西东南部则从9月至10月。斑翅夜鹰不筑巢，直接在植被密集处或裸露地面产卵，每季产卵1-2枚，卵呈椭圆形，颜色多样，孵化期约17天。","identification":"斑翅夜鹰可通过其翼部的白色或淡褐色带纹，以及颈后的红褐色或土黄色环状标记与同属其他物种相区分。在南美南部，它是唯一常见的夜鹰。","protection":"IUCN：LC（无危）","distribution":"斑翅夜鹰广泛分布于南美洲北部、西部、南部和东南部，包括委内瑞拉、巴西、阿根廷、智利等地。在阿根廷南部和智利，它是唯一的常见夜鹰。在里约热内卢，它们表现出行为上的适应性，选择靠近光源的地方栖息，以捕食被光吸引的昆虫。","other":"该物种具有八个亚种，包括近年来新描述的两个亚种。"},{"name":"小斑翅夜鹰","english_name":"Tschudi's Nightjar","scientific_name":"Systellura decussata","overview":"小斑翅夜鹰（英文名：Tschudi's Nightjar，学名：Systellura decussata）是夜鹰目夜鹰科斑翅夜鹰属的鸟类。分布于南美洲西部，包括秘鲁和智利北部。以灰褐色为主色调，拥有独特的外观特征和夜行性习性。","appearance":"小斑翅夜鹰长约20至21厘米，雄鸟体重28.5至35克，雌鸟约32克。整体呈灰褐色，饰有黑色斑点。雄鸟具有一圈浅褐色或肉桂色的颈环，喉部有小块白色斑点，翅膀上有白色条带，尾羽有白色边缘和条带。雌鸟的喉部为淡黄色，翅膀上的条带也为淡黄色，尾巴通常无白色标记。","call":"小斑翅夜鹰的鸣唱是一系列响亮而略带嗡嗡声的‘cueeo’音符，报警时发出轻微吱吱声的‘wick’。","habits":"栖息于低地沙漠地带，有零星矮灌木丛和农业区的树篱与灌木丛。昼间休息于地面或阴凉的低枝上，受惊飞起时，翅膀快速拍打并短暂滑翔。夜晚从地面或低枝上狩猎。","breeding":"关于其繁殖季节的了解有限，推测至少从11月至1月，但在智利北部曾观察到1月有雏鸟。卵为白色，大小约为26.9至27.8毫米×19.8至20.4毫米。","identification":"与同属物种相比，小斑翅夜鹰体型较小，色彩较淡，翅膀上的白色条带更窄，尾羽的白色边缘延伸较短。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁西部和智利北部，包括阿雷基帕和塔拉帕卡至奎利亚瓜。","other":"直到最近才被重新认定为独立物种，此前被认为是斑翅夜鹰的一个亚种。"},{"name":"小燕尾夜鹰","english_name":"Swallow-tailed Nightjar","scientific_name":"Uropsalis segmentata","overview":"小燕尾夜鹰（英文名：Swallow-tailed Nightjar，学名：Uropsalis segmentata），是夜鹰目夜鹰科小燕尾夜鹰属的鸟类。生活在南美洲安第斯山脉较高海拔地区的夜行性鸟类。其最显著的特征是雄鸟的超长尾巴，长度远超其身体，这一特征赋予了它独特的名字。分布于哥伦比亚至玻利维亚中部，是当地颇受关注的物种。","appearance":"雄性小燕尾夜鹰的尾部极其引人注目，拥有数倍于身体长度的长尾，尾羽边缘呈白色。雌鸟则不具备这种夸张的尾部特征，其尾羽较短且较为均匀。整体而言，它们的羽毛以深棕色为主，点缀着赭色斑点，腹部和侧面则带有棕色条纹的淡黄色底色。雄鸟与雌鸟的主要区别在于尾部的长度和形状。","call":"小燕尾夜鹰的鸣声独特而明显，是一种颤动的、先升后降的哨音，被称为 'worr-r-r-e-e-e-e-e-r'，起初声音上扬随后下降，常在黄昏或夜晚鸣叫。","habits":"它们通常栖息于云雾森林边缘，偏好在林边、道路切割面、悬崖或滑坡附近活动，这些地方便于它们在空中捕捉昆虫。昼伏夜出，白天在地面休息。","breeding":"关于繁殖季节的具体信息尚不明确，但似乎包括8月和9月。已知的巢穴建在地面上，由干叶和枯枝铺垫，通常含有一枚蛋，与许多其他夜鹰在地上裸露处产卵的习惯形成对比。","identification":"与之相似的物种有大燕尾夜鹰，但大燕尾夜鹰体型更大，颜色更浅，颈部有更为明显的肉桂色环带。小燕尾夜鹰占据更为开阔的生境，通常出现在更高的海拔。","protection":"IUCN：LC（无危）","distribution":"小燕尾夜鹰的分布范围自哥伦比亚向南延伸至玻利维亚中部，主要栖息在安第斯山脉的高海拔地区。"},{"name":"大燕尾夜鹰","english_name":"Lyre-tailed Nightjar","scientific_name":"Uropsalis lyra","overview":"大燕尾夜鹰（英文名：Lyre-tailed Nightjar，学名：Uropsalis lyra），是夜鹰目夜鹰科小燕尾夜鹰属的鸟类。独特的鸟类，以其雄鸟个体拥有的惊人长尾著称，其长度可达体长的三倍，尾端点缀着白色。分布于南美洲的安第斯山脉，自委内瑞拉至阿根廷西北部，常见于亚热带森林中的陡峭道路切口、滑坡或悬崖面。雄鸟白天在藤蔓或树枝上休息，长尾下垂；雌鸟更倾向于地面休憩。黄昏时分，雄鸟会展示其超大的尾巴，发出甜美、音调逐渐升高的哨声。","appearance":"雄性大燕尾夜鹰的特征在于其异常延长的尾羽，长达60厘米以上，尾尖白色，是其最显著的特点。除尾羽外，其上身呈棕色，点缀以灰色、淡黄色和肉桂色斑点，背部带有淡色的波状花纹。翅膀和尾巴其余部分为深棕色，无白色或淡黄色痕迹。雌鸟的尾羽较短，没有白色，但尾巴可能因外侧尾羽较长而显得叉开。头部、颈背有肉桂色项圈，腹部呈波纹状的棕色条纹。雌雄差异明显，雌鸟冠羽呈灰褐色，而非雄鸟的棕色，且主翼羽有更为突出的肉桂色标记。","call":"雄性大燕尾夜鹰的鸣唱是一系列欢快的、音调逐渐上升的‘wéeou-tee’声，通常在黄昏时从枝头或地面发出，也会在飞行或追逐雌鸟时发出。","habits":"大燕尾夜鹰偏好在海拔1100至2100米的湿润山地森林边缘和开阔地带栖息，尤其偏爱靠近流水的悬崖和峡谷。它们是黄昏和夜间活动的物种，通过从岩石或低矮的栖息处飞扑来觅食，通常返回同一栖息地。日间，它们会在树枝或悬崖上休息，常被植被遮掩。","breeding":"据观察，大燕尾夜鹰可能是多配偶制，雄鸟会在群体繁殖场通过飞行展示吸引雌鸟。繁殖季节尚未明确界定，但似乎随分布范围而异。已知的一个巢穴是在受干扰森林附近牧场土地上的废弃壁炉里，由雌鸟独自照料单个雏鸟，未见雄鸟在附近。","identification":"与类似物种小燕尾夜鹰相比，大燕尾夜鹰的雄鸟具有更加夸张的尾羽，而雌鸟的冠羽呈灰褐色，而非小燕尾夜鹰雌鸟的深棕色，且前者具有更明显的肉桂色项圈。此外，大燕尾夜鹰的栖息地通常位于较低海拔。","protection":"IUCN：LC（无危）","distribution":"大燕尾夜鹰分布于南美洲安第斯山脉，范围从委内瑞拉向南延伸至玻利维亚南部，主要在海拔1100至2100米之间，但也可见于800至3500米的高度。"},{"name":"白尾夜鹰","english_name":"White-tailed Nightjar","scientific_name":"Hydropsalis cayennensis","overview":"白尾夜鹰（英文名：White-tailed Nightjar，学名：Hydropsalis cayennensis），是夜鹰目夜鹰科水夜鹰属的鸟类。这种拥有较长尾巴的夜鹰广泛分布于中美洲的哥斯达黎加至南美洲北部，常见于开阔的草地或灌木丛生的生境。其显著特征包括两性的淡色颈背，雄鸟尾部白色显眼，尤其是飞行时更为明显。","appearance":"白尾夜鹰的体型适中，长度约20到22.5厘米。雄鸟上体呈灰褐色，带有棕色至暗褐色斑点和条纹，面部有白色或淡黄色眉纹和髭纹，颈后有宽阔的橙色环带。翅膀一般为灰色至暗褐色，饰有橙色和淡黄色标记，展开或收拢时可见白色翼带。尾羽外观略呈叉状，除最内侧一对外，其余均部分至完全白色。雌鸟整体较暗，翅膀和尾部无白色标记，喉部淡黄色，胸部棕褐色，腹部淡黄色伴以棕色横纹。雌雄幼鸟的描述尚未记载。","call":"其叫声为尖锐的'pt-cheeeeeeeee'，第二声为悠长上升的哨音，随后轻微下降。","habits":"白尾夜鹰严格夜间活动，日间藏匿于低矮植被下的地面休息，夜晚从地面起飞捕捉飞虫。它们栖息于开阔地带，如大草原、牧场、灌木丛生的草地和散布着灌木丛的小山。飞行特点为从地面或栖息处起飞捕食昆虫，也会在开阔草地上低空飞行狩猎。","breeding":"繁殖季节的定义尚不明确，但已知在分布范围内有所不同。雄鸟会进行翅膀拍击的展示行为。一窝产卵通常为两枚，直接产于地面，仅由雌鸟孵化。","identification":"白尾夜鹰与帕拉夜鹰在分布上有重叠，两者尾部均有大量白色标记（雄鸟），翼部有白色或淡黄色带。然而，普通夜鹰体型更大，颜色更灰，有栗色耳羽，缺少白尾夜鹰的橙色颈背环带。雌性白尾夜鹰可能与托氏夜鹰或白斑尾夜鹰的雌鸟混淆，但托德夜鹰颜色更深，颈背环带不明显，无眉纹，喉部更突出白色。白斑尾夜鹰眉纹更显著，冠部颜色更深，翼部无淡色带。","protection":"IUCN：LC（无危）","distribution":"白尾夜鹰分布于中美洲，从哥斯达黎加延伸至南美洲北部，包括巴西、哥伦比亚、厄瓜多尔北部、法属圭亚那、圭亚那、马丁尼克岛、巴拿马、苏里南、特立尼达和多巴哥以及委内瑞拉。"},{"name":"白斑尾夜鹰","english_name":"Spot-tailed Nightjar","scientific_name":"Hydropsalis maculicaudus","overview":"白斑尾夜鹰（英文名：Spot-tailed Nightjar，学名：Hydropsalis maculicaudus），是夜鹰目夜鹰科水夜鹰属的鸟类。体型较小，以斑驳的羽毛和独特的尾巴标记著称，分布于中美洲南部墨西哥至南美洲大部分地区，除智利和乌拉圭外。","appearance":"白斑尾夜鹰长约20.3至21.5厘米，雄鸟体重介于28.3至35.2克之间，雌鸟体重则在26.0至39.0克之间。上体呈棕色，冠部颜色较深，臀部颜色较浅，带有淡色或棕褐色斑点和条纹。脸部为棕褐色或赤褐色，布满深棕色斑点，具有宽阔的淡色眉线。颈后有一圈肉桂色宽带。翅膀主要为棕色，有棕褐色斑点。四对外侧尾羽呈暗棕色，带棕褐色标记，两到三个大的白色斑点，仅雄鸟有白色尾尖，带有淡色洗涤。内侧尾羽略长，灰棕色，带有棕色斑点和条纹。下巴、喉咙和胸部为肉桂色至淡黄色，腹部和两侧为淡黄色。","call":"鸣唱为高音的‘tip-SEEEUUEEET’，叫声包括快速的‘t-seet t-seet t-seet t-seet’和飞行中的略带哀伤的‘seeeu’或‘see-ee-eeii’。","habits":"白斑尾夜鹰为夜间活动的物种，通过从地面或低空缓慢飞行中掠食昆虫为生。其饮食完全由昆虫组成，已知至少捕食六目十七科的昆虫。栖息于开阔地带，包括草原、灌木丛和农地，海拔范围从低地到1,600米（墨西哥）、1,300米（哥伦比亚）、1,000米（委内瑞拉）和1,350米（秘鲁）。","breeding":"繁殖季节在不同群体中变化较大，一般直接在地面产卵，通常产两枚卵（偶尔一枚），不筑巢。具体繁殖时间尚未完全确定。","identification":"与其他夜鹰相比，白斑尾夜鹰的特征在于窄的赤褐色颈背带、黑色冠顶、更突出的眉线与头部较暗的部分形成对比，以及胸部更明显的斑点。雌雄差异主要在于雄鸟尾部的白色标记，雌鸟则缺乏这一特征。","protection":"IUCN：LC（无危）","distribution":"白斑尾夜鹰在中美洲的分布限于墨西哥南部，以及洪都拉斯和尼加拉瓜的加勒比斜坡。在南美洲，其分布涵盖哥伦比亚东部、委内瑞拉西部、巴西东北部、法属圭亚那、苏里南、圭亚那、秘鲁东南部、玻利维亚、巴西南部、阿根廷北部边缘以及巴拉圭。"},{"name":"梯尾夜鹰","english_name":"Ladder-tailed Nightjar","scientific_name":"Hydropsalis climacocerca","overview":"梯尾夜鹰（英文名：Ladder-tailed Nightjar，学名：Hydropsalis climacocerca），是夜鹰目夜鹰科水夜鹰属的鸟类。广泛分布于亚马逊雨林，尤其在森林河流、沙滩及牛轭湖岸边常见。其最显著的特征是拥有较长且形状独特的尾巴，由中央和最外侧的尾羽形成双凹口。雄鸟具有白色喉咙、翼上的白色条带及尾羽外缘的显著白色边缘；雌鸟尾部较短，缺乏白色喉斑及翅膀、尾部的白色。物种分布于南美低地，偶尔在高达2600米的地区出现。","appearance":"梯尾夜鹰体型较大，羽毛以沙棕色为主，带有不明显的浅色斑纹，尾部长而具特色，呈W形，由最长的中央和最外侧尾羽构成。雄鸟的外侧尾羽宽边白色，翼上有一白色条带，喉咙白色；雌鸟颜色更偏褐色，尾部较短，缺乏雄鸟的白色特征。两性均具有颈部后方的淡色项圈，尾羽形态独特，雄鸟尾羽外侧有白色边缘，雌鸟则较为平实。幼鸟与雌鸟相似，但初级飞羽和次级飞羽上有更多的赤褐色标记。","call":"梯尾夜鹰不常鸣叫，但在飞行中偶尔会发出柔和的叽叽声。","habits":"日间在牛轭湖和河流边缘植被中休息，夜晚在河岸和沙滩附近觅食。主要栖息于亚马逊低地的森林河流、沙滩和牛轭湖周边，活动范围包括河流边缘及砂洲。以夜间飞行捕食昆虫为主要生活方式。","breeding":"繁殖信息有限，但已知雌雄成对紧密相邻筑巢。","identification":"雄性梯尾夜鹰因其长而三叉的尾羽而易于识别，雌鸟则通过较短的尾部、缺乏白色喉斑和翅膀尾部的白色区分。与白尾夜鹰相比，雌性梯尾夜鹰上方颜色更沙色，具有明显的赤褐色颈圈，尾部较短且无双凹口状。剪尾夜鹰具有颈部后方明显的淡色颈圈，雄性剪尾夜鹰尾部比梯尾夜鹰更长。","protection":"IUCN：LC（无危）","distribution":"梯尾夜鹰主要分布在亚马逊盆地，包括巴西、圭亚那、苏里南、法属圭亚那、哥伦比亚、厄瓜多尔、秘鲁和玻利维亚的亚马逊区域，以及委内瑞拉的部分地区。其分布不越过亚马逊河口向东延伸至马罗岛。","other":"梯尾夜鹰在地理分布上与剪尾夜鹰部分重叠，二者共同覆盖了安第斯山脉以东的南美洲大部分地区，从阿根廷中部到加勒比海岸，仅在巴西马兰昂州东南部亚马逊盆地附近的小区域内未发现其踪迹。"},{"name":"剪尾夜鹰","english_name":"Scissor-tailed Nightjar","scientific_name":"Hydropsalis torquata","overview":"剪尾夜鹰（英文名：Scissor-tailed Nightjar，学名：Hydropsalis torquata），是夜鹰目夜鹰科水夜鹰属的鸟类。最显著的特征是雄鸟的外侧尾羽异常延长，长度几乎为其体长的两倍，呈现出剪刀般的形状。雌雄体型介于25至30厘米之间，雄鸟体重47.5至63克，雌鸟48至60克。分布广泛，主要见于南美洲东部，包括亚马逊盆地中部至阿根廷中部的广大区域。","appearance":"雄性剪尾夜鹰上体呈斑驳的褐色、灰色和淡色，具黑色条纹和醒目的红褐色颈环。尾羽外侧极长，外部深色内部浅色，形成剪刀状。雌鸟尾羽较短，无白色。雌雄两性翼部均为均匀的暗色，无白色或淡色带。雌鸟体型略小，颜色更深，缺乏雄鸟的红褐色颈环。","call":"发出一系列持久的‘tsips’声，有时可持续数分钟，通常在黄昏和黎明时从栖木或飞行中发出。另有极高音的‘tsig’飞行叫声和低沉的咕噜声。","habits":"剪尾夜鹰栖息于草地、灌木丛边缘和森林边缘，偏好半开放的环境，如次生林、干燥灌木、草原、金合欢树林、牧场和城市公园。它们夜间活动，以昆虫为食，尤其偏好甲虫，白天在阴凉处地面休息。","breeding":"繁殖季节不明确，至少包括9月至12月。雌雄鸟在地上或裸岩上直接产卵，通常产两枚。","identification":"与梯尾夜鹰地理重叠，但梯尾夜鹰主要限于河岸，如沙洲和河岛。梯尾夜鹰雄鸟尾羽不如剪尾夜鹰长，且尾尖有双缺口。雌性梯尾夜鹰比剪尾夜鹰略小、颜色更深，缺乏红褐色颈环。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲东部，包括亚马逊盆地中南部和东南部，向南延伸至阿根廷中部。北部种群全年留居，而南部种群迁徙至南美亚马逊盆地过冬。"},{"name":"燕尾夜鹰","english_name":"Long-trained Nightjar","scientific_name":"Macropsalis forcipata","overview":"燕尾夜鹰（英文名：Long-trained Nightjar，学名：Macropsalis forcipata），是夜鹰目夜鹰科燕尾夜鹰属的鸟类。独特的夜行性鸟类。其最显著的特征是雄鸟个体拥有一条异常长的黑色叉状尾巴，内侧边缘白色，尾羽长度可达48至68厘米。广泛分布在巴西东南部和阿根廷东北部的湿润森林中。","appearance":"雄性燕尾夜鹰拥有壮观的长尾，其余部分暗褐色，上面点缀着灰色和淡黄色斑点。胸部有大面积红棕色斑块，翅膀覆羽棕色，有红棕色条纹或斑点，其余翼羽棕色，大胆地斑驳着红棕色和淡黄色。背部有淡色线条沿肩胛骨延伸。雌鸟尾巴较短，颜色较深。两性均无翼上的白色标记。虹膜棕色，喙黑，腿脚棕色。","call":"发出重复的、高音调的‘tsip, tsip, tsip, tsip’叫声，由两性共同发出。","habits":"主要栖息于森林和林地，包括次生林和森林边缘。在北部分布区，偏好山地森林环境。活动范围从海平面到海拔1800米。可能为留鸟，以昆虫为食，通过飞近树木捕捉叶子上的昆虫，也会在飞行中猎食，利用人工光源吸引的昆虫为食，有时在地面捕食。","breeding":"可能在11月至1月间繁殖，已记录的求偶行为发生在9月底。巢通常位于植被遮蔽的地方，如苔藓和灌木下，无巢结构，蛋直接产在地面上的落叶上。雄鸟会在裸露的地面上做求偶展示，张开喉咙，举起尾巴形成显眼的白色V字形，也可能在雌鸟身边盘旋。蛋呈椭圆形，粉蓝色，有栗色和淡黄色斑点。孵化主要由雌鸟在白天完成，具体孵化周期未知；若巢被威胁，雌鸟会做引诱动作。雏鸟覆盖着灰白色绒毛，带有淡棕黑色条纹。","identification":"比剪尾夜鹰更大、更暗、翼更长，雄鸟尾巴明显更长；与大燕尾夜鹰相比，体型更大，肩部图案明显，但喉带较淡；雄鸟的尾巴更短、更浅。与小燕尾夜鹰相比，体型更大，色彩更丰富，肩部图案突出，颈环明显；雄鸟尾巴白色边缘更明显。","protection":"IUCN：LC（无危）","distribution":"主要分布于巴西东南部（从米纳斯吉拉斯州和埃斯皮里图圣多州向南至里约热内卢、圣保罗、巴拉那、圣卡塔琳娜和里奥格兰德杜苏尔州），阿根廷东北部（米西奥内斯省），并在巴拉圭南部有记录。","other":"尽管曾经被认为接近受威胁，但现在被认为是常见至局部罕见，特别是在巴西东南部的某些地区，如巴拉那州和圣保罗州常见，但在里奥格兰德杜苏尔州稀少。在阿根廷东北部的米西奥内斯省频繁或常见，且似乎正在扩大其分布范围。"},{"name":"中美夜鹰","english_name":"Least Poorwill","scientific_name":"Siphonorhis brewsteri","overview":"中美夜鹰（英文名：Least Poorwill，学名：Siphonorhis brewsteri），是夜鹰目夜鹰科中美夜鹰属的鸟类。分别是指名亚种S. b. brewsteri和S. b. gonavensis。","appearance":"中美夜鹰体型介于17至21.5厘米之间，上部灰褐色，带有黑色条纹，翅膀折叠时显现出大胆的白色斑点，颈后有一圈宽阔的淡色环。胸部深棕色，布满白色斑点，腹部白色，带有棕色的条纹和网状花纹。除了中央的尾羽外，其余尾羽尖端较浅，雄鸟为白色，雌鸟可能为淡黄色。幼鸟外观与成年鸟相似，但上部更鲜明地散布着黑色条纹，腹部和侧翼呈淡黄色，带有微弱的棕色条纹。","call":"雄性中美夜鹰的鸣唱为一种上升音调的口哨声'toorrrrri'或波动的'tworrri'，此外还有短促的口哨声'toorric'或'to-ic'以及类似鸽子的沙哑声音。","habits":"中美夜鹰栖息于干燥至半干旱的环境，如石灰岩林地、仙人掌和荆棘灌木区，也可见于落叶、针叶和混交林。它的活动范围从海平面到海拔800米左右。关于其饮食和觅食行为知之甚少，但认为以昆虫为主食。","breeding":"中美夜鹰的繁殖季节可能在4月至6月之间，一窝产两枚蛋，直接置于地面，没有筑巢行为。蛋椭圆形，淡白色，带有淡紫色灰色斑点，以及淡黄色和棕色的斑点。","identification":"中美夜鹰与海地夜鹰和卡氏夜鹰相比，体型较小，颜色较浅，尾部末端具有白色带，而其他两者体型较大，颜色较深，缺乏中美夜鹰的尾部特征。gonavensis亚种被认为整体上更小，更苍白。","protection":"IUCN：NT（近危）","distribution":"中美夜鹰分布于希斯帕尼奥拉岛，包括多米尼加共和国和海地，以及Gonâve岛。","other":"中美夜鹰的种群数量估计少于15,000只成熟个体，且正在减少。主要威胁来自栖息地破坏和外来物种如獴和鼠的捕食。"},{"name":"牙买加夜鹰","english_name":"Jamaican Poorwill","scientific_name":"Siphonorhis americana","overview":"牙买加夜鹰（英文名：Jamaican Poorwill，学名：Siphonorhis americana）是夜鹰目夜鹰科中美夜鹰属的特有种。自1860年后未再有确切记录，可能已灭绝。其生存受外来物种入侵及森林破坏的影响。","appearance":"牙买加夜鹰长约23至25厘米，雄鸟上体呈赤褐色，带有黑色条纹，喉部白色，腹部具白色斑点；雌鸟较雄鸟颜色略淡，腹部斑点更明显。尾羽除中央一对外，其余均具白色尖端。","call":"其叫声未曾被描述，无法提供鸣叫特征。","habits":"推测为夜间活动，以空中昆虫为食，栖息于低海拔干燥石灰岩森林、半开放林地和开阔地带。由于缺乏详细记录，具体习性不明。","breeding":"据推测，可能像其近亲一样，在地面产卵，无需筑巢，但具体繁殖细节未知。","identification":"与中美夜鹰相似，但体型较小，尾羽较长，雌雄羽毛颜色有细微差别。与安岛夜鹰和北钩嘴夜鹰可通过大小、颜色和行为特征区分。","protection":"IUCN：CR (PE)（极危（可能已灭绝）），可能灭绝）；被认为已经灭绝。","distribution":"分布于北美，仅限于牙买加岛南侧。","other":"自1860年后，尽管有未经证实的目击报告，但未能再次发现，其鼻孔结构独特，区别于大陆同类物种。"},{"name":"查岛夜鹰","english_name":"Choco Poorwill","scientific_name":"Nyctiphrynus rosenbergi","appearance":"乔科夜鹰体型小，长度约19.5至21厘米，颜色以深褐色为主，头部、背部带有黑色斑点，肩部有明显的淡色条纹。翅膀上的两到三个白色斑点和尾羽末端的狭窄白色尖端是其显著特征。雌雄羽毛相似，幼鸟与成鸟相似，但缺乏翼上的白点，上体和胸部的标记更偏向栗色。","call":"其鸣声独特，是一系列上升的三到四个模糊的哨音，当只有三个音符时，可被描述为“can’t see ME！”的旋律。","habits":"乔科夜鹰偏好生活在低地热带雨林内部，常在河流边缘或树木倒下的开阔地带活动。它们在黄昏和夜间活跃，以昆虫为食，捕食方式包括从地面或停歇处突飞捕捉猎物，或在树冠上方持续飞行捕食。","breeding":"关于乔科夜鹰的繁殖信息知之甚少，但推测其繁殖季节可能在3月至6月之间，如同其他夜鹰一样，它们可能将蛋直接产在地面上。","identification":"乔科夜鹰与黑夜鹰相似，但二者地理分布互不重叠，且鸣声不同。乔科夜鹰的翼上具有白色斑点，而黑夜鹰则没有；黑夜鹰的下胸和腹部有大胆的白色斑点，而乔科夜鹰则没有。","protection":"IUCN：LC（无危）","distribution":"乔科夜鹰的分布范围限于南美洲的哥伦比亚西部和厄瓜多尔西北部，主要栖息于太平洋/Chocó自然区域的非常湿润的常绿森林中，海拔高度从海平面至900米。","other":"乔科夜鹰的种群数量未知，但由于栖息地加速丧失，其数量被认为正在减少。"},{"name":"耳夜鹰","english_name":"Eared Poorwill","scientific_name":"Nyctiphrynus mcleodii","overview":"耳夜鹰（英文名：Eared Poorwill，学名：Nyctiphrynus mcleodii），是夜鹰目夜鹰科弱夜鹰属的小型夜行性鸟类，仅见于墨西哥西部。其最显著的外部特征是头部的冠羽，形成类似耳朵的突起，因此得名。体长约为20至21厘米，体重在24至37克之间。耳夜鹰栖息于半干旱山地的松林和橡树林，偶尔也会出现在云雾林下方的山坡或过耕地上。","appearance":"耳夜鹰上体灰褐色，翼覆羽带白色斑点，肩羽上有明显的黑斑。颈部有一圈较宽的白色环带，喉部有显眼的白色条纹。腹部淡灰色，腹部下方呈淡黄色，带有白色小斑点。尾羽除中央一对外，其余皆有白色尖端。存在红棕色变异个体，颜色偏向肉桂色至红棕色。雌雄外观相似，但雌鸟更倾向于红棕色变体。","call":"雄性耳夜鹰发出响亮而突然的‘peeyo’或‘peejo’声，以强调结尾，每2至3秒重复一次，有时略带模糊音质，夜间从地面或树上歌唱。此外，还会发出下降波动的‘teu-uu-uu’声。受干扰时，雌鸟会发出短促颤音。","habits":"耳夜鹰主要栖息在半干旱的山地松林和橡树林，活动范围在海拔600至2500米之间，但主要在2000米以下。它们通常为留鸟，但在特定季节可能会进行局部迁移。以昆虫为食，尤其是甲虫和蛾子，通过从树上或地面短暂飞翔捕食。","breeding":"繁殖期可能在4月至6月之间。巢建在短草丛中的悬崖底部或松树丛中，没有巢结构，直接在地面或松针上产卵。每窝产两枚象牙白色的蛋，无斑点，由双亲共同孵化。","identification":"与北美小夜鹰相比，耳夜鹰更偏褐色，具有伸长的胸羽和竖立的耳羽，且鸣唱不同。耳夜鹰的鸣声与略有相似，但有明显区别。","protection":"IUCN：LC（无危）","distribution":"耳夜鹰分布于墨西哥西部，包括奇瓦瓦、索诺拉、哈利斯科和科利马等州，以及格雷罗和瓦哈卡州的部分地区。在瓦哈卡州的记录显示，它们可能在2月至5月间进行季节性迁移。","other":"耳夜鹰曾被列为近危物种，但自2004年起，IUCN将其评级为无危。尽管其种群被认为正在减少，但尚未发现直接威胁。"},{"name":"尤卡坦夜鹰","english_name":"Yucatan Poorwill","scientific_name":"Nyctiphrynus yucatanicus","appearance":"尤卡坦夜鹰体长19.5至22厘米，是尤卡坦半岛上最小的夜鹰种类。体重介于21.3到27.7克之间。两性相似，具有棕色和锈色两种形态。棕色形态以深灰褐色为主，带有多种暗色斑纹和条纹，脸部呈深烟灰色至黑褐色，有淡色颈环和白色喉部斑块。锈色形态主要在雌鸟中出现，底色为红褐色。腹部有棕色和灰色斑纹，背部黑色条纹明显。尾巴暗哑黑色，有灰白斑点，翼圆形，外侧四对尾羽有宽白色尖端。","call":"其鸣叫声为响亮且略带共鸣的'whirr'或'whirrrr'，在夜间从树上发出，通常在2月至10月间较为频繁。还发出类似水声的'puk-puk'声，有时加速，以及飞行中的尖锐'week week week'声，后者被认为是警报叫声。","habits":"尤卡坦夜鹰主要栖息在热带湿润森林内部和边缘地带，偏好密集的森林环境，偶尔出现在林缘。活动于黄昏和夜间，通过从树上或地面起跳的方式觅食昆虫。分布海拔从海平面至约250米。在贝尔兹的Shipstern野生动物保护区全年可见，通常形成小群（少于10只）。","breeding":"繁殖季节从4月持续到6月，直接在地面产卵，通常产两枚蛋，没有巢筑。雌雄个体很难区分，但它们的蛋颜色不同，尤卡坦夜鹰的蛋为黄褐色带棕色斑点。当巢穴受到威胁时，孵卵的亲鸟会模拟受伤以分散入侵者的注意力。","identification":"与耳夜鹰相比，尤卡坦夜鹰的翅膀较短，颈背处的颈圈更窄，下体斑点较小，腹部有更明显的白色斑点。两者在歌曲和羽毛特征上有显著差异。","protection":"IUCN：LC（无危）","distribution":"尤卡坦夜鹰分布于中美洲尤卡坦半岛，包括墨西哥的坎佩切州、尤卡坦州（除北部沿海地带）和金塔纳罗奥州，以及危地马拉东北部和伯利兹北部。在海拔0至250米的热带湿润森林中均有发现。","other":"尽管其种群被认为正在下降，但尤卡坦夜鹰的分布范围广泛，总体上数量还算常见。"},{"name":"黑夜鹰","english_name":"Ocellated Poorwill","scientific_name":"Nyctiphrynus ocellatus","overview":"黑夜鹰（英文名：Ocellated Poorwill，学名：Nyctiphrynus ocellatus），是夜鹰目夜鹰科弱夜鹰属的鸟类。居住在中美洲和南美洲湿润森林中的暗褐色夜鹰。其分布区域广阔，包括阿根廷、玻利维亚、巴西、哥伦比亚、哥斯达黎加、厄瓜多尔、洪都拉斯、尼加拉瓜、秘鲁等地。","appearance":"黑夜鹰长约20至21厘米，体重在29至44克之间，雌雄体型相似。上体和翼覆羽呈均匀的暗灰色，无颈圈，肩羽和部分翼覆羽有大胆的黑褐色斑点，边缘带红棕色或淡黄色。喉部有一条明显的白色环带，腹部散布着白色斑点。两性均无翅膀上的白色标记，但尾羽除中央一对或两对外，其余均有狭窄的白色尖端。虹膜深棕色，喙色暗角质，顶端黑色，腿脚深棕色。存在一种较浅、更偏红棕色的色型。幼鸟头部花纹更多变，翼覆羽和腹部有淡黄或白色斑点。","call":"雄性黑夜鹰的鸣唱为重复的颤音‘preeeo’或‘prEEoo’，持续时间约为0.45至0.65秒，常在黄昏时从低处的栖木（2至5米高）或地面发出，间隔约5秒重复多达20次，声音被认为与帕拉夜鹰的歌声相似但较弱。叫声为柔和的喉音‘wah, wah, wah’。","habits":"偏好低地森林，具有开阔的下层植被和小而阴凉的空地，也见于密集的次生林中，富含小型树木和藤蔓。活动范围从海平面到1,350米。以飞蛾、甲虫、蟑螂、螽斯和萤火虫为食，通过从低处栖木进行短暂的捕食冲刺进行觅食。","breeding":"繁殖季节记录不详，可能在3月至4月在哥斯达黎加和尼加拉瓜繁殖，12月在厄瓜多尔东部，8月至11月在秘鲁繁殖。在洪都拉斯记录到雌鸟孵卵两只，以及5月初在另一地点的两只离巢幼鸟。巢位通常位于悬垂的叶片下方，一次记录在竹丛中。巢穴由枯叶构成，通常位于地面上，由两枚椭圆形、偏白至粉白色的蛋组成，大小约为25.2至28毫米×19至20.5毫米，重4.4克。孵化期19至21天，双亲共同孵化。","identification":"与同类物种相比，黑夜鹰的显著特征是其独特的喉部白色环带和尾羽末端的白色尖端，以及特有的叫声。不同亚种间的主要区别在于体型大小和尾羽尖端的白色宽度。","protection":"IUCN：LC（无危）","distribution":"黑夜鹰在中美洲和南美洲的分布呈离散状态。主要分布在南美洲南部哥伦比亚、东厄瓜多尔、秘鲁至玻利维亚，东至亚马逊巴西；另一区域从巴西东南部向西延伸至东巴拉圭和阿根廷东北部。在中美洲，分布于洪都拉斯东部、尼加拉瓜东北部和哥斯达黎加西北部。在巴拿马有一个未确认的目击记录。","other":"栖息地丧失，尤其是因森林砍伐导致的威胁，可能是某些区域，尤其是中美洲群体面临的潜在问题。"},{"name":"北美小夜鹰","english_name":"Common Poorwill","scientific_name":"Phalaenoptilus nuttallii","overview":"北美小夜鹰（英文名：Common Poorwill，学名：Phalaenoptilus nuttallii）是夜鹰目夜鹰科北美小夜鹰属的鸟类。体型小巧，长约18厘米，以独特单调的“poor-WILL”鸣叫著称，其名称即来源于此。分布于加拿大西南部至墨西哥北部，偏好干燥开阔地带，如草原、半干旱平原和岩石丘陵。冬季有进入长时间深度假眠状态的能力，能在岩石堆中度过大部分冬日。","appearance":"体长18厘米左右，翼展约30厘米，体重介于36到58克之间。上身呈灰色和黑色相间的图案，雌雄相似。雄鸟尾羽末端白色较明显，雌鸟则偏褐色。头部扁平较大，喙短小，翅膀短圆，尾巴较短。下体色浅，胸前有宽阔的白色带纹，喉部暗色，胸腹部分布有细碎的黑斑。","call":"发出单调的\"poor-WILL\"叫声，有时可听到第三个音节，形成\"poor-will-low\"。","habits":"严格夜间活动，偏好栖息于干燥、开阔地带，如草原、半干旱平原和岩石丘陵。以夜间昆虫为食，如蛾、甲虫和蚱蜢，通过快速从低矮的栖木或地面起飞捕食。在南缘地区冬季会进入长达数周至数月的深度假眠状态，类似小型哺乳动物的冬眠。","breeding":"繁殖季节为3月至8月，南方地区较早，北方地区晚至5月末至9月。筑巢于地面浅坑中，通常位于山脚或被灌木或草丛遮蔽。每窝产卵两枚，白色至奶油色或淡粉色，偶尔有深色斑点。双亲共同孵卵20至21天，幼鸟再过20至23天即可离巢。每年一般只繁殖一窝，但在特定条件下，雌鸟可能在第一窝附近再次筑巢。","identification":"与相似夜鹰区别在于体型更小，喙短，翅尖至尾端距离较短，且体色为灰白相间。雄鸟尾羽末端的白色比雌鸟的更为显著。","protection":"IUCN：LC（无危）","distribution":"繁殖区域从加拿大西南部至美国西部，非繁殖期间向南迁徙至墨西哥北部。","other":"北美小夜鹰是唯一已知能长时间进入深度假眠状态的鸟类，这一行为接近于小型哺乳动物的冬眠。"},{"name":"卡氏夜鹰","english_name":"Chuck-will's-widow","scientific_name":"Antrostomus carolinensis","overview":"卡氏夜鹰（英文名：Chuck-will's-widow，学名：Antrostomus carolinensis），是夜鹰目夜鹰科卡氏夜鹰属的大型夜行性鸟类。以独特的‘卡氏夜鹰叫声命名，体长约28至33厘米，翼展可达58至66厘米，体重介于66至188克之间。分布于美国东部，包括东南部的松树林和沼泽地带，以及长岛、纽约、加拿大安大略省和马萨诸塞州的科德角等分散地区。","appearance":"卡氏夜鹰拥有显著的大头和长尾，其羽毛颜色从灰褐色到鲜明的赤褐色不等，通常带有复杂的斑纹。上体部分斑驳的棕色、浅黄色和黑色，喉咙呈淡赤色，下喉有半领状图案，雄鸟为白色，雌鸟和幼鸟为浅黄色。胸部为黑色和赤褐色斑点，其余下体为丰富的肉桂色到淡黄色，带有深褐色条纹。雄鸟的外侧尾羽上有白色斑块，雌鸟则没有。成年雄鸟比雌鸟稍大。","call":"卡氏夜鹰的鸣叫声为一系列重复的音符，中间夹杂着振动的音节，两头较短，音高变化不大，速度比鞭穷威的叫声慢，音调更低，穿透力更弱。","habits":"卡氏夜鹰主要栖息于开阔的森林和沙丘地带，夜间活动，白天常在地面或低树枝上休息。它们主要以夜间活跃的昆虫为食，如蛾、甲虫和有翅蚂蚁，偶尔也会吞食小型鸟类和蝙蝠。在满月或接近满月的夜晚，它们的叫声尤其响亮。","breeding":"繁殖期间，卡氏夜鹰会在枯叶覆盖的地面上产卵，一般产2枚粉红色带有棕色和紫罗兰色斑点的蛋，由雌鸟负责孵卵。","identification":"卡氏夜鹰与鞭穷威相似，但体型更大，翅膀更长，颜色更偏向赤褐色。卡氏夜鹰的尾巴上白色较少，但在飞行或休息时不易观察到。通过声音识别是最有效的方式。","protection":"IUCN：NT（近危）","distribution":"繁殖区域主要在美国东部，包括东南部的松树林和沼泽地带。非繁殖季节迁徙至中美洲、南美洲北部以及西印度群岛。","other":"自19世纪以来，卡氏夜鹰的分布范围逐渐向北和向西扩展，超出了其在东南部的核心区域，进入中大西洋各州。"},{"name":"棕夜鹰","english_name":"Rufous Nightjar","scientific_name":"Antrostomus rufus","overview":"棕夜鹰（英文名：Rufous Nightjar，学名：Antrostomus rufus），是夜鹰目夜鹰科卡氏夜鹰属的鸟类。分布广泛，自哥斯达黎加至南美洲南部巴西，包括圣卢西亚岛，常见于热带和温带地区。以棕褐色保护色著称，善于夜间捕食飞行中的昆虫。","appearance":"体型较大，长度约25至30厘米，体重88至98克。全身呈深浅不一的红褐色，颈部有一圈明显的淡色环状斑纹，喉咙下方有一白色带状斑。上体有暗褐色条纹，翅膀具暗褐色斑点与条纹，下体带有暗褐与白色的斑点。雄鸟尾羽外侧三对有白色端斑，雌鸟则为淡黄色尖端。各亚种颜色深浅与斑点大小略有差异。","call":"发出响亮、断续的‘chup, whi-whi-RIoh’或‘chuck whip-his-WIDdow’的声音，节奏感强，通常从低至20米高的栖木上鸣唱。","habits":"活动高峰在黎明与黄昏，日间常隐匿于密林底层或低枝上休息。栖息于多种生境，从灌丛到原始森林与次生林。以空中捕食昆虫为主，具体食性细节有待进一步研究。","breeding":"通常在裸露地面产卵，不筑常规巢穴，一次产卵一至两枚。白天由雌鸟孵卵，隐藏于低矮植被中。","identification":"与卡氏夜鹰（学名：）外观相似，但通过声音可明显区分。棕夜鹰的羽色更偏暖色调，颈部有淡色环，雄鸟尾部有显著白点。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲南部至南美洲东部，包括哥斯达黎加至巴西南部，圣卢西亚岛，以及阿根廷、玻利维亚、巴西、哥伦比亚、厄瓜多尔、圭亚那、巴拿马、巴拉圭、秘鲁、苏里南、特立尼达和多巴哥、委内瑞拉。","other":"至少五种亚种被确认，其中A. r. saltarius毛色较灰。"},{"name":"古巴夜鹰","english_name":"Cuban Nightjar","scientific_name":"Antrostomus cubanensis","overview":"古巴夜鹰（英文名：Cuban Nightjar，学名：Antrostomus cubanensis），是夜鹰目夜鹰科卡氏夜鹰属的鸟类。为古巴特有种。体长约25至29.5厘米，雄鸟体重约76克，雌鸟约70克。上体呈暗褐色，点缀着灰色、淡色和灰褐色斑点。其独特的低沉‘weeyo’声在夜间快速连续发出，易于识别。","appearance":"雄性古巴夜鹰的尾巴尖端为白色，而雌鸟为淡黄色。翅膀较短，未达尾尖，与安岛夜鹰形成区别。脸部棕褐色，带有暗褐色斑点，胸部深褐色，饰以大块斑点和小点的淡黄白色，腹部及两侧为深褐色，伴有灰色斑点。","call":"鸣唱特征为略显粗糙、嗡嗡的单音节叫声，音调起伏，总体呈现下降趋势。","habits":"古巴夜鹰栖息于密林边缘、开阔的树林和沼泽边缘地带，常在夜晚沿着道路活动，眼睛在车灯或观鸟者的聚光灯下闪烁。它们在地面或枝头捕食昆虫，白天则在地面或低矮的栖木上休息。","breeding":"繁殖季节在3月至7月间，通常产两枚蛋直接放置于地面，无需筑巢。雄鸟和雌鸟都会参与孵化。","identification":"与迁徙的卡氏夜鹰相似，但古巴夜鹰的羽毛颜色更深，尾部特征在下方视角更为明显，翅膀长度不到尾部末端，这有助于与安岛夜鹰的区分。","protection":"IUCN：LC（无危）","distribution":"古巴夜鹰主要分布在古巴主岛及其周边多数小岛，亚种A. c. insulaepinorum仅限于Isla de la Juventud（青年岛，前称松树岛）。","other":"古巴夜鹰曾被归入Caprimulgus属，后恢复为独立的Antrostomus属。"},{"name":"斯岛夜鹰","english_name":"Hispaniolan Nightjar","scientific_name":"Antrostomus ekmani","appearance":"伊岛夜鹰体型介于26至30厘米（10至12英寸）之间，上身呈深棕色，带有灰色、浅黄色和灰棕色斑点，头部有宽大的黑色条纹。尾巴为棕色，雄鸟的外侧三对尾羽尖端为白色，雌鸟则为浅黄色。翅膀为棕色，带有较浅色的斑点和条纹。脸部为浅褐色，点缀着深棕色斑点，下巴和喉咙为深棕色，带有肉桂色斑点。胸部为深棕色，带有大斑点和小斑点的浅黄色白色，腹部和侧面为深棕色，带有灰色斑点。与之相比，古巴夜鹰的Island of Youth亚种更小、更暗，尾巴更短。","call":"伊岛夜鹰的叫声被描述为略带粗糙的单音节嗡嗡声，开始时有一个咔哒声，音调逐渐升高。其干扰叫声为低沉、短暂的叫声，听起来像是‘quat…quat…quat…’。","habits":"伊岛夜鹰是黄昏和夜间活动的鸟类，主要栖息在中海拔的阔叶林中，避开低海拔的荆棘灌木丛和高海拔的松树林。它通过飞行捕食昆虫，具体是在持续飞行中捕食还是从栖木或地面出击尚不清楚。","breeding":"繁殖季节在4月至7月之间，通常产两枚蛋直接放在地面上，无需筑巢。据信双亲都会参与孵卵。","identification":"与迁徙的卡氏夜鹰相似，但羽毛颜色更深，且雄鸟尾部尖端为白色，雌鸟为浅黄色，这可能只有从下方观察时才明显。当从上方看时，苍白的尾尖并不显眼，这有助于将其与较小的中美夜鹰区分开来，后者尾部末端有一条狭窄且定义明确的带状图案。短翼不触及尾尖，有助于区分它与安岛夜鹰。","protection":"IUCN：LC（无危）","distribution":"伊岛夜鹰仅在海斯皮奥洛岛上发现，该岛分为多米尼加共和国西部三分之一地区和海地。在多米尼加共和国西部比东部更为常见，在海地则极为罕见。","other":"物种以瑞典自然学家Erik Leonard Ekman命名，他在19世纪首次描述了这一物种。"},{"name":"褐领夜鹰","english_name":"Tawny-collared Nightjar","scientific_name":"Antrostomus salvini","overview":"褐领夜鹰（英文名：Tawny-collared Nightjar，学名：Antrostomus salvini），是夜鹰目夜鹰科卡氏夜鹰属的鸟类。特有于墨西哥东部，常见于干旱至半湿润地区的浓密灌木林和荆棘森林。其最显著的特征是颈部的肉桂色环状斑纹，上身则带有棕色、黑色和灰色的迷彩图案。雄鸟个体尾羽末端有白色，而雌鸟则为较窄的淡黄色或白色。","appearance":"这种夜鹰体型中等偏大，体长约23-25.5厘米。雄鸟上身呈黑褐色，头部有黑色斑点，背部和臀部有细小的棕色斑点和宽阔的黑色条纹。最突出的特征是颈后的肉桂色或淡黄色环状斑纹。尾羽深褐色，外侧三对尾羽有宽白边。翅膀颜色从棕色到黑褐色，有肉桂色斑点和横纹。面部暗红色，有棕色条纹。雌鸟相似，但尾羽末端仅有窄带淡黄色，翼上的肉桂色标记更淡，喉部下方的带子呈淡黄色而非白色。雌雄均有黑色的冠和喉咙，与浅色的前颈环形成鲜明对比。","call":"其叫声独特，为急促的两音节‘chi-wihw’或‘tchi-wheeu’，重复迅速，通常在黎明和黄昏从树丛中的隐蔽枝头发出，主要在3月至7月间。","habits":"褐领夜鹰主要栖息于东北墨西哥的干旱至半湿润地带，包括灌木林、荆棘森林和茂密的灌丛。它们偏好从树枝或地面出击捕食飞行中的昆虫，是夜行性鸟类。在繁殖季节以外，部分个体可能向南迁移。","breeding":"繁殖期从4月至8月，每次产卵数量为两枚，如同其他夜鹰一样，通常直接在地面产卵而不筑巢。","identification":"与相似物种如墨西哥三声夜鹰、卡氏夜鹰相比，褐领夜鹰具有独特的肉桂色颈圈，且体型较小。与尤卡坦褐领夜鹰的区别在于后者尾羽的白色更广泛，冠部和肩羽颜色更浅。","protection":"IUCN：LC（无危）","distribution":"主要分布在墨西哥东部，从新莱昂州和塔毛利帕斯州南部至韦拉克鲁斯州。海拔分布范围从海平面至500米。","other":"曾被认为是丝尾夜鹰的亚种，现确认为独立物种。"},{"name":"尤卡褐领夜鹰","english_name":"Yucatan Nightjar","scientific_name":"Antrostomus badius","appearance":"尤卡坦褐领夜鹰是一种中等体型的暗色夜鹰，身长约为24至25.5厘米。雄鸟的上体呈灰褐色，头部有黑色斑点和灰色斑纹，背部和臀部饰有淡色和肉桂色斑点，以及宽幅的黑色条纹。颈部和侧面有一圈醒目的棕褐色或淡黄色颈环。尾羽为棕色，带有微弱的肉桂色横纹，最外侧三对尾羽末端有宽阔的白色斑块，而最内侧一对尾羽末端则有灰褐色的斑驳。翅膀为棕色至灰褐色，饰有肉桂色斑点和横纹。脸部为肉桂色，饰有黑色斑点。下巴和喉咙为深棕色，带有肉桂色条纹，下喉部有一条狭窄的白色带。胸部为棕色，饰有淡色和肉桂色斑点，腹部和两肋为黑褐色，饰有肉桂色斑点、棕色条纹和许多白色斑点。雌鸟与雄鸟相似，但外侧尾羽的淡色尖端更小，且为淡黄色而非白色。","call":"尤卡坦褐领夜鹰的鸣唱清晰响亮，表现为“puc ree-u-reeeu'”或“pc weeu wee-weeeu”的多音节歌曲，通常从灌木或树上的隐蔽位置发出，主要在2月至8月间听到。此外，它还会发出坚硬空洞的“k-lok k-lok ...”或“p-tok ...”的啄食声。","habits":"尤卡坦褐领夜鹰主要栖息于尤卡坦半岛的灌木丛生的林地、林缘和其他灌木丛生的生境。它们是夜间活动的猎手，主要从林缘的栖木上出击捕食飞行中的昆虫，有时甚至在较为开阔的区域的栅栏柱上狩猎。在冬季，至少部分个体会向南迁移至伯利兹南部和洪都拉斯西北极地区域。","breeding":"尤卡坦褐领夜鹰的繁殖季节尚未明确界定，但据观察，每窝通常产两枚蛋，如同多数夜鹰一样，它们可能直接在地面筑巢，而不建巢。","identification":"与尤卡坦夜鹰相比，尤卡坦褐领夜鹰的尾巴具有更广泛的白色角落，而且面部和喉咙不如后者那么单调。雄性尤卡坦褐领夜鹰的尾部有广泛的白色斑点，而雌鸟的尾部角落则是较窄的淡黄色。与帕拉夜鹰的区别在于，后者缺乏棕褐色的颈环，耳部为赤褐色，且初级飞羽上有白色的（雄鸟）或淡黄色的（雌鸟）横带。卡氏夜鹰和墨西哥三声夜鹰缺乏棕褐色的颈环；卡氏夜鹰体型更大，颜色更接近肉桂色。与尤卡坦褐领夜鹰地理隔离的褐领夜鹰非常相似，但尾羽的白色尖端较小，喉部的白色带也不那么突出；这两种物种的叫声也不同。","protection":"IUCN：LC（无危）。尽管其成熟个体的数量估计至少为50,000，但正在减少。目前尚未识别到直接威胁。","distribution":"尤卡坦褐领夜鹰全年居住在墨西哥的尤卡坦半岛和科苏梅尔岛沿海。在繁殖季节以外，它们会访问伯利兹和洪都拉斯西北部，也有少量记录显示在这一时期出现在危地马拉北部。"},{"name":"丝尾夜鹰","english_name":"Silky-tailed Nightjar","scientific_name":"Antrostomus sericocaudatus","overview":"丝尾夜鹰（英文名：Silky-tailed Nightjar，学名：Antrostomus sericocaudatus），是夜鹰目夜鹰科卡氏夜鹰属的鸟类。相对较大的南美夜鹰，主要分布在巴西、阿根廷、玻利维亚、巴拉圭和秘鲁的热带雨林和亚热带森林中。其最显著的外部特征是长长的翅膀和丝般的尾羽。雌雄异色，雄鸟具有白色尾羽尖，而雌鸟的尾羽尖呈淡褐色。","appearance":"丝尾夜鹰体长24至31厘米，是一种体型较大的夜鹰，两性异形明显。雄鸟拥有独特的白色颈圈，尾羽外缘白色；雌鸟的白色被淡褐色取代。整体羽毛呈暗色，带有黑色斑点和条纹，上部有黑色宽斑点和条纹，下部棕色和白色斑点相间。雄鸟的尾巴末端有白色，雌鸟则是淡褐色。","call":"其叫声是一系列忧郁起伏的‘doh, wheo, eeo’声，经常长时间重复。","habits":"丝尾夜鹰偏好森林边缘和内部，尤其喜欢灌木丛和竹林下层的环境。它们的活动范围广泛，主要在夜间活动，白天则隐藏在茂密的植被中。以昆虫为食，通过空中捕食。","breeding":"繁殖期从8月持续到12月，与干季中期至雨季开始重叠。筑巢于地面，雌雄双方共同孵卵，孵化和育雏。求偶时，雄鸟会发出比平时更快的歌声，雌鸟会飞到附近的一个水平枝上，雄鸟展开尾巴扇形，降低翅膀，向雌鸟飞去。","identification":"与Yucatan夜鹰(Caprimulgus badius)和Tawny-collared夜鹰(Caprimulgus salvini)相比，丝尾夜鹰体型更大，颜色更深，雄鸟有明显的白色颈圈和尾羽尖，而Yucatan夜鹰的颈圈更窄且呈浅褐色，Tawny-collared夜鹰雄鸟的尾羽尖更宽。","protection":"IUCN：LC（无危）","distribution":"丝尾夜鹰广泛分布于南美洲的亚马逊盆地和大西洋森林区域，包括巴西、阿根廷、玻利维亚、巴拉圭和秘鲁的热带雨林和亚热带常绿森林。","other":"尽管丝尾夜鹰目前被列为无危物种，但由于其栖息地——大西洋森林和亚马逊盆地正不断受到人类开发的威胁，已知的丝尾夜鹰种群可能会迅速减少。"},{"name":"黄领夜鹰","english_name":"Buff-collared Nightjar","scientific_name":"Antrostomus ridgwayi","overview":"黄领夜鹰（英文名：Buff-collared Nightjar，学名：Antrostomus ridgwayi）是夜鹰目夜鹰科卡氏夜鹰属的鸟类，又称Ridgway's Whip-poor-will。分布于中美洲墨西哥西北部至尼加拉瓜，以及美国的东南亚利桑那州和西南新墨西哥州。以其独特的亮色颈环和金属质感的上升调鸣声闻名。","appearance":"黄领夜鹰体长22至23厘米，体重约48克。头、背部及尾羽呈灰褐色，饰以灰色、奶油色和锈色斑点。最显著特征为颈部后方的亮肉桂色颈环，以及喉部下方的窄白色带。雄鸟的尾羽末端内侧为白色，雌鸟则为淡肉桂色小尖端。两性相似，但雌鸟前颈环白色较少。","call":"鸣声独特，为一系列急速加速的空洞‘咕噜’声，结尾突然下降成强调的‘chee-aa’。","habits":"栖息于灌木林地、荆棘森林边缘和邻近的开阔地带，主要活动于黄昏和黎明，白天藏身于低矮植被下的地面。以夜间飞行昆虫为食，通过从栖息地飞起至10米高并返回原地的方式觅食。","breeding":"繁殖季节大致在4月至6月间，筑巢于地面，通常选择阴凉处，不建巢，仅避开较大石块。已观察到成鸟为了保护巢穴而展示断翅行为。","identification":"与墨西哥三声夜鹰和三声夜鹰相比，整体色调更浅，冠部条纹更细。雄鸟尾羽特征明显区别于雌鸟。鸣叫声区别明显。","protection":"IUCN：LC（无危）","distribution":"在中美洲，分布于墨西哥西北部至尼加拉瓜；在美国，限于东南亚利桑那州和西南新墨西哥州，高度在933至1400米之间。","other":"在墨西哥，可能面临栖息地丧失的潜在威胁；其在美国的分布区域几乎全部受到某种形式的保护。"},{"name":"三声夜鹰","english_name":"Eastern Whip-poor-will","scientific_name":"Antrostomus vociferus","overview":"三声夜鹰（英文名：Eastern Whip-poor-will，学名：Antrostomus vociferus），是夜鹰目夜鹰科卡氏夜鹰属的鸟类。中等体型的夜行鸟类，以其清脆响亮的‘whip-poor-will’三音节鸣叫著称。该鸟广泛分布于北美中南部和东南部的加拿大，以及美国中东部和东部地区，冬季迁徙至美国东南部、墨西哥和中美洲。其羽毛呈现复杂的灰褐黑混合色，具有极佳的伪装效果。","appearance":"三声夜鹰体长约22-26厘米，翼展约45-50厘米，体重在42-69克之间。头部圆大，胸部健硕，尾部和翅膀较长，赋予其前重后轻的独特外观。上体由灰色、黑色和棕色斑驳构成，下体为灰色和黑色相间的条纹。拥有极短的喙，黑色喉部明显。雄性三声夜鹰喉下有一块白色斑点，尾羽外侧边缘有明显的白色尖端；雌鸟的相应部位则为浅棕色。","call":"三声夜鹰以其标志性的‘whip-poor-will’鸣唱闻名，这是一种响亮而清晰的哨音，反复吟唱，几乎无休无止。","habits":"三声夜鹰栖息于北美的开阔林地，偏好混合松树和落叶树的森林环境，附近需有开阔地带供其夜间捕食。它们主要以飞行中的昆虫为食，如蛾子、甲虫、蚊子等。昼伏夜出，日间通常隐蔽于地面或树干上，难以察觉。","breeding":"三声夜鹰在地面筑巢，巢址选在阴凉处，巢中通常产两枚蛋，蛋壳呈白色，带褐色和淡紫色斑点。繁殖季节，雌鸟承担大部分孵卵和育雏任务，雏鸟孵化后不久便能离巢活动。","identification":"与近似种卡氏夜鹰相比，三声夜鹰体型较小，头部和翅膀更短。查克威尔斯寡妇夜鹰体型更大，颜色偏红棕色，喉咙为棕色，尾羽雄鸟个体的白色区域较小。雄性三声夜鹰尾羽外侧的白色尖端比卡氏夜鹰更为宽阔。","protection":"IUCN：NT（近危）","distribution":"繁殖于加拿大中南部和东南部，美国中东部和东部。非繁殖期分布于美国东南部，墨西哥和中美洲。","other":"三声夜鹰和墨西哥三声夜鹰最近被划分为两个独立物种，主要依据是它们的叫声差异、分布范围不重叠以及DNA序列分析显示的遗传分化。"},{"name":"墨西哥三声夜鹰","english_name":"Mexican Whip-poor-will","scientific_name":"Antrostomus arizonae","overview":"墨西哥三声夜鹰（英文名：Mexican Whip-poor-will，学名：Antrostomus arizonae），是夜鹰目夜鹰科卡氏夜鹰属的鸟类。中等体型的夜鹰，广泛分布于北美西南部、墨西哥以及北中美洲。其最显著的特征为灰褐色的上体，带有黑色条纹的冠羽，以及黑白相间的喉部与胸部。雄鸟的最外侧三对尾羽有宽阔的白色尖端，而雌鸟的相应部位则呈现较窄的淡色。声音特征是标志性的‘whip-poor-will’鸣叫，但音调较低，节奏更为缓慢。","appearance":"墨西哥三声夜鹰长约23至24厘米，体重介于45到50克之间。头部较大且扁平，眼睛周围有睫毛，喙小，边缘由长而未分支的触须包围。脚较小，中趾爪内侧有栉状结构。尾巴和翅膀呈圆形。羽毛颜色为灰褐色，上面布满黑色条纹，冠部有宽大的黑色条纹。腹部为浅黄色，带有棕色条纹，从胸到腹部逐渐变为更深的棕色。喉咙下方有一条白色的带子，与上方的黑色喉咙和下方的深棕色胸部形成鲜明对比。翼覆羽为灰褐色，点缀着淡黄色和棕色斑点。飞行时，翅膀为棕色，带有深色斑点，肩胛骨处有大量斑点。雄鸟的最外侧三对尾羽有宽阔的白色尖端，雌鸟的相应部位则呈现较窄的淡黄色尖端。没有季节性换羽。","call":"发出类似其名字的‘whip-poor-will’叫声，但音调更低沉，节奏更缓慢，声音质感粗糙。","habits":"墨西哥三声夜鹰主要栖息于山丘和峡谷中的森林地带，偏好松树和落叶树混合的环境，附近有开阔地带用于觅食。夜间从地面捕食飞虫。这种夜行性鸟类在黎明和黄昏最为活跃，以昆虫为食，包括蛾类和甲虫。","breeding":"在地面上直接产卵于枯叶层中，通常在5月至6月初。每次产卵两枚，由雌雄双方共同孵化。幼鸟孵化后覆盖有橙色绒毛，外观与成鸟相似，但具有一些差异，如冠羽上的灰色斑点，翼覆羽的完整棕色尖端等。","identification":"与三声夜鹰极为相似，但可通过雄鸟尾羽的白色尖端宽度、叫声的不同以及栖息地的差异来区分。比北美小夜鹰体型更大，尾羽更长，尾尖有更多的白色。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国西南部至洪都拉斯，非繁殖期分布于墨西哥中部南部至洪都拉斯。","other":"直到2010年，墨西哥三声夜鹰与三声夜鹰被归为同一物种，后因遗传学、形态学和声音差异而被分类为独立物种。"},{"name":"波多黎各夜鹰","english_name":"Puerto Rican Nightjar","scientific_name":"Antrostomus noctitherus","appearance":"波多黎各夜鹰体长约22厘米，羽毛呈斑驳的灰、棕、黑色，具隐蔽色。雄鸟喉部黑色，边缘环绕白色条带。尾羽外侧有显著白色，雌鸟喉部和尾羽尖端为淡黄色。孵化时的雏鸟有红肉桂色绒毛。成年个体在能持续飞行前已展现出成鸟的羽毛图案。","call":"波多黎各夜鹰以其重复、模糊的“whip, whip, whip, whip...”或“weep, weep, weep, weep...”的叫声被更多地听到而非看到。","habits":"它们在树干上狩猎昆虫，白天栖息于树枝上，平行于枝干，有时也会在地上休息。夜间则在树冠下飞行捕食。雄鸟全年鸣唱，尤其在4月和5月达到高峰。","breeding":"繁殖季节在2月至7月初，夜鹰会在地面的落叶层直接产下1-2枚蛋，由双亲共同孵卵和育雏。雄鸟常在白天孵卵和照料幼鸟。孵化期约18-20天，半成熟的雏鸟在孵化后14天即可短距离飞行，但在离巢数周后仍留在父母领地。","identification":"与卡氏夜鹰相比，波多黎各夜鹰的尾部更缺乏锈色，且尾尖有白色。与安岛夜鹰区别在于后者翅膀尖锐，翼上有明显白色带，且体型较大，羽毛颜色偏红棕色。","protection":"IUCN：VU（易危）","distribution":"波多黎各夜鹰主要分布在北美波多黎各的西南部，包括Guánica生物圈保护区及其周边的高海拔森林，以及从Cabo Rojo至Guayama东南部地区。","other":"夜鹰的栖息地主要位于私人土地和保护区之外，保护措施的不足是其恢复的最大障碍。扩大保护区网络和走廊，以及在公私土地上管理森林以促进夜鹰筑巢，对于确保物种长期生存至关重要。"},{"name":"美洲乌夜鹰","english_name":"Dusky Nightjar","scientific_name":"Antrostomus saturatus","overview":"美洲乌夜鹰（英文名：Dusky Nightjar，学名：Antrostomus saturatus），是夜鹰目夜鹰科卡氏夜鹰属的鸟类。在中美洲的分布相对局限，仅见于哥斯达黎加中部至巴拿马西部的高地云雾森林边缘，海拔介于1500至3100米之间。此鸟以夜间活动著称，其羽毛呈现复杂的暗褐色图案。","appearance":"美洲乌夜鹰是一种中等体型的夜行性鸟类，全长约21至25厘米。雄鸟上体为烟黑色，带有细小的红肉桂色斑点；面部部分也是红肉桂色。中央尾羽为烟黑色，带红肉桂色条纹；最外侧三对尾羽有宽阔的白色尖端，而条纹较少。翅膀呈深黑色，带有红肉桂色的条纹。喉咙和胸部为烟黑色，散布着白色斑点，有一条狭窄的白黄分离带。腹部为肉桂色到黄色，带有狭窄的黑色条纹。雌鸟与雄鸟相似，但红肉桂色标记更大，整体看起来更红。幼鸟比成鸟颜色稍浅，更偏向红肉桂色。","call":"雄鸟的鸣声为颤音双音节口哨声‘prurrr prureee’或‘prurrrr prruwhip’，通常在繁殖季节期间从树梢发出，有时也会在满月之夜持续鸣唱。","habits":"美洲乌夜鹰栖息于高海拔地区的云雾森林边缘，偏好在草地或开阔地带活动。它们主要在夜间觅食，通过从几米高的栖木上突袭捕捉飞行中的昆虫，如甲虫和蛾子。","breeding":"繁殖季节从2月至4月，已知的一个巢是一个位于草丛和蕨类植物间的草衬凹陷，内含一枚卵。","identification":"与三声夜鹰相比，美洲乌夜鹰体型较小，羽毛颜色更偏向红肉桂色，喉部有黄色带，翅膀上没有白色的主翼覆羽条纹。雄鸟的最外侧尾羽有宽阔的白色尖端，而雌鸟则为黄色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加中部至巴拿马西部的高山地区，主要栖息在1500至3100米的云雾森林边缘。"},{"name":"非洲褐夜鹰","english_name":"Brown Nightjar","scientific_name":"Veles binotatus","overview":"非洲褐夜鹰（英文名：Brown Nightjar，学名：Veles binotatus），是夜鹰目夜鹰科褐夜鹰属的鸟类。是褐夜鹰属的唯一物种。分布于非洲利比里亚至刚果民主共和国中部，主要栖息于低地雨林，以昆虫为食。","appearance":"非洲褐夜鹰体长21–23厘米，重约63克，两性相似，但雌鸟略淡。上体及翼覆羽深棕色，密布土黄色和栗棕色斑点，无颈环；喉部两侧有小白色斑点；口须短而弱；下体暗棕色，杂有土黄和栗棕色斑纹；外侧初级飞羽弯曲，尾部僵硬，休息时呈倒V形；两性均无翼和尾部的白色标记。虹膜棕色，喙暗棕色至黑色，腿和脚暗棕色至黑色。幼鸟与成鸟相似，但肩羽和内侧覆羽呈淡灰色，有深棕色斑点。","call":"雄鸟的鸣唱是一系列重复的、金属质感的“twoh”或“kliou”音节，类似于Epomops蝙蝠的叫声，通常在黎明和黄昏时从树梢或飞行中发出，每分钟可达21个音符。","habits":"主要栖息于低地雨林，包括常绿和半常绿类型，偏好有开阔树冠和茂密下层植被的环境，尤其在姜科和芭蕉科植物附近。活动范围从地面至森林树冠，有时在小溪边缘。夜间活动，以昆虫为主食，黄昏时从树梢捕食。","breeding":"繁殖季节可能在1月到3月间，巢址可能位于地面，如在Raphia棕榈的拱形叶片上。成鸟在孵卵或育雏时会展示威胁姿态，张大嘴巴，呈现出类似蟾蜍的外观。","identification":"与贝氏夜鹰相似，但后者体型更大，停歇于地面，雄鸟翼和尾有白色标记。","protection":"IUCN：LC（无危）","distribution":"分布于利比里亚至刚果民主共和国中部，包括喀麦隆、中非共和国、刚果共和国、刚果民主共和国、象牙海岸、加蓬、加纳和利比里亚。"},{"name":"红颈夜鹰","english_name":"Red-necked Nightjar","scientific_name":"Caprimulgus ruficollis","overview":"红颈夜鹰（英文名：Red-necked Nightjar，学名：Caprimulgus ruficollis），是夜鹰目夜鹰科夜鹰属的鸟类。欧洲最大的夜鹰之一，以红褐色颈部而得名。繁殖于伊比利亚半岛至北非，冬季迁徙至西非热带地区。","appearance":"体长30-32厘米，体重60-119克，具有性别二态性。上体灰褐带黑色条纹，颈后有宽阔的淡色环，翅膀覆羽具灰色斑点，肩羽黑色边缘明显，翼下白色或淡色条纹，喉部白色斑块。雄鸟有显著的白色翼斑和尾羽尖端，雌鸟翼斑和尾斑较小。虹膜深棕色，喙角棕色或深棕色，腿脚灰棕色。较欧洲夜鹰大15%，色调更暖。","call":"发出重复的机械式‘kyok-kyok-kyok...’叫声，音量随头部转动而升降。飞行时偶尔发出‘cutow’声，孵化期间会发出加速敲击声。","habits":"栖息于松树林、半沙漠地带、橄榄树丛等低地或山坡的开阔地带，偏好有零星植被和裸露地面的环境。以飞蛾、蚊子、甲虫等昆虫为食，偶尔在地面觅食。夜间活动，尤其在黄昏时分。","breeding":"繁殖期从5月初至8月底，可能双窝繁殖。通常独居，有时形成松散的群落。巢筑于地面，每窝产1-2枚椭圆形、光滑的白色或奶油色蛋，带有灰色和棕色斑点。孵化期14-19天，雏鸟出生后16-18天首次飞行，4-5周后独立。","identification":"与欧洲夜鹰相比，红颈夜鹰体型更大，颜色更暖，翼斑位置更靠近翼尖，尾羽看起来更长。幼鸟较成鸟更灰白，颈后环减少。","protection":"IUCN：NT（近危）","distribution":"繁殖于伊比利亚半岛至北非，冬季迁徙至西非热带地区。"},{"name":"丛林夜鹰","english_name":"Jungle Nightjar","scientific_name":"Caprimulgus indicus","overview":"丛林夜鹰（英文名：Jungle Nightjar，学名：Caprimulgus indicus），是夜鹰目夜鹰科夜鹰属的鸟类。广泛分布于印度次大陆，主要栖息于森林边缘地带。曾被称为灰夜鹰或印度丛林夜鹰，其分类较为复杂，涉及亚洲多个近似物种。本种与普通夜鹰关系密切，一度被视作其亚种。","appearance":"体长21-24厘米，性别二型性明显。上体灰褐色，具黑色条纹，头部尤为显著；翼下无显眼斑块，呈赤褐色。尾羽灰色，间有细窄黑纹。雄鸟喉部有白色斑点，中央断裂；雌鸟喉部赤褐色，具亚颊纹。虹膜深棕色，喙及腿足棕色。","call":"鸣声独特，常发出一系列快速的‘thacoo’或‘chuck’音节（每2秒约5次），类似远处引擎的运转声。其歌唱为缓慢而规律的‘FWik-m’音符串，持续长达10秒，有时以快速的‘foo-foo’哨音结束，类似吹过空瓶产生的声音。","habits":"活跃于黄昏时分，偏好丘陵草甸或灌木丛地带，常见于树上或突出的岩石上栖息。白天在树上休息，沿枝干排列。主要以蛾类、甲虫、蝽象、飞蚁、蝉、蚱蜢、蝗虫和小型胡蜂为食，捕食时飞行敏捷，常在林间空地或树梢附近猎食，亦会受人造光源吸引的昆虫。","breeding":"繁殖期为2月至5月（印度），南印度为2月至8月，斯里兰卡为2月至7月。巢址通常选在岩石旁或植被遮蔽下的密林中，地面裸露处或灰烬上（野火后）。每窝产卵1-2枚，卵色为淡红褐色至粉白色，布满黑色或红褐色斑点，尺寸28.2-34mm x 20.1-24mm。孵化由雌鸟为主，雄鸟早晚轮流，孵化期约16-17天。雏鸟约17-18天离巢。","identification":"与长尾夜鹰和印度长尾夜鹰相比，翼覆羽上的斑点更为醒目，雄鸟的两根最外侧尾羽尖端仅部分白色。与菲律宾夜鹰区别在于翼覆羽上的大胆斑点，以及前翼的浅色线条。","protection":"IUCN：LC（无危）","distribution":"分布于印度和斯里兰卡，适应力强，常见于许多地区的森林边缘和农业区。","other":"历史分类中，本种曾包含广泛的迁徙亚种jotaka和phalaena，现已独立为普通夜鹰。"},{"name":"普通夜鹰","english_name":"Grey Nightjar","scientific_name":"Caprimulgus jotaka","overview":"普通夜鹰（英文名：Grey Nightjar，学名：Caprimulgus jotaka），是夜鹰目夜鹰科夜鹰属的鸟类。又名: 蚊母鸟、贴树皮、鬼鸟、夜燕，分布广泛的夜行性鸟类。体长约为270毫米，翅展约210毫米，通体呈暗褐色斑驳状，拥有良好的保护色。广泛分布于亚洲东部至东南亚，北自西伯利亚，南至日本、印度等地。","appearance":"普通夜鹰体长24–27厘米，体重77–91.8克，雌雄异形。雄鸟头部中央有宽黑斑，颈上有红褐色条纹，肩部有红褐色斑点的黑色条纹，翅膀覆羽深灰色带红褐色斑点，初级飞羽黑色尖端较淡，尾羽上覆羽和尾羽有明显的黑色横纹及不连续的白色亚端斑。雌鸟上体颜色略暖，喉部有明亮的红褐色斑块和次级髭纹，腹部有更重的条纹。幼鸟冠部标记较少，翅膀覆羽和三级飞羽更浅，胸部和尾下覆羽条纹更细。","call":"鸣唱为快速、均匀间隔的‘SCHurk’SCHurk’SCHurk’SCHurk...’音符，节奏约为5-6音符/秒，每段之间有1-2秒或更长时间的停顿，单次鸣唱可持续长达7分钟。叫声比长尾夜鹰更快、更有节奏感，但不如赤胸拟啄木鸟的叫声响亮。","habits":"普通夜鹰主要在夜间活动，黄昏时分在空中捕食昆虫最为活跃。它适应性强，栖息于早期演替的森林边缘地带，如开阔的灌木丛、林地边缘、烧毁后的植被区。分布海拔从海平面到约3400米，但在印度次大陆主要繁殖于1800米以上高度。","breeding":"繁殖季节从5月至8月不等，具体时间随地区变化。巢建在岩石旁或被植被覆盖的地方，如灌木丛中或石坡上，不筑巢，直接将卵产于落叶层、裸土或火烧后的灰烬上。一窝通常产1-2枚卵，卵呈椭圆形，底色为蓝白色、淡奶油色或灰白色，带有暗灰色或灰褐色的斑点和大理石纹，大小为27.9–34.4毫米×21–24.4毫米。孵卵主要由雌鸟承担，偶尔雄鸟也会在黄昏和黎明时接替，孵化期一般为16-19天。雏鸟在约17天后离巢。","identification":"普通夜鹰与欧夜鹰主要通过分布区区分，欧夜鹰主要分布在新疆，普通夜鹰则在中国内地大部分地区分布，二者在内蒙古中部偏北有分布重叠。与丛林夜鹰相比，普通夜鹰体型较大，雄鸟尾羽外侧无白色。","protection":"IUCN：LC（无危）。普通夜鹰在日本自1970年代以来数量有所下降，但在部分区域仍较为常见。","distribution":"繁殖于喜马拉雅山脉至亚洲东部和东南部，非繁殖期分布于印度次大陆、东南亚南部至大巽他群岛。","other":"普通夜鹰在日本、中国、俄罗斯东部等地是常见的夏季访客，马来西亚则为主要迁徙和越冬地点。"},{"name":"帕劳夜鹰","english_name":"Palau Nightjar","scientific_name":"Caprimulgus phalaena","overview":"帕劳夜鹰（英文名：Palau Nightjar，学名：Caprimulgus phalaena）是夜鹰目夜鹰科夜鹰属的小型灰褐色夜行性鸟类。特有于帕劳群岛，曾被视为丛林夜鹰的亚种。","appearance":"体长21至23厘米，具有灰褐色外观，胸背部及中央尾羽呈栗棕色，喉部有一白色斑块，翼覆羽带淡色斑点，尾羽外缘和部分飞羽末端有小白斑。雌鸟这些部位为栗棕色。","call":"最常见的是低沉、略微加速的连续'kew'音，当停栖时发出。飞行中会发出'karump karump'-似的叫声。","habits":"夜间活动，栖息于红树林和低地森林边缘。帕劳群岛唯一的夜鹰种类。","identification":"与和相比，体型更小，翼长平均值显著差异，下翼覆羽和下尾羽颜色不同，以及羽毛上的色斑和翼尾标记的差异。","protection":"IUCN：LC（无危）。全球范围内受威胁程度较低，但在帕劳群岛，估计成熟个体数不超过1000-2500只，自20世纪70年代晚期开始数量减少。","distribution":"分布于远东地区的帕劳（加罗林群岛西部，密克罗尼西亚西部）。在Arakabesan、Babelthuap、Koror和Peleliu等岛屿均有记录。","other":"目前无其他重要信息记录。"},{"name":"欧夜鹰","english_name":"European Nightjar","scientific_name":"Caprimulgus europaeus","overview":"欧夜鹰（英文名：European Nightjar，学名：Caprimulgus europaeus）是夜鹰目夜鹰科夜鹰属的鸟类，又名欧洲夜鹰。广泛分布于欧洲大部分地区和亚洲温带地区至蒙古，以及非洲西北部。体长24.5-28厘米，棕灰色羽毛上布满杂斑和纵纹，昼伏夜出，以昆虫为食。此鸟善于伪装，羽色似枯叶，白天难觅踪影。","appearance":"成年欧夜鹰体型介于24.5-28厘米，雄鸟体重51-101克，雌鸟67-95克。上体呈灰褐色，饰有黑褐色条纹，颈部有淡黄色项圈，翅膀覆羽棕色，其余部分灰褐色并饰有淡黄色斑点。下体灰褐色，带有棕色条纹和淡黄色斑点，腹部和两侧变为淡黄色条纹。雄鸟有白色翼尖斑点和尾羽末端，雌鸟缺乏白色标记。虹膜深棕色，喙黑色，腿和脚为棕色或肉棕色。幼鸟类似成年雌鸟。随地理位置不同，鸟的体型和颜色略有差异。","call":"雄性欧夜鹰发出持续的、富有特色的咕噜声，音调时高时低，通常在黄昏和夜晚鸣唱，有时从地面或树上发出声音。两性在飞行中会发出短促的‘co-ic’声，雄鸟在与雌鸟的互动中还会发出气泡般的颤音。各种叫声包括‘chunk’、‘chink’、‘chik’、‘dak’、‘chuk’、‘chek’、‘chek-ek’等。","habits":"栖息于干燥的开阔地带，包括低地灌木丛、森林空地、新植林地等。晨昏活动，日间隐藏于地面或树枝上，夜间活跃，猎食飞虫。喝水时低掠水面，类似雨燕的飞行姿态。食物以昆虫为主，包括飞蛾、甲虫、蜻蜓等。","breeding":"繁殖期从5月末至8月，有时4月至7月。单配制，领地性强。在开放地带筑巢于地面，无巢结构，直接在落叶、松针或裸土上产2枚蛋。孵化期17-21天，主要由雌鸟负责。雏鸟出生后由雌鸟照顾约10-16天，之后由雄鸟照料，若雌鸟产第二窝。雏鸟孵化后16-17天离巢，约32天后独立。","identification":"与红颈夜鹰相比，欧夜鹰体型较小，颜色较暗，翼展更短，白翼斑较小，红颈夜鹰有更明显的淡黄色颈圈和翅膀、尾部的白色标记更明显。与非洲的棕颊夜鹰和乌夜鹰相比，欧夜鹰颜色较浅，斑点较少。","protection":"IUCN：LC（无危）","distribution":"繁殖区覆盖欧洲北部至64°N，亚洲北部至60°N，东至贝加尔湖和蒙古东部。南部界限延伸至北非西北部、伊拉克、伊朗和喜马拉雅山脉西北部。所有种群迁徙至撒哈拉以南非洲过冬，部分个体可能在巴基斯坦、摩洛哥和以色列越冬。","other":"欧夜鹰的英文名'goatsucker'源自古老神话，认为它们吸食山羊奶，导致山羊无法产奶。"},{"name":"乌夜鹰","english_name":"Sombre Nightjar","scientific_name":"Caprimulgus fraenatus","overview":"乌夜鹰（英文名：Sombre Nightjar，学名：Caprimulgus fraenatus），是夜鹰目夜鹰科夜鹰属的鸟类。中等体型的夜行性鸟类，主要分布在东非地区，包括厄立特里亚、埃塞俄比亚、索马里至坦桑尼亚东北部。其最显著的外部特征是拥有一圈金色的颈环。","appearance":"乌夜鹰身长25厘米，体重介于46至71克之间，具有明显的性别二态性。上体呈深棕色，点缀着灰白色斑点并带有黑色条纹；拥有宽大的金黄色或淡褐色颈环；翼羽暗棕色，密布金黄色和淡褐色斑点；肩羽不规则地标记着黑色；具有一条白色的颊纹和喉咙斑块；下体深棕色，带淡褐色斑点，腹部和两胁呈现淡褐色条纹。雄鸟有大而明显的白色翼斑和尾羽末端，雌鸟则为淡色的翼斑和淡褐色的尾尖。","call":"其叫声为高音调的机械式颤鸣，与纯色夜鹰相似但音调略低。","habits":"通常栖息于开阔的石质灌木丛和稀树草原，也会出现在草地、鼠尾草灌木丛、Dodonaea灌木丛以及桉树林中。分布海拔从海平面到3200米。一般为留鸟，但在某些范围内会局部迁徙。以蛾类、蚱蜢、蝽象和甲虫为食，通过空中捕捉昆虫的方式觅食。","breeding":"繁殖期在不同地区有所不同，例如在索马里西北部为5月至7月，在肯尼亚西部为2月至5月及11月，在埃塞俄比亚、肯尼亚中部和南部以及坦桑尼亚东北部为1月至3月及9月至11月。可能实行一夫一妻制。没有巢穴，通常将蛋产在裸露的土地或沙地上，通常位于草丛中，有时被灌木或灌木丛部分遮蔽。每窝产1至2枚椭圆形或椭圆卵形的蛋，颜色为粉白色或粉棕色，可能也有光泽的白色，表面有淡褐色、紫罗兰色和灰色的斑点和污渍，标记集中在钝端；通常由雌鸟孵卵，至少在白天如此；雌鸟在巢址受到威胁时可能会做出受伤的分散注意力的展示。","identification":"相较于，乌夜鹰在翅膀覆盖羽和胸部有更多的斑点，后者更灰白且较浅，上体有条纹。相较于，乌夜鹰一般较小，后者较浅色，没有或仅有不明显的颈环，且在翼覆羽上有淡色线；雄鸟该物种有较小的白色翼和尾斑，雌鸟则无白色斑点。","protection":"IUCN：LC（无危）；虽然数据有限，但在适宜的生境中可能是局部常见的。","distribution":"分布于东非的厄立特里亚、埃塞俄比亚和索马里至坦桑尼亚东北部。在苏丹东南极端地区较为罕见；在索马里西北部局部常见；在肯尼亚西部和南部广泛分布且局部较为常见，出现在Tsavo West和Tsavo East国家公园；在坦桑尼亚东北部广泛分布且可能较为常见。"},{"name":"棕颊夜鹰","english_name":"Rufous-cheeked Nightjar","scientific_name":"Caprimulgus rufigena","overview":"棕颊夜鹰（英文名：Rufous-cheeked Nightjar，学名：Caprimulgus rufigena），是夜鹰目夜鹰科夜鹰属的鸟类。广泛分布于非洲南部，中等体型的夜行性鸟类。其最显著的特征是颈部模糊的棕红色饰带，两性均有翼端及尾角的浅色标记，雄鸟为白色，雌鸟则为淡黄色。迁徙物种，活跃于多种开阔生境。","appearance":"体长约23至24厘米，雄鸟体重48至65克，雌鸟46至66克。上体灰褐间黑色条纹，具窄淡黄色或肉桂色颈圈；翼覆羽灰褐色，点缀以肉桂色和淡黄色，肩羽沿缘有宽阔的淡黄色线；喉部有白色斑块；下体灰褐色，杂以淡黄色斑点，腹部和侧腹变为淡黄色横斑。雄鸟四枚最外侧初级飞羽上有大白色斑点，尾端两根外侧尾羽有白色尖端；雌鸟翼上的白色斑点较小，常带肉桂色，尾端两根外侧尾羽有淡黄色尖端。虹膜棕色，喙黑色，腿和脚为棕色。较欧夜鹰小，后者颈圈不明显或不存在，翼覆羽有淡黄色线，雌鸟翅膀和尾部无白色。颜色更深，斑点更重；雄鸟尾端两根外侧尾羽有更宽的白色尖端；雌鸟翼上有更大的淡黄色斑点，尾端两根外侧尾羽有更宽的淡黄色尖端。幼鸟类似成鸟但色泽更淡。","call":"长而干燥、快速的颤音，具体鸣叫声未详细描述。","habits":"栖息于开放的林地草原、米奥博森林、林地边缘、空地、半干旱金合欢灌木丛和半沙漠地带；也在种植园和稀疏植被覆盖的山坡上出现。活动高度从海平面至1600米。迁徙物种，非繁殖季节广泛分布于东部尼日利亚、喀麦隆、刚果共和国、刚果民主共和国和中非共和国西部。","breeding":"繁殖期为9月至11月（安哥拉和赞比亚）、9月至1月（博茨瓦纳）和9月至12月（津巴布韦和南非）。一夫一妻制，领域性。雄鸟通过在潜在巢址持续鸣叫保卫领地；雌鸟和其他雄鸟被吸引到这些地点；入侵雄鸟在地面和空中追逐中受到挑战；雌鸟测试可能的巢点，而驻地雄鸟观察、鸣叫和/或跟随并展示。巢位于部分遮阴或开阔地带，如火烧区、干枯林地或偶尔潮湿的洼地，最近砍伐的林地或开放农业区域；没有巢，卵通常直接产在裸露的地面上，倾向于避开密集的落叶层。每窝产卵1-2枚，卵呈椭圆形，表面光亮，颜色为乳白、淡黄色或淡粉奶油色，带有轻微而密集的棕色、灰色和紫罗兰色斑点，偶尔无斑点；孵化期一般为15-17天，自首枚卵开始；雏鸟覆盖着灰色、白色和红褐色绒毛，约在18-20天内离巢。","identification":"与非洲夜鹰最为相似，但颜色更淡，颈圈不那么鲜艳和明显。雄鸟翼上有更多白色，尾部白色较少；雌鸟尾角淡黄色面积更小。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要分布在非洲南部，包括安哥拉、赞比亚、博茨瓦纳、莫桑比克、纳米比亚、津巴布韦和南非（但东海岸、纳塔尔和西纳米比亚部分地区未见）。非繁殖季节分布于喀麦隆、尼日利亚、刚果共和国、刚果民主共和国、中非共和国西部、苏丹达尔富尔地区。","other":"在多个保护区有记录，包括赞比亚卡富埃国家公园、津巴布韦万基国家公园和纳米比亚埃托沙国家公园。"},{"name":"埃及夜鹰","english_name":"Egyptian Nightjar","scientific_name":"Caprimulgus aegyptius","overview":"埃及夜鹰（英文名：Egyptian Nightjar，学名：Caprimulgus aegyptius），是夜鹰目夜鹰科夜鹰属的鸟类。中等体型（约26厘米）的沙灰色夜鹰，广泛分布于南亚西南部和北非，冬季迁至非洲热带地区。其显著特征为长翼和长尾，昼伏夜出，善于隐蔽。分布范围广阔。","appearance":"成年鸟体长24-26厘米，体重68-93克（雄鸟），雌鸟略重。性别二态性不明显。上体沙灰或淡黄褐色，具黑褐色斑点；不明显的浅色颈环；翅膀沙灰或淡黄褐色，斑点和细纹为棕黑色，大胆的浅色斑点；下体沙灰或淡黄褐色，具浅色斑点和棕色条纹，腹部和侧腹变为棕色条纹。两性通常缺乏白色翼斑，但有白色下翼。雄鸟有窄白边的最外侧尾羽，雌鸟为浅色边缘。眼睛深棕色，喙黑或深褐色，腿和脚黑色、灰色或褐色。","call":"发出独特重复的粗糙音，'Rrrruu rrruu rrruu...'，其叫声为机械式的kroo-kroo-kroo…，随着头部左右转动声音有升降。","habits":"偏好开阔平坦的沙漠或半沙漠地带，常靠近水源。白天静伏于地面，夜间活跃，以昆虫为食，尤其在黄昏时分飞行捕食。飞行时振翼幅度大且有力，滑翔时双翼平展。","breeding":"在北非西北部和中南部亚洲的沙漠和沙质草原繁殖，冬季迁徙至非洲干草原地带。","identification":"比塞氏夜鹰大，后者有白色翼斑；雄鸟有宽白边的最外侧尾羽，雌鸟则为窄的浅色边缘。幼鸟较成鸟更淡且图案简单。","protection":"IUCN：LC（无危）","distribution":"繁殖于非洲西北部至亚洲中南部，冬季迁至非洲东部、中部和西部。具体繁殖区域包括北非、阿拉伯半岛和中东地区，越冬地主要在非洲热带区域。","other":"历史上曾常见于突尼斯，现较为稀少；在以色列作为繁殖物种消失，可能因农业和城市化导致栖息地丧失。"},{"name":"塞氏夜鹰","english_name":"Sykes's Nightjar","scientific_name":"Caprimulgus mahrattensis","overview":"塞氏夜鹰（英文名：Sykes's Nightjar，学名：Caprimulgus mahrattensis），是夜鹰目夜鹰科夜鹰属的鸟类。分布于南亚西北部，包括伊朗东南部、阿富汗南部、巴基斯坦和印度西部。该鸟以英国军官威廉·亨利·塞克斯命名，纪念其在印度服役期间对鸟类学的贡献。","appearance":"塞氏夜鹰体型小巧，全身呈淡灰色，尾羽较短，尾部有细密的黑色条纹，背部散布着小黑斑点，翅膀上可见淡色锈迹斑点，翼上有相对不明显的白色斑块。头部有一圈弱化的锈色颈环。成年鸟的体重介于56至58克之间，雌雄有细微的性别差异，但并不显著。上体颜色为沙灰色，点缀以黑色斑点，翼覆羽同样为沙灰色，带有黑色条纹和淡色锈色斑点。下体为沙灰色，有锈色斑点和棕色条纹，腹部和两侧变为锈色条纹。雄鸟有较大的白色翼斑，尾羽尖端白色，雌鸟翼斑较小，有时带锈色，尾羽尖端为淡黄白色。","call":"雄鸟的叫声为均匀音调的连续颤音，通常在黄昏和黎明时从地面发出，音量比欧亚夜鹰柔和，传播距离约为后者的一半。此外，它也会发出柔和的“chuk-chuk”或“cluk-cluk”声，这种声音在被惊扰时或展示行为中出现，音调低于欧亚夜鹰。","habits":"塞氏夜鹰栖息于干燥的半沙漠地带，有散生的荆棘灌木丛，也可见于干燥的石质灌木丛、砾石平原、盐碱地、石质荒地以及干旱山地岩石露头处，偶尔出现在沙漠中的稀疏沙丘。它偏好未开垦或未灌溉的地区。这是一种低地物种，海拔分布从海平面到500米。它的飞行敏捷而轻盈，善于在开阔地带，包括沼泽地上空捕食昆虫。","breeding":"繁殖季节从2月持续到8月，主要集中在3月至5月。可能形成半群居繁殖模式，至少在巴基斯坦有观察记录。巢址选择在阳光直射的地方或藏于草丛或小灌木下，如柽柳或荆棘。不筑巢，直接在裸露的、石头或盐渍化的地面上产卵。每窝产两枚椭圆形的蛋，颜色为白色或灰白色，密集地带有灰色或棕色斑点，尺寸大约为25.5-30.5毫米×19.6-22毫米。孵卵期约17-18天，主要由雌鸟承担。雏鸟为半早熟型，覆盖着灰色和黑色斑点的绒毛。","identification":"与埃及夜鹰相比，塞氏夜鹰更小，翅膀上的白色斑块更为明显，而埃及夜鹰的下翼通常是白色的。与欧亚夜鹰相比，塞氏夜鹰的颜色更加单调，呈沙色，头顶有斑点而非条纹，腿部分大部分裸露。","protection":"IUCN：LC（无危）","distribution":"繁殖于伊朗东南部、阿富汗南部、巴基斯坦以及印度西部。非繁殖季节广泛分布于印度中北部，从拉贾斯坦邦、库奇、古吉拉特邦北部、苏拉特拉、西部坎德什、德干高原和孔坎南部至迈索尔北部。","other":"塞氏夜鹰在伊朗的部分地区被认为是罕见的，但在巴基斯坦广泛且常见，主要为留鸟，仅在盐山脉、塔尔和下库拉姆谷等地为繁殖访客。"},{"name":"中亚夜鹰","english_name":"Vaurie's Nightjar","scientific_name":"Caprimulgus centralasicus","appearance":"中亚夜鹰是一种小型夜鹰，体长约19厘米。上体颜色为沙黄灰色，布满深褐色的条纹和网状斑点，没有颈圈；翅膀覆羽为沙黄灰色，带有淡黄白色的斑点；肩羽为黄白色，中间有深色条纹；下体为淡奶黄色，带有细小的褐色横斑；翅膀下方为红肉桂色，有褐色标记。眼睛为深棕色，喙为暗角质色，腿和脚为肉棕色。比小，后者略显灰色，有更多的斑点，上翼无条纹，下翼为白色，而centralasicus的外初级飞羽均匀地带有中褐色和淡黄白色的条纹。","habits":"可能栖息在干燥的平原和覆盖着矮小灌木的沙丘地带，海拔高度可达1220米。假设为迁徙鸟类，考虑到冬季新疆南部以食果鸟类为主，温度过低无法支持大量昆虫的存在。已知的唯一标本是在9月初采集的，可能代表了迁徙途中的停歇地。","breeding":"无信息。","protection":"IUCN：DD（数据缺乏）。中亚夜鹰的栖息地近年来因放牧、践踏、农业开发和木材采集受到严重破坏。多次调查未能再次发现该物种。","distribution":"在中国新疆西部（塔里木盆地西南部），可能遍布整个塔里木盆地沿昆仑山脉；推测在塔克拉玛干沙漠或北至戈壁沙漠繁殖，冬季可能迁往巴基斯坦和印度西北部的半沙漠地区。"},{"name":"努比亚夜鹰","english_name":"Nubian Nightjar","scientific_name":"Caprimulgus nubicus","overview":"努比亚夜鹰（英文名：Nubian Nightjar，学名：Caprimulgus nubicus），是夜鹰目夜鹰科夜鹰属的鸟类。小型夜行性鸟类，主要特征为较为紧凑的体型，整体呈淡沙棕色，最显著的特征是颈部后方的红褐色环带。该物种分布于非洲东北部、北部以及阿拉伯半岛西部和西南部，偏好干燥的半沙漠植被环境。","appearance":"努比亚夜鹰体长约21至22厘米，体重介于46至69克之间。上体颜色为灰或浅黄褐色，带有细密的黑色条纹，头部常有浓重的锈色斑点。颈后有一圈宽大的棕黄色环带，翼覆羽和肩羽有淡色或锈色的斑点。喉部有白色斑块，下体为淡褐色并带有棕色条纹。雄鸟具有大而明显的白色翼斑和尾羽尖端，雌鸟的翼斑和尾斑较小。虹膜深棕色，喙和腿脚为暗褐色或灰色。幼鸟较成鸟更平淡且颜色更浅，但整体相似。","call":"努比亚夜鹰的叫声类似远处的双声吠叫，通常被描述为“Kau-kau, kau-kau…”。","habits":"栖息于干燥、植被稀疏的瓦迪（干涸河床）、金合欢灌木丛（常靠近水源）、柽柳灌丛、干涸河床（含部分水源）、沙漠荆棘灌木丛、沙质灌木地、灌木状沿海沙丘及可能的盐沼。在也门，亦可见于成熟金合欢/大戟木林。海拔分布范围从海平面至1000米，偶尔可达1650米。迁徙习性和活动范围尚不明晰。","breeding":"努比亚夜鹰在地面筑巢，巢点往往形成小群，每群1至3个巢。推测其倾向于在农业区附近筑巢，以获取更多食物资源。","identification":"与细尾夜鹰相比，努比亚夜鹰体型更小，尾巴更短，翅膀更圆润。上体有锈色或淡黄色的斑点，而细尾夜鹰的内翼有明显的图案。幼鸟比成鸟更朴素且颜色更浅。","protection":"IUCN：LC（无危）。在苏丹东部、埃塞俄比亚中部和索马里北部（豪德高原）局部常见，肯尼亚广泛分布但数量稀少，以色列、约旦、沙特阿拉伯西南部和也门沿海地区稀缺。自1980年代以来，以色列的种群数量明显下降，可能已减少到仅存15至20对繁殖个体，濒临灭绝边缘。可能的原因包括栖息地丧失、农药使用和道路交通事故。","distribution":"分布于非洲东北部、北部，以及阿拉伯半岛西部和西南部，具体国家包括吉布提、埃及、厄立特里亚、埃塞俄比亚、以色列、肯尼亚、阿曼、沙特阿拉伯、索马里、苏丹和也门。","other":"努比亚夜鹰的分布和种群状况在过去几十年中有所变化，特别是在以色列，由于多种因素导致种群急剧减少。"},{"name":"金夜鹰","english_name":"Golden Nightjar","scientific_name":"Caprimulgus eximius","overview":"金夜鹰（英文名：Golden Nightjar，学名：Caprimulgus eximius），是夜鹰目夜鹰科夜鹰属的小型夜行鸟类，以其独特的金色羽毛和银色条纹著称，分布于撒哈拉以南非洲的萨赫勒地带。偏好半沙漠环境，常在低矮灌木和零星树木间活动。","appearance":"金夜鹰体长约23至25厘米，体重介于42.1至66.3克之间。雌雄外观相似，上体和翼覆羽呈黄褐色，带有灰白色矩形斑点，边缘深棕色并密布斑点，无颈环。喉部有大面积白色斑块，下体颜色逐渐变淡至腹部的无斑点黄褐色。两性均有白色翼尖斑点和尾羽外侧宽幅白边。虹膜、喙、腿和脚均为灰色黑色。幼鸟与成鸟类似，但颜色更浅，图案更简单。simplicior亚种颜色更淡，偏黄。","call":"金夜鹰的鸣唱是一连串持续时间较长的低音颤音，通常在黄昏和黎明从地面发出，速度为每秒23个音符，与纯色夜鹰的鸣唱极为相似。","habits":"金夜鹰栖息于植被稀疏的半沙漠地带，包括沙地、砾石或岩石地形，偶尔出现在废弃的农田。它们倾向于避开浓密的灌木丛或森林。活动于黄昏、夜间，白天在地面或灌木下休息，以昆虫为食，包括飞蛾、蚱蜢、螳螂、虫子和甲虫。","breeding":"金夜鹰的繁殖期在4月至5月（西部）和3月至4月（苏丹）。它们通常在地上筑巢，靠近植被丛，每次产卵2枚。","identification":"金夜鹰与同属其他物种的区别在于其独特的金色羽毛和银色条纹，以及明显的白色翼尖和尾羽末端。此外，它的栖息地偏好与活动模式也有助于与其他夜鹰科鸟类相区分。","protection":"IUCN：LC（无危）","distribution":"金夜鹰广泛分布于非洲东北部、中北部和西部，包括塞内加尔北部、毛里塔尼亚西南部、马里中部、苏丹部分地区，以及喀麦隆北部和尼日利亚查德湖盆地。最近的记录显示，它们也可能在西帕莱亚尔提克地区的摩洛哥南部西方撒哈拉繁殖。","other":"金夜鹰在2015年首次在摩洛哥南部西方撒哈拉被记录到，这可能是其在西帕莱亚尔提克区域的首次确认繁殖记录。"},{"name":"印度长尾夜鹰","english_name":"Jerdon's Nightjar","scientific_name":"Caprimulgus atripennis","overview":"印度长尾夜鹰（英文名：Jerdon's Nightjar，学名：Caprimulgus atripennis），是夜鹰目夜鹰科夜鹰属的鸟类。分布于印度南部、东部及斯里兰卡。以独特的‘bwr-wr-wr’鸣叫声著称，叫声似木板被周期性敲击，尾音颤动。纪念Thomas C. Jerdon而命名。","appearance":"头部较大，喉部白色鲜明。雄鸟翼尖和尾羽边缘有亮白斑点，雌鸟为淡褐色。与大型尾夜鹰相似，但冠部条纹较少，翼斑较小。体型比印度夜鹰小，图案更为复杂，缺乏白色喉部。雄鸟有白色翼斑和尾羽尖端，雌鸟为淡褐色。虹膜棕色，喙及脚暗棕色。","call":"叫声为快速重复的‘ch-woo-woo’，另有一种类似蛙鸣的叫声。","habits":"栖息于森林、林地和次生林，包括常绿、湿润落叶和干燥森林，以及竹林和次生林。也见于咖啡种植园和树木繁茂的郊区。活动于黄昏至黎明，以昆虫为食，如甲虫、蛾类和白蚁，飞行捕食，间歇滑翔。","breeding":"繁殖期为3月至7月在印度，2月至5月及8月至9月在斯里兰卡。无巢，通常在沙地或灌木下产卵。一窝两枚椭圆形蛋，颜色为奶油色或淡黄色，带稀疏的棕色、深棕色和灰色斑点。双亲共同孵卵，雏鸟半早熟。","identification":"与大型尾夜鹰相比，冠部条纹较少，翼斑更小。与印度夜鹰相比，体型更小，图案更复杂，喉部无白色。雄鸟和雌鸟的翼斑和尾羽尖端颜色不同。","protection":"IUCN：LC（无危）","distribution":"分布于印度南部、东部和斯里兰卡，包括各种森林类型，海拔高度从海平面至2000米。在斯里兰卡，也见于半耕作地区和灌木丛，尤其是有树木或林地的地方。","other":"物种历史中曾被认为是长尾夜鹰的亚种，后基于叫声研究确认为独立物种。"},{"name":"长尾夜鹰","english_name":"Large-tailed Nightjar","scientific_name":"Caprimulgus macrurus","overview":"长尾夜鹰（英文名：Large-tailed Nightjar，学名：Caprimulgus macrurus），是夜鹰目夜鹰科夜鹰属的鸟类。居住在远东、澳新界的夜行鸟类。分布范围自印度东部至澳大利亚北部，新几内亚和俾斯密群岛。以复杂的羽毛图案著称，通常在开放森林、次生林和耕作区的地面或低枝上休憩。","appearance":"体长25-29厘米，体重雄鸟54-79克，雌鸟60-77克，未性别区分55-90克。雄雌异形。上体灰褐带黑褐色条纹，头部条纹宽大；颈背模糊的淡黄褐色环颈；翅膀覆羽灰褐，斑点淡黄或土黄，小覆羽较暗，肩羽黑褐色，边缘淡黄；白色眉纹和喉部大片白色斑点；下体棕褐色，横纹和斑点淡黄色，腹部和侧腹变为淡黄横纹棕色。雄鸟有大的白色翼尖斑点和最外侧两根尾羽的宽白尖；雌鸟有土黄翼尖斑点和最外侧两根尾羽的窄土黄或土白色尖端。虹膜深棕色，喙黑色，腿脚黑色。","call":"鸣唱为连续的'砍伐'或'敲击'声，'tok, tok, tok, tok'，从栖木或地面发出，偶尔在飞行中。在满月之夜可能会整夜鸣叫，但在黄昏后和黎明前约30分钟最为活跃。","habits":"栖息于多种环境，偏好有树木的区域，如落叶林、竹林、季风和沿海森林、雨林边缘、次生林和灌木丛、森林空地、山麓森林和茂密灌木；也会出现在开阔乡村、草原、中山区和其他草地、受扰动的生境、郊区花园、村庄、耕地和咖啡庄园、道路旁、宽阔的森林河流或干涸河床旁、海滩附近、离岸岛屿和河沙洲，以及红树林、沼泽和过度生长的溪流。活动范围可能覆盖约50公顷。在黄昏后和黎明前最活跃。","breeding":"繁殖季节在印度北部和缅甸为3月至5月，泰国北部为3月至6月，马来半岛（包括新加坡）至少到9月，苏门答腊为1月至5月，巴拉望岛为7月，砂拉越至4月，爪哇为9月至2月，塞兰岛为8月，弗洛雷斯岛为10月，巴坎岛为9月，新几内亚（包括西部高地）为9月至1月，澳大利亚北部和东北部为9月至11月（偶尔8月至1月）。可能单窝繁殖，但在新加坡一对长尾夜鹰在三个月后又产下了第二个窝。在部分地区，可能是松散的群居繁殖，如印度、巴基斯坦，巢间距仅约90米；领地性，可能有永久的配偶关系。","identification":"与印度长尾夜鹰的区别在于头部颜色更深，冠部条纹更多；后者颈部、披肩、背部和胸部更偏赤褐色；雄鸟有较小的白色翼斑，雌鸟有较小的土黄斑点。菲律宾夜鹰体型较小，斑点更多，翅膀覆羽有土黄线；雄鸟有较小的白色翼斑和较窄的白色尾尖，雌鸟通常有土黄翼斑。有较小的白色翼斑和较窄的白色尾尖。","protection":"IUCN：LC（无危）。在整个分布范围内普遍常见至局部丰盛。在巴基斯坦东北部，夏季访客稀少且局部。在印度西北部，最近扩展到了古吉拉特邦。马来西亚西部局部常见。在华莱士区广泛但局部少见至相当常见，但在许多地点稀缺，某些地区如卡伊群岛和班达海岛屿罕见；婆罗洲、文莱、可能沙捞越和沙巴（1995年首次在加里曼丹记录）局部常见；可能在苏门答腊稀缺；爪哇局部常见；摩鹿加群岛广泛分布。在新几内亚局部常见至非常常见，快速殖民森林被清除的区域。","distribution":"分布于印度东部至澳大利亚北部，新几内亚和俾斯麦群岛，包括澳大利亚、孟加拉国、不丹、文莱、柬埔寨、中国、印度、印度尼西亚、老挝、马来西亚、缅甸、尼泊尔、巴基斯坦、巴布亚新几内亚、菲律宾、新加坡、泰国、东帝汶和越南。","other":"在马来西亚，已知在夜间频繁出没于墓地，故有'graveyard nightjar'的俗名。"},{"name":"米氏夜鹰","english_name":"Mees's Nightjar","scientific_name":"Caprimulgus meesi","overview":"米氏夜鹰（英文名：Mees's Nightjar，学名：Caprimulgus meesi），是夜鹰目夜鹰科夜鹰属的鸟类。以纪念前莱顿自然历史博物馆馆长Gerlof Mees。","appearance":"成年雄性米氏夜鹰体长25至29厘米，头部顶部及上身大部分为淡灰色，带有细黑褐色波纹，头顶侧面略带红棕色，中央冠部有暗褐色斑点线，背部有暗褐色中心标记，肩羽有对比鲜明的暗褐色标记，边缘部分羽毛带有粉红棕色色调；翅膀上的中翼覆羽和大覆羽有肉桂棕色和褐色斑点与条纹，尖端为淡色斑点，外缘更明显；次级飞羽为深棕色，有不规则的肉桂色斑点带，初级飞羽同样为深棕色，有不规则的肉桂色条纹，最外侧五根初级飞羽有白色斑块；尾巴呈灰褐色，有深棕色横纹，最外两对尾羽在淡色区域更显粉红色或肉桂色，末端部分为白色；面部由一条从额侧穿过眼上方并绕到耳羽后方的深色线条框起，耳羽为肉桂棕色或榛色，带有细暗褐色标记；喙周围有长而深色的刚毛，下唇髭纹白色，后部带有淡黄色调；喉咙为肉桂棕色，有暗褐色标记，下喉部有一个大的白色斑点，与下方一排圆形黑色斑点形成对比；下体其余部分底色为淡灰色，向下逐渐变为粉红棕色，羽毛上有深棕色波纹或条纹；虹膜深棕色；眼睑浅棕色；喙黑色，口角粉红色。","call":"米氏夜鹰的鸣叫特征表现为一种爆炸性的模糊“chow-chow”叫声。","habits":"栖息于森林边缘、灌木丛和红树林，主要分布在低地，偶尔也会出现在丘陵地带。体型较大，尾巴较长，当停歇时，尾巴明显伸出翼尖之外。其头部图案引人注目，脸颊为红棕色，有明显的苍白髭纹。与林夜鹰相比，它体型更大，尾巴更长，头部标记更为突出，尾羽外侧有宽广的白色尖端。","identification":"与长尾夜鹰相比，米氏夜鹰在形态上极为相似，但通过声音分析可以明确区分。与共域的林夜鹰相比较，米氏夜鹰体型更大，羽毛更偏棕色，图案更为大胆，尾羽外侧有大白色斑点。","protection":"IUCN：LC（无危）。限制范围物种：存在于Sumba EBA和Northern Nusa Tenggara EBA。可能并不罕见，在某些地方被报道为常见。在弗洛勒斯岛上，已被记录在一个保护区，Wolo Tadu自然保护区。","distribution":"分布于印度尼西亚的松巴岛、弗洛勒斯岛、Alor和Pantar（小巽他群岛西南部和中部）。","other":"之前被包含在‘长尾夜鹰复杂’的华莱士和澳大利亚群体中（种族schlegelii）；然而，声音记录的分析揭示了与该复杂群中所有其他种群显著不同的声乐差异，导致其正式描述。"},{"name":"安达曼夜鹰","english_name":"Andaman Nightjar","scientific_name":"Caprimulgus andamanicus","overview":"安达曼夜鹰（英文名：Andaman Nightjar，学名：Caprimulgus andamanicus），是夜鹰目夜鹰科夜鹰属的鸟类。在安达曼群岛广泛分布，常见于柚木林和树木稀疏的开阔地带。其体型中等，外观呈暗色，具有较明显的灰白色喉部斑块。","appearance":"该鸟长约24至26厘米，外表以黑色为主，冠部和背部带有灰色，中央有黑色条纹，翼覆羽尖端明显较浅，初级飞羽基部有亮红棕色条纹。雄鸟的翅膀边缘有窄白边，尾羽角部有中等大小的白色区域，而雌鸟则为淡黄色。腹部暗色，带有狭窄的淡色横纹。幼鸟特征尚未详述。","call":"安达曼夜鹰的鸣唱由一系列快速重复的‘tyuk’音符组成，音调相对平缓，频率约为每秒3至4.5个音符，与近缘种长尾夜鹰的深沉回响声截然不同。","habits":"栖息于开放的林地、森林空地和红树林中，夜间活跃，白天则隐蔽于植被中休息。","breeding":"繁殖季节为2月底至4月，一窝产1-2枚淡粉色蛋，可能带有紫色标记，大小约27.3-31.8毫米×20.6-22.2毫米。若首次筑巢失败，会重新产卵。孵化通常由雌鸟在白天进行，雏鸟绒毛状态未知。成鸟在巢穴受到威胁时会做出受伤吸引注意力的行为。","identification":"与长尾夜鹰相比，安达曼夜鹰体型更小，颜色更深，雄鸟外侧初级飞羽上的白色较少，雌鸟外侧初级飞羽上的淡色斑点显著减少，喉部斑块为淡肉桂色而非白色。","protection":"IUCN：LC（无危）","distribution":"分布于安达曼群岛（Andaman Islands），包括主要岛屿及其附近的小岛。"},{"name":"菲律宾夜鹰","english_name":"Philippine Nightjar","scientific_name":"Caprimulgus manillensis","overview":"菲律宾夜鹰（英文名：Philippine Nightjar，学名：Caprimulgus manillensis），是夜鹰目夜鹰科夜鹰属的鸟类。夜行性鸟类，广泛分布在菲律宾（除巴拉望岛及周边岛屿）。其本地名称包括kandarapa（塔加洛语）和tagolilong（宿务语）。菲律宾夜鹰以其独特的棕色斑纹和两音节的叫声而著称。","appearance":"体长约23至25厘米，体重在59至71克之间，雌雄相似。上体呈灰褐色，有黑色条纹，尤其是头部，胸部有斑点，腹部和两侧为棕色条纹。翅膀暗褐色，有粉色和白色的大斑点，尾巴末端有一宽白带。喉侧有白色线条，下方有一黑线。雄鸟翼上有白色斑点，雌鸟为赤褐色。","call":"发出独特响亮的两音节叫声“pyok prraw”，第二音较低沉，带有颤音。","habits":"栖息于低地到山区的森林和开阔地带，包括原始和次生林、松树林、灌木丛、有树木的开阔地、红树林、城镇边缘、农田和岩石海滩边。以昆虫为主食，如蛾类和甲虫，通常在飞行中捕食。","breeding":"繁殖季节为4月至5月，可能更长。不在巢中产卵，而是将卵产于地面落叶堆中，一般在森林或林地空地，或路旁。每次产卵1至2枚，卵呈椭圆形或卵形，白色，有大量棕色、深棕色和灰色的斑点。雏鸟半早熟，被覆有棕色红褐色绒毛。","identification":"与Eurostopdus macrotis相比，整体颜色较浅，初级飞羽和尾羽无淡色标记。雄鸟有较大的白色翼斑和更宽的白色尾端，雌鸟的翼和尾部标记为赤褐色。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾（除巴拉望岛及其附属岛屿），从低地至海拔2000米的地区。","other":"在Rajah Sikatuna国家公园（保和岛）和Mount Katanglad国家公园（棉兰老岛）有其栖息地。"},{"name":"苏拉夜鹰","english_name":"Sulawesi Nightjar","scientific_name":"Caprimulgus celebensis","appearance":"该鸟长尾，体长24至30厘米，雄雌相似，上身灰褐带黑褐条纹，中央冠部尤为明显，无颈背圈；翼羽暗棕，点缀浅黄与米色；肩羽深棕镶边米色；喉咙白色；腹部灰褐色，点缀棕色、灰白与米色斑点，腹部和两侧形成米色横纹。两性均有白色斑点于第二、三、四最外侧初级飞羽及尾羽最外侧两根的白色尖端。虹膜深棕，喙、腿及脚黑色。","call":"发出独特而有力的“tok-tok-toktrrtrr”叫声，起初急促加速随后音量渐弱。","habits":"栖息于低地森林、边缘地带、灌木丛和红树林。飞行时，动作轻盈敏捷，以昆虫为食，通过在空中捕捉猎物的方式觅食。","identification":"与菲律宾夜鹰的区别在于尾羽外侧两根具有更白的尖端。比长尾夜鹰体型小且斑纹较少，雄鸟的翼部白色斑点较小，尾羽白色尖端较窄。比环颈毛腿夜鹰颜色更淡，斑点较少，后者喉部有宽带，翼部白色斑点较小，尾部无白色。","protection":"IUCN：LC（无危）。分布于苏拉威西东区生物多样性热点区域及邦盖和苏拉群岛，局部地区稀少至相当常见，但在苏拉威西北部和东部较为普遍，最近在Buton岛发现，状态不明。在Tangkoko自然保护区（苏拉威西东北部）有记录。栖息地丧失因森林砍伐可能是其面临的最大威胁。","distribution":"分布在印尼苏拉威西岛、邦盖群岛及苏拉群岛的东部区域。"},{"name":"德氏夜鹰","english_name":"Donaldson Smith's Nightjar","scientific_name":"Caprimulgus donaldsoni","overview":"德氏夜鹰（英文名：Donaldson Smith's Nightjar，学名：Caprimulgus donaldsoni），是夜鹰目夜鹰科夜鹰属的小型而精致的鸟类。其羽毛带有赤褐色调，常见于非洲的干燥草原和荆棘灌木丛中，分布于埃塞俄比亚东部和索马里西北部至坦桑尼亚东北部。","appearance":"成年德氏夜鹰体长约18-19厘米，体重介于21-36克之间，雌雄有细微差异。上体呈灰褐色条纹，翼覆羽赤褐或红褐色，斑点和条纹交错，颈部有宽阔的红褐或浅黄褐色颈环。下体赤褐或红褐色，密布淡色斑点，腹部有深色条纹。雄鸟的最外侧四枚初级飞羽有白色斑点，尾羽最外侧两枚有宽幅白色尖端；雌鸟则有较小的白色标记。虹膜、喙、腿和脚均为深褐色。幼鸟与雌鸟相似，但颜色更偏赤褐色。","call":"雄性德氏夜鹰的鸣唱是一系列悦耳的高音哨声，通常在黄昏和黎明时分从地面发出，每组持续约0.5秒，频率约为每10秒八次，声音特征为‘tu-wee, tiu’。","habits":"德氏夜鹰主要栖息在干旱或半干旱的灌木丛和金合欢树林地带，海拔范围从海平面到1700米，但多数发现于1050米以下的区域。它们的迁徙模式尚不清楚，可能在某些范围内是留鸟。以蚂蚁、蚱蜢、蛾子、甲虫和毛虫为食，常在黄昏前开始觅食，通过低空或水面追逐猎物，有时在水井附近活动，飞行敏捷迅速。","breeding":"繁殖季节在索马里为5月至6月，在埃塞俄比亚为3月，肯尼亚可能在8月至10月。它们不筑巢，通常在沙地上产卵，一般位于植被如小灌木下。一窝产两枚卵，卵呈卵圆形，淡象牙色，表面有灰褐色斑点，大小约为24.3-25.2毫米×18.2-20.1毫米。关于雏鸟的描述未见报道。","identification":"德氏夜鹰是最小的非洲夜鹰之一，比其分布区内的其他夜鹰更红褐色，通过叫声最容易识别。雄鸟与雌鸟的区别在于雄鸟的白色翼斑和尾尖更大、更白，而雌鸟的则更小、更偏褐色。","protection":"IUCN：LC（无危）","distribution":"德氏夜鹰分布于非洲的埃塞俄比亚东部和索马里西北部至坦桑尼亚东北部，主要栖息于干旱或半干旱的灌木丛和金合欢树林地带。","other":"德氏夜鹰在适宜的生境内广泛且局部常见，特别是在1400米以下的地区。在肯尼亚的Tsavo West、Tsavo East和Awash国家公园中较为常见，但在更高海拔处较为罕见。"},{"name":"黑肩夜鹰","english_name":"Black-shouldered Nightjar","scientific_name":"Caprimulgus nigriscapularis","overview":"黑肩夜鹰（英文名：Black-shouldered Nightjar，学名：Caprimulgus nigriscapularis），是夜鹰目夜鹰科夜鹰属的雌雄异型鸟类。主要特征为上体暗褐色带红褐色调，颈部有宽阔的肉桂色颈圈，翼部黑色较小覆羽，余部棕色斑点，肩部黑色覆羽边缘带淡黄色，喉部白色斑块，下体红褐色至肉桂色，腹部和两胁变为肉桂色。雄鸟具小白色翼尖斑点和尾羽外侧宽白色尖端；雌鸟翼尖斑点较小。","appearance":"黑肩夜鹰具有明显的性二型性，整体呈暗褐色，带有红褐色色调。上体覆盖着红褐色颈圈，翼部黑色较小覆羽，其余翼部覆羽棕色斑点，肩部覆羽黑色边缘带淡黄色。喉部有白色斑块，下体颜色从红褐色至肉桂色，腹部和两胁逐渐变为肉桂色。雄鸟特征包括翼尖四枚外侧初级飞羽上有小白色斑点，以及最外侧两根尾羽的宽白色尖端；雌鸟的白色标记通常较小。幼鸟弱化版的成年雌鸟外观，头部顶冠有少数短黑纹，翼尖无白色，代之以小型肉桂色斑点，白色喉部斑块较小。","call":"雄鸟的歌曲在黄昏、黎明和月光之夜从低枝或高树顶发出，甚至从象草茎上，是一种颤音、音高均匀、双音节的液体哨声，频率在1.2至2.2千赫之间，持续1.4秒，每5至8秒重复一次，持续长时间。歌声前常有一系列快速单调的werp或weet音符，重复规律至少12.5秒，每秒4.1个音符。叫声包括柔和的chuk或tuc音，经常在飞行中发出，有时连续发出多达十个或更多的双tuc-tuc声音。","habits":"黑肩夜鹰栖息于低地森林边缘，包括浓密的林地、画廊森林、雨林、二次生长林和稀疏树木的草地或石质山坡，甚至花园中带有半异域森林。活动范围从海平面到约1450米，偶尔可达约2000米。夜间捕食昆虫，包括蛾子、甲虫和其他昆虫，通过在树间或开阔地带、草坪上空或山丘上方的2至20米高空捕猎。可能为留鸟和定居种。","breeding":"繁殖季节可能在5月的冈比亚，4月的科特迪瓦，5月（雌鸟有活跃卵巢）的中非共和国，11月至12月的喀麦隆，8月至12月（9月和12月发现雏鸟）的刚果民主共和国西部，4月至8月的刚果民主共和国北部，1月至2月的刚果民主共和国东北部。巢筑于地面，通常在树叶堆中，蛋数1至2枚，椭圆形，浅粉色或奶油色，带有红褐色和灰色斑点，标记通常集中在钝端周围，尺寸为21.0至30.1×18.0至21.4毫米。","identification":"与非洲夜鹰、灰头夜鹰和卢旺达夜鹰（C. ruwenzorii）相比，黑肩夜鹰更红褐色，翼部覆羽图案更鲜明，红褐色颈圈，翼尖白色斑点较小。与非洲夜鹰的绝对区别在于黑肩夜鹰的翼尖白色斑点仅限于第9初级飞羽的内网，头冠上的暗纹较少，翅膀较短。","protection":"IUCN：LC（无危）","distribution":"分布零散，从冈比亚、塞内加尔和西部塞拉利昂向东穿过尼日利亚和喀麦隆到南苏丹东南部和肯尼亚西部，可能还有坦桑尼亚西北部，向南至刚果和刚果民主共和国西南部。记录显示在贝宁、多哥、加纳、尼日利亚南部、喀麦隆西部、刚果民主共和国东部、乌干达、卢旺达、布隆迪、肯尼亚西部和南苏丹极地常见。","other":"黑肩夜鹰与非洲夜鹰关系密切，过去常被视作同种。"},{"name":"非洲夜鹰","english_name":"Fiery-necked Nightjar","scientific_name":"Caprimulgus pectoralis","overview":"非洲夜鹰（英文名：Fiery-necked Nightjar，学名：Caprimulgus pectoralis），是夜鹰目夜鹰科夜鹰属的鸟类。中等体型的夜鹰，广泛分布于非洲南部至东南部，以独特的赤褐色颈环而闻名。常见于多种生境，包括草原、林地、森林和种植园。雌雄异型，雄鸟翼端白点较大，尾羽白尖更长。","appearance":"非洲夜鹰成鸟体长约23-25厘米，上体呈暗棕色，饰有灰色斑纹和棕色白点，具有明显的赤褐色颈环，下体棕色，带有黑色细纹和棕色白色条纹。雄鸟翼端有大白点，尾羽外侧两根有宽白尖；雌鸟翼上的白点较小，偏黄褐色，尾羽白尖较短。喙黑色，有6-11根黑或暗色的触须状刚毛，长14-25毫米。脚趾有栉状爪，长5-8毫米，有5-14颗齿。雏鸟柔软，上体更赤褐色，斑点和翼覆羽标记减少，头部暗色条纹较少，下体浅黄色，带有灰褐色窄条纹。","call":"雄鸟的鸣唱是一系列悦耳但变化多端的口哨声，通常被描述为'亲爱的主，拯救我们！'，首音波动，第二音为均匀音阶颤音，有时长达22秒，以加速的三重呼唤结束。雌鸟也会发出类似的呼唤，甚至在巢中。","habits":"栖息于各种环境，包括草原、林地、森林边缘和种植园。常在树上或地面唱歌，主要在黄昏和黎明活动，偶尔在月光下。以昆虫为食，包括螳螂、蜘蛛、飞蛾、蝗虫和甲虫。通过飞扑捕捉猎物，有时会突然转弯追逐猎物。","breeding":"繁殖期为8月至11月，巢建在树下的地面上，通常在枯叶中。每窝产1-2枚卵，通常为两枚，卵呈椭圆形，白色至淡粉色，可能有红褐色、灰色和深粉色斑点。孵化期约为18天，孵化后雏鸟半自立，约18天后能够飞行。","identification":"与棕颊夜鹰相比，非洲夜鹰颜色更深，颈环更亮更明显。雄鸟翼上的白点较小，尾部白尖更多；雌鸟尾部角上的黄褐色斑点比棕颊夜鹰更大。与Abyssinian Nightjar和Rwenzori Nightjar相比，尾部外侧两根尾羽上的白点较少，歌声更高。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲南部至东南部，包括南苏丹、肯尼亚、坦桑尼亚中部、刚果、刚果民主共和国、安哥拉、纳米比亚、博茨瓦纳和南非等地。","other":"非洲夜鹰在迁徙时返回同一繁殖地点，但不会离开其家园太远。"},{"name":"灰头夜鹰","english_name":"Montane Nightjar","scientific_name":"Caprimulgus poliocephalus","overview":"灰头夜鹰（英文名：Montane Nightjar，学名：Caprimulgus poliocephalus），是夜鹰目夜鹰科夜鹰属的鸟类。主要栖息于海拔1,000至3,350米的高山区，包括森林边缘、开阔地带、草地、耕作区和灌木丛。其别名包括山地夜鹰和阿比西尼亚夜鹰。","appearance":"灰头夜鹰是一种中等体型的夜鹰，长约23厘米，上体呈暗灰褐色，饰有黑色斑点。雄鸟的四个主要初级飞羽上有白色斑点，尾羽外缘白色明显；雌鸟的初级飞羽上的斑点为淡黄色，尾部白色较少。其下体通常为深灰色，饰以淡黄色和淡黄褐色条纹，腹部和侧腹带有棕色条纹。雄鸟在外侧四枚初级飞羽上具有小白斑，最外两枚尾羽尖端白色；雌鸟的翼斑带淡黄色，尾部白色部分较少。","call":"发出鼻音般的\"ank-ank-ank\"声，常接以高音哨声\"piiyyu-pirrr\"，首音节先降后升，第二音节颤音下降。","habits":"栖息于多种高海拔生境，包括森林空地、边缘、草地、耕作区和灌木丛。夜间活动，以蛾类和其他大型昆虫为食。主要分布于非洲中东部，包括安哥拉、刚果民主共和国、埃塞俄比亚、肯尼亚、马拉维、沙特阿拉伯、苏丹、坦桑尼亚、乌干达和赞比亚。","identification":"与非洲夜鹰相比，灰头夜鹰的叫声更高亢，栖息于高山环境，整体颜色更深，红褐色颈圈较弱。与方尾夜鹰、非洲长尾夜鹰和细尾夜鹰的区别在于翼缘白色或淡黄色，而这些物种的尾侧有大量白色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中东部，包括埃塞俄比亚至赞比亚和安哥拉中部，以及沙特阿拉伯西南部。","other":"已知四个亚种，其中ruwenzorii曾被认为是独立物种Ruwenzori夜鹰。"},{"name":"印度夜鹰","english_name":"Indian Nightjar","scientific_name":"Caprimulgus asiaticus","overview":"印度夜鹰（英文名：Indian Nightjar，学名：Caprimulgus asiaticus），是夜鹰目夜鹰科夜鹰属的小型夜行鸟类，广泛分布于南亚和东南亚的开放地带。其特征包括暗色脸颊、白色喉侧斑点、金色颈环和尾端角，以及独特的‘石跳湖面’般的鸣叫声，使它易于识别。","appearance":"成年印度夜鹰体长约23-24厘米，体重40-46克，上体呈灰褐色并带有黑色条纹，头部宽条纹边缘呈赤褐色，具宽阔的黄褐色颈环。翅膀覆羽灰褐色，散布着赤褐色斑点，肩羽边缘呈淡黄色。有明显的白色亚口须纹和两侧喉咙上的大白色斑块。下体灰褐色，有棕色横纹和明显的淡黄色斑点，腹部和两胁变成淡黄色横纹。雄鸟有白色斑点位于最外侧四根初级飞羽上，尾端两根羽毛宽白边；雌鸟有较小的白色翼斑，边缘或染淡黄色，尾端两根羽毛有较窄的淡黄色白边。虹膜深棕色，喙角褐色至黑色，腿脚棕粉色。幼鸟比成鸟更淡，几乎银灰色，图案更简单，颈环仅微弱可见。种族差异细微，指名亚种颜色变化大，有灰褐色、沙黄色、灰色、棕色和赤褐色个体。","call":"雄鸟的叫声非常独特，是一种加速敲击声，类似石头在冰冻湖面上跳跃或乒乓球快速弹跳落地的声音。","habits":"栖息于多种生境，包括稀疏灌木丛、竹林、年轻的人工林、废弃耕地与灌木丛、大戟篱笆、靠近耕地的石质干沟以及茂盛的花园。偏好低丘陵地带，稀疏植被中散布着荆棘灌木，也出现在低矮石质山丘和盐碱地的柽柳灌木丛。在斯里兰卡，常见于灌木丛、沙滩土壤上的丛林地带、开阔的林地和肉桂种植园。海拔分布范围从海平面至1500米，但主要分布在1000米以下。可能部分迁徙，如在巴基斯坦南部和缅甸南部有记录，但迁徙模式尚不完全清楚。以昆虫为主食，如飞蛾、粪金龟、蚱蜢、蟋蟀和蝽象。在非繁殖季节，也可能食用大戟的花朵和小鼠。主要在连续飞行中捕食。","breeding":"繁殖时间在不同地区有所不同，如巴基斯坦从4月开始，在印度为2月至9月（主要为4月至5月），斯里兰卡为1月至10月（主要为3月至5月和9月），缅甸为2月至7月。巢址通常靠近灌木或树桩，隐蔽于树下或幼树旁，或位于人造墙基、干燥碎石沟或石质田野，不筑巢，蛋直接产于落叶层或裸露地面的轻微凹坑中。每窝产2枚蛋（偶尔1枚），椭圆形，底色为奶油色或浅鲑鱼粉红色，有红棕色和紫色斑点，大小约为24.6-29.2毫米×18.3-21.3毫米。双亲共同孵化，雌鸟似乎主要在白天孵化。雏鸟覆盖着赤褐色绒毛。","identification":"与其他夜鹰种类的区别在于更复杂的标记，与长尾夜鹰相比，缺乏后者特有的白色喉咙；与草原和丛林夜鹰相比，后两者缺乏印度夜鹰的白色‘胡须’纹和清晰的颈环。雄鸟在飞行中显示靠近翼尖和尾尖的明亮白色斑块。幼鸟比成鸟更淡，几乎银灰色，图案更简单，颈环仅微弱可见。与其他亚种相比，指名亚种颜色变化大，有灰褐色、沙黄色、灰色、棕色和赤褐色个体。","protection":"IUCN：LC（无危）","distribution":"分布于南亚和东南亚的开放地带，从巴基斯坦东南部至东南亚，包括印度、斯里兰卡、孟加拉国、缅甸和越南。","other":"在巴基斯坦、印度和斯里兰卡的多个保护区中发现，如Khirtar国家公园、Keoladeo Ghana国家公园和Yala国家公园。"},{"name":"马岛夜鹰","english_name":"Madagascar Nightjar","scientific_name":"Caprimulgus madagascariensis","overview":"马岛夜鹰（英文名：Madagascar Nightjar，学名：Caprimulgus madagascariensis），是夜鹰目夜鹰科夜鹰属的鸟类。广泛分布于马达加斯加岛，包括Nosy Boraha和Aldabra等地，偏好栖息于接近人类居住区的各种环境，但不会进入密林深处。","appearance":"马岛夜鹰具有典型的隐蔽花纹，适应夜间活动的生活习性。当停歇时，它与有红褐色领圈的领夜鹰明显不同，而飞行时，翼下的白色斑点成为其显著特征。","call":"其美妙的鸣叫声常在黎明和黄昏时响起，开始以一声‘tuk’为前奏，随后是一连串宛如木制响板的长音。","habits":"马岛夜鹰主要在黎明、黄昏和夜间活动，以飞行中捕获的昆虫为食。它适应力强，能在各种生境中生存，包括城镇和农田，但不常见于茂密森林。","identification":"与领夜鹰相比，马岛夜鹰缺乏红褐色领圈，这是两者间的重要辨识特征。","protection":"IUCN状态未提及，因此暂无相关保护等级。","distribution":"马岛夜鹰主要分布于马达加斯加岛，同时在Aldabra（西南塞舌尔群岛的一部分）也有记录。","other":"关于马岛夜鹰的系统学历史和其他有趣信息，有待进一步探索和记录。"},{"name":"非洲白尾夜鹰","english_name":"Swamp Nightjar","scientific_name":"Caprimulgus natalensis","overview":"非洲白尾夜鹰（英文名：Swamp Nightjar，学名：Caprimulgus natalensis），是夜鹰目夜鹰科夜鹰属的鸟类。常见于非洲的湿地环境，如草甸、沼泽和灌木丛。其背部有强烈的鳞状斑纹，雄鸟尾部外侧有明显的白色斑块，而雌鸟则呈淡褐色。","appearance":"体长约20-24厘米，体重介于65-86.5克之间，性别二态性明显。上体呈棕色或灰褐色，翅膀覆羽、肩羽和三级飞羽上有大型不规则暗棕色斑点。颈部有一模糊的淡色颈环，喉咙有白色斑块，下体颜色较深，腹部有条纹。雄鸟具有大的白色翼缘和尾端白色斑块，雌鸟则有淡黄褐色的翼斑和尾羽尖端。","call":"鸣唱为一系列单调的‘chop’音符，飞行叫声快速连贯的‘chip’声，求偶时发出‘whip’或旋律性的‘wip, hulululul’音符。","habits":"偏好湿润或潮湿的生境，如草地、沼泽边缘和森林边缘。海拔分布从海平面至2200米。迁徙模式未知，但可能随季节性水位变化而移动。","breeding":"繁殖信息不详，但一般夜鹰科鸟类会在地面筑巢，雌雄共同参与孵化和育雏。","identification":"与方尾夜鹰相似，但外侧尾羽的白色斑块更大，脸颊呈黑色。与灰头夜鹰相比，色泽更浅，缺乏红褐色领圈，且生境和分布范围不同。","protection":"IUCN：LC（无危）。在某些地区受到栖息地丧失、排水、耕作和火灾的威胁。","distribution":"分布于安哥拉、博茨瓦纳、布隆迪等国，主要在非洲的湿地环境中，包括沼泽、草原和森林边缘。","other":"在许多保护区内有记录，如乌干达的Rwenzori国家公园和南非的Mkuzi游戏保护区。"},{"name":"内基萨夜鹰","english_name":"Nechisar Nightjar","scientific_name":"Caprimulgus solala","overview":"内基萨夜鹰（英文名：Nechisar Nightjar，学名：Caprimulgus solala），是夜鹰目夜鹰科夜鹰属的鸟类。仅在埃塞俄比亚南部发现。于1990年首次被发现，当时研究人员在内基萨国家公园内找到了一具腐烂的标本，仅带回了一只翅膀，这成为其种小名solala（意为“只有翅膀”）的由来。","appearance":"由于记录有限，关于内基萨夜鹰的外观特征描述不详。","call":"目前没有关于其鸣叫特征的记录。","habits":"栖息地为非洲南部的亚热带草原地带，具体生活习性尚不清楚。","identification":"由于记录稀少，与其他夜鹰的辨识要点尚未明确。","protection":"IUCN：VU（易危）","distribution":"分布于非洲埃塞俄比亚南部，确切分布范围未知，仅知其存在于内基萨国家公园内。","other":"其生存状况受到关注，因栖息地受到过度放牧、森林砍伐和火灾威胁，需要进一步调查以确定其真实状况。"},{"name":"纯色夜鹰","english_name":"Plain Nightjar","scientific_name":"Caprimulgus inornatus","overview":"纯色夜鹰（英文名：Plain Nightjar，学名：Caprimulgus inornatus），是夜鹰目夜鹰科夜鹰属的鸟类。颜色从赤褐色到棕色再到灰色不等。其分布范围涵盖南部萨赫勒地区、南苏丹、非洲之角和阿拉伯半岛西南部，迁徙时会前往较低纬度区域，如刚果中部和坦桑尼亚北部。","appearance":"体长约22-23厘米，雄鸟体重33-61克，雌鸟32-57克。性别二型性明显，上体和翼覆羽颜色多变，从黑色至棕色、灰褐色、紫红色、赤褐色、淡肉桂色到沙色，较为朴素，头部和肩部有黑色条纹和斑点，无颈圈；缺乏明显的白色喉部斑块；下体呈棕色或肉桂色，有棕色条纹。雄鸟有白色斑点在最外侧四根初级飞羽上，最外侧两根尾羽有宽白边；雌鸟有肉桂色翼斑，尾部无白色。虹膜深棕色，喙棕色带黑色尖端，腿和脚浅棕色。","call":"雄鸟的歌声为持续、音调均匀的啾啾声，偶尔以一系列深沉的'cuk'音开始。在飞行中发出柔和的咕噜声；叫声包括低沉的'chuk'音。在威胁或防御展示时会发出嘶哑的嘶嘶声。","habits":"主要栖息于有树木和灌木的草原，半沙漠草原，较稀疏的茂密草原林地，以及森林空地。非繁殖季节，主要生活在有树木的草原。在沙特阿拉伯，通常栖息在阿西尔山脉内陆的贫瘠低地，但也在海拔较高的岩石地形中出现。在也门，栖息于伊拉夫山的杜松森林和瓦迪哈德拉毛特地区，以及干旱河谷的斜坡。","breeding":"繁殖时间在不同地区有所差异，例如在马里为4月至6月，在尼日尔为5月至6月，在埃塞俄比亚为3月至6月，在索马里为12月至6月中旬，在肯尼亚西北部为5月至8月，在尼日利亚为3月至5月；可能在利比里亚5月至6月繁殖，偶尔在此地发现（尽管12月和1月有幼鸟记录）；在沙特阿拉伯和也门的数据不详。可能是单配偶制。无巢，卵产在裸露的土壤上，通常靠近或在小灌木下。每窝通常产2枚卵，卵椭圆状卵形，表面光滑，象牙白或乳白色，带有红棕色和淡紫色的斑点和斑块；孵化期未知；雏鸟覆盖着浅肉桂色绒羽，离巢期未知。","identification":"与星斑夜鹰相比，纯色夜鹰更朴素，雄鸟具有白色翼斑（4根羽毛）和大的白色尾角，喉部无白色；雌鸟有肉桂色翼斑，尾部无白色。与多个其他夜鹰种类相似，但通过整体的朴素外观、喉部缺乏白色以及叫声来识别。","protection":"IUCN：LC（无危）。在全球范围内广泛分布，种群趋势稳定，因此评估为无危级别。","distribution":"繁殖于毛里塔尼亚和塞内加尔北部至埃塞俄比亚和索马里，以及阿拉伯半岛西南部。迁徙时到达刚果中部和坦桑尼亚北部。冬季栖息地从塞内加尔到利比里亚，东至刚果民主共和国西南部和可能的埃塞俄比亚西南部，南至刚果民主共和国和坦桑尼亚。","other":"被记录于多个国家保护区，如尼日尔的西部国家公园、乌干达的卡巴莱加瀑布国家公园，以及肯尼亚的察沃西国家公园和察沃东国家公园。"},{"name":"星斑夜鹰","english_name":"Star-spotted Nightjar","scientific_name":"Caprimulgus stellatus","overview":"星斑夜鹰（英文名：Star-spotted Nightjar，学名：Caprimulgus stellatus），是夜鹰目夜鹰科夜鹰属的鸟类。中等体型的典型夜鹰。其外观异常朴素，最显著的特点是在喉咙两侧有小块白色斑点。整体颜色从赤褐色到棕色再到灰色不等。两性相似，但在翅膀外侧和尾巴角落处都可见微小的淡色标记。星斑夜鹰栖息于干旱草原和荆棘灌木丛中的裸露地带。","appearance":"星斑夜鹰体长21-23厘米，体重雄鸟54-64克，雌鸟50-69克。性别间外观相似，个体色彩差异不大，从灰褐色至较浅的沙棕色。背部和翼羽盖相对简单，通常呈深灰褐色，点缀以细小的暗褐色斑点；头部和肩部稀疏地带有星状暗褐色条纹和斑点，没有颈环；下喉部两侧有小型白色斑块；下体颜色比上体淡，常带有棕色或浅黄褐色的横斑。两性均在四个最外侧初级飞羽上有白色斑点，以及两根最外侧尾羽尖端有狭窄的白色。虹膜深棕色，喙黑色，腿和脚肉棕色。","call":"星斑夜鹰的叫声为重复的“cheuu”声。","habits":"星斑夜鹰生活在干旱的草原和荆棘灌木丛中，偏好有裸露地面的环境。","identification":"星斑夜鹰与纯色夜鹰的区别在于喉咙上的白色标记和雄鸟两根最外侧尾羽的白色尖端更窄。与埃及夜鹰相比，星斑夜鹰在翅膀和尾巴上有更大的淡色斑块。","protection":"IUCN：LC（无危）","distribution":"星斑夜鹰分布于非洲的埃塞俄比亚、索马里、南苏丹，以及肯尼亚中部。"},{"name":"林夜鹰","english_name":"Savanna Nightjar","scientific_name":"Caprimulgus affinis","overview":"林夜鹰（英文名：Savanna Nightjar，学名：Caprimulgus affinis），是夜鹰目夜鹰科夜鹰属的鸟类。分布于南亚和东南亚地区。该物种包含六个亚种，适应力强，能耐受多种环境，甚至在都市环境中也能生存。体长20-26厘米，体重54-110克。","appearance":"雄鸟与雌鸟外观有别。上体呈灰褐色，点缀以淡色斑点和黑色条纹；颈背有一圈淡色或肉桂色项环；翼覆羽棕色，斑点明显；肩羽深棕色，边缘泛淡色或白色；下体棕色，横纹、斑点交织，腹部和侧腹呈淡色条纹。雄鸟四根外侧初级飞羽有大块白色斑点，两根最外侧尾羽通常白色，顶端或边缘棕色；雌鸟翼部斑点淡色，尾部无白色。虹膜深棕色，喙黑色，腿脚棕色。幼鸟似成年雌鸟，但色泽更淡，偏灰褐色。","call":"以其响亮、重复的“chwip”或“chweep”叫声闻名，主要在飞行中发出，偶尔在栖息处鸣叫。还发出低沉的笑声和柔和的尖叫声。","habits":"栖息于草原、草地平原、开阔的森林地带，亦常见于农田、沙石山丘、沼泽边缘、红树林、沙滩、裸露的沙地或河岸、干涸的河流、海岸灌木丛和城市环境。活动高度可达1500米，可能至2000米。以夜间飞行捕食为主，猎物包括蛾子、螳螂、甲虫、白蚁和飞蚁。常在森林上空、农田、城市、机场和高尔夫球场上空觅食。会聚集形成大型觅食群。","breeding":"繁殖季节在北巴基斯坦为6-7月，印度和喜马拉雅山区为4-8月，菲律宾为5月至翌年3月，爪哇为3-12月，苏门答腊为4-1月。巢筑于开阔地带，靠近树基，隐藏于灌木或草丛中，或位于灌木下。每窝产卵1-2枚，卵椭圆形，颜色为鲑粉色或浅肉桂色，带有红褐色和深红色的斑点。两性共同孵化，具体孵化期未记载。雏鸟留巢，未详细描述，离巢时间未知。","identification":"与印度夜鹰,相比，体色较单一，项环较窄，翼覆羽斑点较弱；雄鸟的白色翼斑较小，最外侧两根尾羽宽端白色。比丛林夜鹰略小，翼覆羽斑点较少，雄鸟尾羽白色尖端较少。比长尾夜鹰稍小、偏灰色且体色较单一，雄鸟尾羽最外侧两根有白色尖端。","protection":"IUCN：LC（无危）。在其分布区内局部常见到普遍分布。在北巴基斯坦为常见的繁殖鸟和过境候鸟；在中国东南部可能并不少见；在台湾为留鸟；泰国北部和中部为罕见至局部常见；在整个华莱士区、菲律宾和婆罗洲低地普遍；在苏门答腊、爪哇和巴厘岛的低地普遍。","distribution":"分布于远东、澳大利亚和新西兰地区，广泛分布于印度、中国南部、菲律宾、马来西亚等地。","other":"曾经被认为与叽喳夜鹰为同一物种。"},{"name":"雀斑夜鹰","english_name":"Freckled Nightjar","scientific_name":"Caprimulgus tristigma","overview":"雀斑夜鹰（英文名：Freckled Nightjar，学名：Caprimulgus tristigma），是夜鹰目夜鹰科夜鹰属的大型夜行性鸟类。分布于非洲的广阔区域，尤其在岩石地带与稀树草原中常见。其显著特征为上体布满白色、肉桂色及淡黄色斑点，喉部有一块白色斑块。","appearance":"雀斑夜鹰体长26至28厘米，体重雄鸟70至100克，雌鸟69至91克。两性异形，上体及翼覆羽呈黑褐色，布满白色、肉桂色和浅黄色斑点，无颈环；喉部具白色斑块；下体深棕色带状，白色和肉桂色相间，腹部变为肉桂色带状。雄鸟在外翼四枚最外侧初级飞羽上有小白斑点，两根最外侧尾羽宽白尖；雌鸟翼上有较小的白斑点，尾部无白色。虹膜深棕色，喙黑色，腿脚黑色。幼鸟与成鸟相似。不同亚种在体型和整体色调上略有差异。","call":"雄鸟的歌声为变化的‘whow, whow, whow’或‘ow-whow, ow-whow’，有时会发出连续的4到5个音节；还有重复的、响亮的‘wha’或‘wa’声。飞行叫声包括‘kheh, kheh, kheh’或一系列‘wok’叫声；受惊时发出‘kluk, kluk, kluk’的叫声。警戒叫声为尖锐的‘gobble’声；成鸟在做假动作时发出低沉的‘grok, grok’声；雏鸟发出柔和的‘wee-oo’声。","habits":"栖息于岩石地形与植被环境，如岩层、石堆、山丘、悬崖和森林边缘的斜坡。偶尔在火灾后离开烧焦的地区。在繁殖季节外，偶尔远离岩石栖息地。海拔高度记录在600米至2000米之间。食谱主要由飞行昆虫组成，如蛾、白蚁、金龟子等。","breeding":"繁殖季节在尼日利亚为1月至5月，在埃塞俄比亚、肯尼亚和东北扎伊尔为5月至6月，在卢旺达、布隆迪、坦桑尼亚、赞比亚和马拉维为8月至11月，在津巴布韦为8月至12月，在南非和莫桑比克南部为9月至11月。可能两次繁殖，第二次产卵在首次离巢后不久。一窝通常产2枚卵，孵化期约为17至19天，主要由雌鸟白天孵卵，幼鸟在约12天内被照顾，约20天离巢。","identification":"与欧亚夜鹰最为相似，但体型更小，上体缺乏明显的淡色标记。雄鸟通过外翼的白色斑点和尾端的白色区分开，而雌鸟尾部无白色，翼上的斑点较小。","protection":"IUCN：LC（无危）","distribution":"广泛分布于撒哈拉以南非洲，包括安哥拉、贝宁、博茨瓦纳、布基纳法索、布隆迪、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、斯威士兰、埃塞俄比亚、加蓬、加纳、几内亚、肯尼亚、利比里亚、马拉维、马里、莫桑比克、纳米比亚、尼日尔、尼日利亚、卢旺达、塞拉利昂、南非、南苏丹、坦桑尼亚、多哥、乌干达、赞比亚和津巴布韦。"},{"name":"白喉夜鹰","english_name":"Bonaparte's Nightjar","scientific_name":"Caprimulgus concretus","overview":"白喉夜鹰（英文名：Bonaparte's Nightjar，学名：Caprimulgus concretus），是夜鹰目夜鹰科夜鹰属的鸟类。体型较小的夜行性鸟类，以亮白色的喉部斑纹而得名。其分布局限于印尼的苏门答腊岛、勿里洞岛和婆罗洲的低地森林，面临因栖息地丧失而导致的威胁。","appearance":"成年白喉夜鹰体长约21-22厘米，上体呈暗褐色，带有栗色斑点，无颈背环带；翼覆羽为棕色，点缀着栗色和肉桂色；肩羽深褐，边缘淡色。最显著的特征是其白色的眼颊条纹和较大的白色喉部斑块。下体栗色横纹，腹部和两胁变为淡色横纹。两性皆无翼上的白色标记，雄鸟尾羽外侧两根具白色尖端，雌鸟罕见地可能有极窄的白色尾尖。虹膜深棕色，喙、腿和脚均为棕色。","call":"雄鸟的叫声是一声低沉哀伤的‘wa-ouuuu’，第二音节音调下降。通常在黄昏、黎明和月光之夜从栖木上发出叫声。","habits":"主要栖息于低地森林，包括龙脑香林、湿地森林和次生林，海拔高度从海平面至500米。白天隐匿于茂密纠结的植被中，夜间活动，常从栖木上进行短暂的飞扑捕食，偏好在河流上方狩猎昆虫。","breeding":"关于繁殖行为的信息尚未记录。","identification":"与萨氏夜鹰相比，白喉夜鹰颜色更浅，斑点较轻。萨氏夜鹰雄鸟的四枚最外侧初级飞羽上有小的白色标记，且尾羽外侧两根具白色尖端。","protection":"IUCN：VU（易危）。尽管分布广泛，但物种可能稀少，且记录不足。在几个保护区中存在，包括丹南谷保护森林保护区、库塔伊国家公园、尼亚图佩尼森自然保护区和Way Kambas国家公园。","distribution":"分布于苏门答腊岛、勿里洞岛和婆罗洲。在苏门答腊岛的记录自1916年后中断，直到1995年在Way Kambas国家公园再次被发现。在婆罗洲的马来西亚部分，近来仅在沙捞越有少量记录。"},{"name":"萨氏夜鹰","english_name":"Salvadori's Nightjar","scientific_name":"Caprimulgus pulchellus","overview":"萨氏夜鹰（英文名：Salvadori's Nightjar，学名：Caprimulgus pulchellus），是夜鹰目夜鹰科夜鹰属的鸟类。分布于印尼的苏门答腊和爪哇岛的森林高地区域。这种夜鹰体型较小，数量较为稀少，属于印尼特有种。","appearance":"萨氏夜鹰长约19至21.5厘米，性别二态性不显著。上部和翼覆羽呈深棕色，带有浅黄褐色、肉桂色和淡黄色的斑点和条纹；头顶和颈背颜色较浅，呈灰褐色，中央羽毛有黑色条纹；不明显的浅黄褐色颈环；两侧有浅黄褐色颊纹和下喉部的大白色斑块；下部羽毛为浅黄褐色、淡黄色和灰白色，有棕色条纹，腹部下方、侧腹和下尾覆羽变为淡黄色有棕色条纹。雄鸟翼端有小白色斑点或条纹，尾羽最外侧两根有白色尖端；雌鸟翼上有浅黄褐色斑点，尾羽最外侧两根有白色或淡黄色尖端。虹膜棕色，喙黑色，跗跖呈棕色。","call":"雄鸟的鸣唱可能是一系列短暂的‘tok’音节，持续约2.5秒，第一个音节柔和且非常短促，其余音节响亮且较长。","habits":"萨氏夜鹰通常栖息于山地和亚山地森林，常在悬崖和崖壁上活动，偶尔也会出现在小型湿地。其活动范围在爪哇岛海拔800米至2100米之间，在苏门答腊则位于1350至2200米之间。它们可能以昆虫为食，常在林间空地或靠近悬崖的地方觅食，狩猎时缓慢拍打翅膀并频繁滑翔，也从栖木处做短距离飞扑捕食，或直接从崖壁上捕获猎物。","breeding":"繁殖信息了解较少。在爪哇岛，繁殖季节为3月底至5月；在苏门答腊的繁殖季节未知。已知的筑巢地点位于茶树下，无巢，直接将卵产于地面落叶上。每窝产卵1至2枚，卵呈椭圆形，光滑的白色，大小约为29毫米×21.5毫米。","identification":"萨氏夜鹰比白喉夜鹰颜色更深，斑点更重，两性均无翼上的白色标记；白喉夜鹰雄鸟的尾羽最外侧两根有白色尖端。与其他同域夜鹰相比，一般体型更大，颜色更浅。","protection":"IUCN：LC（无危），但由于分布范围狭窄，尤其是苏门答腊地区的栖息地因农业扩张和伐木而受到威胁，需要进一步研究。","distribution":"分布于苏门答腊山区和爪哇岛，具体而言，在繁殖区域内位于爪哇岛海拔800至2100米和苏门答腊海拔1350至2200米的森林地带。","other":"萨氏夜鹰在印尼的苏门答腊和爪哇岛上的记录有限，直到近期才在南巴里桑山脉的大部分地区发现其踪迹，在Kerinci-Seblat国家公园内定期被观察到。"},{"name":"普氏夜鹰","english_name":"Prigogine's Nightjar","scientific_name":"Caprimulgus prigoginei","appearance":"普氏夜鹰是一种小型夜鹰，体长约19厘米，尾巴短，头部大。已知的唯一标本是一只成年雌鸟，体色深褐，带有厚重的斑点。飞行时，全身主要呈现褐色，翅膀上没有许多近亲具有的白色标记，仅有淡褐色的翼斑和白色的尾羽尖端。雄鸟的外观未知。","call":"雄鸟的鸣叫声未知，但在其繁殖区域内听到的未识别夜鹰叫声包括快速的颤音和敲击声。","habits":"普氏夜鹰的栖息地、活动范围和食物来源尚未明确，但推测它像其他夜鹰一样，以夜间活动为主，捕食昆虫。","breeding":"关于普氏夜鹰的繁殖信息几乎空白，但假设它会在裸露的地面上筑巢，如同其他夜鹰种类。","identification":"普氏夜鹰与其他夜鹰的区别在于飞行时缺乏白色翼部标记，以及其独特的叫声。","protection":"IUCN：DD（数据缺乏）","distribution":"非洲：刚果民主共和国东部，可能分布于喀麦隆东南部、刚果共和国北部和加蓬。","other":"普氏夜鹰的名字是为了纪念鸟类学家亚历山大·普里戈金。"},{"name":"贝氏夜鹰","english_name":"Bates's Nightjar","scientific_name":"Caprimulgus batesi","overview":"贝氏夜鹰（英文名：Bates's Nightjar，学名：Caprimulgus batesi），是夜鹰目夜鹰科夜鹰属的大型暗色森林夜鹰，特征为长尾，雄鸟具有翼尖和尾端的小白色斑点，而雌鸟全身暗色，尾端可能呈现淡褐色。分布于非洲西部的雨林地带，包括喀麦隆南部至乌干达和刚果民主共和国东部。","appearance":"体长约29-31厘米，体重介于89-112克。上部和翼覆羽呈深棕色，带有黑色和淡褐色条纹、斑点。颈背有不明显的淡褐色领圈，喉部白色。下部黑褐色，胸部有淡褐色斑点，腹部则为淡褐色条纹。雄鸟翼尖和两根最外侧尾羽有小白色斑点，雌鸟较淡，无白色标记。眼睛、喙、腿和脚均为深棕色。幼鸟与成鸟相似，但颜色更浅，更偏黄褐色。","call":"发出独特的叫声，开始是一声像狗吠般的“kow”，随后短暂停顿后连续几声类似的音符。","habits":"主要栖息于低地原始雨林，偏好林间空地和边缘地带，常出现在水边，尤其是河流或泛滥的森林附近。以昆虫为食，如螳螂、蟋蟀、蚱蜢、甲虫、飞蛾和蚂蚁。在林冠上方和草甸上觅食，沿河岸森林边缘活动。","breeding":"繁殖季节在加蓬为12月至1月，在刚果民主共和国可能全年。筑巢于林间小径或稀疏植被的地面，或厚密森林、种植园或花园边缘。单产一枚卵，直接置于裸露的土壤或落叶层上。孵化期未知，雏鸟覆盖黄色绒毛，离巢时间不明。","identification":"与非洲褐夜鹰在同一生境发现，但体型更大，尾巴更长。雄鸟的翼和尾上的淡色斑点是进一步的区别。","protection":"IUCN：LC（无危）","distribution":"分布零散，主要见于喀麦隆南部、加蓬、中非共和国南部、刚果西部、刚果民主共和国东部至乌干达的Bwamba森林，以及刚果民主共和国中部。"},{"name":"非洲长尾夜鹰","english_name":"Long-tailed Nightjar","scientific_name":"Caprimulgus climacurus","overview":"非洲长尾夜鹰（英文名：Long-tailed Nightjar，学名：Caprimulgus climacurus），是夜鹰目夜鹰科夜鹰属的鸟类。最显著的外部特征是拥有极长的尾巴。分布广泛，覆盖非洲的中部、中西部和西部地区，包括安哥拉、贝宁、布基纳法索、喀麦隆等国。","appearance":"非洲长尾夜鹰体型苗条，长度在28至43厘米之间，体重介于35至61克，雌雄异色。颜色从浅棕到灰棕色，甚至沙色。上部和翼覆羽通常呈灰棕色，带有细小的褐色条纹。雄鸟的前翅有一白色线条，而雌鸟为淡黄色或淡黄白色线条。两性均有宽阔的淡色颈圈和白色的喉部斑点。雄鸟的外侧五根主翼羽有宽阔的白色带，内翼边缘也是白色；雌鸟的翼带和内翼边缘为淡黄色或淡黄白色。尾巴呈渐变状，中央一对最长，外侧尾羽边缘和尖端白色或淡黄色。","call":"发出快速机械般的颤音，音调比同类夜鹰高，还有‘chiow’的叫声，常在飞行中发出。","habits":"栖息地多样，从干旱的半沙漠到森林和林间空地，常见于各种草地和耕作区。迁徙模式不详，部分种群在繁殖季节后向南移动。以甲虫、蛾子、螳螂、昆虫、蚂蚁、白蚁和蚱蜢为食，狩猎方式是在空中捕食，飞行中饮水。","breeding":"繁殖时间因地区而异，可能为单配偶制。在叶面或裸露地面产卵，通常为2枚椭圆形、奶油色、淡黄色或粉红色的蛋，布满灰色或灰紫色斑点并染有红褐色。孵化和离巢时间未知。","identification":"与细尾夜鹰相似，但非洲长尾夜鹰尾巴更长，体色更偏赤褐色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部、中西部和西部，包括但不限于安哥拉、贝宁、布基纳法索、喀麦隆、中非共和国、乍得、刚果共和国、刚果民主共和国、科特迪瓦、厄立特里亚、埃塞俄比亚、加蓬、冈比亚、加纳、几内亚、几内亚比绍、肯尼亚、利比里亚、马里、毛里塔尼亚、尼日尔、尼日利亚、塞内加尔、塞拉利昂、苏丹、坦桑尼亚、多哥和乌干达。"},{"name":"细尾夜鹰","english_name":"Slender-tailed Nightjar","scientific_name":"Caprimulgus clarus","overview":"细尾夜鹰（英文名：Slender-tailed Nightjar，学名：Caprimulgus clarus），是夜鹰目夜鹰科夜鹰属的鸟类。体型纤瘦，具有略显延长的中央尾羽。主要分布在非洲东部，从埃塞俄比亚和索马里至坦桑尼亚中部，常见于干燥的灌木丛生地带。","appearance":"成年细尾夜鹰长约28厘米，体重介于34至53克，性别间存在差异。上体和翅膀覆羽通常呈灰褐色，带有暗褐色条纹；雄鸟拥有白色翼线，雌鸟则为淡褐色。雄鸟具有宽阔的白色主翼带和内翼边缘，尾羽渐变楔形，中央尾羽最长，边缘和尖端白色；雌鸟的翼带较窄，内翼边缘淡褐色或淡黄白色，尾羽渐变程度较低，边缘和尖端为淡褐色。虹膜棕色，喙棕色顶端黑色，腿脚呈棕褐色。幼鸟与成年雌鸟相似，但颜色更浅。","call":"雄鸟的鸣唱是一系列快速的‘wa, wa, wa, wa, wa’音符，可能形成缓慢的颤音，偶尔夹杂着高音的‘weet’叫声，结尾为‘chor-chor’或气泡音。飞行叫声为高音的‘whit, whit, whit’。","habits":"栖息于荆棘丛生的灌木区、金合欢树丛、稀疏的草原和开放的林地，海拔从海平面至2000米。以蛾类、蝇类、甲虫、蚂蚁、蝽象和直翅目昆虫为食，常在低空或草地、岩石斜坡上猎食。也可能在人工光源附近捕食被吸引而来的昆虫。","breeding":"繁殖季节一般为2月至5月，北部种群可能更早开始。通常产2枚卵，卵椭圆形，底色为乳白色或粉红色，带有棕色斑点和淡灰色紫罗兰色的微弱标记。成鸟在受到威胁时可能会装死以分散天敌注意力。雏鸟的绒毛和离巢时间尚不清楚。","identification":"与非洲长尾夜鹰相比，尾部较短，色彩变化较小；比方尾夜鹰更浅色和灰，冠部条纹较弱，尾羽更明显地渐变。","protection":"IUCN：LC（无危）。在整个分布范围内常见到局部丰富。在埃塞俄比亚、索马里南部、南苏丹东南部、乌干达、肯尼亚和坦桑尼亚东北部广泛分布且局部常见。","distribution":"分布于吉布提和索马里西北极地区，从埃塞俄比亚和南苏丹东南部至坦桑尼亚西北部和南部中部。"},{"name":"方尾夜鹰","english_name":"Square-tailed Nightjar","scientific_name":"Caprimulgus fossii","overview":"方尾夜鹰（英文名：Square-tailed Nightjar，学名：Caprimulgus fossii），是夜鹰目夜鹰科夜鹰属的鸟类，又称加蓬夜鹰或莫桑比克夜鹰。其最显著的特征是尾部带有明显的方形轮廓，尽管并非完全方形。广泛分布于非洲中南部及东南部的热带和亚热带木林地带。","appearance":"体型中等，雄鸟体重约54至68克，雌鸟47至77克。上体暗灰褐色，密布灰色斑点；具宽大的棕黄色颈环，翼覆羽深灰褐，布满灰白与淡棕斑点；雄鸟前翅有白色或微黄横带，雌鸟为淡黄色。眼虹膜棕色，喙黑色，腿足肉棕色或黑色。雄鸟外侧五根初级飞羽有宽阔的白色横带，翼内缘白色，外侧尾羽边缘与尖端白色；雌鸟翼带较窄，翼内缘淡色，外侧尾羽边缘与尖端呈淡黄色。幼鸟与雌鸟相似，但颜色更浅且图案更简单。","call":"雄鸟发出独特的上升音调的颤音，然后保持平稳，偶尔以单个“wow”音符结束。飞行中会发出一系列短促的‘a-whoow’音节，站立时发出‘whit, joe’声，受惊时发出快速的‘shwip-ip-ip-ip-ip’声。","habits":"栖息于开放的木林、灌丛、河岸森林、郊区花园、沙质土地近水处。在莫帕尼木林、米奥博木林、城市公园等地活动。海拔高度从海平面至1850米。以蛾子、甲虫、蚱蜢、飞蚁、蚂蚁和蝽象为食，通过低空捕猎或从地面或栖木短暂飞行捕捉猎物。","breeding":"繁殖期因地区而异，如在坦桑尼亚和莫桑比克为9月至12月。可能仅产一窝。巢址通常位于灌木丛或零散草丛间，地面裸露或接近水源。巢中无构造，蛋直接产于枯叶、裸土、沙石上。每窝产1至2枚蛋，椭圆形，表面呈哑光或光泽，乳粉色底，布满棕色斑块与灰色细斑点。孵化期约为14至17天，主要由雌鸟负责。雏鸟半早熟，覆盖着深棕和淡黄绒毛。","identification":"与长尾夜鹰和纤尾夜鹰的区别在于其尾部特征，纤尾夜鹰尾部中央羽毛突出，而方尾夜鹰的尾部较为平齐。雄鸟与雌鸟的翼部标记有明显差异。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲南部和东南部，包括安哥拉、博茨瓦纳、布隆迪、刚果共和国、斯威士兰、莱索托、马拉维、莫桑比克、纳米比亚、卢旺达、南非、坦桑尼亚、赞比亚和津巴布韦。","other":"在多个保护区中可见，例如布隆迪的鲁武夫国家公园、马拉维的利翁德国家公园和赞比亚的卡富埃国家公园。"},{"name":"旗翅夜鹰","english_name":"Standard-winged Nightjar","scientific_name":"Caprimulgus longipennis","overview":"旗翅夜鹰（英文名：Standard-winged Nightjar，学名：Caprimulgus longipennis），是夜鹰目夜鹰科夜鹰属的鸟类。带有棕色颈环。其无声、像蛾子般的飞行姿态和缺少白色翼尾标记是显著特征。歌声为连续的颤音。","appearance":"成年旗翅夜鹰雄鸟在繁殖季节展现出独特的翼部装饰，由两根异常延长的内侧次级飞羽构成，长度可达38厘米，其中20厘米以上为无羽毛的羽轴。非繁殖期，雄鸟和雌鸟在外表上无明显区别。成鸟体长21-22厘米（不含雄鸟的‘标准’），体重32-65克。色彩变异较大，雄鸟通常呈黑色，点缀以白色斑点，雌鸟则多为沙色或土黄色。上身有灰白斑点，头部亦有类似斑点，背部有明显的土黄或土褐色领圈；翅膀覆羽为褐色，有灰白和淡土黄色斑点，肩羽深褐色，边缘较浅；眉纹土黄色但较短；喉部有土黄色带状斑块；下身呈褐色，点缀以灰白色和土黄色斑点，腹部和侧面变为土黄色带状。两性均无翼和尾部的白色标记。繁殖期雄鸟有极度延长的次级内侧飞羽，仅尖端有羽毛，形成‘标准’或旗帜。虹膜深褐色，喙黑色，腿和脚深褐色。体型小于翎翅夜鹰；雌鸟略小且颜色更淡，颈部领圈更浅，眉纹更短，缺乏白色喉部斑块，下身条纹不明显。幼鸟与成年雌鸟相似，但毛色更单一，对比不强烈，上身更多红褐色，头部和肩羽仅有少量深褐色斑点，颈部领圈不明显，主翼羽和尾羽比成鸟窄。亚成年雄鸟无‘标准’装饰。","call":"鸣声为快速而柔和的一系列高音‘ts’音符，持续约75秒，几乎总是以一个‘tchoou’（或‘seee’）音符结束，类似于蚱蜢的摩擦声或小型哺乳动物的吱吱声。在回应不同雄鸟的展示飞行时，声音可能变得更响亮、更紧迫，但节奏变慢。还会有更慢、更粗糙的‘s-ch’音符，同样是对抗者的展示作出反应。","habits":"栖息于轻度林木覆盖的草原，或带灌木或荆棘灌丛的草原。也见于树木稀疏的农田、开阔的草地、石质山坡植被散生地带、沿海平原和沙质荒地；较少出现在牧场、荆棘灌木丛、林中空地（常靠近村庄）、森林内的草质孤山、草坪和铺砌区域。海拔分布从海平面至1400米，但在埃塞俄比亚可达2030米。以甲虫、蛾、蝗虫、蝉、蠼螋、臭虫、叶蝉、蝇、有翅蚂蚁、有翅白蚁和蚊子为食。黄昏开始觅食，有时持续至夜晚甚至黎明前；夜间觅食与月光水平正相关，新月期间增加黄昏觅食活动，补偿较短的夜间觅食时间。在开阔地带和路边猎捕昆虫，也在昆虫群集处和受火扰动的昆虫中觅食，有时被人造光源吸引。","breeding":"繁殖期在塞内加尔至3月至7月，马里11月至7月，利比里亚2月至5月，可能还包括多哥，加纳1月至5月，尼日利亚1月至6月，埃塞俄比亚南部4月至5月，乌干达北部9月和2月至4月，刚果民主共和国北部1月底至4月初。可能受到雨季影响，因为雨后不久猎物数量达到高峰，随后四个月内逐渐减少。雄鸟为多配偶制；单独或半群居繁殖，几巢相距20米以内。巢址位于近植被处，草丛中或小树丛中，或开阔地带；无巢，蛋直接产于地面，通常在裸露的沙土上。雄鸟和雌鸟（最多十只个体）聚集在展示场地（求偶场），进行地面和空中互动。求偶时，雄鸟围绕雌鸟飞行，发出微弱的咔哒声，然后着陆，雌鸟随后落地或在颤抖的振翅中绕雄鸟飞行。","identification":"与翎翅夜鹰雌鸟和非繁殖期雄鸟非常相似，但体型较小。旗翅夜鹰两性均无翼和尾部的白色标记，而翎翅夜鹰有明显的白色标记。此外，旗翅夜鹰的颈部领圈更淡，眉纹更短，缺乏白色喉部斑块。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部，从塞内加尔和冈比亚至利比里亚，东至苏丹西南部和乌干达北部。繁殖季节外，分布在撒哈拉以南非洲的多个地区。","other":"在非繁殖季节，旗翅夜鹰可能因群居习性和在道路上栖息，面临较高的交通死亡风险。"},{"name":"翎翅夜鹰","english_name":"Pennant-winged Nightjar","scientific_name":"Caprimulgus vexillarius","overview":"翎翅夜鹰（英文名：Pennant-winged Nightjar，学名：Caprimulgus vexillarius），是夜鹰目夜鹰科夜鹰属的鸟类。分布于非洲安哥拉至南非东部。繁殖季节雄鸟具有独特的‘翎翅’，非繁殖季节雄鸟和雌鸟也具有显著的外观特征。","appearance":"体型24–28厘米（不计雄鸟的‘翎翅’，最长可达78厘米）；雄鸟体重59–79克，雌鸟65–88克。雄鸟繁殖季节时拥有显著的‘翎翅’，上体呈棕色，斑点和条纹灰褐色，头部具黑色斑点；颈背有一宽阔的棕黄色环；翅膀覆羽棕色，斑点灰色和白色；肩羽内侧黑色，外侧淡色；眉纹淡色且较长；喉部白色；下体棕色，带有棕黄色或淡黄色斑点，腹部和两胁有棕色条纹。雄鸟翅膀黑色，最外四根初级飞羽尖端白色，内翼边缘白色，八根外侧初级飞羽有宽白带；繁殖季节雄鸟第二内侧初级飞羽极度延长，形成‘翎翅’；雌鸟翅膀棕色，有宽幅棕黄色条纹，尾部无白色标记。虹膜深棕色，喙黑色，腿脚粉棕色或灰棕色。","call":"雄鸟的叫声是一系列快速的高音‘tseet’声，常在展示飞行或栖息时发出。飞行时会发出哀怨的‘wheeeo’或‘chup’声。雌鸟在交配前可能会发出柔和的‘schurr’声。","habits":"主要栖息于成熟的miombo或mopane林地，也出现在其他类型的林地、火烧或清理过的区域、灌木草原、开放草地、郊区树林、耕作区、废弃农田和花园、河谷、火烧的湿地和草甸；偶尔在森林空地和桉树种植园中被发现。飞行高度较高，以捕捉空中飞行的昆虫为食，如蛾子、甲虫、白蚁、蚂蚁、蟋蟀、蚱蜢、螳螂、蟑螂、蠼螋、盾蝽、叶蝉和蝉。有时白天也会觅食。","breeding":"繁殖期在安哥拉为8月至10月，赞比亚为8月末至11月，坦桑尼亚南部为8月至3月，马拉维、莫桑比克和津巴布韦为10月至12月，南非为9月至11月（可能延续至12月）。一季一次繁殖，可能实行多配偶制。雄鸟会在求偶场进行领地展示，但不在巢址处。巢位于开放地带或树荫下，通常在火烧过的地面，没有巢材，蛋直接产在裸露的地面上或落叶层上。每窝产1-2枚椭圆形、近圆锥形或双锥形的光泽卵，浅至深鲑鱼粉色，带有暗粉色、红棕色、紫色和灰色的斑点，间隔1-2天产下。通常由雌鸟孵卵，自第一枚卵开始，孵化期15-18天。绒毛雏鸟的描述未见记载，离巢时间未记录。","identification":"与标准翼夜鹰相似，但体型更大，翅膀上有更多条纹。雄鸟在繁殖季节有明显的‘翎翅’，而雌鸟则没有。雌鸟较暗，颈背颜色更深，眉纹更长，喉咙白色，下体条纹不那么强烈。","protection":"IUCN：LC（无危）","distribution":"分布于中、东北及东安哥拉，刚果民主共和国南部和坦桑尼亚西南部南部至纳米比亚（卡普里维地带），博茨瓦纳和南非东北部。冬季从尼日利亚东南部至乌干达和肯尼亚西部。","other":"翎翅夜鹰是一种非洲内部迁徙的物种，迁徙模式复杂，尚未完全理解。"},{"name":"叽喳夜鹰","english_name":"Chirruping Nightjar","scientific_name":"Caprimulgus griseatus","overview":"叽喳夜鹰（英文名：Chirruping Nightjar，学名：Caprimulgus griseatus），是夜鹰目夜鹰科夜鹰属的鸟类。具有出色保护色的夜行性鸟类，主要分布在菲律宾。体型中等，体长20至26厘米，上部呈斑驳的灰褐色，下部则为带有斑点和条纹的棕色，雌雄异型明显。鸣声独特，高亢重复的“追－追”声，使其易于被发现。","appearance":"成年叽喳夜鹰的上部为棕色，点缀着白或肉桂色斑点，有黑色斑纹；颈部有淡色环状斑；翼羽基部有淡色大斑点；肩羽边缘为浅色；嘴角须纹淡色，喉部下方有小白色斑块；下体棕色，带有肉桂色和淡色斑点及条纹，腹部和侧腹则为淡色带棕色条纹。雄鸟四枚最外侧初级飞羽有大白色斑点，两根最外侧尾羽一般为白色，端部或边缘为棕色；雌鸟翼上有淡色斑点，尾部无白色。幼鸟与雌鸟相似，但颜色较淡，偏灰棕色。","call":"发出响亮的双音节叫声“chee-wit！”或“chee-vee！”，重复时间长达数秒，间隔约2秒，持续时间约0.23秒，最高频率约5kHz。声音在声谱图上呈现独特的V型波形，先大后小。","habits":"栖息于菲律宾的草地、林缘、河岸岩石区，也可见于农田、石质或植被稀疏的山坡、沼泽边缘、红树林、沙滩、裸露沙地、干涸的石质河床、沿海灌木丛及城市环境。海拔高度从海平面到1500米，可能高达2000米。主要以飞蛾、螳螂、甲虫、白蚁和飞蚁为食，常在空中捕食，甚至在人造光源附近寻找昆虫。白天隐藏，黄昏至黎明时活跃。","breeding":"繁殖季节从五月可能延续至三月。","identification":"与林夜鹰在鸣声上有显著区别，后者的声音有粗糙的音质，不是明显的双音节。叽喳夜鹰的鸣叫声在分析中显示第二V型波比林夜鹰更长。","protection":"IUCN：LC（无危）","distribution":"主要分布于菲律宾的吕宋岛、卡坦端内斯岛、民都洛岛、锡布延岛、内格罗斯岛、宿务岛和棉兰老岛。","other":"曾被认为是林夜鹰的亚种，但基于鸣声的显著差异，现在被视为独立物种。"},{"name":"大裸鼻夜鹰","english_name":"Feline Owlet-nightjar","scientific_name":"Aegotheles insignis","overview":"大裸鼻夜鹰（英文名：Feline Owlet-nightjar，学名：Aegotheles insignis），是裸鼻夜鹰目裸鼻夜鹰科裸鼻夜鹰属的鸟类。体型较大，主要分布在新几内亚山区的热带或亚热带湿润山地森林。","appearance":"体长28至30厘米，体重59至85克。外观独特，上部呈棕色或深赤褐色，背部有少量白色斑点或条纹，显著的侧冠纹。喉咙部位为白色或淡黄色，胸部和腹部有大胆的白色斑点。存在定义明确的棕色型和赤褐色型，两者间有过渡类型。关于幼鸟的信息很少，一例被描述为赤褐色型。","call":"叫声包括一系列上升的轻微颤音“owrr”和单个或重复的尖锐“kee”声，还有描述为“foh... foh”的叫声。","habits":"主要栖息于山地森林，尤其是原始森林边缘，但也见于次生林和开放地区的河岸树林，海拔主要在1150至2800米，偶尔可达3000米。生活方式基本为定居，以昆虫为食，包括甲虫，但具体的觅食行为未知。","breeding":"繁殖季节知之甚少，曾在4月、5月、8月和9月发现处于繁殖状态的个体，11月曾观察到一只离巢雏鸟。推测筑巢地点为树洞。","identification":"其独特的V形弯曲、浅色眉毛，尖刺状须毛，以及身体上的三条宽大的垂直白色带，由泪滴形状的白色斑点组成，一条位于每侧侧面，另一条从喙部延伸至胸部，是辨识的重要特征。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的山地，特别是在该岛的山脉区域，物种在当地可以相当频繁，如在塔里谷常有记录。"},{"name":"星斑裸鼻夜鹰","english_name":"Starry Owlet-nightjar","scientific_name":"Aegotheles tatei","overview":"星斑裸鼻夜鹰（英文名：Starry Owlet-nightjar，学名：Aegotheles tatei），是裸鼻夜鹰目裸鼻夜鹰科裸鼻夜鹰属的鸟类。亦被称为斑点裸鼻夜鹰，以独特的亮红褐色羽毛和腹部三道垂直条纹著称，体型较小，具有醒目的白色眉纹和尖刺状须羽，生活在新几内亚低地森林的特定区域。","appearance":"星斑裸鼻夜鹰体型中等偏大，约25厘米长，羽毛呈亮红褐色，腹部带有三道明显的垂直条纹。头部的白色眉毛和尖锐的须羽十分显眼，下翼颜色为红褐色而非深褐色，与近似种形成对比。目前尚未有关于幼鸟羽毛的详细描述。","call":"星斑裸鼻夜鹰的叫声为粗糙的三至四音节系列“gew! gok-gak!”，首音较低沉，最后两个音节接近且几乎在同一音高。","habits":"这种夜鹰栖息于新几内亚的低地森林中，常在树冠中部直立栖息。","breeding":"关于星斑裸鼻夜鹰的繁殖信息，目前资料有限，需更多研究。","identification":"与相似的裸鼻夜鹰相比，星斑裸鼻夜鹰体型更小，白色条纹较细，且两者不会在同一地区共存。","protection":"IUCN：LC（无危）","distribution":"星斑裸鼻夜鹰分布于新几内亚东部和东南部的低地森林，包括Fly/Elevala区域和Amazon Bay周边。最近在印尼西巴布亚的Kali Muyu河流域也有记录。","other":"星斑裸鼻夜鹰曾仅知于四个标本，分别采集自相距1000公里的新几内亚东部和东南部两地，自2008年起，在新几内亚西部省的Kiunga镇附近及相邻的印尼西巴布亚有新的发现，可能在Kali Muyu河流域的低地森林广泛存在。"},{"name":"冠裸鼻夜鹰","english_name":"Moluccan Owlet-nightjar","scientific_name":"Aegotheles crinifrons","overview":"冠裸鼻夜鹰（英文名：Moluccan Owlet-nightjar，学名：Aegotheles crinifrons），是裸鼻夜鹰目裸鼻夜鹰科裸鼻夜鹰属的鸟类。亦称: 蛾鸱，该物种特有于北摩鹿加群岛，如哈马黑拉岛和巴坎岛。以独特的冠状羽毛和夜间活动性而知名。","appearance":"体长约29厘米，体重在105至167克之间。背部羽毛呈灰色或黑色，混杂着白色细纹，形成独特的星点图案。胸部有三条宽阔的淡褐色竖向条纹，间隔以两条深色带。幼鸟外观较为单一，呈浅红褐色，缺乏成鸟的斑纹。成鸟两性相似，但雌鸟可能体型略大。","call":"发出一系列3个或更多下降音符的叫声，首声最长且音调下滑，常伴随疯狂的咯咯声。","habits":"栖息于低地和山脚森林，包括次生林、森林边缘和偶尔的轻度树木栽培区，如椰子种植园。活动范围从海平面至海拔1800米。以小型昆虫为食，通过从中间层的栖木上突飞捕捉空中昆虫。","breeding":"关于繁殖习性的信息有限，通常被观察到单独或成对出现，有时3至5只小群体可能是家庭单位。","identification":"是其分布范围内唯一的裸鼻夜鹰，可通过背部的白色星点和胸部的箭头状深色标记来识别。","protection":"IUCN：LC（无危）","distribution":"分布于印尼的北摩鹿加群岛，具体为哈马黑拉岛和巴坎岛。","other":"1994年，在拟建的哈马黑拉国家公园的地点发现了该物种，此后被认为在岛上常见。"},{"name":"华氏裸鼻夜鹰","english_name":"Wallace's Owlet-nightjar","scientific_name":"Aegotheles wallacii","overview":"华氏裸鼻夜鹰（英文名：Wallace's Owlet-nightjar，学名：Aegotheles wallacii），是裸鼻夜鹰目裸鼻夜鹰科裸鼻夜鹰属的鸟类。小型夜行鸟类。以英国自然学家阿尔弗雷德·拉塞尔·华莱士命名，分布于新几内亚及其周边地区，包括Waigeo（四王群岛西北部）、印尼阿鲁群岛（新几内亚西南部）、鸟头半岛（新几内亚西北部）。","appearance":"体长约20至23厘米，体重46.5至52克，具暗褐色翅膀和尾巴，带有横纹和额外的白色斑点。头部深色，腹部白色，胸部基部呈浅黄褐色，覆盖着不规则的暗色箭头状标记。幼鸟的冠部全黑褐，仅带有细而不规则的横纹和淡黄色斑点，下体有重横纹。","call":"叫声为简单的双音节口哨声“pweet pyuut”，第一个音节下降，第二个音节更低，有时伴有颤音，可能作为其歌曲。有时仅发出其中一个音节。","habits":"栖息于山脚森林，关于其具体生活习性的信息有限。","breeding":"相关繁殖信息未详。","identification":"与山地、Vogelkop和条纹裸鼻夜鹰可能共存，但华氏裸鼻夜鹰缺乏条纹裸鼻夜鹰和Vogelkop的明显横纹，也没有其他三种的浅色颈环。","protection":"IUCN：LC（无危）。在其分布范围内似乎是稀少或难以捉摸的物种，仅在分散的地点有少量标本记录。由于其所有亚种的分布区内仍有大片森林，因此目前不太可能面临直接威胁。","distribution":"分布于新几内亚及其周边地区，包括Waigeo（四王群岛西北部）、印尼阿鲁群岛（新几内亚西南部）、鸟头半岛（新几内亚西北部），在新几内亚零星分布。"},{"name":"灰裸鼻夜鹰","english_name":"Mountain Owlet-nightjar","scientific_name":"Aegotheles albertisi","overview":"灰裸鼻夜鹰（英文名：Mountain Owlet-nightjar，学名：Aegotheles albertisi），是裸鼻夜鹰目裸鼻夜鹰科裸鼻夜鹰属的鸟类。分布于新几内亚的高山区，栖息于亚热带或热带湿润的山地森林。","appearance":"灰裸鼻夜鹰体型小，长度约18至20厘米，体重36至40克。头部暗色，颈部有淡色环状斑纹，背部与尾巴有条纹。存在红褐色变型。幼鸟上部主要为暗淡的红褐色，有少量模糊的暗条纹，下部颜色较浅，带有多条暗淡的沙黄色条纹和不显眼的黑色斑点。","call":"发出尖锐下降的‘wek！’或‘wek-wek！’声，类似挤压玩具的响声或粗糙的音调。","habits":"白天在茂密的灌木丛中休息，夜晚在山地森林的树冠下或空旷处寻找昆虫。主要食物为昆虫（如鞘翅目、鳞翅目、双翅目和直翅目），偶尔也会吃一些蚯蚓。","breeding":"繁殖季节不详，但观察到在6月和9月处于繁殖状态，8月和11月发现有卵，4月或5月有巢中幼鸟。巢建在枯死树木的洞穴中，一次观察位于森林边缘，另一次在原始森林中，距地面约3.5米。每巢仅含一枚白色卵。孵化和离巢时间未知，也不清楚两性在照顾卵和幼鸟中的角色。","identification":"与华莱士裸鼻夜鹰的区别在于后者缺乏淡色颈部环纹，与弗格克裸鼻夜鹰的区别在于后者胸部有条纹。存在红褐色和棕色变型，通过中间类型相连。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚山区，海拔范围报告为800至3700米，但在东高地的已知范围内，高度约为1385至2615米。"},{"name":"新喀裸鼻夜鹰","english_name":"New Caledonian Owlet-nightjar","scientific_name":"Aegotheles savesi","overview":"新喀裸鼻夜鹰（英文名：New Caledonian Owlet-nightjar，学名：Aegotheles savesi），是裸鼻夜鹰目裸鼻夜鹰科裸鼻夜鹰属的鸟类。极为罕见的裸鼻夜鹰科鸟类，可能已灭绝。仅被记录在新喀里多尼亚的Grande Terre岛上，自1880年首次发现以来，仅有两次确切记录和一些未确认报告。","appearance":"新喀裸鼻夜鹰的羽毛整体为棕色，翅膀和尾巴上带有灰色白边的条纹，这种暗淡的羽色有助于它在森林环境中保持隐蔽。","habits":"最近的观察记录发现该鸟在海拔约1000米的湿润河岸森林中活动，可能在次冠层中觅食，但其确切的生活习性和栖息地仍然未知。","breeding":"有关繁殖的信息极为匮乏。仅有的标本标签上注明其食谱含甲虫，但实际繁殖习性、筑巢地点和幼鸟成长情况均未有详细记录。","protection":"IUCN：CR（极危）。新喀裸鼻夜鹰可能因栖息地破坏、鼠类入侵和猫的捕猎而数量锐减。","distribution":"新喀裸鼻夜鹰的分布局限于新喀里多尼亚的Grande Terre岛，可能已在该区域内灭绝。","other":"已知的第二个标本发现于1999年，之前认为可能已经灭绝。"},{"name":"斑裸鼻夜鹰","english_name":"Barred Owlet-nightjar","scientific_name":"Aegotheles bennettii","overview":"斑裸鼻夜鹰（英文名：Barred Owlet-nightjar，学名：Aegotheles bennettii），是裸鼻夜鹰目裸鼻夜鹰科裸鼻夜鹰属的鸟类。低地及丘陵森林中常见的中等体型裸鼻夜鹰，全身深灰具细密横纹，头顶中央具黑色纵纹，眉纹黑色并延至后颈，颈背有浅色半环。仅见于新几内亚东部大陆及外海三座小岛，海拔自海平面至约1100米，目前对其食性及繁殖仍所知极少。","appearance":"体长20–23厘米，体重45–47克。雌雄同色，无多态。上体黑褐至黑灰色，密布灰白或淡褐色细虫蠹纹；眉纹淡黄褐色，颈背具可变色的淡色半领。尾羽黑褐，具10–12道窄淡色横带（常见8–11道）。下体灰白至淡黄褐，胸侧及胁部具粗黑斑与不规则横斑，腹部渐疏。喙黑褐至黑色，下喙稍淡；虹膜褐色；脚淡褐至淡黄色或带粉色。幼鸟资料匮乏，仅知刚离巢个体颈背半领极不明显。","call":"鸣唱被形容为沙哑似犬吠的“wra, wra”或“ap…ap…ap…”，回放时音调更高、节奏更快，如“chyek…chyek…”。另有低沉颤音或下倾空洞的“churr”。外海岛屿亚种夜间发出嘶哑哀婉的“U whoa whoa”，首音与次音间有短暂停顿。","habits":"栖于低地雨林、季风林及其边缘，主要活动海拔500–1100米（亚种plumifer），指名亚种活动于海平面至800米。白昼栖于树洞，偶在树枝上露天休息，受扰时可惊飞；似为留鸟。食物与捕食方式尚无确切记录。","breeding":"繁殖信息极少。10月在东南新几内亚曾采得刚离巢幼鸟；12月末在北部Huon半岛采得雌鸟卵巢含卵；9月曾发现一株枯树干内巢含2枚纯白色卵，卵大小指名亚种28.4–32.0×21.5–23.5毫米，北部分化亚种31.4–32.2×24.3–24.8毫米。巢址及窝卵数资料仍缺乏。","identification":"与同域分布的澳洲裸鼻夜鹰相比，斑裸鼻夜鹰体型较小，耳羽无红褐色，尾横带较窄，下体横斑更显。与弗格克裸鼻夜鹰及卡里穆伊裸鼻夜鹰极难现场区分，但斑裸鼻夜鹰通常栖于低地，胸腹横斑较密且腹部偏淡，颈背半领常不明显。","protection":"IUCN: LC（无危）。目前与卡里穆伊裸鼻夜鹰合并评估，整体被列为“无危”。各亚种所在的新几内亚雨林大面积仍存，但1972–2002年间巴布亚新几内亚西部与南部高地的毁林率估计达11–15%，需关注长期趋势。","distribution":"繁殖区：新几内亚东部及中央地区，北部水系西达Taritatu河，南部水系至Trans-Fly的Kumbe河，东抵Milne湾；外海的D’Entrecasteaux群岛（Fergusson岛、Goodenough岛、Normanby岛）。非繁殖区：无迁徙记录，全年留居上述区域。","other":"历史上曾与澳洲裸鼻夜鹰、弗格克裸鼻夜鹰及卡里穆伊裸鼻夜鹰视为同一种，后因遗传、形态及地理差异被拆分。亚种plumifer曾被质疑与指名亚种差异不足，但基于岛屿标本及原始描述仍被保留。"},{"name":"弗格克裸鼻夜鹰","english_name":"Vogelkop Owlet-nightjar","scientific_name":"Aegotheles affinis","overview":"弗格克裸鼻夜鹰（英文名：Vogelkop Owlet-nightjar，学名：Aegotheles affinis），是裸鼻夜鹰目裸鼻夜鹰科裸鼻夜鹰属的鸟类。中型的裸鼻夜鹰，生活在新几内亚西部的阿法克山脉和鸟头半岛的低山森林中。过去常被误认为与斑裸鼻夜鹰同种，但因其独特的棕色羽毛、明显的淡色颈圈和较为圆润的体型而得以区分。其自然历史和行为仍鲜为人知。","appearance":"弗格克裸鼻夜鹰外观丰满，头部大，上体呈深棕至黑色，有细窄的灰白虫状斑纹；有宽浅色眉毛和白色至浅黄褐色的后颈环；下体颜色较淡，灰色至白色，有宽点和条纹。雌雄相似，无明显性别二态性。","call":"该物种的鸣叫特征尚未被记录。","habits":"栖息于海拔80至1500米的低地和山地森林，关于其迁徙、飞行特点、活动范围、觅食方式和食物的信息尚未明确。","breeding":"关于繁殖行为、营巢、产卵和育雏等信息尚无具体记录。","identification":"与华氏裸鼻夜鹰和斑裸鼻夜鹰相比，弗格克裸鼻夜鹰胸部仅有条纹，背部无小白点或斑点，且体型更大。","protection":"IUCN：NT（近危）。可能数量不多，估计种群趋势正在下降。","distribution":"仅知分布于新几内亚的鸟头半岛（Vogelkop）和阿法克山脉（Arfak Mts.）。","other":"遗传距离和形态差异支持将其视为独立物种。"},{"name":"澳洲裸鼻夜鹰","english_name":"Australian Owlet-nightjar","scientific_name":"Aegotheles cristatus","overview":"澳洲裸鼻夜鹰（英文名：Australian Owlet-nightjar，学名：Aegotheles cristatus），是裸鼻夜鹰目裸鼻夜鹰科裸鼻夜鹰属的小型夜间活动鸟类。以灰褐色为主，具大型眼睛、较长尾巴和面部‘胡须’。在澳大利亚和新几内亚南部广泛分布，尤其在干燥的林地最为常见。","appearance":"体长21-25厘米，体重35-65克。上体暗灰色，有浅色斑点和细纹，明显的浅色眉线、后冠带和颈环；下体较淡，常呈淡褐色，有狭窄的棕色细纹。雌雄相似，但雌鸟有灰色和赤褐色两种形态，赤褐色形态在北澳较为明显。雏鸟外观类似成鸟，但羽毛更柔软，有更细的斑点，尾巴和面部触须较短。","call":"最常见叫声为高音、刺耳的‘chirr-chiiiirrr’，由2-3个单元组成，可能用于领地宣告，叫声在黄昏和黎明前后最为频繁，有时也会在夜晚中间发出。","habits":"栖息于开阔的林地、沿水道的树木、桉树和金合欢灌木丛，偏好干燥、成熟的林地。海拔分布从海平面至1000米。通常永久性定居，领域范围不大，从10到100公顷不等。以多种小昆虫为食，包括蟑螂、甲虫、蠼螋、半翅目昆虫、蚂蚁、鳞翅目昆虫和直翅目昆虫。","breeding":"繁殖季节为8月至12月，可能终身配偶。巢建于树洞底部，高度1-5米，由新鲜树叶或树皮碎片构成。每窝产3-4枚白色无斑点的蛋，孵化期25-27天，主要由雌鸟负责，幼鸟在约3周后离巢。","identification":"与同属物种区分主要通过体型、羽色和栖息地，尤其是在新几内亚东南部的近缘种斑裸鼻夜鹰，但后者不会出现在澳洲裸鼻夜鹰偏好的栖息地中。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚和塔斯马尼亚，以及新几内亚的中南部和东南部。","other":"尽管面临一些威胁，如捕食、竞争和人为因素，澳洲裸鼻夜鹰仍能在受人类影响的环境中维持其种群数量。"},{"name":"凤头雨燕","english_name":"Crested Treeswift","scientific_name":"Hemiprocne coronata","overview":"凤头雨燕（英文名：Crested Treeswift，学名：Hemiprocne coronata），是雨燕目树燕科凤头雨燕属的鸟类。体长21-25厘米。其特征性的头部羽冠闪耀着绿色光泽，美丽且独特。上体蓝灰色，下体白色，雄鸟面颊和耳羽橙色，雌鸟有灰色面纹。常见于印度次大陆至东南亚的开阔林地和次生林区。","appearance":"凤头雨燕拥有23-25厘米的体长，成年个体的头部有高达2.5-3厘米的暗绿蓝色羽冠。雄鸟全身从中央冠至尾上覆羽为均匀的淡绿色，翼覆羽具光泽的绿黑色，下体淡灰色，腹部白色。雌鸟面部无橙色，有灰色耳覆羽和脸颊，下颌和喉部灰色，面纹更显眼。幼鸟羽毛边缘白色，头和翅主要为深灰色，其余部分条纹明显。","call":"发出典型的、类似猛禽的叫声，尤其像褐耳鹰，但在飞行中会发出‘kee-kyew’的双音节叫声，而停歇时的叫声为三音节‘kip-kee-kep’，中间音节加重。","habits":"凤头雨燕栖息于散落树木、林缘和次生林，偏好轻度林木覆盖的环境，避开开阔平原和湿润森林。它们通常在树冠外表面选择裸露的停歇位。活动范围从平地到印度次大陆约1300米，东南亚可达1400米。以飞虫为食，包括半翅目、甲虫和小蝇，捕食时远离植被表面。","breeding":"繁殖季节总体上为12月至10月，高峰期在印度次大陆为1-4月，在斯里兰卡为3-5月和7-9月，在缅甸为3-6月。巢建在高处的活树枝上，用硬化唾液结合小块树皮碎片和羽毛制成，呈半碟形，直径30-50毫米，厚度10-12毫米。每次产一枚蛋，大小约为23.7mm x 17.1mm，孵化期未知，雏鸟灰色绒羽，由双亲喂养，离巢期为42天。","identification":"凤头雨燕与灰腰凤头雨燕的区别在于尾羽流苏超出折叠翼尖，上体整体更浅色，无对比鲜明的臀部，翼下覆羽与飞羽颜色对比不明显，面部斑块更大更亮，上体光泽蓝色而非绿色。","protection":"IUCN：LC（无危）","distribution":"凤头雨燕分布于印度次大陆、斯里兰卡、尼泊尔南部、不丹南部、缅甸、中国西南部云南、泰国北部和西部、东南亚诸国如越南、柬埔寨、老挝和中国。在中国仅见于云南部分地区。","other":"凤头雨燕能够适应人类活动周边环境，偶尔在公园和花园中发现。"},{"name":"灰腰凤头雨燕","english_name":"Grey-rumped Treeswift","scientific_name":"Hemiprocne longipennis","overview":"灰腰凤头雨燕（英文名：Grey-rumped Treeswift，学名：Hemiprocne longipennis），是雨燕目树燕科凤头雨燕属的鸟类。具有独特暗灰色喉部和胸部、白色腹部的鸟类。雌雄差异明显，雌鸟耳羽无橙红/栗色。分布于马来半岛至印尼苏拉威西岛和小巽他群岛西部，偏好低地和山脚森林，尤其是湿润森林。","appearance":"成年雄鸟具有明显的暗灰色喉部和胸部，与白色的腹部形成鲜明对比，耳羽呈暗橙红色/栗色。雌鸟耳羽缺乏这一色彩。两性上半身带绿色光泽，翼尖在栖息时会交叉于尾上。雄鸟翼展长于雌鸟，尾部颜色和光泽度亦有细微差别。幼鸟头部和身体特征与凤头雨燕相似，但背部花纹更复杂，尤其在头部，无明显的侧向条纹和苍白的眼眶斑点。亚种harterti和perlonga比指名亚种颜色更深，臀部颜色较淡，而wallacii体型最大，羽色与指名亚种相近。","call":"发出尖锐的涉水鸟或燕鸥般的叫声，既在栖息时也飞行中发出，变化多样，最常见的是一种刺耳的‘ki’声，有时连续发出‘ki-ki-ki-kew’，也会发出双音节的‘too-eit’或‘whit-kep’声，第二音节略高且金属质感，类似凤头雨燕。","habits":"栖息于大型树木的林冠层、半常绿和常绿森林边缘，偶尔出现在高大的红树林和海岸松林，利用成熟橡胶园等高大种植园和成熟的公园树木。活动高度从地面到1200米不等。以飞行中的节肢动物为食，特别喜欢攻击飞蚁群和蜜蜂。黄昏和雨后特别活跃，此时会与其他空中觅食者共同活动，形成多达70只的同类群。","breeding":"在北半球的繁殖季节为2月至8月/9月，高峰在3月至6月，南半球（Java和Sulawesi）活动巢穴从12月至8月。在Kalimantan Barat（Borneo）一年繁殖两次，分别在4月至5月和8月至9月。巢通常建在5至30米高的裸露树枝上，形状似半碗，由硬化唾液、苔藓、树皮碎片和体羽构成，大小约36×24毫米，深度可达12毫米。每次产一枚白色卵，大小约为25.6×17.4毫米，孵化和育雏至少需50天。","identification":"与凤头雨燕相比，灰腰凤头雨燕体型较大但尾巴较短，流线型不突出于折叠翼尖之外，脸部橙红/栗色较少，上下体色对比更明显。小须凤头雨燕颜色更深、体型更小，有白色面部条纹和青铜色上半身。雌雄和亚种间存在颜色深浅和体型大小差异。","protection":"IUCN：LC（无危）。在其分布范围内普遍常见，总体上没有严重威胁。然而，过度使用有机磷农药可能影响其郊区公园栖息地，新加坡近期观察到种群下降。此外，西印尼的非法狩猎对非森林种群造成损害。","distribution":"广泛分布在马来半岛至印尼苏拉威西岛和小巽他群岛西部，包括Brunei、Indonesia、Malaysia、Myanmar、Philippines、Singapore和Thailand。主要栖息于亚热带或热带湿润低地森林、亚热带或热带红树林和亚热带或热带湿润山地森林。","other":"灰腰凤头雨燕偏好斑驳的树冠覆盖和边缘生境，这可能使其受益于某些森林扰动，但不适应油棕榈农业的快速扩张。"},{"name":"小须凤头雨燕","english_name":"Whiskered Treeswift","scientific_name":"Hemiprocne comata","overview":"小须凤头雨燕（英文名：Whiskered Treeswift，学名：Hemiprocne comata）是雨燕目树燕科凤头雨燕属中体型最小的物种。其独特的外观如同智慧老者的形象，拥有细长的白色'胡须'和眉毛，分布于东洋界，包括马来半岛、印尼苏门答腊岛、婆罗洲和菲律宾。","appearance":"小须凤头雨燕长约14-16厘米，翼展约13厘米。雄鸟具有黑色的额部，一对从额头延伸至颈后的细长白色‘胡须’，栗色耳羽，头部、喉部、尾羽、上翼覆羽和初级飞羽呈深金属蓝色。每片次级飞羽内侧有大片白色斑点，背部至上尾覆羽、胸部和上腹部为青铜橄榄色，下腹和下尾覆羽为白色。雌鸟缺乏雄鸟的栗色耳羽。幼鸟的羽毛细节未知。喙为黑色，眼睛深棕色，腿脚紫褐色。","call":"其鸣叫声与灰腰凤头雨燕相似，但尖锐的叽叽喳喳声更为柔和，音调较高，发出'she-she-she-she-SHOO-she'的声音，最后两个音节音调最高；还有高音的'kweeo'声，以及在栖息时发出的类似欧金翅雀的'chew'声。","habits":"小须凤头雨燕栖息于常绿森林的边缘和主树冠层，偶尔也会出现在成熟的红树林中。在原生森林中，它们常靠近河流。海拔分布从平原至1000-1100米的高度，但在马来半岛北部不超过800米。它们主要以小型飞虫为食，通常在离地面较近的地方觅食，偶尔会悬停片刻，不会飞得高于主要树冠层。通常单独或成对出现，有时会形成最多六只的小群体，偶尔允许灰腰凤头雨燕共享觅食区域。","breeding":"繁殖期为2月至8月（最晚的雏鸟出现在10月初），菲律宾记录仅限于5月。巢穴由硬化唾液制成的半碟状结构，包含羽毛，但尚未确认是否含有植物物质，由两性共同建造。巢建于8-40米高的细枝顶端或表面。每次产一枚白色卵，由双方轮流孵卵（雌鸟可能承担更多工作），并共同照顾幼鸟。孵化期至少21天，幼鸟在28天后离巢，总发育时间不少于50天。离巢后的幼鸟可能还会被喂养长达三周。","identification":"与灰腰凤头雨燕相比，小须凤头雨燕的面部条纹更明显，翅膀上的白色斑点更大，上体有铜色光泽。雄鸟与雌鸟在外观上略有差异，主要体现在耳羽的颜色。幼鸟的羽毛颜色为棕色、浅黄色、灰色和白色混杂，面部白色条纹比成鸟短。","protection":"IUCN：LC（无危）。在分布区的大部分地方常见，但在新加坡记录很少。在菲律宾较为局部，但在1991年Mindoro的森林调查中广泛观察到。对原始森林的依赖使其面临更大的栖息地丧失风险。","distribution":"小须凤头雨燕分布在马来半岛、印尼苏门答腊岛、婆罗洲和菲律宾。在原生森林中，从平原至海拔1000-1100米的高度均可发现其踪迹。","other":"小须凤头雨燕更依赖于原始森林，这使它面临因森林砍伐而失去栖息地的风险。在次生林中较少见，但能利用选择性伐木造成的边缘效应。"},{"name":"须凤头雨燕","english_name":"Moustached Treeswift","scientific_name":"Hemiprocne mystacea","overview":"须凤头雨燕（英文名：Moustached Treeswift，学名：Hemiprocne mystacea），是雨燕目树燕科凤头雨燕属的鸟类。以其显著的空中觅食能力著称。这种大型、长尾的雨燕常见于低地和山麓森林边缘。","appearance":"体长28-31厘米，体重56-79克，头部略具冠羽。飞行时展现长而细的翅膀，翼后缘黑色，有一条白色线条，尾部深叉且长，通常保持尖端。停歇时可见面部两侧两条白色羽毛，雄鸟有锈色耳斑。雄鸟上体蓝灰色，下体较浅，腹部至尾下覆羽常呈白色，脸部黑白对比鲜明，耳羽颜色变化不定。雌鸟与雄鸟相似，仅耳羽为暗黑绿色。幼鸟头部和身体羽毛复杂地带状分布，基部黑色，前部赤褐色，顶部奶油色到赤褐色，下体基部奶油色。","call":"发出尖锐的下降音调‘kwik！kwik！kwik！’或向下猛禽般的‘kweeuu！’叫声。","habits":"栖息于红树林高处树冠、海滩林地、零散树木和树林边缘，以及俯瞰开阔地带的内陆森林边缘。活动范围从海平面至海拔1580米，偏好黄昏和黎明觅食，偶尔在黑暗中活动。主要以飞行中的节肢动物为食，如蜜蜂、蚂蚁、半翅目昆虫和甲虫。通常从裸露的树梢出发，进行长时间的空中觅食，返回固定树冠，有时贴近地面捕食昆虫。","breeding":"繁殖季节因地区而异，活跃筑巢记录全年皆有，但3月除外。巢穴为羽毛和植物材料与硬化唾液制成的小盘状结构，固定于高枝上，偶尔位于近垂直表面。每次产一枚蛋，尺寸约29-33毫米×20-21毫米，两性共同孵化，孵化和育雏期超过60天，有记录显示可能在同一巢穴中育有第二窝。","identification":"在分布范围内无其他树燕科鸟类。与白腰雨燕相比，具有更深的尾叉、更长的尾巴、无喉部和臀部白色，头部图案显著，飞行姿态不同。各亚种主要在体型和体色上有差异。","protection":"IUCN：LC（无危）","distribution":"分布于印尼北部摩鹿加群岛、新几内亚、俾斯麦群岛和所罗门群岛，遍及澳新界的多个岛屿。","other":"须凤头雨燕的羽毛更换模式对于其敏捷飞行和成功捕食至关重要，这已被科学研究所证实。"},{"name":"斑额黑雨燕","english_name":"Spot-fronted Swift","scientific_name":"Cypseloides cherriei","overview":"斑额黑雨燕（英文名：Spot-fronted Swift，学名：Cypseloides cherriei），是雨燕目雨燕科黑雨燕属的鸟类。主要栖息于中美洲至南美洲北部的山地森林中，包括哥斯达黎加、巴拿马、哥伦比亚、委内瑞拉和厄瓜多尔等地。其最显著的特征是头部两侧及眼后的白色斑点。","appearance":"斑额黑雨燕全身几乎呈黑色，带有灰褐色的下翼，以及独特的白色下巴。它们的体型中等，长约14厘米，体重约23克。具有短而方形的尾巴和相对短的翅膀。一些个体可能显示腹部的白色鳞状斑纹，但这似乎与年龄或性别无关。","call":"其鸣叫声被形容为类似激光枪的声音，先是一连串的颤音，随后跟上‘pew pew pew’的音调。","habits":"斑额黑雨燕主要生活在海拔1100至2200米的山地森林中，偶尔也会在较低海拔的地区出现。它们通常以昆虫为食，尤其是半翅目和膜翅目的昆虫。群体活动时，最多可达50只，有时会与其他种类的雨燕混群。","breeding":"繁殖季节大致从4月持续到7月，但因地理位置而异。它们会在岩石垂直面靠近水源处筑巢，巢由苔藓、蕨类和泥土构成，每次产一枚卵。孵化期为26至28天，幼鸟大约在孵化后65至70天离巢。","identification":"与白颏黑雨燕最为相似，但斑额黑雨燕脸部的白色斑点是明显的区别。在远处，当面部细节难以辨认时，与其他Cypseloides属物种很难区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲北部，包括哥斯达黎加、巴拿马、哥伦比亚、委内瑞拉北部和厄瓜多尔北部。"},{"name":"白颏黑雨燕","english_name":"White-chinned Swift","scientific_name":"Cypseloides cryptus","overview":"白颏黑雨燕（英文名：White-chinned Swift，学名：Cypseloides cryptus），是雨燕目雨燕科黑雨燕属的鸟类。中型的黑雨燕属鸟类，分布于中美洲的伯利兹至南美洲的圭亚那、巴西北部和秘鲁东南部。罕见而零星分布，识别困难，通常在瀑布和峡谷附近发现，尤其是在繁殖季节。","appearance":"白颏黑雨燕具有中等到大型的体型，尾端呈方形，全身暗灰色。成鸟的头部为深褐色，前额和脸颊有狭窄的白色羽尖，喉部为深褐色但下巴处有白色的鳞状斑纹。翅膀和尾巴比背部略黑，腹部颜色稍浅。幼鸟的腹部羽毛末端有更宽的白色斑点。","call":"其鸣叫被描述为尖锐的短促声和更为悦耳的颤音，也会发出爆炸性的断续点击声，以及单一干燥的滴答声。","habits":"白颏黑雨燕广泛分布于各种生境，从海平面到3000米的海拔高度，包括常绿山地和低地森林、牧场和年轻的次生林。它们通常群居，以空中昆虫为食，如膜翅目、鞘翅目、双翅目、鳞翅目、半翅目和同翅目昆虫。","breeding":"繁殖信息大多来自哥斯达黎加的研究，筑巢于瀑布附近的岩石壁上，使用苔藓、肝蕨和泥土构建巢穴，一窝仅产一枚蛋，孵化期约30天，雏鸟在孵化后55至58天离巢。在巴西的一个繁殖地点，7月时巢穴活跃，但具体的孵化时间和离巢时间未知。","identification":"与栗领黑雨燕和斑额黑雨燕相似，但栗领黑雨燕体型较小，头部更圆润，尾巴有叉，而白颏黑雨燕的下巴和前额的白色羽尖是其独特标志。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的伯利兹至南美洲的圭亚那、巴西北部和秘鲁东南部，包括海平面至3000米的各种生境。","other":"尽管分布广泛，但由于识别难度高，白颏黑雨燕的记录较少，且目前仅在哥斯达黎加和巴西北部确认了繁殖地点。"},{"name":"白额黑雨燕","english_name":"White-fronted Swift","scientific_name":"Cypseloides storeri","overview":"白额黑雨燕（英文名：White-fronted Swift，学名：Cypseloides storeri），是雨燕目雨燕科黑雨燕属的鸟类。分布于墨西哥西南部，主要栖息于山地森林地带，以瀑布后的洞穴为巢址。","appearance":"外观特征较为粗壮，头部较大，尾端呈方形。其大小与常见的白枕黑雨燕相似，但在良好光照下可见其独特的白色前额。全身羽毛看似全黑，仅近距离观察时才能发现白色额头，需与稍大的黑雨燕区分开来。","habits":"栖息于海拔1500至2500米的森林区域，偏好有瀑布和峡谷的环境。与大量白枕黑雨燕和栗领黑雨燕共同出现在瀑布栖息地附近。活动范围及迁徙模式尚不清楚，可能全年留居或在特定季节出现。","breeding":"繁殖信息有限，有记录显示雄鸟个体在六月时睾丸增大，提示可能在此时期繁殖。","identification":"与黑雨燕相比，白额黑雨燕的白色前额是重要的识别特征。在飞行中，需仔细观察头部特征以区分。","protection":"IUCN：DD（数据缺乏）。已知数量稀少，仅基于少量标本和目击记录，最新记录为2012年，存在识别难度，导致其分布和状态难以明确。","distribution":"分布于墨西哥的哈利斯科、科利马、米却肯和格雷罗州的山区，主要集中在墨西哥西南部的山地云雾林和松树-橡树林过渡带。","other":"由于其分布范围狭窄和记录稀少，关于白额黑雨燕的许多生态信息仍待进一步研究。"},{"name":"乌黑雨燕","english_name":"Sooty Swift","scientific_name":"Cypseloides fumigatus","appearance":"乌黑雨燕是一种中等体型的雨燕，全身覆盖着病态的黑色羽毛，无明显性别差异。头部呈棕色，眼睛周围有一片黑色斑块，前额颜色稍浅。背部比头部和颈背更暗，而臀部略显淡一些。尾巴上表面为棕色，下表面则呈现灰棕色。翼上的小覆羽和中覆羽及最外侧的初级飞羽为病态的黑色，与背部颜色相近；内侧初级飞羽、次级飞羽及大覆羽的颜色较淡。飞羽内缘颜色比外缘更浅。幼鸟与成鸟相似，但体羽和飞羽边缘带有灰色。","call":"乌黑雨燕的飞行叫声被描述为快速、类似滚珠的'ti-i-i-i-a-a-a'声，以及'tiju-tiju'声和微弱的'sip'或'sip-sip'声。","habits":"乌黑雨燕偏好在山地或热带低地的常绿森林上空飞行，也可见于次生灌木丛、草地和沼泽地带。它们一天中的大部分时间都在空中飞行，通常以3到6只的小群体出现，以捕食飞行中的昆虫为主食。其活动范围广泛，能够在不同的海拔高度间迁徙。","breeding":"乌黑雨燕的繁殖季节在10月至2月之间，它们会在岩石壁面上筑巢，巢材包括苔藓、蕨类植物、树叶、小石子和泥巴，大多数巢穴位于悬崖的岩架上，甚至在瀑布后面。每次仅产一枚蛋，但关于孵化期和雏鸟离巢的时间尚不清楚。","identification":"乌黑雨燕与大黑雨燕相似，但体型较小且颜色更深。与罗氏黑雨燕相比，颜色更深，两者在地理分布上几乎无重叠。乌黑雨燕尾羽末端裸露，这是罗氏黑雨燕所不具备的特征。","protection":"IUCN：LC（无危）","distribution":"乌黑雨燕主要分布在南美洲的东部地区，包括巴西东南部、巴拉圭东部和阿根廷东北部。具体而言，其分布范围从巴西东南部的米纳斯吉拉斯州南部至南里奥格兰德州，涵盖东部巴拉圭及阿根廷的米西奥内斯省。","other":"乌黑雨燕属于雨燕科黑雨燕属，与罗氏黑雨燕形成超种群，部分分类学者曾将其视为同种。"},{"name":"罗氏黑雨燕","english_name":"Rothschild's Swift","scientific_name":"Cypseloides rothschildi","overview":"罗氏黑雨燕（英文名：Rothschild's Swift，学名：Cypseloides rothschildi），是雨燕目雨燕科黑雨燕属的鸟类。中等体型的雨燕，分布于南美洲的特定区域，包括玻利维亚南部至阿根廷西北部。全身呈现均匀的中褐色，缺乏显著的羽毛特征，容易与西氏雨燕混淆，但体型更大，翅膀更长，外观更流线型。","appearance":"罗氏黑雨燕长约15厘米，拥有长而宽的翅膀和短小的方形尾巴，全身覆盖着一致的中褐色羽毛，没有明显的色斑或图案。","call":"其叫声特征记录有限，已知会发出短促的'pip'或'peep'声，通常在飞行中听到。","habits":"这种鸟通常在湿润的森林上空成群活动，群大小从几只到20只以上不等，高度从500米到2000米之间。它是空中昆虫捕食者，但具体的饮食细节尚不清楚。","identification":"与西氏雨燕相比，罗氏黑雨燕体型更大，翅膀更长；与栗领黑雨燕相比，翅膀基部稍窄，但两者区分有时较为困难。","protection":"IUCN：LC（无危）","distribution":"罗氏黑雨燕的分布限于南美洲东南部玻利维亚（Santa Cruz, Chuquisaca和Tarija）和阿根廷西北部（Jujuy, Salta和W Formosa至Córdoba）。","other":"罗氏黑雨燕与乌黑雨燕形成超物种，两者曾被认为是同一物种。目前在一些保护区可见，如阿根廷的Calilegua国家公园。"},{"name":"黑雨燕","english_name":"American Black Swift","scientific_name":"Cypseloides niger","overview":"黑雨燕（英文名：American Black Swift，学名：Cypseloides niger），是雨燕目雨燕科黑雨燕属的鸟类。广泛分布于北美至中美洲，远至南美的巴西和加勒比海地区。在夏季繁殖于北美的西部地区，最北可达加拿大东南部的不列颠哥伦比亚省，最东延伸至科罗拉多州中部，南至墨西哥和中美洲，直至哥斯达黎加，且在西印度群岛也有分布。尽管分布广泛，但具体繁殖地相对稀少，美国已知的繁殖地不到150处，其中科罗拉多州就有108处（截至2012年7月）。在繁殖季节后离开北美，冬季迁徙路径尚不明确，但部分个体已被追踪到巴西的热带雨林。","appearance":"黑雨燕体型较大，长度约18厘米，体重约45克。飞行时展现长而尖锐的翅膀和稍带缺口的长尾，全身呈深黑色，头部羽毛略显灰褐色或棕色，有时可见前额两侧有微弱的白色斑点。成年雄鸟和雌鸟外观相似，但在腹部和尾羽下方有不同程度的白色边缘，雌鸟通常更为明显。幼鸟的羽毛边缘有显著的白色边缘或斑点，特别是在额头、喉咙、下腹和下尾覆羽上。","call":"黑雨燕发出的鸣叫声较低沉，与范围内其他种类的雨燕有所不同。","habits":"黑雨燕栖息于山区或丘陵地带，常见于悬崖峭壁或瀑布附近。它们偏好在黑暗潮湿的环境中筑巢，如悬崖壁或瀑布背后。繁殖期间，它们会迁徙到特定的繁殖地点。飞行时翼拍较慢，与其它雨燕种类形成对比。以飞行中的昆虫为食，尤其是富含脂肪的有翅生殖蚁。","breeding":"黑雨燕的繁殖期较长，产卵量仅一枚，孵化期长达23至27天。雏鸟出生后初期可能每天被喂养多次，但随着成长，喂食频率降至每天一次，通常由父母双亲在黄昏时进行。成鸟夜晚会在巢址附近栖息。","identification":"黑雨燕与其它同属物种相比，具有较大的体型和几乎全黑的羽毛。与较小的沃氏雨燕和烟囱雨燕不同，后者虽也呈深色但体型更小，且喉部和下巴颜色较浅。与白喉雨燕的区别在于后者黑色羽毛上有大面积的白色斑块。在南美洲，与其他同属大型物种的区别主要在于体型和飞行特征。","protection":"IUCN：VU（易危）","distribution":"繁殖区域主要集中在北美西部至中美洲，包括西印度群岛。非繁殖期分布于南美，尤其在巴西的低地热带雨林。在北美，它们主要繁殖于科罗拉多州、加利福尼亚州、亚利桑那州等地的悬崖和瀑布附近。","other":"黑雨燕的繁殖生态独特，包括单卵繁殖、长时间的孵化和育雏期，以及依赖于有翅生殖蚁群飞作为食物来源的特性。"},{"name":"白胸黑雨燕","english_name":"White-chested Swift","scientific_name":"Cypseloides lemosi","overview":"白胸黑雨燕（英文名：White-chested Swift，学名：Cypseloides lemosi），是雨燕目雨燕科黑雨燕属的鸟类。具有独特的黑色外观和变化的白色胸斑。分布于南美洲中东部安第斯山脉的中海拔地带，包括哥伦比亚、厄瓜多尔、秘鲁，可能还有巴西部分地区。在1962年首次被描述时，仅在哥伦比亚中部的卡乌卡河谷有记录，近期发现其非繁殖季节可能更广泛分布。","appearance":"白胸黑雨燕体型较小，全身呈黑色，胸部有一块明显的白色斑块，宽度在中央最宽。尾部呈方形或微凹。成鸟上身带有微弱的绿色光泽，翅膀和尾巴略带蓝色。嘴眼间黑色，下体较上体稍淡，略带褐色。幼鸟缺乏白色胸带，下体呈暗石板灰色，羽端有白色。雄鸟尾部凹口更深。","call":"其鸣叫被描述为快速的哨音“pi'pi'pi-pee pee”以及单独的“tip”和“pee”音符。","habits":"常见于山区或相邻低地，常与其他雨燕混群。它们在空中捕食昆虫，食物包括小甲虫，通常群居觅食。","breeding":"关于繁殖生态学的细节未知，推测可能在悬崖附近的水源附近筑巢。","identification":"与白颈雨燕相比，白胸黑雨燕更小，胸斑位置较低，翅膀较短，尾部凹口较浅。幼鸟与黑雨燕、白颏雨燕和点额雨燕相似，但颜色更偏蓝灰，头部和侧面颜色更深，背部更有光泽。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚至厄瓜多尔东北部和秘鲁西北部，可能也出现在玻利维亚和巴西部分地区。在哥伦比亚的卡乌卡河谷有记录，南至秘鲁库斯科省。","other":"物种的保护状况评估较为困难，直到确切的繁殖范围确定为止。"},{"name":"大黑雨燕","english_name":"Great Dusky Swift","scientific_name":"Cypseloides senex","overview":"大黑雨燕（英文名：Great Dusky Swift，学名：Cypseloides senex），是雨燕目雨燕科黑雨燕属的鸟类。体型较大，体羽呈均匀的冷褐色，面部略显苍白。常见于瀑布附近栖息和筑巢，常形成大群。广泛分布于巴西、巴拉圭、阿根廷，以及可能的玻利维亚东北部。","appearance":"大黑雨燕体长约18厘米，体重介于56到110克之间。成鸟头部巧克力棕色，带有黑色羽轴条纹和灰色边缘，营造出头部霜化外观。背部颜色较深，臀部介于头背两色之间，尾羽黑褐色。翼上表面主要为褐色，翼下表面稍浅。幼鸟与成鸟相似，但翼羽有更窄的淡色边缘。","call":"主要发出‘ti-ti-ti’的声音后接以嗡嗡声，即‘tirr-tshaarr’。","habits":"全年留居于其分布范围内。以空中昆虫为食，包括至少五个不同家族的昆虫。常成群觅食，有时与白领黑雨燕混群。","breeding":"在悬崖上成群筑巢，通常位于瀑布旁或后方。巢由苔藓、石子与泥浆粘合而成。","identification":"与乌黑雨燕相比，体型更大，颜色更浅。与白领黑雨燕和巴西黑雨燕相比，体型更大且颜色更深，后者具有明显的白色颈环。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲，从巴西中部至玻利维亚东北部，巴拉圭东部和阿根廷东北部，包括伊瓜苏瀑布区域。"},{"name":"费氏黑雨燕","english_name":"Tepui Swift","scientific_name":"Streptoprocne phelpsi","overview":"费氏黑雨燕（英文名：Tepui Swift，学名：Streptoprocne phelpsi），是雨燕目雨燕科白领黑雨燕属的鸟类。特征显著，拥有橙色的喉部和颈圈，这一特征仅见于两种新热带雨燕中。分布区主要集中在南美洲的特普伊山脉，覆盖了委内瑞拉南部、巴西最北端和圭亚那西部。偶尔有记录显示在委内瑞拉北部海岸出现，可能表明存在额外的群体或是长距离的扩散。","appearance":"费氏黑雨燕体型中等，翼展宽广，尾部长而深叉。成年鸟通常呈现黑色，最引人注目的是其宽阔的橙色胸颈环，延伸至头部两侧、下胸和喉部，雌鸟个体的环颜色较淡。幼鸟的下体羽毛边缘带有明显的浅灰色。雄鸟的上体羽毛近乎黑色，有时可见少量白色羽毛位于胸环下方。雌鸟和雄鸟相似，但部分个体的胸部颜色更淡，混有棕色。幼鸟的尾叉较浅，下体羽毛有突出的浅色边缘。","call":"费氏黑雨燕的叫声包括一系列的颤音和短促的尖叫，以及缓慢的、类似芦苇或嘶嘶声的tic音节。","habits":"生活在特普伊山脉的湿润山地森林、山地草原和悬崖附近，海拔高度主要在200到2200米之间，最高可达2630米。它们可能全年在繁殖区内定居，但也有可能迁徙。以空中昆虫为食，常与白领黑雨燕一起群飞觅食。","breeding":"繁殖生态知之甚少，似乎主要在北半球的春末夏初繁殖。巢穴发现于悬崖和岩石洞穴中，至少有一次观察到巢穴位于洞穴岩架上的苔藓和根须制成的杯状巢。有迹象表明该物种可能成群筑巢。","identification":"费氏黑雨燕与栗领黑雨燕大小相近，但后者不在特普伊山脉区域出现，两物种通常地理隔离。与栗领黑雨燕相比，费氏黑雨燕尾叉更深，雌鸟个体的颈环颜色更淡，且颈环延伸至下巴和上喉部。叫声也有所不同。","protection":"IUCN：LC（无危）","distribution":"主要分布在委内瑞拉南部、圭亚那西部和巴西最北端的特普伊山脉地区。有记录显示在委内瑞拉北部海岸有零星分布。"},{"name":"栗领黑雨燕","english_name":"Chestnut-collared Swift","scientific_name":"Streptoprocne rutila","overview":"栗领黑雨燕（英文名：Chestnut-collared Swift，学名：Streptoprocne rutila），是雨燕目雨燕科白领黑雨燕属的鸟类。显著特征为成年雄鸟个体拥有独特的深栗色领圈，分布广泛，见于墨西哥至南美的山地地区，包括委内瑞拉安第斯山脉至玻利维亚，以及特立尼达岛。","appearance":"成年雄性栗领黑雨燕的头部呈烟熏般的黑褐色，背部同样为黑褐色，而臀部和上尾覆羽稍淡一些，尾羽为烟熏黑褐色。它们具有窄小的黑色眼斑，脸颊、下巴和喉咙为灰褐色，混杂着暗红色的羽毛。最显著的特征是它们在下喉部和上胸部有一条宽阔的暗红色领圈，环绕到颈部背面形成。翅膀上表面呈现不同程度的黑色，腹部颜色比背部稍浅。成年雌鸟的羽毛颜色通常比雄鸟淡，领圈要么很小要么缺失。幼鸟的色彩较成鸟淡，仅在颈侧和喉咙处有暗红色的羽毛尖，形成部分领圈。","call":"其鸣叫声被描述为类似电流通过电线的声音，带有噼啪声和嗡嗡声，有时会连续成一串嘈杂声：'bzzzz'tzz'tzz'tzz zz zzzz zzzzz zzzz.'","habits":"栗领黑雨燕栖息于多种生境，包括湿润的山区森林、松栎林、半落叶林、常绿林、半开放地带，甚至小型人类聚居区。它们通常在海拔几百米至最高3,100米的地方活动。这种鸟全年居住在其分布范围内，但会进行局部季节性迁移。它们以空中昆虫为食，偏好飞行蚂蚁和小甲虫，常与其它雨燕种类一同觅食，保持在混合群的顶部。","breeding":"繁殖季节随纬度变化，一般在北半球的5月至8月之间，而在赤道及以南地区的繁殖季尚未确定。它们在潮湿阴凉处，如洞穴、桥下或涵洞附近的岩石壁小龛中，使用泥浆和植物材料（如苔藓、地衣和蕨类植物）筑巢。每次产卵两枚，由双亲共同孵化约22至23天，雏鸟在孵化后五至六周离巢。","identification":"雄性栗领黑雨燕在良好光线条件下容易识别，因为它们具有独特的栗色领圈。然而，雌鸟的领圈往往不可见或非常小。与其他Cypseloides属物种相比，如黑雨燕、白额黑雨燕、白胸黑雨燕、白颏黑雨燕和斑额黑雨燕，栗领黑雨燕可以通过其独特的嗡嗡声鸣叫来区分。此外，与Tepui雨燕相比，栗领黑雨燕的尾巴更短、更少凹陷，且领圈不延伸至下巴和上喉部。","protection":"IUCN：LC（无危）","distribution":"栗领黑雨燕广泛分布于中美洲和南美洲，包括从墨西哥南部至秘鲁和玻利维亚的区域，以及委内瑞拉的沿海山脉和特立尼达岛。","other":"尽管分布广泛，但关于栗领黑雨燕的某些亚种分类仍存在争议，例如S. r. brunnitorques亚种的分类地位。"},{"name":"白领黑雨燕","english_name":"White-collared Swift","scientific_name":"Streptoprocne zonaris","appearance":"成年白领黑雨燕体型庞大，全身呈炭黑色，除了一条显眼的白色颈圈，颈圈在胸部最为宽广。头部颜色稍带烟灰色，其余部位黑色，尾部略显灰黑色。翅膀和尾羽内部边缘较浅，带烟灰色。幼鸟较成鸟暗淡，具灰色至白色的羽尖。性别间无明显差异。","call":"发出变化多端的尖叫和喋喋不休的声音，有时类似鹦鹉的叫声。","habits":"白领黑雨燕栖息于各种环境，从山地到沿海低地的常绿森林、开阔地带和城镇，日间大多时间在空中飞翔，以飞行昆虫为食。飞行迅速有力，能攀升至高空，速度可达每小时70至100公里。群体活动，有时与其他雨燕种类混群。","breeding":"繁殖季节在南部墨西哥和哥斯达黎加至少涵盖4月和5月，具体日期在其他地区未知。在洞穴内集体筑巢，巢穴通常位于溪流旁或瀑布后。巢为扁平圆形，由泥土、苔藓和昆虫甲壳构成，内衬树叶或蕨类植物叶片，直径120至170毫米，深度30至90毫米。每次产卵两枚，孵化期和雏鸟离巢时间未详，雏鸟约在孵化后45至55天独立。","identification":"在大部分分布范围内，白领黑雨燕是最大型的雨燕，其特征性的白色颈圈易于识别。在北墨西哥，与白枕黑雨燕共存，后者更大，具黑色胸膛和宽阔的白色颈背环。在南美洲东部，与巴西黑雨燕重叠分布，后者的白色颈圈断裂，胸部白色斑块呈三角形，指向鸟喙，且额头、面颊和下巴颜色更浅。","protection":"IUCN：LC（无危）","distribution":"白领黑雨燕广泛分布于中美洲、南美洲大陆及加勒比海岛屿，从北部墨西哥至阿根廷，包括特立尼达岛。","other":"白领黑雨燕展示出多样化的迁徙策略，部分种群为海拔迁移，而另一些则为留鸟。"},{"name":"巴西黑雨燕","english_name":"Biscutate Swift","scientific_name":"Streptoprocne biscutata","overview":"巴西黑雨燕（英文名：Biscutate Swift，学名：Streptoprocne biscutata），是雨燕目雨燕科白领黑雨燕属的鸟类。体型较大的雨燕，拥有黑色的身躯，最显著的特征是其不完整的白色领圈，形似白色的围嘴，有时脸部颜色较淡。在东部南美洲的特定区域内广泛分布，包括巴西东部和阿根廷东北部。栖息地多样，从山地到低地森林，再到次生灌木丛，均可见其踪迹。","appearance":"巴西黑雨燕的体长约为22厘米，头部呈烟灰色，额头、下巴和眼周颜色稍浅。身体主要为烟黑色，独特的白色领圈在颈部形成断续的环带，胸部有一宽阔的白带，形状略呈菱形或三角形，尖端指向下巴。翅膀和尾巴的外缘为黑色，内缘呈灰棕色。雄鸟和雌鸟外观相似，幼鸟羽毛边缘有灰白色，尤其是在腹部和尾羽尖端。","call":"其主要叫声被描述为一系列的'chee chee chee chee chee...'或'weep-weep-weep'声。","habits":"巴西黑雨燕大部分时间在空中飞翔，通常成群结队，以捕食飞行中的昆虫为生。它们在干燥的洞穴中水平的岩石上筑巢，日落后返回巢穴休息。尽管迁徙模式尚未完全明确，但相信至少部分个体具有迁徙习性。","breeding":"繁殖季节，巴西黑雨燕在洞穴中集体繁殖，巢由苔藓、地衣、植物材料和土壤构成，通常位于岩壁的水平突出处或垂直壁面上。每次产卵1至4枚，双亲共同孵卵和育雏。孵卵期大约24天，幼鸟在孵化后约33天离巢。","identification":"与更为广泛的白领黑雨燕相比，巴西黑雨燕的白色领圈不完整，且在胸部更宽，形状略呈菱形或三角形，尖端朝向下巴。此外，巴西黑雨燕的前额、下巴和眼周颜色较浅，而白领黑雨燕的头部颜色均匀。尾巴形状上，巴西黑雨燕略显方形，而白领黑雨燕为楔形。","protection":"IUCN：LC（无危）","distribution":"巴西黑雨燕主要分布在南美洲东部，包括巴西东部和阿根廷东北部。栖息于多种生态系统，如山地或低地常绿森林、温带森林、热带落叶林和次生灌木丛。","other":"巴西黑雨燕的迁徙模式尚不完全清楚，但已知它们在南美洲北部仅于2月至10月的南半球冬季出现，其具体繁殖范围未知。"},{"name":"白枕黑雨燕","english_name":"White-naped Swift","scientific_name":"Streptoprocne semicollaris","overview":"白枕黑雨燕（英文名：White-naped Swift，学名：Streptoprocne semicollaris），是雨燕目雨燕科白领黑雨燕属的鸟类。是雨燕目中体型最大的物种之一，仅亚洲的紫针尾雨燕能与其相媲美。该物种主要分布在墨西哥西部至中美洲，常在海拔1500至3000米的高地，偶尔下降至沿海低地。其显著特征为全身深色，仅后颈处有一圈醒目的白色半月形环带。","appearance":"体长20.5-25厘米，翼展22.8-23.3厘米，体重约170-180克。背部在良好光照下呈现蓝色光泽，尾部方形，飞行时略显缺口。雌雄同形同色，无明显差异。幼鸟信息缺乏，但可能与成鸟相似，白色后颈带可能不明显。","call":"发出多种尖锐的尖叫和嘈杂声，类似鹦鹉的叫声，通常在群体中更为喧闹。","habits":"栖息于高山景观，偏好悬崖峭壁、河谷和高耸的岩层，主要生境包括松栎林、热带落叶林和次生灌丛。飞行快速有力，能在热气流中攀升至高空。以飞行中的昆虫为食，如甲虫、蜜蜂和飞蚁。","breeding":"群居繁殖，有时集群可达200只。巢穴通常位于洞穴中，由干燥沙土构成浅坑，通常不含任何筑巢材料或唾液。每窝产两枚白色蛋，具体育雏行为未知。","identification":"与白领黑雨燕区别在于后者胸前有完整的白色环带，而白枕黑雨燕仅在后颈有白色环带，且尾部的缺口不如前者明显。","protection":"IUCN：LC（无危）","distribution":"主要分布于墨西哥西部，偶尔可见于中美洲，包括墨西哥西部的高原地区，向南至瓜地马拉边境。","other":"白枕黑雨燕会在瀑布附近的洞穴、天坑等结构中集体筑巢，常与其他雨燕共栖。"},{"name":"瀑布雨燕","english_name":"Giant Swiftlet","scientific_name":"Hydrochous gigas","overview":"瀑布雨燕（英文名：Giant Swiftlet，学名：Hydrochous gigas），是雨燕目雨燕科瀑布雨燕属的鸟类。身长可达16厘米，翅膀平均展开宽度约为150毫米，雄鸟体重约37克，雌鸟介于35至39克之间。以山间瀑布为栖息地，主要分布于马来西亚、苏门答腊和爪哇的山地森林和河流附近，面临因栖息地丧失而带来的威胁。","appearance":"瀑布雨燕拥有深叉状尾巴和圆胖的身体，全身呈均匀的暗褐色，上部颜色略深，下部稍浅但仍保持一致。头部黑色带光泽，翅膀和尾羽亦为黑褐色。额部和眼上窄线羽毛边缘略灰，显得比周围羽毛稍淡。眼睛周围有较白的基部羽毛。耳羽相似，但远离头顶逐渐变淡。喉咙为中褐色至灰褐色，略显斑驳。下体颜色较为均匀的中褐色，喉咙部分通常略浅。覆尾羽有明显的灰色或白色边缘。上翼显示深色有光泽的灰色飞羽与较深的灰色覆羽间的对比，尤其是更黑的较小覆羽，翅膀前缘略显苍白，灰色边缘明显。","call":"其声音描述为尖锐的刺耳声或响亮的叽叽喳喳声，能在瀑布的轰鸣声中被听见，与小白腰雨燕的声音有些许相似。","habits":"瀑布雨燕通常在山地雨林的瀑布区活动，海拔高度在马来半岛约为800至1500米，在苏门答腊约为440米，在西爪哇则在300至1500米之间。它们似乎全年留居在这些地区，但确切的移动模式尚不清楚。食物多样，取决于可用性，但似乎特别偏好飞行中的白蚁，尤其是在繁殖季节。","breeding":"繁殖期记录在西爪哇为10月至3月，在马来半岛为4月末。巢穴通常建在瀑布后面或附近的岩石壁架上，由苔藓、地衣、蕨类植物和其他材料构成，巢的直径约90至100毫米，高40至60毫米，深仅10至15毫米，一般产一枚白色的蛋。","identification":"瀑布雨燕比同域的所有雨燕大得多，飞行姿态平稳直接，翅膀仅略低于水平位置，与雨燕的不稳定摇摆飞行不同。它的尾部在飞行中经常紧闭，只有尾叉明显。","protection":"IUCN：NT（近危）","distribution":"瀑布雨燕分布在马来半岛的山区以及大巽他群岛的苏门答腊和爪哇，可能在婆罗洲也有零星分布。具体而言，已知在马来半岛、西爪哇和苏门答腊的特定山区有记录。","other":"瀑布雨燕的巢穴建造方式独特，它并不像其他雨燕那样用唾液粘合巢穴，而是将其建在平坦的水平表面上。"},{"name":"毛趾金丝燕","english_name":"Plume-toed Swiftlet","scientific_name":"Collocalia affinis","overview":"毛趾金丝燕（英文名：Plume-toed Swiftlet，学名：Collocalia affinis），是雨燕目雨燕科侏金丝燕属的鸟类。分布于东印度洋岛屿、马来半岛、苏门答腊和婆罗洲低地。曾在分类上被认为是光泽金丝燕的亚种。","appearance":"体长9-10厘米，拥有方形尾巴。背部和翅膀上表面呈现均匀的暗绿色至蓝绿色光泽。喉咙和上胸呈深灰色，逐渐变为下胸和侧腹的灰白色V字形图案，腹部通常为白色。其脚趾后方有一簇小羽毛。与同属其他物种相比，缺乏明显的白色臀部和尾羽内缘的白色斑点。","call":"发出重复的、喉音浓厚的‘krrr’或‘churrr’声，通常在巢区或栖息地附近能听到。也有更长的多音节叫声，带有相似的音质，类似短促的嘶哑歌声。","habits":"常见于多种生境，常与人类聚居地相关联。偏好湿润环境而非干旱地带。在低地雨林区域活动，如巴布亚新几内亚的森林、森林边缘和非森林区域。飞行高度在森林区域平均为52.8米，开阔地带为68米，常在离植被10米范围内觅食。以膜翅目昆虫为主食，包括蚁类、蜂类和黄蜂，也吃鞘翅目、等翅目和其他昆虫，平均猎物尺寸为4毫米。","breeding":"繁殖季节主要在2月至3月的安达曼群岛和尼科巴群岛。在马来西亚半岛的吉隆坡，产卵期从3月到8月，高峰在4月。筑巢于建筑物、浅洞穴、大洞穴入口、岩石下悬处、岩洞、空心树和大树根丛中，形成单巢或庞大的群体巢。巢由苔藓、根须、地衣和其他植物物质组成，通过唾液固定在垂直或陡峭的表面上。每窝产两枚蛋，孵化期约为21.5天，幼鸟喂养频率高，平均繁殖成功率57%，每次繁殖努力平均有1.1只幼鸟离巢。","identification":"与同域的Aerodramus属金丝燕区别明显，如具有蓝色光泽的背部，白色的腹部和暗色的臀部。不同亚种在臀部白色程度、下体颜色和尾羽白色斑点的有无上有差异。","protection":"IUCN：LC（无危）。在分布范围内常见于多个保护区，如婆罗洲的基纳巴卢国家公园和爪哇的贡德格德/庞格朗国家公园。","distribution":"繁殖区域包括东印度洋岛屿、马来半岛、苏门答腊和婆罗洲。在非繁殖季节仅在南文莱记录到。在巴布亚新几内亚的记录从海平面至4500米的卡尔斯滕茨山脊，但在苏拉威西和爪哇更常见于海拔1500米以下。","other":"在马来西亚安邦水库附近的马来西亚族群约有10,000对。在尼科巴群岛，该物种似乎正在取代因过度采集而数量下降的爪哇金丝燕。"}];
